#[cfg(target_arch = "wasm32")]
fn story_backdrop_tone() -> Tone {
    ThemeId::Dark.palette().surface_1()
}

#[cfg(target_arch = "wasm32")]
#[derive(Debug, Clone, Copy, PartialEq, Eq)]
enum StoryId {
    Component(UiComponentId),
    Block(BlockId),
}

#[cfg(target_arch = "wasm32")]
impl StoryId {
    fn name(self) -> &'static str {
        match self {
            Self::Component(id) => id.definition().name,
            Self::Block(id) => id.definition().name,
        }
    }

    fn route_id(self) -> String {
        match self {
            Self::Component(id) => format!("ui-{}", id.definition().slug),
            Self::Block(id) => format!("block-{}", id.definition().slug),
        }
    }
}

