#[cfg(target_arch = "wasm32")]
#[derive(Component)]
struct InteractivePrimitive {
    rest: Color,
    selected: Color,
    hover: Color,
    pressed: Color,
    latched: bool,
    stateful: bool,
}

#[cfg(target_arch = "wasm32")]
impl InteractivePrimitive {
    fn momentary(rest: Color, theme: &Theme) -> Self {
        Self {
            rest,
            selected: theme.selected_tint().to_bevy(),
            hover: theme.hover_tint().to_bevy(),
            pressed: theme.press_tint().to_bevy(),
            latched: false,
            stateful: false,
        }
    }

    fn stateful(rest: Color, selected: Color, latched: bool, theme: &Theme) -> Self {
        Self {
            rest,
            selected,
            hover: theme.hover_tint().to_bevy(),
            pressed: theme.press_tint().to_bevy(),
            latched,
            stateful: true,
        }
    }
}

#[cfg(target_arch = "wasm32")]
fn story_canvas_resolution() -> WindowResolution {
    let dimensions = web_sys::window()
        .and_then(|window| window.document())
        .and_then(|document| document.query_selector(CANVAS_SELECTOR).ok().flatten())
        .map(|canvas| {
            (
                u32::try_from(canvas.client_width().max(1)).unwrap_or(960),
                u32::try_from(canvas.client_height().max(1)).unwrap_or(704),
            )
        })
        .unwrap_or((960, 704));

    WindowResolution::new(dimensions.0, dimensions.1)
}

