#[cfg(not(target_arch = "wasm32"))]
fn main() {}

#[cfg(target_arch = "wasm32")]
fn selected_story_id() -> StoryId {
    web_sys::window()
        .and_then(|window| window.location().search().ok())
        .as_deref()
        .and_then(story_id_from_search)
        .unwrap_or(StoryId::Component(UiComponentId::Button))
}

#[cfg(target_arch = "wasm32")]
fn story_id_from_search(search: &str) -> Option<StoryId> {
    let query = search.strip_prefix('?').unwrap_or(search);
    query.split('&').find_map(|pair| {
        let (key, value) = pair.split_once('=').unwrap_or((pair, ""));
        (key == "story")
            .then_some(value)
            .and_then(story_id_for_route)
    })
}

#[cfg(target_arch = "wasm32")]
fn story_id_for_route(value: &str) -> Option<StoryId> {
    if let Some(slug) = value.strip_prefix("ui-") {
        return SHADCN_COMPONENTS
            .iter()
            .find(|definition| definition.slug == slug)
            .map(|definition| StoryId::Component(definition.id));
    }

    block_by_slug(value.strip_prefix("block-")?).map(|definition| StoryId::Block(definition.id))
}

#[cfg(target_arch = "wasm32")]
fn setup_story_scene(
    mut commands: Commands,
    asset_server: Res<AssetServer>,
    active_theme: Res<ActiveTheme>,
    selection: Res<StorySelection>,
    windows: Query<&Window>,
) {
    let theme = active_theme.palette();
    let fonts = StoryFonts {
        inter: asset_server.load("fonts/InterVariable.ttf"),
        arabic: asset_server.load("fonts/NotoSansArabicVariable.ttf"),
    };
    let window_size = windows
        .single()
        .map(|window| Vec2::new(window.width(), window.height()))
        .unwrap_or(Vec2::new(RESPONSIVE_BREAKPOINT, 704.0));

    commands.insert_resource(fonts.clone());
    commands.spawn((Camera2d, IsDefaultUiCamera));
    let viewport_id = commands
        .spawn((
            Node {
                width: percent(100),
                height: percent(100),
                padding: if matches!(selection.id, StoryId::Block(_)) {
                    UiRect::ZERO
                } else {
                    UiRect::all(px(scale::space::s(window_size.x)))
                },
                overflow: Overflow::scroll_y(),
                flex_direction: FlexDirection::Column,
                align_items: AlignItems::Center,
                ..default()
            },
            BackgroundColor(theme.surface_1().to_bevy()),
            ScrollPosition::default(),
            StoryViewport,
        ))
        .id();
    let viewport_context = StoryViewportContext {
        entity: viewport_id,
        size: window_size,
    };
    commands.insert_resource(PendingStoryContent {
        viewport: viewport_context,
    });
}

#[cfg(target_arch = "wasm32")]
fn spawn_story_content_when_fonts_ready(
    mut commands: Commands,
    asset_server: Res<AssetServer>,
    fonts: Res<StoryFonts>,
    pending: Option<Res<PendingStoryContent>>,
    selection: Res<StorySelection>,
    active_theme: Res<ActiveTheme>,
) {
    let Some(pending) = pending else {
        return;
    };
    if !asset_server.is_loaded_with_dependencies(&fonts.inter)
        || !asset_server.is_loaded_with_dependencies(&fonts.arabic)
    {
        return;
    }

    let viewport_context = pending.viewport;
    let theme = active_theme.palette();
    commands
        .entity(viewport_context.entity)
        .with_children(|viewport| match selection.id {
            StoryId::Component(id) => {
                spawn_component_story(viewport, id, active_theme.0, viewport_context, &fonts);
            }
            StoryId::Block(id) => {
                spawn_block_story(
                    viewport,
                    id,
                    active_theme.0,
                    &theme,
                    viewport_context,
                    &fonts,
                );
            }
        });
    commands.remove_resource::<PendingStoryContent>();
}

#[cfg(target_arch = "wasm32")]
#[allow(clippy::too_many_arguments)]
fn mark_story_runtime_ready(
    selection: Res<StorySelection>,
    asset_server: Res<AssetServer>,
    fonts: Option<Res<StoryFonts>>,
    viewport: Query<&ComputedNode, With<StoryViewport>>,
    component_hosts: Query<&ComputedNode, With<BlockComponentHost>>,
    nodes: Query<&ComputedNode>,
    text_layouts: Query<(&Text, &TextLayoutInfo)>,
    mut previous_layout: Local<Option<StoryLayoutFingerprint>>,
    mut stable_frames: Local<u8>,
    mut marked: Local<bool>,
) {
    if *marked {
        return;
    }
    let Some(fonts) = fonts else {
        return;
    };
    if !asset_server.is_loaded_with_dependencies(&fonts.inter)
        || !asset_server.is_loaded_with_dependencies(&fonts.arabic)
    {
        *stable_frames = 0;
        return;
    }
    if text_layouts
        .iter()
        .filter(|(text, _)| !text.0.trim().is_empty())
        .any(|(_, layout)| layout.glyphs.is_empty() || layout.size.x <= 0.0 || layout.size.y <= 0.0)
    {
        *stable_frames = 0;
        return;
    }
    let Ok(computed) = viewport.single() else {
        *stable_frames = 0;
        return;
    };
    let size = computed.size();
    if size.x <= 0.0 || size.y <= 0.0 {
        *stable_frames = 0;
        return;
    }
    let layout = story_layout_fingerprint(&nodes);
    if layout.nonzero_count <= 1 {
        *stable_frames = 0;
        *previous_layout = Some(layout);
        return;
    }
    if previous_layout.as_ref() == Some(&layout) {
        *stable_frames = stable_frames.saturating_add(1);
    } else {
        *stable_frames = 0;
        *previous_layout = Some(layout);
    }
    if *stable_frames < 12 {
        return;
    }
    let Some(document) = web_sys::window().and_then(|window| window.document()) else {
        return;
    };
    let Ok(Some(canvas)) = document.query_selector(CANVAS_SELECTOR) else {
        return;
    };
    if canvas.set_attribute("data-story-ready", "true").is_err()
        || canvas
            .set_attribute("data-story-route", &selection.id.route_id())
            .is_err()
        || canvas
            .set_attribute("data-story-width", &format!("{:.0}", size.x))
            .is_err()
        || canvas
            .set_attribute("data-story-height", &format!("{:.0}", size.y))
            .is_err()
    {
        return;
    }
    if let Some(host) = component_hosts.iter().next() {
        let _ = canvas.set_attribute(
            "data-story-component-host",
            &format!("width={:.2};height={:.2}", host.size().x, host.size().y),
        );
    }
    info!(
        "BEVY_STORY_READY route={} size={:.0}x{:.0}",
        selection.id.route_id(),
        size.x,
        size.y
    );
    *marked = true;
}

fn story_layout_fingerprint(nodes: &Query<&ComputedNode>) -> StoryLayoutFingerprint {
    let mut fingerprint = StoryLayoutFingerprint {
        node_count: 0,
        nonzero_count: 0,
        width_sum: 0,
        height_sum: 0,
        content_width_sum: 0,
        content_height_sum: 0,
    };
    for node in nodes {
        let size = node.size();
        let content_size = node.content_size();
        fingerprint.node_count += 1;
        fingerprint.nonzero_count += usize::from(size.x > 0.0 && size.y > 0.0);
        fingerprint.width_sum += quantize_layout_value(size.x);
        fingerprint.height_sum += quantize_layout_value(size.y);
        fingerprint.content_width_sum += quantize_layout_value(content_size.x);
        fingerprint.content_height_sum += quantize_layout_value(content_size.y);
    }
    fingerprint
}

#[cfg(target_arch = "wasm32")]
fn quantize_layout_value(value: f32) -> i64 {
    if value.is_finite() {
        (value * 16.0).round() as i64
    } else {
        0
    }
}

#[cfg(target_arch = "wasm32")]
fn spawn_component_story(
    viewport: &mut ChildSpawnerCommands,
    id: UiComponentId,
    theme_id: ThemeId,
    viewport_context: StoryViewportContext,
    fonts: &StoryFonts,
) {
    let window_width = viewport_context.size.x;
    let variants = bevy_story_variants_for_component(id, theme_id);
    let single_column = false;
    let columns = story_grid_column_count(window_width, single_column);
    let story_gap = scale::space::s(window_width);
    let grid_width = (window_width - story_gap * 2.0).clamp(1.0, CONTENT_MAX_WIDTH);
    let cell_width =
        (grid_width - story_gap * f32::from(columns.saturating_sub(1))) / f32::from(columns);

    viewport
        .spawn((
            Node {
                display: Display::Grid,
                width: percent(100),
                max_width: px(CONTENT_MAX_WIDTH),
                margin: UiRect::horizontal(auto()),
                grid_template_columns: RepeatedGridTrack::fr(columns, 1.0),
                grid_auto_rows: GridTrack::auto(),
                row_gap: px(story_gap),
                column_gap: px(story_gap),
                align_items: AlignItems::Stretch,
                padding: UiRect::bottom(px(story_gap)),
                ..default()
            },
            StoryGrid { single_column },
        ))
        .with_children(|grid| {
            for variant in &variants {
                spawn_story_variant(
                    grid,
                    id,
                    variant,
                    fonts,
                    cell_width,
                    window_width,
                    viewport_context,
                );
            }
        });
}

#[cfg(target_arch = "wasm32")]
fn spawn_block_story(
    viewport: &mut ChildSpawnerCommands,
    id: BlockId,
    theme_id: ThemeId,
    theme: &Theme,
    viewport_context: StoryViewportContext,
    fonts: &StoryFonts,
) {
    let window_size = viewport_context.size;
    let viewport_size = Vec2::new(window_size.x.max(240.0), window_size.y.max(1.0));
    let instance = BlockInstance::fixture(id.definition());

    match bevy_block_primitives(&instance, theme, viewport_size) {
        Ok(primitives) => {
            spawn_block_primitives(
                viewport,
                &primitives,
                theme_id,
                theme,
                fonts,
                viewport_context,
            );
        }
        Err(report) => spawn_text(
            viewport,
            format!("Block validation failed: {report}"),
            fonts.inter.clone(),
            scale::font_size::F0,
            FontWeight::SEMIBOLD,
            theme.danger().to_bevy(),
        ),
    }
}

#[cfg(target_arch = "wasm32")]
fn spawn_block_primitives(
    viewport: &mut ChildSpawnerCommands,
    primitives: &[BevyBlockPrimitive],
    theme_id: ThemeId,
    theme: &Theme,
    fonts: &StoryFonts,
    viewport_context: StoryViewportContext,
) {
    let section = primitives
        .iter()
        .find(|primitive| primitive.kind == BevyBlockPrimitiveKind::Section)
        .cloned();
    let section_fill = section
        .as_ref()
        .map_or_else(|| theme.surface_1().to_bevy(), |primitive| primitive.fill);
    let section_size = section
        .as_ref()
        .map_or(Vec2::new(240.0, 1.0), |primitive| primitive.size);
    let has_component_host = primitives
        .iter()
        .any(|primitive| matches!(primitive.kind, BevyBlockPrimitiveKind::UiComponentHost(_)));

    viewport
        .spawn((
            Node {
                position_type: PositionType::Relative,
                width: px(section_size.x),
                height: px(section_size.y),
                min_width: px(section_size.x),
                min_height: px(section_size.y),
                flex_shrink: 0.0,
                margin: UiRect::horizontal(auto()),
                ..default()
            },
            BackgroundColor(section_fill),
        ))
        .with_children(|root| {
            for primitive in primitives
                .iter()
                .filter(|primitive| primitive.kind != BevyBlockPrimitiveKind::Section)
                .filter(|primitive| {
                    !has_component_host
                        || primitive.ui.is_none()
                        || matches!(primitive.kind, BevyBlockPrimitiveKind::UiComponentHost(_))
                })
            {
                spawn_block_primitive(
                    root,
                    primitive,
                    section_size,
                    theme_id,
                    theme,
                    fonts,
                    viewport_context,
                );
            }
        });
}

#[cfg(target_arch = "wasm32")]
fn spawn_block_primitive(
    parent: &mut ChildSpawnerCommands,
    primitive: &BevyBlockPrimitive,
    content_size: Vec2,
    theme_id: ThemeId,
    theme: &Theme,
    fonts: &StoryFonts,
    viewport_context: StoryViewportContext,
) {
    let component_id = match primitive.kind {
        BevyBlockPrimitiveKind::UiComponentHost(id) => Some(id),
        _ => None,
    };
    let centers_label = primitive.centers_label();
    let origin = block_primitive_origin(primitive.center, primitive.size, content_size);
    let text_justify = block_text_justify(primitive.text_align);
    let disabled = primitive.ui.as_ref().is_some_and(|ui| ui.disabled);
    let fill = if component_id.is_some() {
        Color::NONE
    } else if disabled {
        primitive.fill.with_alpha(0.42)
    } else {
        primitive.fill
    };
    let text_color = if disabled {
        primitive.text.with_alpha(0.38)
    } else {
        primitive.text
    };
    let mut entity = parent.spawn((
        Node {
            position_type: PositionType::Absolute,
            left: px(origin.x),
            top: px(origin.y),
            width: px(primitive.size.x.max(0.0)),
            height: px(primitive.size.y.max(0.0)),
            min_width: px(0.0),
            padding: block_primitive_padding(primitive.kind),
            border: block_primitive_border(primitive),
            border_radius: block_primitive_radius(primitive, theme),
            justify_content: block_justify_content(primitive.text_align),
            align_items: if component_id.is_some() {
                AlignItems::Stretch
            } else {
                AlignItems::Center
            },
            overflow: if component_id.is_some() {
                Overflow::default()
            } else {
                Overflow::clip()
            },
            flex_direction: if centers_label {
                FlexDirection::Row
            } else {
                FlexDirection::Column
            },
            ..default()
        },
        BackgroundColor(fill),
        BorderColor::all(if component_id.is_some() {
            Color::NONE
        } else {
            primitive.border
        }),
    ));

    if let Some(id) = component_id {
        entity.insert(BlockComponentHost);
        if let Some(variant) = bevy_story_variants_for_component(id, theme_id)
            .into_iter()
            .next()
        {
            entity.with_children(|host| {
                spawn_story_model_content(
                    host,
                    id,
                    &variant,
                    fonts,
                    primitive.size.x,
                    content_size.x,
                    viewport_context,
                );
            });
        }
        return;
    }

    if primitive.font_size > 0.0 && !primitive.label.trim().is_empty() {
        let line_break = if centers_label {
            LineBreak::NoWrap
        } else {
            LineBreak::WordOrCharacter
        };
        entity.with_children(|container| {
            let mut label = container.spawn((
                Text::new(primitive.label.clone()),
                TextFont {
                    font: fonts.inter.clone().into(),
                    font_size: FontSize::Px(primitive.font_size),
                    weight: FontWeight(primitive.font_weight).clamp(),
                    ..default()
                },
                LineHeight::RelativeToFont(primitive.line_height),
                LetterSpacing::Rem(primitive.letter_spacing),
                TextColor(text_color),
                TextLayout::new(text_justify, line_break),
            ));
            if !centers_label {
                label.insert(Node {
                    width: percent(100),
                    max_width: percent(100),
                    min_width: px(0),
                    ..default()
                });
            }
        });
    }

    let ui_interactive = primitive
        .ui
        .as_ref()
        .is_some_and(|ui| ui.intent != UiWidgetIntent::None && !ui.disabled);
    if primitive.kind == BevyBlockPrimitiveKind::Action || ui_interactive {
        let interaction = if let Some(ui) = &primitive.ui {
            InteractivePrimitive::stateful(
                fill,
                theme.selected_tint().to_bevy(),
                ui.selected,
                theme,
            )
        } else {
            InteractivePrimitive::momentary(fill, theme)
        };
        entity.insert((Button, interaction));
    }
}

#[cfg(target_arch = "wasm32")]
fn block_primitive_origin(center: Vec2, size: Vec2, content_size: Vec2) -> Vec2 {
    Vec2::new(
        content_size.x / 2.0 + center.x - size.x / 2.0,
        content_size.y / 2.0 - center.y - size.y / 2.0,
    )
}

#[cfg(target_arch = "wasm32")]
const fn block_justify_content(align: GridAlign) -> JustifyContent {
    match align {
        GridAlign::Center => JustifyContent::Center,
        GridAlign::End => JustifyContent::FlexEnd,
        GridAlign::Start | GridAlign::Stretch => JustifyContent::FlexStart,
    }
}

#[cfg(target_arch = "wasm32")]
const fn block_text_justify(align: GridAlign) -> Justify {
    match align {
        GridAlign::Center => Justify::Center,
        GridAlign::End => Justify::Right,
        GridAlign::Start | GridAlign::Stretch => Justify::Left,
    }
}

#[cfg(target_arch = "wasm32")]
const fn block_primitive_padding(_kind: BevyBlockPrimitiveKind) -> UiRect {
    UiRect::ZERO
}

#[cfg(target_arch = "wasm32")]
fn block_primitive_border(primitive: &BevyBlockPrimitive) -> UiRect {
    if matches!(primitive.kind, BevyBlockPrimitiveKind::UiComponentHost(_)) {
        return UiRect::ZERO;
    }
    let width = px(primitive.border_width.max(0.0));
    match primitive.part.as_str() {
        "InputPrefix" | "InputGroupAddon" => UiRect::right(width),
        "InputSuffix" | "InputGroupButton" => UiRect::left(width),
        "InputControl" | "InputGroupInput" => UiRect::ZERO,
        "item-footer" => UiRect::top(width),
        _ => UiRect::all(width),
    }
}

#[cfg(target_arch = "wasm32")]
fn block_primitive_radius(primitive: &BevyBlockPrimitive, theme: &Theme) -> BorderRadius {
    if matches!(
        primitive.part.as_str(),
        "Input" | "InputGroup" | "ItemMedia" | "item-content"
    ) || primitive.part.starts_with("ItemActions")
    {
        return BorderRadius::all(px(theme.radius_field));
    }
    if matches!(primitive.part.as_str(), "InputPrefix" | "InputGroupAddon") {
        return BorderRadius::px(theme.radius_field, 0.0, 0.0, theme.radius_field);
    }
    if matches!(primitive.part.as_str(), "InputSuffix" | "InputGroupButton") {
        return BorderRadius::px(0.0, theme.radius_field, theme.radius_field, 0.0);
    }
    if matches!(primitive.part.as_str(), "InputControl" | "InputGroupInput") {
        return BorderRadius::ZERO;
    }
    let radius = match primitive.kind {
        BevyBlockPrimitiveKind::Action => theme.radius_field,
        BevyBlockPrimitiveKind::Item
        | BevyBlockPrimitiveKind::Media
        | BevyBlockPrimitiveKind::UiComponent => theme.radius_box,
        BevyBlockPrimitiveKind::UiComponentHost(_) => 0.0,
        BevyBlockPrimitiveKind::Section
        | BevyBlockPrimitiveKind::Heading
        | BevyBlockPrimitiveKind::Text => 0.0,
    };
    BorderRadius::all(px(radius))
}

#[cfg(target_arch = "wasm32")]
fn spawn_story_variant(
    parent: &mut ChildSpawnerCommands,
    id: UiComponentId,
    variant: &BevyUiStoryVariant,
    fonts: &StoryFonts,
    available_width: f32,
    inline_size: f32,
    viewport_context: StoryViewportContext,
) {
    let compact = id == UiComponentId::Accordion;
    let popover_stage_min_height = match &variant.model {
        UiStoryModel::Popover(model) => {
            let metrics = popover_layout_metrics(model, inline_size);
            Some(
                metrics.trigger_outer_height(variant.theme_id.palette().border.max(1.0))
                    + scale::space::xl4(inline_size)
                    + scale::space::xl(inline_size),
            )
        }
        _ => None,
    };
    parent
        .spawn((
            Node {
                width: if compact {
                    px(available_width.min(scale::container::CONTROL))
                } else {
                    auto()
                },
                max_width: if compact {
                    px(scale::container::CONTROL)
                } else {
                    auto()
                },
                min_width: px(0.0),
                min_height: popover_stage_min_height.map_or_else(auto, px),
                justify_self: if compact {
                    JustifySelf::Start
                } else {
                    JustifySelf::Stretch
                },
                align_self: AlignSelf::Stretch,
                flex_direction: FlexDirection::Column,
                ..default()
            },
            StoryVariantCell,
        ))
        .with_children(|cell| {
            spawn_story_model_content(
                cell,
                id,
                variant,
                fonts,
                available_width,
                inline_size,
                viewport_context,
            );
        });
}

#[cfg(target_arch = "wasm32")]
fn spawn_story_model_content(
    parent: &mut ChildSpawnerCommands,
    id: UiComponentId,
    variant: &BevyUiStoryVariant,
    fonts: &StoryFonts,
    available_width: f32,
    inline_size: f32,
    viewport_context: StoryViewportContext,
) {
    match &variant.model {
        UiStoryModel::Alert(model) => {
            spawn_alert(
                parent,
                model,
                variant.theme_id.palette(),
                fonts,
                inline_size,
            );
        }
        UiStoryModel::AlertDialog(model) => {
            spawn_alert_dialog(
                parent,
                model,
                variant.default_open,
                variant.theme_id.palette(),
                fonts,
                available_width,
                inline_size,
            );
        }
        UiStoryModel::Breadcrumb(model) => {
            spawn_breadcrumb(
                parent,
                model,
                variant.theme_id.palette(),
                fonts,
                inline_size,
            );
        }
        _ => spawn_primitive_component(
            parent,
            id,
            variant,
            fonts,
            available_width,
            inline_size,
            viewport_context,
        ),
    }
}

#[cfg(target_arch = "wasm32")]
fn spawn_alert(
    parent: &mut ChildSpawnerCommands,
    model: &AlertModel,
    theme: Theme,
    fonts: &StoryFonts,
    inline_size: f32,
) {
    let dense = model.density == AlertDensity::Dense;
    let padding = if dense {
        scale::space::xs(inline_size)
    } else {
        scale::space::s(inline_size)
    };
    let gap = if dense {
        scale::space::xs2(inline_size)
    } else {
        scale::space::xs(inline_size)
    };
    let radius = if dense {
        theme.radius_field
    } else {
        theme.radius_box
    };
    let (background, border, marker, marker_text) = alert_colors(model.tone, &theme);

    parent
        .spawn((
            Node {
                width: auto(),
                justify_self: JustifySelf::Stretch,
                padding: UiRect::all(px(padding)),
                border: UiRect::all(px(theme.border.max(1.0))),
                border_radius: BorderRadius::all(px(radius)),
                ..default()
            },
            BackgroundColor(background),
            BorderColor::all(border),
            if model.disabled {
                BoxShadow::default()
            } else {
                BoxShadow::new(
                    theme.text_1().to_bevy().with_alpha(0.025),
                    px(0.0),
                    px(scale::space::xs3(inline_size)),
                    px(0.0),
                    px(scale::space::xs2(inline_size)),
                )
            },
        ))
        .with_children(|alert| {
            alert
                .spawn(Node {
                    width: percent(100),
                    flex_direction: FlexDirection::Row,
                    flex_wrap: FlexWrap::Wrap,
                    align_items: AlignItems::Start,
                    row_gap: px(gap),
                    column_gap: px(gap),
                    ..default()
                })
                .with_children(|row| {
                    row.spawn((
                        Node {
                            width: px(scale::space::s(inline_size)),
                            height: px(scale::space::s(inline_size)),
                            min_width: px(scale::space::s(inline_size)),
                            min_height: px(scale::space::s(inline_size)),
                            justify_content: JustifyContent::Center,
                            align_items: AlignItems::Center,
                            border_radius: BorderRadius::MAX,
                            ..default()
                        },
                        BackgroundColor(marker),
                        Text::new(alert_marker_label(model.tone)),
                        TextFont {
                            font: fonts.inter.clone().into(),
                            font_size: FontSize::Px(scale::font_size::f00(inline_size)),
                            weight: FontWeight::BOLD,
                            ..default()
                        },
                        TextColor(marker_text),
                        TextLayout::new(Justify::Center, LineBreak::NoWrap),
                    ));

                    row.spawn(Node {
                        min_width: px(180.0),
                        flex_basis: px(220.0),
                        flex_grow: 1.0,
                        flex_direction: FlexDirection::Column,
                        row_gap: px(scale::space::xs2(inline_size)),
                        ..default()
                    })
                    .with_children(|body| {
                        spawn_text_with_line_height(
                            body,
                            model.title.clone(),
                            fonts.inter.clone(),
                            if dense {
                                scale::font_size::f0(inline_size)
                            } else {
                                scale::font_size::f1(inline_size)
                            },
                            FontWeight::BOLD,
                            theme.text_1().to_bevy(),
                            if dense {
                                scale::line_height::LH0
                            } else {
                                scale::line_height::LH2
                            },
                        );
                        spawn_text(
                            body,
                            model.description.clone(),
                            fonts.inter.clone(),
                            if dense {
                                scale::font_size::f00(inline_size)
                            } else {
                                scale::font_size::f0(inline_size)
                            },
                            FontWeight::NORMAL,
                            theme.text_2().to_bevy(),
                        );
                    });

                    if let Some(action) = &model.action {
                        let disabled = model.disabled || model.loading || action.disabled;
                        let rest = theme.surface_2().to_bevy();
                        row.spawn((
                            Button,
                            Node {
                                min_height: px(scale::space::l(inline_size)),
                                padding: UiRect::axes(
                                    px(scale::space::xs(inline_size)),
                                    px(scale::space::xs2(inline_size)),
                                ),
                                border: UiRect::all(px(theme.border.max(1.0))),
                                border_radius: BorderRadius::all(px(theme.radius_field)),
                                justify_content: JustifyContent::Center,
                                align_items: AlignItems::Center,
                                ..default()
                            },
                            BackgroundColor(if disabled {
                                rest.with_alpha(0.42)
                            } else {
                                rest
                            }),
                            BorderColor::all(theme.border_strong().to_bevy()),
                            Text::new(if model.loading {
                                "Loading".to_owned()
                            } else {
                                action.label.clone()
                            }),
                            TextFont {
                                font: fonts.inter.clone().into(),
                                font_size: FontSize::Px(scale::font_size::f0(inline_size)),
                                weight: FontWeight::SEMIBOLD,
                                ..default()
                            },
                            LineHeight::Px(
                                scale::font_size::f0(inline_size) * scale::line_height::LH0,
                            ),
                            TextColor(if disabled {
                                theme.text_disabled().to_bevy()
                            } else {
                                theme.text_1().to_bevy()
                            }),
                            TextLayout::new(Justify::Center, LineBreak::NoWrap),
                            InteractivePrimitive::momentary(rest, &theme),
                        ));
                    }
                });
        });
}

#[cfg(target_arch = "wasm32")]
fn alert_colors(tone: AlertTone, theme: &Theme) -> (Color, Color, Color, Color) {
    match tone {
        AlertTone::Default => (
            theme.surface_1().to_bevy(),
            theme.border_subtle().to_bevy(),
            theme.surface_2().to_bevy(),
            theme.text_muted().to_bevy(),
        ),
        AlertTone::Info => (
            theme.info_soft().to_bevy_on(theme.surface_1()),
            theme.info.to_bevy(),
            theme.info.to_bevy(),
            theme.text_on_brand().to_bevy(),
        ),
        AlertTone::Success => (
            theme.success_soft().to_bevy_on(theme.surface_1()),
            theme.success.to_bevy(),
            theme.success.to_bevy(),
            theme.text_on_brand().to_bevy(),
        ),
        AlertTone::Warning => (
            theme.warning_soft().to_bevy_on(theme.surface_1()),
            theme.warning.to_bevy(),
            theme.warning.to_bevy(),
            theme.text_on_brand().to_bevy(),
        ),
        AlertTone::Destructive => (
            theme.error_soft().to_bevy_on(theme.surface_1()),
            theme.danger().to_bevy(),
            theme.danger().to_bevy(),
            theme.text_on_brand().to_bevy(),
        ),
    }
}

#[cfg(target_arch = "wasm32")]
const fn alert_marker_label(tone: AlertTone) -> &'static str {
    match tone {
        AlertTone::Default | AlertTone::Info => "i",
        AlertTone::Success => "+",
        AlertTone::Warning | AlertTone::Destructive => "!",
    }
}

#[cfg(target_arch = "wasm32")]
fn spawn_alert_dialog(
    parent: &mut ChildSpawnerCommands,
    model: &AlertDialogModel,
    default_open: bool,
    theme: Theme,
    fonts: &StoryFonts,
    available_width: f32,
    inline_size: f32,
) {
    let state = if default_open {
        AlertDialogState::open()
    } else {
        AlertDialogState::closed()
    };
    let border_width = theme.border.max(1.0);
    let metrics = alert_dialog_layout_metrics(
        model,
        state.is_open(),
        available_width,
        inline_size,
        border_width,
    );
    let root_id = parent
        .spawn(Node {
            width: percent(100),
            min_width: px(0.0),
            flex_direction: FlexDirection::Column,
            row_gap: px(metrics.root_gap),
            ..default()
        })
        .id();
    let mut commands = parent.commands();
    let trigger_disabled = model.disabled;
    let trigger_fill = theme.surface_2().to_bevy();
    let trigger_background = if trigger_disabled {
        theme
            .surface_2()
            .with_opacity(scale::opacity::DISABLED)
            .to_bevy_on(theme.surface_1())
    } else {
        trigger_fill
    };
    let trigger_border = if trigger_disabled {
        theme
            .border_strong()
            .with_opacity(scale::opacity::DISABLED)
            .to_bevy_on(theme.surface_1())
    } else {
        theme.border_strong().to_bevy()
    };
    let trigger_text = if trigger_disabled {
        theme
            .text_1()
            .with_opacity(scale::opacity::DISABLED)
            .to_bevy_on(theme.surface_1())
    } else {
        theme.text_1().to_bevy()
    };
    let mut trigger_entity = commands.spawn((
        ChildOf(root_id),
        AlertDialogControl {
            group: root_id,
            part: AlertDialogPart::Trigger,
            disabled: trigger_disabled,
        },
        Node {
            width: percent(100),
            min_width: px(0.0),
            min_height: px(metrics.trigger_height),
            flex_grow: if state.is_open() { 0.0 } else { 1.0 },
            padding: UiRect::axes(
                px(metrics.trigger_padding_inline),
                px(metrics.trigger_padding_block),
            ),
            border: UiRect::all(px(border_width)),
            border_radius: BorderRadius::all(px(theme.radius_field)),
            justify_content: JustifyContent::Center,
            align_items: AlignItems::Center,
            overflow: Overflow::clip(),
            ..default()
        },
        BackgroundColor(trigger_background),
        BorderColor::all(trigger_border),
        bevy_shadow_1(&theme, inline_size),
    ));
    if !trigger_disabled {
        trigger_entity.insert((
            Button,
            InteractivePrimitive::momentary(trigger_fill, &theme),
        ));
    }
    let trigger_id = trigger_entity.id();
    let trigger_content_id = commands
        .spawn((
            ChildOf(trigger_id),
            Node {
                display: Display::Grid,
                width: percent(100),
                height: percent(100),
                min_width: px(0.0),
                flex_grow: 1.0,
                justify_items: JustifyItems::Center,
                align_items: AlignItems::Center,
                ..default()
            },
        ))
        .id();
    commands.spawn((
        ChildOf(trigger_content_id),
        Node {
            width: auto(),
            height: auto(),
            justify_self: JustifySelf::Center,
            align_self: AlignSelf::Center,
            ..default()
        },
        Text::new(model.trigger_label.clone()),
        TextFont {
            font: fonts.inter.clone().into(),
            font_size: FontSize::Px(scale::font_size::f0(inline_size)),
            weight: FontWeight::SEMIBOLD,
            ..default()
        },
        LineHeight::RelativeToFont(scale::line_height::LH0),
        TextColor(trigger_text),
        TextLayout::new(Justify::Center, LineBreak::NoWrap),
    ));

    let overlay_id = commands
        .spawn((
            ChildOf(root_id),
            Node {
                display: if state.is_open() {
                    Display::Flex
                } else {
                    Display::None
                },
                width: percent(100),
                min_width: px(0.0),
                min_height: px(metrics.overlay_height),
                flex_grow: 1.0,
                padding: UiRect::all(px(metrics.overlay_padding)),
                border_radius: BorderRadius::all(px(theme.radius_box)),
                justify_content: JustifyContent::Center,
                align_items: AlignItems::Center,
                ..default()
            },
            BackgroundColor(
                theme
                    .surface_overlay()
                    .to_bevy_css_alpha_on(theme.surface_1()),
            ),
        ))
        .id();
    let content_id = commands
        .spawn((
            ChildOf(overlay_id),
            Node {
                width: percent(100),
                min_width: px(0.0),
                min_height: px(metrics.content_height),
                padding: UiRect::all(px(metrics.content_padding)),
                border: UiRect::all(px(border_width)),
                border_radius: BorderRadius::all(px(theme.radius_box)),
                flex_direction: FlexDirection::Column,
                row_gap: px(metrics.content_gap),
                ..default()
            },
            BackgroundColor(theme.surface_elevated().to_bevy()),
            BorderColor::all(if model.destructive {
                theme.danger().to_bevy()
            } else {
                theme.border_subtle().to_bevy()
            }),
            if model.size == rs_dean_ui::AlertDialogSize::Small {
                bevy_shadow_2(&theme, inline_size)
            } else {
                bevy_shadow_3(&theme, inline_size)
            },
        ))
        .id();
    let header_id = commands
        .spawn((
            ChildOf(content_id),
            Node {
                width: percent(100),
                min_width: px(0.0),
                min_height: px(metrics.header_height),
                flex_direction: FlexDirection::Column,
                row_gap: px(metrics.header_gap),
                ..default()
            },
        ))
        .id();
    commands.spawn((
        ChildOf(header_id),
        Node {
            width: percent(100),
            min_width: px(0.0),
            min_height: px(metrics.title_height),
            ..default()
        },
        Text::new(model.title.clone()),
        TextFont {
            font: fonts.inter.clone().into(),
            font_size: FontSize::Px(metrics.title_font_size),
            weight: FontWeight::BOLD,
            ..default()
        },
        LineHeight::RelativeToFont(if model.size == rs_dean_ui::AlertDialogSize::Small {
            scale::line_height::LH0
        } else {
            scale::line_height::LH2
        }),
        TextColor(theme.text_1().to_bevy()),
        TextLayout::new(Justify::Left, LineBreak::WordOrCharacter),
    ));
    commands.spawn((
        ChildOf(header_id),
        Node {
            width: percent(100),
            min_width: px(0.0),
            min_height: px(metrics.description_height),
            ..default()
        },
        Text::new(model.description.clone()),
        TextFont {
            font: fonts.inter.clone().into(),
            font_size: FontSize::Px(metrics.description_font_size),
            ..default()
        },
        LineHeight::RelativeToFont(scale::line_height::LH0),
        TextColor(theme.text_2().to_bevy()),
        TextLayout::new(Justify::Left, LineBreak::WordOrCharacter),
    ));

    let footer_id = commands
        .spawn((
            ChildOf(content_id),
            Node {
                width: percent(100),
                min_width: px(0.0),
                min_height: px(metrics.footer_height),
                flex_direction: FlexDirection::Row,
                flex_wrap: FlexWrap::Wrap,
                justify_content: JustifyContent::FlexEnd,
                align_items: AlignItems::Center,
                row_gap: px(metrics.footer_gap),
                column_gap: px(metrics.footer_gap),
                ..default()
            },
        ))
        .id();
    let cancel_disabled = model.disabled || model.loading || model.cancel.disabled;
    let cancel_fill = theme.surface_2().to_bevy();
    let cancel_background = if cancel_disabled {
        theme
            .surface_2()
            .with_opacity(scale::opacity::DISABLED)
            .to_bevy_on(theme.surface_elevated())
    } else {
        cancel_fill
    };
    let cancel_border = if cancel_disabled {
        theme
            .border_strong()
            .with_opacity(scale::opacity::DISABLED)
            .to_bevy_on(theme.surface_elevated())
    } else {
        theme.border_strong().to_bevy()
    };
    let cancel_text = if cancel_disabled {
        theme
            .text_1()
            .with_opacity(scale::opacity::DISABLED)
            .to_bevy_on(theme.surface_elevated())
    } else {
        theme.text_1().to_bevy()
    };
    let mut cancel_entity = commands.spawn((
        ChildOf(footer_id),
        AlertDialogControl {
            group: root_id,
            part: AlertDialogPart::Cancel,
            disabled: cancel_disabled,
        },
        Node {
            width: px(metrics.cancel_width),
            height: px(metrics.button_height),
            min_width: px(metrics.cancel_width),
            min_height: px(metrics.button_height),
            padding: UiRect::axes(
                px(metrics.trigger_padding_inline),
                px(metrics.trigger_padding_block),
            ),
            border: UiRect::all(px(border_width)),
            border_radius: BorderRadius::all(px(theme.radius_field)),
            justify_content: JustifyContent::Center,
            align_items: AlignItems::Center,
            ..default()
        },
        BackgroundColor(cancel_background),
        BorderColor::all(cancel_border),
        Text::new(model.cancel.label.clone()),
        TextFont {
            font: fonts.inter.clone().into(),
            font_size: FontSize::Px(scale::font_size::f0(inline_size)),
            weight: FontWeight::SEMIBOLD,
            ..default()
        },
        LineHeight::RelativeToFont(scale::line_height::LH0),
        TextColor(cancel_text),
        TextLayout::new(Justify::Center, LineBreak::NoWrap),
    ));
    if !cancel_disabled {
        cancel_entity.insert((Button, InteractivePrimitive::momentary(cancel_fill, &theme)));
    }
    let action_disabled = model.disabled || model.loading || model.action.disabled;
    let action_fill = if model.destructive {
        theme.error_soft().to_bevy_on(theme.surface_elevated())
    } else {
        theme.primary_soft().to_bevy_on(theme.surface_elevated())
    };
    let action_tone = if model.destructive {
        theme.error_soft()
    } else {
        theme.primary_soft()
    };
    let action_background = if action_disabled {
        action_tone
            .with_opacity(scale::opacity::DISABLED)
            .to_bevy_on(theme.surface_elevated())
    } else {
        action_fill
    };
    let action_border_tone = if model.destructive {
        theme.danger()
    } else {
        theme.brand()
    };
    let action_border = if action_disabled {
        action_border_tone
            .with_opacity(scale::opacity::DISABLED)
            .to_bevy_on(theme.surface_elevated())
    } else {
        action_border_tone.to_bevy()
    };
    let action_text = if action_disabled {
        theme
            .text_1()
            .with_opacity(scale::opacity::DISABLED)
            .to_bevy_on(theme.surface_elevated())
    } else {
        theme.text_1().to_bevy()
    };
    let mut action_entity = commands.spawn((
        ChildOf(footer_id),
        AlertDialogControl {
            group: root_id,
            part: AlertDialogPart::Action,
            disabled: action_disabled,
        },
        Node {
            width: px(metrics.action_width),
            height: px(metrics.button_height),
            min_width: px(metrics.action_width),
            min_height: px(metrics.button_height),
            padding: UiRect::axes(
                px(metrics.trigger_padding_inline),
                px(metrics.trigger_padding_block),
            ),
            border: UiRect::all(px(border_width)),
            border_radius: BorderRadius::all(px(theme.radius_field)),
            justify_content: JustifyContent::Center,
            align_items: AlignItems::Center,
            ..default()
        },
        BackgroundColor(action_background),
        BorderColor::all(action_border),
        Text::new(if model.loading {
            "Working".to_owned()
        } else {
            model.action.label.clone()
        }),
        TextFont {
            font: fonts.inter.clone().into(),
            font_size: FontSize::Px(scale::font_size::f0(inline_size)),
            weight: FontWeight::BOLD,
            ..default()
        },
        LineHeight::RelativeToFont(scale::line_height::LH0),
        TextColor(action_text),
        TextLayout::new(Justify::Center, LineBreak::NoWrap),
    ));
    if !action_disabled {
        action_entity.insert((Button, InteractivePrimitive::momentary(action_fill, &theme)));
    }

    commands.entity(root_id).insert(AlertDialogGroupState {
        model: model.clone(),
        state,
        trigger: trigger_id,
        overlay: overlay_id,
    });
}

#[cfg(target_arch = "wasm32")]
fn spawn_dialog_primitives(
    parent: &mut ChildSpawnerCommands,
    variant: &BevyUiStoryVariant,
    fonts: &StoryFonts,
    available_width: f32,
    inline_size: f32,
) {
    let UiStoryModel::Dialog(model) = &variant.model else {
        return;
    };
    let theme = variant.theme_id.palette();
    let state = model.state();
    let render_nodes = dialog_render_nodes(model, &state);
    let blocked = model.loading || model.disabled;
    let border_width = theme.border.max(1.0);
    let metrics = dialog_layout_metrics(
        model,
        state.is_open(),
        available_width,
        inline_size,
        border_width,
    );
    let root_fill = theme.surface_1();
    let root_id = parent
        .spawn(Node {
            width: percent(100),
            min_width: px(0.0),
            flex_direction: FlexDirection::Column,
            row_gap: px(metrics.root_gap),
            ..default()
        })
        .id();
    let mut commands = parent.commands();
    let trigger_node = render_nodes
        .iter()
        .find(|node| node.part == DialogPart::Trigger)
        .expect("invariant: dialog render nodes include trigger");
    let trigger_palette = dialog_trigger_palette(state.is_open(), blocked, root_fill, &theme);
    let trigger_id = commands
        .spawn((
            ChildOf(root_id),
            Button,
            Node {
                width: percent(100),
                min_width: px(0.0),
                min_height: px(metrics.trigger_height),
                flex_grow: if state.is_open() { 0.0 } else { 1.0 },
                padding: UiRect::axes(
                    px(metrics.trigger_padding_inline),
                    px(metrics.trigger_padding_block),
                ),
                border: UiRect::all(px(border_width)),
                border_radius: BorderRadius::all(px(theme.radius_field)),
                justify_content: JustifyContent::Center,
                align_items: AlignItems::Center,
                ..default()
            },
            BackgroundColor(trigger_palette.background),
            BorderColor::all(trigger_palette.border),
            bevy_shadow_1(&theme, inline_size),
            InteractivePrimitive {
                rest: trigger_palette.background,
                selected: trigger_palette.background,
                hover: trigger_palette.hover,
                pressed: trigger_palette.hover,
                latched: state.is_open(),
                stateful: true,
            },
            DialogControl {
                group: root_id,
                kind: DialogControlKind::Trigger,
                disabled: blocked,
            },
        ))
        .id();
    let trigger_text = commands
        .spawn((
            ChildOf(trigger_id),
            Node {
                min_width: px(0.0),
                ..default()
            },
            Text::new(trigger_node.label.clone()),
            TextFont {
                font: fonts.inter.clone().into(),
                font_size: FontSize::Px(metrics.trigger_font_size),
                weight: if state.is_open() {
                    FontWeight::BOLD
                } else {
                    FontWeight::SEMIBOLD
                },
                ..default()
            },
            LineHeight::RelativeToFont(metrics.trigger_line_height),
            TextColor(trigger_palette.text),
            TextLayout::new(Justify::Center, LineBreak::NoWrap),
        ))
        .id();
    let overlay_background = match model.mode {
        DialogMode::Modal => theme
            .surface_overlay()
            .to_bevy_css_alpha_on(theme.surface_1()),
        DialogMode::NonModal => theme.surface_2().to_bevy_on(root_fill),
    };
    let overlay_id = commands
        .spawn((
            ChildOf(root_id),
            Node {
                display: if state.is_open() {
                    Display::Flex
                } else {
                    Display::None
                },
                width: percent(100),
                min_width: px(0.0),
                min_height: px(metrics.overlay_height),
                flex_grow: if state.is_open() { 1.0 } else { 0.0 },
                padding: UiRect::all(px(metrics.overlay_padding)),
                border: if model.mode == DialogMode::NonModal {
                    UiRect::all(px(border_width))
                } else {
                    UiRect::ZERO
                },
                border_radius: BorderRadius::all(px(theme.radius_box)),
                justify_content: JustifyContent::Center,
                align_items: AlignItems::Center,
                ..default()
            },
            BackgroundColor(overlay_background),
            BorderColor::all(theme.border_subtle().to_bevy_on(root_fill)),
        ))
        .id();
    let content_fill = theme.surface_elevated();
    let content_id = commands
        .spawn((
            ChildOf(overlay_id),
            Node {
                width: percent(100),
                max_width: px(scale::container::CONTROL),
                min_width: px(0.0),
                min_height: px(metrics.content_height),
                padding: UiRect::all(px(metrics.content_padding)),
                border: UiRect::all(px(border_width)),
                border_radius: BorderRadius::all(px(theme.radius_box)),
                flex_direction: FlexDirection::Column,
                row_gap: px(metrics.content_gap),
                ..default()
            },
            BackgroundColor(content_fill.to_bevy_on(root_fill)),
            BorderColor::all(theme.border_subtle().to_bevy_on(root_fill)),
            if model.size == DialogSize::Small {
                bevy_shadow_2(&theme, inline_size)
            } else {
                bevy_shadow_3(&theme, inline_size)
            },
        ))
        .id();
    let header_id = commands
        .spawn((
            ChildOf(content_id),
            Node {
                width: percent(100),
                min_width: px(0.0),
                min_height: px(metrics.header_height),
                flex_direction: FlexDirection::Column,
                row_gap: px(metrics.header_gap),
                ..default()
            },
        ))
        .id();
    commands.spawn((
        ChildOf(header_id),
        Node {
            width: percent(100),
            min_width: px(0.0),
            min_height: px(metrics.title_height),
            ..default()
        },
        Text::new(model.title.clone()),
        TextFont {
            font: fonts.inter.clone().into(),
            font_size: FontSize::Px(metrics.title_font_size),
            weight: FontWeight::BOLD,
            ..default()
        },
        LineHeight::RelativeToFont(metrics.title_line_height),
        TextColor(theme.text_1().to_bevy_on(content_fill)),
        TextLayout::new(Justify::Left, LineBreak::WordOrCharacter),
    ));
    commands.spawn((
        ChildOf(header_id),
        Node {
            width: percent(100),
            min_width: px(0.0),
            min_height: px(metrics.description_height),
            ..default()
        },
        Text::new(model.description.clone()),
        TextFont {
            font: fonts.inter.clone().into(),
            font_size: FontSize::Px(metrics.description_font_size),
            ..default()
        },
        LineHeight::RelativeToFont(metrics.description_line_height),
        TextColor(theme.text_2().to_bevy_on(content_fill)),
        TextLayout::new(Justify::Left, LineBreak::WordOrCharacter),
    ));
    commands.spawn((
        ChildOf(content_id),
        Node {
            width: percent(100),
            min_width: px(0.0),
            min_height: px(metrics.body_height),
            ..default()
        },
        Text::new(model.body.clone()),
        TextFont {
            font: fonts.inter.clone().into(),
            font_size: FontSize::Px(metrics.body_font_size),
            ..default()
        },
        LineHeight::RelativeToFont(metrics.body_line_height),
        TextColor(theme.text_2().to_bevy_on(content_fill)),
        TextLayout::new(Justify::Left, LineBreak::WordOrCharacter),
    ));
    let footer_id = commands
        .spawn((
            ChildOf(content_id),
            Node {
                width: percent(100),
                min_width: px(0.0),
                min_height: px(metrics.footer_height),
                flex_direction: FlexDirection::Row,
                flex_wrap: FlexWrap::Wrap,
                justify_content: JustifyContent::FlexEnd,
                align_items: AlignItems::Center,
                row_gap: px(metrics.footer_gap),
                column_gap: px(metrics.footer_gap),
                ..default()
            },
        ))
        .id();
    let mut actions = Vec::with_capacity(model.actions.len().max(1));
    for node in render_nodes
        .iter()
        .filter(|node| node.part == DialogPart::Footer)
    {
        let entity = spawn_dialog_action(
            &mut commands,
            footer_id,
            root_id,
            node,
            blocked,
            &metrics,
            content_fill,
            &theme,
            fonts,
        );
        actions.push(DialogActionEntities {
            value: node.value.clone(),
            close_dialog: node.close_dialog,
            entity,
        });
    }
    commands.entity(root_id).insert(DialogGroupState {
        model: model.clone(),
        state,
        trigger: trigger_id,
        trigger_text,
        overlay: overlay_id,
        actions,
        theme,
        available_width,
        inline_size,
        blocked,
    });
}

#[cfg(target_arch = "wasm32")]
#[allow(clippy::too_many_arguments)]
fn spawn_dialog_action(
    commands: &mut Commands,
    parent: Entity,
    group: Entity,
    node: &rs_dean_ui::DialogRenderNode,
    blocked: bool,
    metrics: &DialogLayoutMetrics,
    root_fill: Tone,
    theme: &Theme,
    fonts: &StoryFonts,
) -> Entity {
    let disabled = blocked || node.disabled || !node.actionable;
    let palette = dialog_action_palette(node.index, node.selected, disabled, root_fill, theme);
    commands
        .spawn((
            ChildOf(parent),
            Button,
            Node {
                min_height: px(metrics.action_height),
                padding: UiRect::axes(
                    px(metrics.action_padding_inline),
                    px(metrics.action_padding_block),
                ),
                border: UiRect::all(px(theme.border.max(1.0))),
                border_radius: BorderRadius::all(px(theme.radius_field)),
                justify_content: JustifyContent::Center,
                align_items: AlignItems::Center,
                ..default()
            },
            BackgroundColor(palette.background),
            BorderColor::all(palette.border),
            Text::new(node.label.clone()),
            TextFont {
                font: fonts.inter.clone().into(),
                font_size: FontSize::Px(metrics.action_font_size),
                weight: if node.index == 0 || node.selected {
                    FontWeight::BOLD
                } else {
                    FontWeight::SEMIBOLD
                },
                ..default()
            },
            LineHeight::RelativeToFont(metrics.action_line_height),
            TextColor(palette.text),
            TextLayout::new(Justify::Center, LineBreak::NoWrap),
            InteractivePrimitive {
                rest: palette.background,
                selected: palette.background,
                hover: palette.hover,
                pressed: palette.hover,
                latched: node.selected,
                stateful: true,
            },
            DialogControl {
                group,
                kind: DialogControlKind::Action {
                    value: node.value.clone(),
                    close_dialog: node.close_dialog,
                },
                disabled,
            },
        ))
        .id()
}

#[cfg(target_arch = "wasm32")]
#[derive(Debug, Clone, Copy)]
struct DialogPalette {
    background: Color,
    border: Color,
    text: Color,
    hover: Color,
}

#[cfg(target_arch = "wasm32")]
fn dialog_resolve_tone(tone: Tone, faded: bool, root_fill: Tone) -> Color {
    if faded {
        tone.with_opacity(scale::opacity::DISABLED)
            .to_bevy_on(root_fill)
    } else {
        tone.to_bevy_on(root_fill)
    }
}

#[cfg(target_arch = "wasm32")]
fn dialog_trigger_palette(
    open: bool,
    faded: bool,
    root_fill: Tone,
    theme: &Theme,
) -> DialogPalette {
    let background_tone = if open {
        theme.primary_soft()
    } else {
        theme.surface_2()
    };
    let border_tone = if open {
        theme.brand()
    } else {
        theme.border_strong()
    };
    let background = dialog_resolve_tone(background_tone, faded, root_fill);
    DialogPalette {
        background,
        border: dialog_resolve_tone(border_tone, faded, root_fill),
        text: dialog_resolve_tone(theme.text_1(), faded, root_fill),
        hover: if faded {
            background
        } else if open {
            theme.selected_tint().to_bevy_on(root_fill)
        } else {
            theme.hover_tint().to_bevy_on(root_fill)
        },
    }
}

#[cfg(target_arch = "wasm32")]
fn dialog_action_palette(
    index: usize,
    selected: bool,
    faded: bool,
    root_fill: Tone,
    theme: &Theme,
) -> DialogPalette {
    let (background_tone, border_tone) = if selected {
        (theme.selected_tint(), theme.brand())
    } else if index == 0 {
        (theme.primary_soft(), theme.brand())
    } else {
        (theme.surface_2(), theme.border_strong())
    };
    let background = dialog_resolve_tone(background_tone, faded, root_fill);
    DialogPalette {
        background,
        border: dialog_resolve_tone(border_tone, faded, root_fill),
        text: dialog_resolve_tone(theme.text_1(), faded, root_fill),
        hover: if faded {
            background
        } else if selected || index == 0 {
            theme.selected_tint().to_bevy_on(root_fill)
        } else {
            theme.hover_tint().to_bevy_on(root_fill)
        },
    }
}

#[cfg(target_arch = "wasm32")]
fn spawn_breadcrumb(
    parent: &mut ChildSpawnerCommands,
    model: &BreadcrumbModel,
    theme: Theme,
    fonts: &StoryFonts,
    inline_size: f32,
) {
    let metrics = breadcrumb_layout_metrics(model.density, inline_size);
    let last_index = model.entries.len().saturating_sub(1);
    let root_id = parent
        .spawn(Node {
            width: auto(),
            justify_self: JustifySelf::Stretch,
            flex_direction: FlexDirection::Row,
            flex_wrap: FlexWrap::Wrap,
            align_items: AlignItems::Center,
            row_gap: px(metrics.list_gap),
            column_gap: px(metrics.list_gap),
            ..default()
        })
        .id();
    let mut commands = parent.commands();
    let mut links = Vec::with_capacity(model.entries.len().saturating_sub(1));
    for (index, entry) in model.entries.iter().enumerate() {
        let current = index == last_index;
        let disabled = model.disabled || model.loading || entry.disabled;
        let label = if model.loading {
            "Loading".to_owned()
        } else {
            entry.label.clone()
        };
        let value = entry.value();
        let item_id = commands
            .spawn((
                ChildOf(root_id),
                Node {
                    min_width: px(0.0),
                    align_items: AlignItems::Center,
                    column_gap: px(metrics.item_gap),
                    ..default()
                },
            ))
            .id();
        let rest = if model.loading && !current {
            theme.surface_3().to_bevy()
        } else {
            Color::NONE
        };
        let text_color = if model.loading && !current {
            theme.text_muted().to_bevy()
        } else if disabled {
            theme.text_disabled().to_bevy()
        } else if current {
            theme.text_1().to_bevy()
        } else {
            theme.text_2().to_bevy()
        };
        let mut content = commands.spawn((
            ChildOf(item_id),
            Node {
                min_height: if current {
                    auto()
                } else {
                    px(metrics.link_min_height)
                },
                padding: if current {
                    UiRect::ZERO
                } else {
                    UiRect::axes(
                        px(if model.loading {
                            metrics.loading_padding_inline
                        } else {
                            metrics.link_padding_inline
                        }),
                        px(metrics.link_padding_block),
                    )
                },
                border_radius: BorderRadius::all(px(theme.radius_field)),
                align_items: AlignItems::Center,
                ..default()
            },
            Text::new(label),
            TextFont {
                font: fonts.inter.clone().into(),
                font_size: FontSize::Px(metrics.font_size),
                weight: if current {
                    FontWeight::BOLD
                } else {
                    FontWeight::NORMAL
                },
                ..default()
            },
            LineHeight::RelativeToFont(metrics.line_height),
            TextColor(text_color),
            TextLayout::new(Justify::Left, LineBreak::NoWrap),
            BackgroundColor(rest),
        ));
        if !current && !disabled {
            let selected = theme.selected_tint().to_bevy_on(theme.surface_1());
            let hover = theme.hover_tint().to_bevy_on(theme.surface_1());
            let mut visual = InteractivePrimitive::stateful(rest, selected, false, &theme);
            visual.hover = hover;
            visual.pressed = hover;
            content.insert((
                Button,
                BreadcrumbLinkControl {
                    group: root_id,
                    value: value.clone(),
                },
                visual,
            ));
            links.push(BreadcrumbLinkEntity {
                value,
                entity: content.id(),
            });
        }
        if !current {
            commands.spawn((
                ChildOf(item_id),
                Text::new(model.separator.clone()),
                TextFont {
                    font: fonts.inter.clone().into(),
                    font_size: FontSize::Px(metrics.font_size),
                    ..default()
                },
                LineHeight::RelativeToFont(metrics.line_height),
                TextColor(theme.text_muted().to_bevy()),
                TextLayout::new(Justify::Center, LineBreak::NoWrap),
            ));
        }
    }
    commands.entity(root_id).insert(BreadcrumbGroupState {
        state: model.state(),
        links,
        theme,
    });
}

