#[cfg(target_arch = "wasm32")]
#[derive(Debug, Clone, Copy)]
struct DatePickerPalette {
    background: Color,
    border: Color,
    text: Color,
    hover: Color,
}

#[cfg(target_arch = "wasm32")]
fn date_picker_resolve_tone(tone: Tone, disabled: bool, root_fill: Tone) -> Color {
    if disabled {
        tone.with_opacity(scale::opacity::DISABLED)
            .to_bevy_on(root_fill)
    } else {
        tone.to_bevy_on(root_fill)
    }
}

#[cfg(target_arch = "wasm32")]
fn date_picker_trigger_palette(
    open: bool,
    style_disabled: bool,
    faded: bool,
    root_fill: Tone,
    theme: &Theme,
) -> DatePickerPalette {
    let background_tone = if open && !style_disabled {
        theme.primary_soft()
    } else {
        theme.surface_2()
    };
    let border_tone = if open && !style_disabled {
        theme.brand()
    } else {
        theme.border_strong()
    };
    let background = date_picker_resolve_tone(background_tone, faded, root_fill);
    DatePickerPalette {
        background,
        border: date_picker_resolve_tone(border_tone, faded, root_fill),
        text: date_picker_resolve_tone(
            if style_disabled {
                theme.text_disabled()
            } else {
                theme.text_1()
            },
            faded,
            root_fill,
        ),
        hover: if faded {
            background
        } else if open {
            theme.selected_tint().to_bevy_on(root_fill)
        } else {
            theme.hover_tint().to_bevy_on(root_fill)
        },
    }
}

#[cfg(target_arch = "wasm32")]
fn date_picker_control_palette(
    disabled: bool,
    root_fill: Tone,
    theme: &Theme,
) -> DatePickerPalette {
    let background = date_picker_resolve_tone(theme.surface_2(), disabled, root_fill);
    DatePickerPalette {
        background,
        border: date_picker_resolve_tone(theme.border_strong(), disabled, root_fill),
        text: date_picker_resolve_tone(
            if disabled {
                theme.text_disabled()
            } else {
                theme.text_1()
            },
            disabled,
            root_fill,
        ),
        hover: if disabled {
            background
        } else {
            theme.hover_tint().to_bevy_on(root_fill)
        },
    }
}

#[cfg(target_arch = "wasm32")]
fn spawn_calendar_primitives(
    parent: &mut ChildSpawnerCommands,
    id: UiComponentId,
    variant: &BevyUiStoryVariant,
    fonts: &StoryFonts,
    inline_size: f32,
) {
    match (id, &variant.model) {
        (UiComponentId::Calendar, UiStoryModel::Calendar(model)) => spawn_calendar_story(
            parent,
            model,
            variant.theme_id.palette(),
            fonts,
            inline_size,
        ),
        (UiComponentId::DatePicker, UiStoryModel::DatePicker(model)) => spawn_date_picker_story(
            parent,
            model,
            variant.theme_id.palette(),
            fonts,
            inline_size,
        ),
        _ => {}
    }
}

#[cfg(target_arch = "wasm32")]
fn spawn_selection_primitives(
    parent: &mut ChildSpawnerCommands,
    id: UiComponentId,
    variant: &BevyUiStoryVariant,
    fonts: &StoryFonts,
    available_width: f32,
    inline_size: f32,
) {
    match id {
        UiComponentId::RadioGroup => spawn_radio_group(parent, variant, fonts, inline_size),
        UiComponentId::Checkbox => {
            spawn_checkbox(parent, variant, fonts, available_width, inline_size);
        }
        UiComponentId::Switch => {
            spawn_switch(parent, variant, fonts, available_width, inline_size);
        }
        _ => {}
    }
}

#[cfg(target_arch = "wasm32")]
fn spawn_checkbox(
    parent: &mut ChildSpawnerCommands,
    variant: &BevyUiStoryVariant,
    fonts: &StoryFonts,
    available_width: f32,
    inline_size: f32,
) {
    let UiStoryModel::Checkbox(model) = &variant.model else {
        return;
    };
    let theme = variant.theme_id.palette();
    let dense = model.density == CheckboxDensity::Dense;
    let blocked = model.loading || model.disabled;
    let invalid = model.error.is_some();
    let border_width = theme.border.max(1.0);
    let metrics = checkbox_layout_metrics(model, available_width, inline_size, border_width);
    let state = model.state();
    let root_fill = if model.disabled {
        theme.surface_2().to_bevy()
    } else if invalid {
        theme.error_soft().to_bevy_on(theme.surface_1())
    } else {
        theme.surface_1().to_bevy()
    };
    let root_border = if model.disabled {
        theme.border_muted().to_bevy_on(theme.surface_2())
    } else if invalid {
        theme.danger().to_bevy()
    } else {
        theme.border_subtle().to_bevy_on(theme.surface_1())
    };
    let label_color = if model.disabled {
        theme.text_disabled().to_bevy()
    } else {
        theme.text_1().to_bevy()
    };
    let description_color = if model.disabled {
        theme.text_disabled().to_bevy()
    } else if invalid {
        theme.danger().to_bevy()
    } else {
        theme.text_2().to_bevy()
    };
    let description = model
        .error
        .as_ref()
        .or(model.description.as_ref())
        .cloned()
        .unwrap_or_else(|| "No checkbox description".to_owned());
    let (indicator_fill, indicator_border, indicator_text) =
        checkbox_indicator_colors(&theme, state.checked(), invalid, blocked);

    let root_id = parent
        .spawn((
            Node {
                width: percent(100),
                height: px(metrics.height),
                min_height: px(metrics.height),
                max_width: px(metrics.width),
                min_width: px(0.0),
                padding: UiRect::all(px(metrics.padding)),
                border: UiRect::all(px(border_width)),
                border_radius: BorderRadius::all(px(if dense {
                    theme.radius_field
                } else {
                    theme.radius_box
                })),
                flex_direction: FlexDirection::Row,
                align_items: AlignItems::Start,
                column_gap: px(metrics.gap),
                flex_shrink: 0.0,
                ..default()
            },
            BackgroundColor(root_fill),
            BorderColor::all(root_border),
            if model.disabled {
                BoxShadow::default()
            } else {
                BoxShadow::new(
                    theme.text_1().to_bevy().with_alpha(0.025),
                    px(0.0),
                    px(scale::space::xs3(inline_size)),
                    px(0.0),
                    px(scale::space::xs2(inline_size)),
                )
            },
        ))
        .id();
    let mut commands = parent.commands();
    let indicator_id = commands
        .spawn((
            ChildOf(root_id),
            Button,
            CheckboxTrigger {
                group: root_id,
                disabled: blocked,
            },
            Node {
                width: px(metrics.indicator_size),
                height: px(metrics.indicator_size),
                min_width: px(metrics.indicator_size),
                min_height: px(metrics.indicator_size),
                border: UiRect::all(px(border_width)),
                border_radius: BorderRadius::all(px(theme.radius_selector)),
                justify_content: JustifyContent::Center,
                align_items: AlignItems::Center,
                ..default()
            },
            BackgroundColor(indicator_fill),
            BorderColor::all(indicator_border),
            Text::new(checkbox_indicator_label(state.checked())),
            TextFont {
                font: fonts.inter.clone().into(),
                font_size: FontSize::Px(metrics.helper_font_size),
                weight: FontWeight::BOLD,
                ..default()
            },
            LineHeight::Px(metrics.helper_font_size * scale::line_height::LH0),
            TextColor(indicator_text),
            TextLayout::new(Justify::Center, LineBreak::NoWrap),
            checkbox_interaction(&theme, state.checked(), invalid, blocked, indicator_fill),
        ))
        .id();
    let copy_id = commands
        .spawn((
            ChildOf(root_id),
            Node {
                min_width: px(0.0),
                flex_grow: 1.0,
                flex_direction: FlexDirection::Column,
                row_gap: px(metrics.text_gap),
                ..default()
            },
        ))
        .id();
    let label_id = commands
        .spawn((
            ChildOf(copy_id),
            Node {
                width: percent(100),
                min_width: px(0.0),
                flex_direction: FlexDirection::Row,
                ..default()
            },
        ))
        .id();
    commands.spawn((
        ChildOf(label_id),
        Text::new(model.label.clone()),
        TextFont {
            font: fonts.inter.clone().into(),
            font_size: FontSize::Px(metrics.label_font_size),
            weight: FontWeight::BOLD,
            ..default()
        },
        LineHeight::Px(metrics.label_font_size * scale::line_height::LH0),
        TextColor(label_color),
        TextLayout::new(Justify::Left, LineBreak::WordOrCharacter),
    ));
    if model.required {
        commands.spawn((
            ChildOf(label_id),
            Text::new(" *"),
            TextFont {
                font: fonts.inter.clone().into(),
                font_size: FontSize::Px(metrics.label_font_size),
                weight: FontWeight::BOLD,
                ..default()
            },
            LineHeight::Px(metrics.label_font_size * scale::line_height::LH0),
            TextColor(theme.danger().to_bevy()),
            TextLayout::new(Justify::Left, LineBreak::NoWrap),
        ));
    }
    commands.spawn((
        ChildOf(copy_id),
        Text::new(description),
        TextFont {
            font: fonts.inter.clone().into(),
            font_size: FontSize::Px(metrics.helper_font_size),
            weight: if invalid {
                FontWeight::SEMIBOLD
            } else {
                FontWeight::NORMAL
            },
            ..default()
        },
        LineHeight::Px(metrics.helper_font_size * scale::line_height::LH0),
        TextColor(description_color),
        TextLayout::new(Justify::Left, LineBreak::WordOrCharacter),
    ));
    commands.entity(root_id).insert(CheckboxGroupState {
        state,
        indicator: indicator_id,
        theme,
        blocked,
        invalid,
    });
}

#[cfg(target_arch = "wasm32")]
fn checkbox_indicator_colors(
    theme: &Theme,
    checked: CheckboxChecked,
    invalid: bool,
    blocked: bool,
) -> (Color, Color, Color) {
    if blocked {
        return (
            theme.surface_3().to_bevy(),
            theme.border_muted().to_bevy_on(theme.surface_3()),
            theme.text_disabled().to_bevy(),
        );
    }
    if invalid {
        return (
            theme.error_soft().to_bevy_on(theme.surface_1()),
            theme.danger().to_bevy(),
            theme.text_1().to_bevy(),
        );
    }
    match checked {
        CheckboxChecked::Unchecked => (
            theme.surface_1().to_bevy(),
            theme.border_strong().to_bevy_on(theme.surface_1()),
            theme.text_1().to_bevy(),
        ),
        CheckboxChecked::Checked => (
            theme.brand().to_bevy(),
            theme.brand().to_bevy(),
            theme.text_on_brand().to_bevy(),
        ),
        CheckboxChecked::Indeterminate => (
            theme.primary_soft().to_bevy_on(theme.surface_1()),
            theme.brand().to_bevy(),
            theme.text_1().to_bevy(),
        ),
    }
}

#[cfg(target_arch = "wasm32")]
const fn checkbox_indicator_label(checked: CheckboxChecked) -> &'static str {
    match checked {
        CheckboxChecked::Unchecked => "",
        CheckboxChecked::Checked => "x",
        CheckboxChecked::Indeterminate => "-",
    }
}

#[cfg(target_arch = "wasm32")]
fn checkbox_interaction(
    theme: &Theme,
    checked: CheckboxChecked,
    invalid: bool,
    blocked: bool,
    fill: Color,
) -> InteractivePrimitive {
    let hover = if blocked {
        fill
    } else if invalid {
        theme.press_tint().to_bevy_on(theme.surface_1())
    } else if checked == CheckboxChecked::Checked {
        theme.brand().to_bevy()
    } else {
        theme.selected_tint().to_bevy_on(theme.surface_1())
    };
    InteractivePrimitive {
        rest: fill,
        selected: fill,
        hover,
        pressed: if blocked {
            fill
        } else {
            theme.press_tint().to_bevy_on(theme.surface_1())
        },
        latched: checked.is_active(),
        stateful: true,
    }
}

#[cfg(target_arch = "wasm32")]
fn spawn_radio_group(
    parent: &mut ChildSpawnerCommands,
    variant: &BevyUiStoryVariant,
    fonts: &StoryFonts,
    inline_size: f32,
) {
    let theme = variant.theme_id.palette();
    let UiStoryModel::RadioGroup(model) = &variant.model else {
        return;
    };
    let state = model.state();
    let nodes = radio_group_render_nodes(model, &state);
    let root = nodes
        .iter()
        .find(|node| node.part == RadioGroupPart::Root)
        .expect("invariant: radio group has a root");
    let metrics = radio_group_layout_metrics(model, inline_size);
    let border_width = theme.border.max(1.0);
    let invalid = model.error.is_some();
    let dense_root = model.density == RadioGroupDensity::Dense && !invalid && !model.disabled;
    let root_opacity = if model.disabled {
        scale::opacity::DISABLED
    } else {
        1.0
    };
    let (root_fill, root_border) = if model.disabled {
        (
            radio_group_resolve_tone(&theme, theme.surface_2(), root_opacity),
            radio_group_resolve_tone(&theme, theme.border_muted(), root_opacity),
        )
    } else if invalid {
        (
            theme.error_soft().to_bevy_on(theme.surface_1()),
            theme.danger().to_bevy(),
        )
    } else {
        (
            theme.surface_1().to_bevy(),
            theme.border_subtle().to_bevy_on(theme.surface_1()),
        )
    };
    let root_id = parent
        .spawn((
            Node {
                display: Display::Grid,
                width: percent(100),
                max_width: px(metrics.max_width),
                min_width: px(0.0),
                padding: UiRect::all(px(metrics.root_padding)),
                border: UiRect::all(px(theme.border.max(1.0))),
                border_radius: BorderRadius::all(px(if dense_root {
                    theme.radius_field
                } else {
                    theme.radius_box
                })),
                align_items: AlignItems::Stretch,
                row_gap: px(metrics.root_gap),
                grid_auto_rows: GridTrack::auto(),
                ..default()
            },
            BackgroundColor(root_fill),
            BorderColor::all(root_border),
            if model.disabled {
                BoxShadow::default()
            } else {
                bevy_shadow_1(&theme, inline_size)
            },
        ))
        .id();
    let mut commands = parent.commands();
    let title_row_id = commands
        .spawn((
            ChildOf(root_id),
            Node {
                width: percent(100),
                min_width: px(0.0),
                flex_direction: FlexDirection::Row,
                flex_wrap: FlexWrap::Wrap,
                justify_content: JustifyContent::SpaceBetween,
                align_items: AlignItems::Center,
                row_gap: px(metrics.title_row_gap),
                column_gap: px(metrics.title_row_gap),
                ..default()
            },
        ))
        .id();
    let title_group_id = commands
        .spawn((
            ChildOf(title_row_id),
            Node {
                flex_direction: FlexDirection::Row,
                align_items: AlignItems::Center,
                ..default()
            },
        ))
        .id();
    commands.spawn((
        ChildOf(title_group_id),
        Text::new(root.label.clone()),
        TextFont {
            font: fonts.inter.clone().into(),
            font_size: FontSize::Px(metrics.title_font_size),
            weight: FontWeight::BOLD,
            ..default()
        },
        LineHeight::RelativeToFont(metrics.line_height),
        TextColor(radio_group_resolve_tone(
            &theme,
            theme.text_1(),
            root_opacity,
        )),
        TextLayout::new(Justify::Left, LineBreak::NoWrap),
    ));
    if model.required {
        commands.spawn((
            ChildOf(title_group_id),
            Text::new(" *"),
            TextFont {
                font: fonts.inter.clone().into(),
                font_size: FontSize::Px(metrics.title_font_size),
                weight: FontWeight::BOLD,
                ..default()
            },
            LineHeight::RelativeToFont(metrics.line_height),
            TextColor(radio_group_resolve_tone(
                &theme,
                theme.danger(),
                root_opacity,
            )),
            TextLayout::new(Justify::Left, LineBreak::NoWrap),
        ));
    }
    commands.spawn((
        ChildOf(title_row_id),
        Text::new(root.detail.clone()),
        TextFont {
            font: fonts.inter.clone().into(),
            font_size: FontSize::Px(metrics.status_font_size),
            weight: FontWeight::SEMIBOLD,
            ..default()
        },
        LineHeight::RelativeToFont(metrics.line_height),
        TextColor(radio_group_resolve_tone(
            &theme,
            theme.text_muted(),
            root_opacity,
        )),
        TextLayout::new(Justify::Right, LineBreak::NoWrap),
    ));
    let horizontal = model.orientation == RadioGroupOrientation::Horizontal;
    let list_id = commands
        .spawn((
            ChildOf(root_id),
            Node {
                display: if horizontal {
                    Display::Flex
                } else {
                    Display::Grid
                },
                width: percent(100),
                min_width: px(0.0),
                flex_direction: FlexDirection::Row,
                flex_wrap: FlexWrap::Wrap,
                row_gap: px(metrics.list_gap),
                column_gap: px(metrics.list_gap),
                grid_auto_rows: GridTrack::auto(),
                ..default()
            },
        ))
        .id();
    let mut items = Vec::with_capacity(model.options.len());
    for item in nodes
        .iter()
        .filter(|node| node.part == RadioGroupPart::Item)
    {
        let indicator = nodes
            .iter()
            .find(|node| node.part == RadioGroupPart::Indicator && node.index == item.index)
            .expect("invariant: radio group item has an indicator");
        let label = nodes
            .iter()
            .find(|node| node.part == RadioGroupPart::Label && node.index == item.index)
            .expect("invariant: radio group item has a label");
        let emphasized =
            radio_group_item_uses_emphasized_metrics(item.selected, item.focused, item.disabled);
        let item_height = metrics.item_outer_height(emphasized, item.disabled, border_width);
        let item_opacity = root_opacity
            * if item.disabled {
                scale::opacity::DISABLED
            } else {
                1.0
            };
        let control_opacity = item_opacity
            * if item.disabled {
                scale::opacity::DISABLED
            } else {
                1.0
            };
        let (item_fill, item_border) = radio_group_item_colors(
            &theme,
            item.selected,
            item.focused,
            item.disabled,
            item_opacity,
            Interaction::None,
        );
        let item_id = commands
            .spawn((
                ChildOf(list_id),
                RadioGroupItemVisual,
                Node {
                    width: if horizontal { auto() } else { percent(100) },
                    min_width: px(0.0),
                    height: if model.density == RadioGroupDensity::Standard {
                        px(item_height)
                    } else {
                        auto()
                    },
                    min_height: if model.density == RadioGroupDensity::Standard {
                        px(item_height)
                    } else {
                        auto()
                    },
                    padding: UiRect::all(px(if emphasized {
                        metrics.emphasized_item_padding
                    } else {
                        metrics.item_padding
                    })),
                    border: UiRect::all(px(theme.border.max(1.0))),
                    border_radius: BorderRadius::all(px(theme.radius_field)),
                    flex_direction: FlexDirection::Row,
                    align_items: AlignItems::FlexStart,
                    column_gap: px(if emphasized {
                        metrics.emphasized_item_gap
                    } else {
                        metrics.item_gap
                    }),
                    ..default()
                },
                BackgroundColor(item_fill),
                BorderColor::all(item_border),
                if !item.disabled && (item.selected || item.focused) {
                    bevy_shadow_1(&theme, inline_size)
                } else {
                    BoxShadow::default()
                },
            ))
            .id();
        let (control_fill, control_border, dot_color) = radio_group_control_colors(
            &theme,
            item.selected,
            item.disabled,
            invalid,
            control_opacity,
        );
        let control_id = commands
            .spawn((
                ChildOf(item_id),
                Button,
                RadioGroupControl {
                    group: root_id,
                    value: item.value.clone(),
                    disabled: item.disabled,
                },
                Node {
                    width: px(metrics.control_size),
                    height: px(metrics.control_size),
                    min_width: px(metrics.control_size),
                    min_height: px(metrics.control_size),
                    border: UiRect::all(px(theme.border.max(1.0))),
                    border_radius: BorderRadius::MAX,
                    justify_content: JustifyContent::Center,
                    align_items: AlignItems::Center,
                    flex_shrink: 0.0,
                    ..default()
                },
                BackgroundColor(control_fill),
                BorderColor::all(control_border),
                if !item.disabled && (invalid || item.selected) {
                    bevy_shadow_1(&theme, inline_size)
                } else {
                    BoxShadow::default()
                },
            ))
            .id();
        let dot_id = commands
            .spawn((
                ChildOf(control_id),
                RadioGroupDotVisual,
                Node {
                    display: if indicator.selected {
                        Display::Flex
                    } else {
                        Display::None
                    },
                    width: px(metrics.dot_size),
                    height: px(metrics.dot_size),
                    min_width: px(metrics.dot_size),
                    min_height: px(metrics.dot_size),
                    border_radius: BorderRadius::MAX,
                    ..default()
                },
                BackgroundColor(dot_color),
            ))
            .id();
        let text_id = commands
            .spawn((
                ChildOf(item_id),
                Node {
                    min_width: px(0.0),
                    flex_grow: 1.0,
                    flex_direction: FlexDirection::Column,
                    row_gap: px(metrics.text_gap),
                    ..default()
                },
            ))
            .id();
        commands.spawn((
            ChildOf(text_id),
            Text::new(label.label.clone()),
            TextFont {
                font: fonts.inter.clone().into(),
                font_size: FontSize::Px(if item.disabled {
                    metrics.emphasized_label_font_size
                } else {
                    metrics.label_font_size
                }),
                weight: FontWeight::BOLD,
                ..default()
            },
            LineHeight::RelativeToFont(metrics.line_height),
            TextColor(radio_group_resolve_tone(
                &theme,
                if item.disabled {
                    theme.text_disabled()
                } else {
                    theme.text_1()
                },
                item_opacity,
            )),
            TextLayout::new(Justify::Left, LineBreak::NoWrap),
        ));
        commands.spawn((
            ChildOf(text_id),
            Text::new(label.detail.clone()),
            TextFont {
                font: fonts.inter.clone().into(),
                font_size: FontSize::Px(metrics.detail_font_size),
                weight: if invalid {
                    FontWeight::SEMIBOLD
                } else {
                    FontWeight::NORMAL
                },
                ..default()
            },
            LineHeight::RelativeToFont(metrics.line_height),
            TextColor(radio_group_resolve_tone(
                &theme,
                if item.disabled {
                    theme.text_disabled()
                } else if invalid {
                    theme.danger()
                } else {
                    theme.text_2()
                },
                item_opacity,
            )),
            TextLayout::new(Justify::Left, LineBreak::WordOrCharacter),
        ));
        items.push(RadioGroupItemEntities {
            value: item.value.clone(),
            item: item_id,
            control: control_id,
            dot: dot_id,
            disabled: item.disabled,
        });
    }
    commands.entity(root_id).insert(RadioGroupGroup {
        state,
        items,
        metrics,
        theme,
        inline_size,
        invalid,
        root_disabled: model.disabled,
    });
}

#[cfg(target_arch = "wasm32")]
fn radio_group_resolve_tone(theme: &Theme, tone: Tone, opacity: f32) -> Color {
    if opacity < 1.0 {
        tone.with_opacity(opacity).to_bevy_on(theme.surface_1())
    } else {
        tone.to_bevy()
    }
}

#[cfg(target_arch = "wasm32")]
fn radio_group_item_colors(
    theme: &Theme,
    selected: bool,
    focused: bool,
    disabled: bool,
    opacity: f32,
    interaction: Interaction,
) -> (Color, Color) {
    let fill = if disabled {
        theme.surface_2()
    } else if matches!(interaction, Interaction::Hovered | Interaction::Pressed) && selected {
        theme.selected_tint()
    } else if matches!(interaction, Interaction::Hovered | Interaction::Pressed) {
        theme.hover_tint()
    } else if selected {
        theme.primary_soft()
    } else {
        theme.surface_1()
    };
    let border = if disabled {
        theme.border_muted()
    } else if selected || focused {
        theme.brand()
    } else {
        theme.border_subtle()
    };
    (
        radio_group_resolve_tone(theme, fill, opacity),
        radio_group_resolve_tone(theme, border, opacity),
    )
}

#[cfg(target_arch = "wasm32")]
fn radio_group_control_colors(
    theme: &Theme,
    selected: bool,
    disabled: bool,
    invalid: bool,
    opacity: f32,
) -> (Color, Color, Color) {
    let (fill, border, dot) = if disabled {
        (
            theme.surface_3(),
            theme.border_muted(),
            theme.text_on_brand(),
        )
    } else if invalid {
        (theme.error_soft(), theme.danger(), theme.text_on_brand())
    } else if selected {
        (theme.brand(), theme.brand(), theme.text_on_brand())
    } else {
        (
            theme.surface_1(),
            theme.border_strong(),
            theme.text_on_brand(),
        )
    };
    (
        radio_group_resolve_tone(theme, fill, opacity),
        radio_group_resolve_tone(theme, border, opacity),
        radio_group_resolve_tone(theme, dot, opacity),
    )
}

#[cfg(target_arch = "wasm32")]
fn spawn_switch(
    parent: &mut ChildSpawnerCommands,
    variant: &BevyUiStoryVariant,
    fonts: &StoryFonts,
    available_width: f32,
    inline_size: f32,
) {
    let UiStoryModel::Switch(model) = &variant.model else {
        return;
    };
    let theme = variant.theme_id.palette();
    let state = model.state();
    let nodes = switch_render_nodes(model, &state);
    let root = nodes
        .iter()
        .find(|node| node.part == SwitchPart::Root)
        .expect("invariant: switch has a root");
    let label = nodes
        .iter()
        .find(|node| node.part == SwitchPart::Label)
        .expect("invariant: switch has a label");
    let blocked = model.loading || model.disabled;
    let invalid = model.error.is_some();
    let border_width = theme.border.max(1.0);
    let metrics = switch_layout_metrics(model, available_width, inline_size, border_width);
    let dense_root = switch_uses_dense_root_metrics(model.density, model.disabled, invalid);
    let root_opacity = if model.disabled {
        scale::opacity::DISABLED
    } else {
        1.0
    };
    let root_fill_tone = if model.disabled {
        theme.surface_2()
    } else if invalid {
        theme.error_soft()
    } else {
        theme.surface_1()
    };
    let root_border_tone = if model.disabled {
        theme.border_muted()
    } else if invalid {
        theme.danger()
    } else {
        theme.border_subtle()
    };
    let root_fill = switch_resolve_tone(&theme, root_fill_tone, root_opacity);
    let root_border = switch_resolve_tone(&theme, root_border_tone, root_opacity);
    let root_id = parent
        .spawn((
            Node {
                width: percent(100),
                max_width: px(metrics.width),
                min_width: px(0.0),
                min_height: px(metrics.height),
                align_self: AlignSelf::Stretch,
                justify_self: JustifySelf::Start,
                padding: UiRect::all(px(metrics.root_padding)),
                border: UiRect::all(px(border_width)),
                border_radius: BorderRadius::all(px(if dense_root {
                    theme.radius_field
                } else {
                    theme.radius_box
                })),
                flex_direction: FlexDirection::Row,
                justify_content: JustifyContent::SpaceBetween,
                align_items: AlignItems::Center,
                column_gap: px(metrics.root_gap),
                flex_shrink: 0.0,
                ..default()
            },
            BackgroundColor(root_fill),
            BorderColor::all(root_border),
            if model.disabled {
                BoxShadow::default()
            } else {
                bevy_shadow_1(&theme, inline_size)
            },
        ))
        .id();
    let mut commands = parent.commands();
    let copy_id = commands
        .spawn((
            ChildOf(root_id),
            Node {
                display: Display::Grid,
                min_width: px(0.0),
                flex_grow: 1.0,
                row_gap: px(metrics.copy_gap),
                ..default()
            },
        ))
        .id();
    let label_row_id = commands
        .spawn((
            ChildOf(copy_id),
            Node {
                width: percent(100),
                min_width: px(0.0),
                flex_direction: FlexDirection::Row,
                flex_wrap: FlexWrap::Wrap,
                align_items: AlignItems::Center,
                row_gap: px(metrics.label_row_gap),
                column_gap: px(metrics.label_row_gap),
                ..default()
            },
        ))
        .id();
    commands.spawn((
        ChildOf(label_row_id),
        Text::new(label.label.clone()),
        TextFont {
            font: fonts.inter.clone().into(),
            font_size: FontSize::Px(metrics.label_font_size),
            weight: FontWeight::BOLD,
            ..default()
        },
        LineHeight::RelativeToFont(scale::line_height::LH0),
        TextColor(switch_resolve_tone(
            &theme,
            if model.disabled {
                theme.text_disabled()
            } else {
                theme.text_1()
            },
            root_opacity,
        )),
        TextLayout::new(Justify::Left, LineBreak::WordOrCharacter),
    ));
    if root.required {
        commands.spawn((
            ChildOf(label_row_id),
            Text::new(" *"),
            TextFont {
                font: fonts.inter.clone().into(),
                font_size: FontSize::Px(metrics.label_font_size),
                weight: FontWeight::BOLD,
                ..default()
            },
            LineHeight::RelativeToFont(scale::line_height::LH0),
            TextColor(switch_resolve_tone(&theme, theme.danger(), root_opacity)),
            TextLayout::new(Justify::Left, LineBreak::NoWrap),
        ));
    }
    let (status_fill, status_border, status_text) =
        switch_status_colors(model, state.checked(), &theme, root_opacity);
    let status_id = commands
        .spawn((
            ChildOf(label_row_id),
            Node {
                width: px(metrics.status_width),
                height: px(metrics.status_height),
                min_width: px(metrics.status_width),
                min_height: px(metrics.status_height),
                max_width: px(metrics.status_width),
                max_height: px(metrics.status_height),
                padding: UiRect::axes(
                    px(metrics.status_padding_inline),
                    px(metrics.status_padding_block),
                ),
                border: UiRect::all(px(border_width)),
                border_radius: BorderRadius::MAX,
                justify_content: JustifyContent::Center,
                align_items: AlignItems::Center,
                flex_shrink: 0.0,
                ..default()
            },
            BackgroundColor(status_fill),
            BorderColor::all(status_border),
            Text::new(switch_status_label(model, state.checked()).to_uppercase()),
            TextFont {
                font: fonts.inter.clone().into(),
                font_size: FontSize::Px(metrics.status_font_size),
                weight: FontWeight::BOLD,
                ..default()
            },
            LineHeight::RelativeToFont(scale::line_height::LH0),
            LetterSpacing::Rem(metrics.status_letter_spacing),
            TextColor(status_text),
            TextLayout::new(Justify::Center, LineBreak::NoWrap),
        ))
        .id();
    commands.spawn((
        ChildOf(copy_id),
        Node {
            width: percent(100),
            min_width: px(0.0),
            ..default()
        },
        Text::new(label.detail.clone()),
        TextFont {
            font: fonts.inter.clone().into(),
            font_size: FontSize::Px(metrics.detail_font_size),
            weight: FontWeight::NORMAL,
            ..default()
        },
        LineHeight::RelativeToFont(scale::line_height::LH0),
        TextColor(switch_resolve_tone(
            &theme,
            if model.disabled {
                theme.text_disabled()
            } else if invalid {
                theme.danger()
            } else {
                theme.text_2()
            },
            root_opacity,
        )),
        TextLayout::new(Justify::Left, LineBreak::WordOrCharacter),
    ));
    if let Some(error) = &model.error {
        commands.spawn((
            ChildOf(copy_id),
            Node {
                width: percent(100),
                min_width: px(0.0),
                padding: UiRect::all(px(scale::space::xs(inline_size))),
                border: UiRect::all(px(border_width)),
                border_radius: BorderRadius::all(px(theme.radius_field)),
                ..default()
            },
            BackgroundColor(switch_resolve_tone(
                &theme,
                theme.error_soft(),
                root_opacity,
            )),
            BorderColor::all(switch_resolve_tone(&theme, theme.danger(), root_opacity)),
            Text::new(error.clone()),
            TextFont {
                font: fonts.inter.clone().into(),
                font_size: FontSize::Px(metrics.detail_font_size),
                weight: FontWeight::NORMAL,
                ..default()
            },
            LineHeight::RelativeToFont(scale::line_height::LH0),
            TextColor(switch_resolve_tone(&theme, theme.text_1(), root_opacity)),
            TextLayout::new(Justify::Left, LineBreak::WordOrCharacter),
        ));
    }
    let (track_fill, track_border) = switch_track_colors(model, &state, &theme, Interaction::None);
    let track_id = commands
        .spawn((
            ChildOf(root_id),
            Button,
            Node {
                width: px(metrics.track_width),
                height: px(metrics.track_height),
                min_width: px(metrics.track_width),
                min_height: px(metrics.track_height),
                max_width: px(metrics.track_width),
                max_height: px(metrics.track_height),
                padding: UiRect::all(px(metrics.track_padding)),
                border: UiRect::all(px(border_width)),
                border_radius: BorderRadius::MAX,
                justify_content: switch_thumb_alignment(model, &state),
                align_items: AlignItems::Center,
                flex_shrink: 0.0,
                ..default()
            },
            BackgroundColor(track_fill),
            BorderColor::all(track_border),
            switch_track_shadow(model, &state, &theme, inline_size),
        ))
        .id();
    let (thumb_fill, thumb_border) = switch_thumb_colors(model, &state, &theme);
    let thumb_id = commands
        .spawn((
            ChildOf(track_id),
            Node {
                width: px(metrics.thumb_size),
                height: px(metrics.thumb_size),
                min_width: px(metrics.thumb_size),
                min_height: px(metrics.thumb_size),
                max_width: px(metrics.thumb_size),
                max_height: px(metrics.thumb_size),
                border: UiRect::all(px(border_width)),
                border_radius: BorderRadius::MAX,
                flex_shrink: 0.0,
                ..default()
            },
            BackgroundColor(thumb_fill),
            BorderColor::all(thumb_border),
            switch_thumb_shadow(model, &theme, inline_size),
        ))
        .id();
    commands.entity(track_id).insert(SwitchControl {
        group: root_id,
        disabled: blocked,
    });
    commands.entity(root_id).insert(SwitchStoryState {
        model: model.clone(),
        state,
        track: track_id,
        thumb: thumb_id,
        status: status_id,
        theme,
        metrics,
        inline_size,
    });
}

#[cfg(target_arch = "wasm32")]
fn switch_resolve_tone(theme: &Theme, tone: Tone, opacity: f32) -> Color {
    tone.with_opacity(opacity)
        .to_bevy_css_alpha_on(theme.surface_1())
}

#[cfg(target_arch = "wasm32")]
fn switch_status_colors(
    model: &SwitchModel,
    checked: SwitchChecked,
    theme: &Theme,
    root_opacity: f32,
) -> (Color, Color, Color) {
    let (fill, border, text) = if model.disabled {
        (
            theme.surface_2(),
            theme.border_muted(),
            theme.text_disabled(),
        )
    } else if model.error.is_some() {
        (theme.error_soft(), theme.danger(), theme.text_1())
    } else if checked.is_on() {
        (theme.primary_soft(), theme.brand(), theme.text_1())
    } else {
        (theme.surface_2(), theme.border_subtle(), theme.text_muted())
    };
    (
        switch_resolve_tone(theme, fill, root_opacity),
        switch_resolve_tone(theme, border, root_opacity),
        switch_resolve_tone(theme, text, root_opacity),
    )
}

#[cfg(target_arch = "wasm32")]
fn switch_track_opacity(model: &SwitchModel) -> f32 {
    let root_opacity = if model.disabled {
        scale::opacity::DISABLED
    } else {
        1.0
    };
    if model.loading || model.disabled {
        root_opacity * scale::opacity::DISABLED
    } else {
        root_opacity
    }
}

#[cfg(target_arch = "wasm32")]
fn switch_track_colors(
    model: &SwitchModel,
    state: &SwitchState,
    theme: &Theme,
    interaction: Interaction,
) -> (Color, Color) {
    let blocked = model.loading || model.disabled;
    let invalid = model.error.is_some();
    let active = state.is_active(SwitchPart::Track) || interaction == Interaction::Pressed;
    let (fill, border) = if blocked {
        (theme.surface_2(), theme.border_muted())
    } else if invalid {
        (theme.error_soft(), theme.danger())
    } else if active {
        (theme.primary_soft(), theme.brand())
    } else if interaction == Interaction::Hovered {
        if state.is_on() {
            (theme.selected_tint(), theme.brand())
        } else {
            (theme.hover_tint(), theme.border_strong())
        }
    } else if state.is_on() {
        (theme.brand(), theme.brand())
    } else {
        (theme.surface_3(), theme.border_strong())
    };
    let opacity = switch_track_opacity(model);
    (
        switch_resolve_tone(theme, fill, opacity),
        switch_resolve_tone(theme, border, opacity),
    )
}

#[cfg(target_arch = "wasm32")]
fn switch_thumb_colors(model: &SwitchModel, state: &SwitchState, theme: &Theme) -> (Color, Color) {
    let blocked = model.loading || model.disabled;
    let invalid = model.error.is_some();
    let dense = switch_uses_dense_track_metrics(model.density, blocked, invalid);
    let (fill, border) = if blocked {
        (theme.surface_2(), theme.border_muted())
    } else if invalid {
        (theme.surface_1(), theme.danger())
    } else if state.is_active(SwitchPart::Track) {
        (theme.surface_1(), theme.brand())
    } else if state.is_on() && !dense {
        (theme.surface_1(), theme.surface_1())
    } else {
        (theme.surface_1(), theme.border_subtle())
    };
    let opacity = switch_track_opacity(model);
    (
        switch_resolve_tone(theme, fill, opacity),
        switch_resolve_tone(theme, border, opacity),
    )
}

#[cfg(target_arch = "wasm32")]
fn switch_thumb_alignment(model: &SwitchModel, state: &SwitchState) -> JustifyContent {
    if !model.loading && !model.disabled && model.error.is_none() && state.is_on() {
        JustifyContent::FlexEnd
    } else {
        JustifyContent::FlexStart
    }
}

#[cfg(target_arch = "wasm32")]
fn switch_track_shadow(
    model: &SwitchModel,
    state: &SwitchState,
    theme: &Theme,
    inline_size: f32,
) -> BoxShadow {
    if model.loading || model.disabled {
        BoxShadow::default()
    } else if state.is_active(SwitchPart::Track) || state.is_on() {
        bevy_shadow_2(theme, inline_size)
    } else {
        bevy_shadow_1(theme, inline_size)
    }
}

#[cfg(target_arch = "wasm32")]
fn switch_thumb_shadow(model: &SwitchModel, theme: &Theme, inline_size: f32) -> BoxShadow {
    let dense = switch_uses_dense_track_metrics(
        model.density,
        model.loading || model.disabled,
        model.error.is_some(),
    );
    if dense || model.error.is_some() || model.loading || model.disabled {
        bevy_shadow_1(theme, inline_size)
    } else {
        bevy_shadow_2(theme, inline_size)
    }
}

#[cfg(target_arch = "wasm32")]
fn spawn_data_table_primitives(
    parent: &mut ChildSpawnerCommands,
    variant: &BevyUiStoryVariant,
    fonts: &StoryFonts,
    inline_size: f32,
) {
    let UiStoryModel::DataTable(model) = &variant.model else {
        return;
    };
    let theme = variant.theme_id.palette();
    let state = model.state();
    let render_nodes = data_table_render_nodes(model, &state);
    let metrics = data_table_layout_metrics(model.density, model.disabled, inline_size);
    let blocked = model.loading || model.disabled;
    let dense_root = model.density == DataTableDensity::Dense && !model.disabled;
    let border_width = theme.border.max(1.0);
    let root_fill = if model.disabled {
        theme.surface_2()
    } else {
        theme.surface_1()
    };
    let root_border = if model.disabled {
        theme.border_muted()
    } else {
        theme.border_subtle()
    };
    let root_id = parent
        .spawn((
            Node {
                width: percent(100),
                max_width: px(metrics.max_width),
                min_width: px(0.0),
                align_self: AlignSelf::Stretch,
                padding: UiRect::all(px(metrics.root_padding)),
                border: UiRect::all(px(border_width)),
                border_radius: BorderRadius::all(px(if dense_root {
                    theme.radius_field
                } else {
                    theme.radius_box
                })),
                flex_direction: FlexDirection::Column,
                align_items: AlignItems::Stretch,
                row_gap: px(metrics.root_gap),
                ..default()
            },
            BackgroundColor(root_fill.to_bevy()),
            BorderColor::all(root_border.to_bevy_on(root_fill)),
            if model.disabled {
                BoxShadow::default()
            } else {
                bevy_shadow_1(&theme, inline_size)
            },
        ))
        .id();
    let mut commands = parent.commands();
    let toolbar_id = commands
        .spawn((
            ChildOf(root_id),
            Node {
                width: percent(100),
                min_width: px(0.0),
                flex_grow: 1.0,
                flex_direction: FlexDirection::Row,
                flex_wrap: FlexWrap::Wrap,
                justify_content: JustifyContent::SpaceBetween,
                align_items: AlignItems::Center,
                row_gap: px(metrics.toolbar_gap),
                column_gap: px(metrics.toolbar_gap),
                ..default()
            },
        ))
        .id();
    commands.spawn((
        ChildOf(toolbar_id),
        Node {
            min_width: px(0.0),
            align_items: AlignItems::Center,
            ..default()
        },
        Text::new(model.title.clone()),
        TextFont {
            font: fonts.inter.clone().into(),
            font_size: FontSize::Px(metrics.title_font_size),
            weight: FontWeight::BOLD,
            ..default()
        },
        LineHeight::RelativeToFont(metrics.title_line_height),
        TextColor(theme.text_1().to_bevy_on(root_fill)),
        TextLayout::new(Justify::Left, LineBreak::NoWrap),
    ));
    let filter_placeholder = state.filter().is_empty();
    let (filter_background, filter_border, filter_text) =
        data_table_filter_colors(filter_placeholder, false, blocked, root_fill, &theme);
    let filter_id = commands
        .spawn((
            ChildOf(toolbar_id),
            Button,
            Node {
                min_width: px(0.0),
                min_height: px(metrics.filter_min_height),
                flex_grow: 1.0,
                padding: UiRect::axes(
                    px(metrics.filter_padding_inline),
                    px(metrics.filter_padding_block),
                ),
                border: UiRect::all(px(border_width)),
                border_radius: BorderRadius::all(px(theme.radius_field)),
                align_items: AlignItems::Center,
                ..default()
            },
            BackgroundColor(filter_background),
            BorderColor::all(filter_border),
            Text::new(if filter_placeholder {
                model.filter_placeholder.clone()
            } else {
                state.filter().to_owned()
            }),
            TextFont {
                font: fonts.inter.clone().into(),
                font_size: FontSize::Px(metrics.filter_font_size),
                ..default()
            },
            LineHeight::RelativeToFont(metrics.filter_line_height),
            TextColor(filter_text),
            TextLayout::new(Justify::Left, LineBreak::NoWrap),
            InteractivePrimitive {
                rest: filter_background,
                selected: filter_background,
                hover: filter_background,
                pressed: filter_background,
                latched: false,
                stateful: false,
            },
            DataTableFilterControl {
                group: root_id,
                disabled: blocked,
            },
        ))
        .id();
    let frame_fill = theme.surface_1();
    let frame_id = commands
        .spawn((
            ChildOf(root_id),
            Node {
                width: percent(100),
                min_width: px(0.0),
                flex_grow: 1.0,
                border: UiRect::all(px(border_width)),
                border_radius: BorderRadius::all(px(theme.radius_field)),
                flex_direction: FlexDirection::Column,
                align_items: AlignItems::Stretch,
                overflow: Overflow::clip(),
                ..default()
            },
            BackgroundColor(frame_fill.to_bevy_on(root_fill)),
            BorderColor::all(theme.border_subtle().to_bevy_on(root_fill)),
        ))
        .id();
    let header_row = commands
        .spawn((
            ChildOf(frame_id),
            Node {
                width: percent(100),
                min_width: px(0.0),
                flex_direction: FlexDirection::Row,
                align_items: AlignItems::Stretch,
                ..default()
            },
        ))
        .id();
    let column_weights = data_table_column_weights(model, &render_nodes);
    let mut headers = Vec::with_capacity(model.columns.len());
    for (column_index, column) in model.columns.iter().enumerate() {
        let node = render_nodes
            .iter()
            .find(|node| node.part == DataTablePart::Header && node.column_value == column.value)
            .expect("invariant: data table render nodes include every header");
        let palette = data_table_header_palette(node.selected, node.disabled, root_fill, &theme);
        let header_id = commands
            .spawn((
                ChildOf(header_row),
                Button,
                Node {
                    min_width: px(0.0),
                    flex_basis: px(0.0),
                    flex_grow: column_weights[column_index],
                    padding: UiRect::axes(
                        px(metrics.header_padding_inline),
                        px(metrics.header_padding_block),
                    ),
                    border: UiRect::bottom(px(border_width)),
                    justify_content: JustifyContent::SpaceBetween,
                    align_items: AlignItems::Center,
                    column_gap: px(metrics.root_gap),
                    ..default()
                },
                BackgroundColor(palette.background),
                BorderColor::all(palette.border),
                InteractivePrimitive {
                    rest: palette.background,
                    selected: palette.background,
                    hover: palette.background,
                    pressed: palette.background,
                    latched: node.selected,
                    stateful: false,
                },
                DataTableHeaderControl {
                    group: root_id,
                    column: column.value.clone(),
                    disabled: node.disabled,
                },
            ))
            .id();
        let label_id = commands
            .spawn((
                ChildOf(header_id),
                Node {
                    min_width: px(0.0),
                    flex_grow: 1.0,
                    ..default()
                },
                Text::new(node.label.to_uppercase()),
                TextFont {
                    font: fonts.inter.clone().into(),
                    font_size: FontSize::Px(metrics.header_font_size),
                    weight: FontWeight::BOLD,
                    ..default()
                },
                LineHeight::RelativeToFont(metrics.header_line_height),
                LetterSpacing::Rem(0.08),
                TextColor(palette.text),
                TextLayout::new(Justify::Left, LineBreak::NoWrap),
            ))
            .id();
        let marker_id = commands
            .spawn((
                ChildOf(header_id),
                Text::new(data_table_sort_marker(node.sort_direction)),
                TextFont {
                    font: fonts.inter.clone().into(),
                    font_size: FontSize::Px(metrics.header_font_size),
                    weight: FontWeight::BOLD,
                    ..default()
                },
                LineHeight::RelativeToFont(metrics.header_line_height),
                LetterSpacing::Rem(0.08),
                TextColor(palette.marker),
                TextLayout::new(Justify::Right, LineBreak::NoWrap),
            ))
            .id();
        headers.push(DataTableHeaderEntities {
            column: column.value.clone(),
            entity: header_id,
            label: label_id,
            marker: marker_id,
            disabled: !column.sortable,
        });
    }
    let mut rows = Vec::with_capacity(model.rows.len());
    for row in &model.rows {
        let node = render_nodes
            .iter()
            .find(|node| node.part == DataTablePart::Row && node.row_value == row.value);
        let selected = node.is_some_and(|node| node.selected);
        let disabled = node.map_or(blocked || row.disabled, |node| node.disabled);
        let palette = data_table_row_palette(selected, disabled, root_fill, &theme);
        let row_id = commands
            .spawn((
                ChildOf(frame_id),
                Button,
                Node {
                    display: if node.is_some() {
                        Display::Flex
                    } else {
                        Display::None
                    },
                    width: percent(100),
                    min_width: px(0.0),
                    flex_direction: FlexDirection::Row,
                    align_items: AlignItems::Stretch,
                    border: UiRect::bottom(px(border_width)),
                    ..default()
                },
                BackgroundColor(palette.background),
                BorderColor::all(palette.border),
                InteractivePrimitive {
                    rest: palette.background,
                    selected: palette.background,
                    hover: palette.hover,
                    pressed: palette.hover,
                    latched: selected,
                    stateful: true,
                },
                DataTableRowControl {
                    group: root_id,
                    value: row.value.clone(),
                    disabled,
                },
            ))
            .id();
        let mut cells = Vec::with_capacity(row.cells.len());
        for (column_index, cell) in row.cells.iter().enumerate() {
            let cell_id = commands
                .spawn((
                    ChildOf(row_id),
                    Node {
                        min_width: px(0.0),
                        flex_basis: px(0.0),
                        flex_grow: column_weights[column_index],
                        padding: UiRect::axes(
                            px(metrics.cell_padding_inline),
                            px(metrics.cell_padding_block),
                        ),
                        align_items: AlignItems::Center,
                        ..default()
                    },
                    Text::new(cell.clone()),
                    TextFont {
                        font: fonts.inter.clone().into(),
                        font_size: FontSize::Px(metrics.cell_font_size),
                        ..default()
                    },
                    LineHeight::RelativeToFont(metrics.cell_line_height),
                    TextColor(palette.text),
                    TextLayout::new(Justify::Left, LineBreak::NoWrap),
                ))
                .id();
            cells.push(cell_id);
        }
        rows.push(DataTableRowEntities {
            value: row.value.clone(),
            entity: row_id,
            cells,
            disabled: row.disabled,
        });
    }
    let empty_node = render_nodes
        .iter()
        .find(|node| node.part == DataTablePart::Row && node.value == "empty");
    let empty_id = commands
        .spawn((
            ChildOf(frame_id),
            Node {
                display: if empty_node.is_some() {
                    Display::Flex
                } else {
                    Display::None
                },
                width: percent(100),
                min_width: px(0.0),
                padding: UiRect::axes(
                    px(metrics.empty_padding_inline),
                    px(metrics.empty_padding_block),
                ),
                border: UiRect::bottom(px(border_width)),
                justify_content: JustifyContent::Center,
                align_items: AlignItems::Center,
                ..default()
            },
            BackgroundColor(theme.surface_2().to_bevy_on(root_fill)),
            BorderColor::all(theme.border_muted().to_bevy_on(root_fill)),
            Text::new(
                empty_node.map_or_else(|| model.empty_label.clone(), |node| node.label.clone()),
            ),
            TextFont {
                font: fonts.inter.clone().into(),
                font_size: FontSize::Px(metrics.empty_font_size),
                ..default()
            },
            LineHeight::RelativeToFont(metrics.empty_line_height),
            TextColor(theme.text_muted().to_bevy_on(root_fill)),
            TextLayout::new(Justify::Center, LineBreak::WordOrCharacter),
        ))
        .id();
    let pagination_node = render_nodes
        .iter()
        .find(|node| node.part == DataTablePart::Pagination)
        .expect("invariant: data table render nodes include pagination");
    let pagination_id = commands
        .spawn((
            ChildOf(root_id),
            Node {
                width: percent(100),
                min_width: px(0.0),
                flex_grow: 1.0,
                flex_direction: FlexDirection::Row,
                flex_wrap: FlexWrap::Wrap,
                justify_content: JustifyContent::SpaceBetween,
                align_items: AlignItems::Center,
                row_gap: px(metrics.pagination_gap),
                column_gap: px(metrics.pagination_gap),
                ..default()
            },
        ))
        .id();
    let previous_disabled = blocked || state.page_index() == 0;
    let previous = spawn_data_table_page_button(
        &mut commands,
        pagination_id,
        root_id,
        "Previous",
        DataTablePageAction::Previous,
        previous_disabled,
        &metrics,
        root_fill,
        &theme,
        fonts,
    );
    let page_label = commands
        .spawn((
            ChildOf(pagination_id),
            Text::new(pagination_node.label.to_uppercase()),
            TextFont {
                font: fonts.inter.clone().into(),
                font_size: FontSize::Px(metrics.page_label_font_size),
                weight: FontWeight::SEMIBOLD,
                ..default()
            },
            LineHeight::RelativeToFont(metrics.page_label_line_height),
            LetterSpacing::Rem(0.08),
            TextColor(theme.text_muted().to_bevy_on(root_fill)),
            TextLayout::new(Justify::Center, LineBreak::NoWrap),
        ))
        .id();
    let next_disabled = blocked || state.page_index() >= max_data_table_page_index(model, &state);
    let next = spawn_data_table_page_button(
        &mut commands,
        pagination_id,
        root_id,
        "Next",
        DataTablePageAction::Next,
        next_disabled,
        &metrics,
        root_fill,
        &theme,
        fonts,
    );
    commands.entity(root_id).insert(DataTableGroupState {
        model: model.clone(),
        state,
        filter: filter_id,
        headers,
        rows,
        empty: empty_id,
        page_label,
        previous,
        next,
        theme,
        root_fill,
        focused: false,
        blocked,
    });
}

#[cfg(target_arch = "wasm32")]
#[allow(clippy::too_many_arguments)]
fn spawn_data_table_page_button(
    commands: &mut Commands,
    parent: Entity,
    group: Entity,
    label: &str,
    action: DataTablePageAction,
    disabled: bool,
    metrics: &rs_dean_ui::DataTableLayoutMetrics,
    root_fill: Tone,
    theme: &Theme,
    fonts: &StoryFonts,
) -> Entity {
    let palette = data_table_page_palette(disabled, root_fill, theme);
    commands
        .spawn((
            ChildOf(parent),
            Button,
            Node {
                min_height: px(metrics.page_button_min_height),
                padding: UiRect::axes(
                    px(metrics.page_button_padding_inline),
                    px(metrics.page_button_padding_block),
                ),
                border: UiRect::all(px(theme.border.max(1.0))),
                border_radius: BorderRadius::all(px(theme.radius_field)),
                justify_content: JustifyContent::Center,
                align_items: AlignItems::Center,
                ..default()
            },
            BackgroundColor(palette.background),
            BorderColor::all(palette.border),
            Text::new(label),
            TextFont {
                font: fonts.inter.clone().into(),
                font_size: FontSize::Px(metrics.page_button_font_size),
                weight: FontWeight::SEMIBOLD,
                ..default()
            },
            LineHeight::RelativeToFont(metrics.page_button_line_height),
            TextColor(palette.text),
            TextLayout::new(Justify::Center, LineBreak::NoWrap),
            InteractivePrimitive {
                rest: palette.background,
                selected: palette.background,
                hover: palette.hover,
                pressed: palette.hover,
                latched: false,
                stateful: true,
            },
            DataTablePageControl {
                group,
                action,
                disabled,
            },
        ))
        .id()
}

#[cfg(target_arch = "wasm32")]
#[derive(Debug, Clone, Copy)]
struct DataTablePalette {
    background: Color,
    border: Color,
    text: Color,
    marker: Color,
    hover: Color,
}

#[cfg(target_arch = "wasm32")]
fn data_table_filter_colors(
    placeholder: bool,
    focused: bool,
    disabled: bool,
    root_fill: Tone,
    theme: &Theme,
) -> (Color, Color, Color) {
    let resolve = |tone: Tone| {
        if disabled {
            tone.with_opacity(scale::opacity::DISABLED)
                .to_bevy_on(root_fill)
        } else {
            tone.to_bevy_on(root_fill)
        }
    };
    (
        resolve(theme.surface_1()),
        resolve(if focused {
            theme.brand()
        } else {
            theme.border_strong()
        }),
        resolve(if disabled {
            theme.text_disabled()
        } else if placeholder {
            theme.text_muted()
        } else {
            theme.text_1()
        }),
    )
}

#[cfg(target_arch = "wasm32")]
fn data_table_header_palette(
    selected: bool,
    disabled: bool,
    root_fill: Tone,
    theme: &Theme,
) -> DataTablePalette {
    let background_tone = if selected && !disabled {
        theme.primary_soft()
    } else {
        theme.surface_2()
    };
    let border_tone = if selected && !disabled {
        theme.brand()
    } else {
        theme.border_subtle()
    };
    let text_tone = if disabled {
        theme.text_disabled()
    } else if selected {
        theme.text_1()
    } else {
        theme.text_muted()
    };
    let background = background_tone.to_bevy_on(root_fill);
    DataTablePalette {
        background,
        border: border_tone.to_bevy_on(root_fill),
        text: text_tone.to_bevy_on(root_fill),
        marker: theme.text_muted().to_bevy_on(root_fill),
        hover: background,
    }
}

#[cfg(target_arch = "wasm32")]
fn data_table_row_palette(
    selected: bool,
    disabled: bool,
    root_fill: Tone,
    theme: &Theme,
) -> DataTablePalette {
    let (background_tone, border_tone, text_tone) = if disabled {
        (
            theme.surface_2(),
            theme.border_muted(),
            theme.text_disabled(),
        )
    } else if selected {
        (theme.primary_soft(), theme.brand(), theme.text_1())
    } else {
        (theme.surface_1(), theme.border_faint(), theme.text_1())
    };
    let background = background_tone.to_bevy_on(root_fill);
    DataTablePalette {
        background,
        border: border_tone.to_bevy_on(root_fill),
        text: text_tone.to_bevy_on(root_fill),
        marker: theme.text_muted().to_bevy_on(root_fill),
        hover: if disabled {
            background
        } else if selected {
            theme.selected_tint().to_bevy_on(root_fill)
        } else {
            theme.hover_tint().to_bevy_on(root_fill)
        },
    }
}

#[cfg(target_arch = "wasm32")]
fn data_table_page_palette(disabled: bool, root_fill: Tone, theme: &Theme) -> DataTablePalette {
    let resolve = |tone: Tone| {
        if disabled {
            tone.with_opacity(scale::opacity::DISABLED)
                .to_bevy_on(root_fill)
        } else {
            tone.to_bevy_on(root_fill)
        }
    };
    let background = resolve(theme.surface_2());
    DataTablePalette {
        background,
        border: resolve(theme.border_strong()),
        text: resolve(if disabled {
            theme.text_disabled()
        } else {
            theme.text_1()
        }),
        marker: resolve(theme.text_muted()),
        hover: if disabled {
            background
        } else {
            theme.hover_tint().to_bevy_on(root_fill)
        },
    }
}

#[cfg(target_arch = "wasm32")]
const fn data_table_sort_marker(direction: Option<DataTableSortDirection>) -> &'static str {
    match direction {
        Some(DataTableSortDirection::Ascending) => "ASC",
        Some(DataTableSortDirection::Descending) => "DESC",
        None => "-",
    }
}

#[cfg(target_arch = "wasm32")]
fn data_table_column_weights(
    model: &DataTableModel,
    render_nodes: &[rs_dean_ui::DataTableRenderNode],
) -> Vec<f32> {
    model
        .columns
        .iter()
        .enumerate()
        .map(|(column_index, column)| {
            let marker_length = render_nodes
                .iter()
                .find(|node| {
                    node.part == DataTablePart::Header && node.column_value == column.value
                })
                .map_or(1, |node| {
                    data_table_sort_marker(node.sort_direction).chars().count()
                });
            let header_units = column.label.chars().count().saturating_add(marker_length);
            let cell_units = render_nodes
                .iter()
                .filter(|node| {
                    node.part == DataTablePart::Cell && node.column_index == column_index
                })
                .map(|node| node.label.chars().count())
                .max()
                .unwrap_or(0)
                .saturating_mul(4)
                .div_ceil(5);
            header_units.max(cell_units).max(8) as f32
        })
        .collect()
}

#[cfg(target_arch = "wasm32")]
fn spawn_table_primitives(
    parent: &mut ChildSpawnerCommands,
    variant: &BevyUiStoryVariant,
    fonts: &StoryFonts,
    available_width: f32,
    inline_size: f32,
) {
    let UiStoryModel::Table(model) = &variant.model else {
        return;
    };
    let theme = variant.theme_id.palette();
    let state = model.state();
    let blocked = model.loading || model.disabled;
    let invalid = model.error.is_some();
    let border_width = theme.border.max(1.0);
    let metrics = table_layout_metrics(model, available_width, inline_size, border_width);
    let dense_root = table_uses_dense_root_metrics(model.density, model.disabled, invalid);
    let root_opacity = if model.disabled {
        scale::opacity::DISABLED
    } else {
        1.0
    };
    let root_fill_tone = if model.disabled {
        theme.surface_2()
    } else if invalid {
        theme.error_soft()
    } else {
        theme.surface_1()
    };
    let root_border_tone = if model.disabled {
        theme.border_muted()
    } else if invalid {
        theme.danger()
    } else {
        theme.border_subtle()
    };
    let root_id = parent
        .spawn((
            Node {
                display: Display::Grid,
                width: percent(100),
                max_width: px(metrics.width),
                min_width: px(0.0),
                min_height: px(metrics.root_content_min_height(border_width)),
                padding: UiRect::all(px(metrics.root_padding)),
                border: UiRect::all(px(border_width)),
                border_radius: BorderRadius::all(px(if dense_root {
                    theme.radius_field
                } else {
                    theme.radius_box
                })),
                grid_template_columns: RepeatedGridTrack::fr(1, 1.0),
                grid_auto_rows: GridTrack::auto(),
                row_gap: px(metrics.root_gap),
                align_items: AlignItems::Stretch,
                align_self: AlignSelf::Stretch,
                justify_self: JustifySelf::Start,
                flex_shrink: 0.0,
                ..default()
            },
            BackgroundColor(table_resolve_tone(
                &theme,
                root_fill_tone,
                root_opacity,
                theme.surface_1(),
            )),
            BorderColor::all(table_resolve_tone(
                &theme,
                root_border_tone,
                root_opacity,
                theme.surface_1(),
            )),
            if model.disabled {
                BoxShadow::default()
            } else {
                bevy_shadow_1(&theme, inline_size)
            },
        ))
        .id();
    let grid_tracks = table_grid_tracks(&metrics);
    let mut commands = parent.commands();
    let frame_id = commands
        .spawn((
            ChildOf(root_id),
            Node {
                width: percent(100),
                min_width: px(0.0),
                min_height: px(metrics.frame_content_min_height(border_width)),
                border: UiRect::all(px(border_width)),
                border_radius: BorderRadius::all(px(theme.radius_field)),
                overflow: Overflow::clip(),
                flex_direction: FlexDirection::Column,
                ..default()
            },
            BackgroundColor(table_resolve_tone(
                &theme,
                theme.surface_elevated(),
                root_opacity,
                theme.surface_1(),
            )),
            BorderColor::all(table_resolve_tone(
                &theme,
                theme.border_subtle(),
                root_opacity,
                theme.surface_1(),
            )),
        ))
        .id();
    let header_id = commands
        .spawn((
            ChildOf(frame_id),
            Node {
                display: Display::Grid,
                width: percent(100),
                min_width: px(0.0),
                min_height: px(metrics.header_height),
                height: px(metrics.header_height),
                max_height: px(metrics.header_height),
                grid_template_columns: grid_tracks.clone(),
                grid_auto_rows: GridTrack::auto(),
                border: UiRect::bottom(px(border_width)),
                ..default()
            },
            BackgroundColor(table_resolve_tone(
                &theme,
                theme.surface_2(),
                root_opacity,
                theme.surface_1(),
            )),
            BorderColor::all(table_resolve_tone(
                &theme,
                theme.border_subtle(),
                root_opacity,
                theme.surface_1(),
            )),
        ))
        .id();
    for column in &model.columns {
        let cell = table_head_layout_metrics(model.density, column.numeric, inline_size);
        commands.spawn((
            ChildOf(header_id),
            Node {
                width: percent(100),
                min_width: px(0.0),
                padding: UiRect::axes(px(cell.padding_inline), px(cell.padding_block)),
                align_items: AlignItems::Center,
                ..default()
            },
            Text::new(column.label.to_uppercase()),
            TextFont {
                font: fonts.inter.clone().into(),
                font_size: FontSize::Px(cell.font_size),
                weight: FontWeight::BOLD,
                ..default()
            },
            LineHeight::RelativeToFont(cell.line_height),
            LetterSpacing::Rem(scale::letter_spacing::LABEL),
            TextColor(table_resolve_tone(
                &theme,
                theme.text_muted(),
                root_opacity,
                theme.surface_2(),
            )),
            TextLayout::new(
                if column.numeric {
                    Justify::Right
                } else {
                    Justify::Left
                },
                LineBreak::WordOrCharacter,
            ),
        ));
    }

    let mut row_entities = Vec::with_capacity(model.rows.len());
    for (row_index, row) in model.rows.iter().enumerate() {
        let row_disabled = blocked || row.disabled;
        let selected = state.is_selected(&row.value);
        let (row_fill, row_text) =
            table_row_colors(model, selected, row_disabled, Interaction::None, &theme);
        let row_id = commands
            .spawn((
                ChildOf(frame_id),
                Button,
                Node {
                    display: Display::Grid,
                    width: percent(100),
                    min_width: px(0.0),
                    min_height: px(metrics.row_heights[row_index]),
                    height: px(metrics.row_heights[row_index]),
                    max_height: px(metrics.row_heights[row_index]),
                    grid_template_columns: grid_tracks.clone(),
                    grid_auto_rows: GridTrack::auto(),
                    border: if row_index == 0 {
                        UiRect::ZERO
                    } else {
                        UiRect::top(px(border_width))
                    },
                    ..default()
                },
                BackgroundColor(row_fill),
                BorderColor::all(table_resolve_tone(
                    &theme,
                    theme.border_subtle(),
                    table_row_opacity(model, row_disabled),
                    theme.surface_elevated(),
                )),
                Outline::new(px(border_width * 2.0), px(border_width * 2.0), Color::NONE),
            ))
            .id();
        let mut cell_entities = Vec::with_capacity(model.columns.len());
        for (column_index, column) in model.columns.iter().enumerate() {
            let cell = table_cell_layout_metrics(model.density, column.numeric, inline_size);
            let cell_id = commands
                .spawn((
                    ChildOf(row_id),
                    Node {
                        width: percent(100),
                        min_width: px(0.0),
                        padding: UiRect::axes(px(cell.padding_inline), px(cell.padding_block)),
                        align_items: AlignItems::Center,
                        ..default()
                    },
                    Text::new(row.cells[column_index].clone()),
                    TextFont {
                        font: fonts.inter.clone().into(),
                        font_size: FontSize::Px(cell.font_size),
                        weight: FontWeight::NORMAL,
                        ..default()
                    },
                    LineHeight::RelativeToFont(cell.line_height),
                    TextColor(row_text),
                    TextLayout::new(
                        if column.numeric {
                            Justify::Right
                        } else {
                            Justify::Left
                        },
                        LineBreak::WordOrCharacter,
                    ),
                ))
                .id();
            cell_entities.push(cell_id);
        }
        commands.entity(row_id).insert(TableRowControl {
            group: root_id,
            value: row.value.clone(),
            disabled: row_disabled,
        });
        row_entities.push(TableRowEntities {
            value: row.value.clone(),
            row: row_id,
            cells: cell_entities,
            disabled: row_disabled,
        });
    }

    commands.spawn((
        ChildOf(frame_id),
        Node {
            width: percent(100),
            min_width: px(0.0),
            min_height: px(metrics.caption_content_height()),
            height: px(metrics.caption_content_height()),
            max_height: px(metrics.caption_content_height()),
            padding: UiRect::axes(
                px(metrics.caption_padding_inline),
                px(metrics.caption_padding_block),
            ),
            align_items: AlignItems::Center,
            ..default()
        },
        Text::new(model.error.as_ref().unwrap_or(&model.caption).clone()),
        TextFont {
            font: fonts.inter.clone().into(),
            font_size: FontSize::Px(metrics.caption_font_size),
            weight: FontWeight::NORMAL,
            ..default()
        },
        LineHeight::RelativeToFont(metrics.caption_line_height),
        TextColor(table_resolve_tone(
            &theme,
            if invalid {
                theme.danger()
            } else {
                theme.text_2()
            },
            root_opacity,
            theme.surface_elevated(),
        )),
        TextLayout::new(Justify::Left, LineBreak::WordOrCharacter),
    ));
    if let Some(error) = &model.error {
        commands.spawn((
            ChildOf(root_id),
            Node {
                width: percent(100),
                min_width: px(0.0),
                min_height: px(metrics.error_height),
                padding: UiRect::all(px(scale::space::s(inline_size))),
                border: UiRect::all(px(border_width)),
                border_radius: BorderRadius::all(px(theme.radius_field)),
                ..default()
            },
            BackgroundColor(table_resolve_tone(
                &theme,
                theme.error_soft(),
                root_opacity,
                theme.surface_1(),
            )),
            BorderColor::all(table_resolve_tone(
                &theme,
                theme.danger(),
                root_opacity,
                theme.surface_1(),
            )),
            Text::new(error.clone()),
            TextFont {
                font: fonts.inter.clone().into(),
                font_size: FontSize::Px(scale::font_size::f0(inline_size)),
                weight: FontWeight::NORMAL,
                ..default()
            },
            LineHeight::RelativeToFont(scale::line_height::LH0),
            TextColor(table_resolve_tone(
                &theme,
                theme.text_1(),
                root_opacity,
                theme.error_soft(),
            )),
            TextLayout::new(Justify::Left, LineBreak::WordOrCharacter),
        ));
    }
    commands.entity(root_id).insert(TableStoryState {
        model: model.clone(),
        state,
        rows: row_entities,
        theme,
    });
}

#[cfg(target_arch = "wasm32")]
fn table_grid_tracks(metrics: &TableLayoutMetrics) -> Vec<RepeatedGridTrack> {
    metrics
        .column_weights
        .iter()
        .map(|weight| GridTrack::flex::<RepeatedGridTrack>(*weight))
        .collect()
}

#[cfg(target_arch = "wasm32")]
fn table_resolve_tone(_theme: &Theme, tone: Tone, opacity: f32, backdrop: Tone) -> Color {
    tone.with_opacity(opacity).to_bevy_css_alpha_on(backdrop)
}

#[cfg(target_arch = "wasm32")]
fn table_row_opacity(model: &TableModel, row_disabled: bool) -> f32 {
    let root_opacity = if model.disabled {
        scale::opacity::DISABLED
    } else {
        1.0
    };
    if row_disabled {
        root_opacity * scale::opacity::DISABLED
    } else {
        root_opacity
    }
}

#[cfg(target_arch = "wasm32")]
fn table_row_colors(
    model: &TableModel,
    selected: bool,
    row_disabled: bool,
    interaction: Interaction,
    theme: &Theme,
) -> (Color, Color) {
    let opacity = table_row_opacity(model, row_disabled);
    let fill = if row_disabled {
        theme.surface_2()
    } else if interaction == Interaction::Hovered {
        if selected {
            theme.selected_tint()
        } else {
            theme.hover_tint()
        }
    } else if selected {
        theme.primary_soft()
    } else {
        return (
            Color::NONE,
            table_resolve_tone(theme, theme.text_1(), opacity, theme.surface_elevated()),
        );
    };
    (
        table_resolve_tone(theme, fill, opacity, theme.surface_elevated()),
        table_resolve_tone(
            theme,
            if row_disabled {
                theme.text_disabled()
            } else {
                theme.text_1()
            },
            opacity,
            theme.surface_elevated(),
        ),
    )
}

#[cfg(target_arch = "wasm32")]
fn spawn_spinner_primitives(
    parent: &mut ChildSpawnerCommands,
    variant: &BevyUiStoryVariant,
    fonts: &StoryFonts,
    inline_size: f32,
) {
    let UiStoryModel::Spinner(model) = &variant.model else {
        return;
    };
    let theme = variant.theme_id.palette();
    let state = model.state();
    let invalid = model.error.is_some();
    let border_width = theme.border.max(1.0);
    let metrics = spinner_layout_metrics(model, inline_size, border_width);
    let root_tone = if model.disabled {
        theme.surface_2()
    } else if invalid {
        theme.error_soft()
    } else {
        theme.surface_1()
    };
    let root_fill = if model.disabled {
        root_tone
            .with_opacity(scale::opacity::DISABLED)
            .to_bevy_on(theme.surface_1())
    } else {
        root_tone.to_bevy_on(theme.surface_1())
    };
    let root_border = if model.disabled {
        theme
            .border_muted()
            .with_opacity(scale::opacity::DISABLED)
            .to_bevy_on(theme.surface_1())
    } else if invalid {
        theme.danger().to_bevy()
    } else {
        theme.border_subtle().to_bevy_on(root_tone)
    };
    let track_border = if model.disabled {
        theme
            .border_muted()
            .with_opacity(scale::opacity::DISABLED * scale::opacity::DISABLED)
            .to_bevy_on(theme.surface_1())
    } else if invalid {
        theme.danger().to_bevy()
    } else {
        theme.border_muted().to_bevy_on(root_tone)
    };
    let root_id = parent
        .spawn((
            Button,
            Node {
                width: auto(),
                min_width: px(0.0),
                max_width: percent(100),
                min_height: px(metrics.height),
                padding: UiRect::axes(px(metrics.padding_inline), px(metrics.padding_block)),
                border: UiRect::all(px(metrics.border_width)),
                border_radius: BorderRadius::all(px(theme.radius_field)),
                flex_direction: FlexDirection::Row,
                align_items: AlignItems::Center,
                align_self: AlignSelf::FlexStart,
                column_gap: px(metrics.gap),
                ..default()
            },
            BackgroundColor(root_fill),
            BorderColor::all(root_border),
            if metrics.shadow_level == 0 {
                BoxShadow::default()
            } else {
                bevy_shadow_1(&theme, inline_size)
            },
        ))
        .id();
    let mut commands = parent.commands();
    let track_id = commands
        .spawn((
            ChildOf(root_id),
            Node {
                display: if model.loading {
                    Display::Flex
                } else {
                    Display::None
                },
                position_type: PositionType::Relative,
                width: px(metrics.edge),
                height: px(metrics.edge),
                min_width: px(metrics.edge),
                min_height: px(metrics.edge),
                max_width: px(metrics.edge),
                max_height: px(metrics.edge),
                border: UiRect::all(px(metrics.border_width)),
                border_radius: BorderRadius::MAX,
                ..default()
            },
            BorderColor::all(track_border),
        ))
        .id();
    let indicator_id = commands
        .spawn((
            ChildOf(track_id),
            Node {
                position_type: PositionType::Absolute,
                left: px(-metrics.border_width),
                top: px(-metrics.border_width),
                width: px(metrics.edge),
                height: px(metrics.edge),
                min_width: px(metrics.edge),
                min_height: px(metrics.edge),
                border: UiRect::all(px(metrics.border_width)),
                border_radius: BorderRadius::MAX,
                ..default()
            },
            spinner_indicator_border(model, &state, &theme),
            UiTransform::IDENTITY,
        ))
        .id();
    if model.show_label {
        commands.spawn((
            ChildOf(root_id),
            Node {
                min_width: px(0.0),
                ..default()
            },
            Text::new(model.label.clone()),
            TextFont {
                font: fonts.inter.clone().into(),
                font_size: FontSize::Px(metrics.label_font_size),
                weight: FontWeight::SEMIBOLD,
                ..default()
            },
            LineHeight::RelativeToFont(metrics.label_line_height),
            TextColor(if model.disabled {
                let tone = if model.density == rs_dean_ui::SpinnerDensity::Dense {
                    theme.text_2()
                } else {
                    theme.text_1()
                };
                tone.with_opacity(scale::opacity::DISABLED)
                    .to_bevy_on(theme.surface_1())
            } else if model.density == rs_dean_ui::SpinnerDensity::Dense {
                theme.text_2().to_bevy()
            } else {
                theme.text_1().to_bevy()
            }),
            TextLayout::new(Justify::Left, LineBreak::NoWrap),
        ));
    }
    if let Some(error) = &model.error {
        commands.spawn((
            ChildOf(root_id),
            Node {
                min_width: px(0.0),
                padding: UiRect::all(px(metrics.error_padding)),
                border: UiRect::all(px(border_width)),
                border_radius: BorderRadius::all(px(theme.radius_field)),
                ..default()
            },
            BackgroundColor(theme.error_soft().to_bevy_on(root_tone)),
            BorderColor::all(theme.danger().to_bevy()),
            Text::new(error.clone()),
            TextFont {
                font: fonts.inter.clone().into(),
                font_size: FontSize::Px(metrics.error_font_size),
                weight: FontWeight::NORMAL,
                ..default()
            },
            LineHeight::Px(metrics.error_font_size * metrics.error_line_height),
            TextColor(theme.text_1().to_bevy_css_alpha_on(theme.error_soft())),
            TextLayout::new(Justify::Left, LineBreak::WordOrCharacter),
        ));
    }
    commands.entity(root_id).insert(SpinnerGroupState {
        model: model.clone(),
        state,
        indicator: indicator_id,
        theme,
        hovered: false,
        angle: 0.0,
    });
}

#[cfg(target_arch = "wasm32")]
fn spinner_indicator_border(
    model: &SpinnerModel,
    state: &SpinnerState,
    theme: &Theme,
) -> BorderColor {
    let paused = state.is_paused() || !model.animated || !model.loading;
    let tone = if model.disabled {
        theme
            .border_muted()
            .with_opacity(scale::opacity::DISABLED * scale::opacity::DISABLED)
            .to_bevy_on(theme.surface_1())
    } else if paused {
        let background = if model.error.is_some() {
            theme.error_soft()
        } else {
            theme.surface_1()
        };
        theme.border_muted().to_bevy_on(background)
    } else if model.error.is_some() {
        theme.danger().to_bevy()
    } else {
        match model.tone {
            SpinnerTone::Default => theme.accent.to_bevy(),
            SpinnerTone::Brand => theme.brand().to_bevy(),
            SpinnerTone::Info => theme.info.to_bevy(),
            SpinnerTone::Success => theme.success.to_bevy(),
            SpinnerTone::Warning => theme.warning.to_bevy(),
            SpinnerTone::Destructive => theme.danger().to_bevy(),
        }
    };
    BorderColor {
        top: tone,
        right: Color::NONE,
        bottom: Color::NONE,
        left: Color::NONE,
    }
}

#[cfg(target_arch = "wasm32")]
fn spawn_toggle_primitives(
    parent: &mut ChildSpawnerCommands,
    variant: &BevyUiStoryVariant,
    fonts: &StoryFonts,
    available_width: f32,
    inline_size: f32,
) {
    let UiStoryModel::Toggle(model) = &variant.model else {
        return;
    };
    let theme = variant.theme_id.palette();
    let state = model.state();
    let blocked = model.loading || model.disabled;
    let border_width = theme.border.max(1.0);
    let metrics = toggle_layout_metrics(model, &state, available_width, inline_size, border_width);
    let (button_fill, button_border, button_text) =
        toggle_button_colors(model, &state, &theme, Interaction::None);
    let (indicator_fill, indicator_text) = toggle_indicator_colors(model, &state, &theme);
    let (status_fill, status_border, status_text) = toggle_status_colors(model, &state, &theme);
    let root_id = parent
        .spawn(Node {
            display: Display::Grid,
            width: percent(100),
            height: percent(100),
            min_width: px(0.0),
            max_width: px(metrics.width),
            grid_template_columns: RepeatedGridTrack::fr(1, 1.0),
            grid_auto_rows: GridTrack::auto(),
            align_items: AlignItems::Stretch,
            align_self: AlignSelf::Stretch,
            row_gap: px(metrics.frame_gap),
            ..default()
        })
        .id();
    let mut commands = parent.commands();
    let button_id = commands
        .spawn((
            ChildOf(root_id),
            Button,
            Node {
                width: px(metrics.button_width),
                min_width: px(metrics.button_width),
                min_height: px(metrics.button_height),
                max_width: px(metrics.button_width),
                padding: UiRect::axes(
                    px(metrics.button_padding_inline),
                    px(metrics.button_padding_block),
                ),
                border: UiRect::all(px(border_width)),
                border_radius: BorderRadius::all(px(theme.radius_field)),
                flex_direction: FlexDirection::Row,
                justify_content: JustifyContent::Center,
                align_items: AlignItems::Center,
                column_gap: px(metrics.button_gap),
                ..default()
            },
            BackgroundColor(button_fill),
            BorderColor::all(button_border),
            if blocked {
                BoxShadow::default()
            } else if state.is_pressed() {
                bevy_shadow_2(&theme, inline_size)
            } else {
                bevy_shadow_1(&theme, inline_size)
            },
        ))
        .id();
    let indicator_id = commands
        .spawn((
            ChildOf(button_id),
            Node {
                width: px(metrics.indicator_width),
                height: px(metrics.indicator_height),
                min_width: px(metrics.indicator_width),
                min_height: px(metrics.indicator_height),
                max_width: px(metrics.indicator_width),
                max_height: px(metrics.indicator_height),
                padding: UiRect::horizontal(px(metrics.indicator_padding_inline)),
                border_radius: BorderRadius::MAX,
                justify_content: JustifyContent::Center,
                align_items: AlignItems::Center,
                ..default()
            },
            BackgroundColor(indicator_fill),
            Text::new(toggle_indicator_label(model, state.pressed()).to_uppercase()),
            TextFont {
                font: fonts.inter.clone().into(),
                font_size: FontSize::Px(metrics.indicator_font_size),
                weight: FontWeight::BOLD,
                ..default()
            },
            LineHeight::RelativeToFont(metrics.indicator_line_height),
            LetterSpacing::Rem(metrics.indicator_letter_spacing),
            TextColor(indicator_text),
            TextLayout::new(Justify::Center, LineBreak::NoWrap),
        ))
        .id();
    let label_id = commands
        .spawn((
            ChildOf(button_id),
            Node {
                min_width: px(0.0),
                ..default()
            },
            Text::new(model.label.clone()),
            TextFont {
                font: fonts.inter.clone().into(),
                font_size: FontSize::Px(metrics.button_font_size),
                weight: if state.is_pressed() {
                    FontWeight::BOLD
                } else {
                    FontWeight::SEMIBOLD
                },
                ..default()
            },
            LineHeight::RelativeToFont(metrics.button_line_height),
            TextColor(button_text),
            TextLayout::new(Justify::Left, LineBreak::NoWrap),
        ))
        .id();
    let meta_id = commands
        .spawn((
            ChildOf(root_id),
            Node {
                width: percent(100),
                min_width: px(0.0),
                flex_direction: FlexDirection::Row,
                flex_wrap: FlexWrap::Wrap,
                align_items: AlignItems::Center,
                row_gap: px(metrics.frame_gap),
                column_gap: px(metrics.frame_gap),
                ..default()
            },
        ))
        .id();
    let status_id = commands
        .spawn((
            ChildOf(meta_id),
            Node {
                width: px(metrics.status_width),
                height: px(metrics.status_height),
                min_width: px(metrics.status_width),
                min_height: px(metrics.status_height),
                max_width: px(metrics.status_width),
                max_height: px(metrics.status_height),
                padding: UiRect::axes(
                    px(metrics.status_padding_inline),
                    px(metrics.status_padding_block),
                ),
                border: UiRect::all(px(border_width)),
                border_radius: BorderRadius::MAX,
                justify_content: JustifyContent::Center,
                align_items: AlignItems::Center,
                ..default()
            },
            BackgroundColor(status_fill),
            BorderColor::all(status_border),
            Text::new(toggle_status_label(model, state.pressed()).to_uppercase()),
            TextFont {
                font: fonts.inter.clone().into(),
                font_size: FontSize::Px(metrics.status_font_size),
                weight: FontWeight::BOLD,
                ..default()
            },
            LineHeight::RelativeToFont(metrics.status_line_height),
            LetterSpacing::Rem(metrics.status_letter_spacing),
            TextColor(status_text),
            TextLayout::new(Justify::Center, LineBreak::NoWrap),
        ))
        .id();
    let detail_id = commands
        .spawn((
            ChildOf(meta_id),
            Node {
                width: percent(100),
                min_width: px(0.0),
                ..default()
            },
            Text::new(model.detail.clone()),
            TextFont {
                font: fonts.inter.clone().into(),
                font_size: FontSize::Px(metrics.detail_font_size),
                weight: FontWeight::NORMAL,
                ..default()
            },
            LineHeight::RelativeToFont(metrics.detail_line_height),
            TextColor(toggle_detail_color(model, &theme)),
            TextLayout::new(Justify::Left, LineBreak::WordOrCharacter),
        ))
        .id();
    if let Some(error) = &model.error {
        commands.spawn((
            ChildOf(root_id),
            Node {
                width: percent(100),
                min_width: px(0.0),
                ..default()
            },
            Text::new(error.clone()),
            TextFont {
                font: fonts.inter.clone().into(),
                font_size: FontSize::Px(metrics.detail_font_size),
                weight: FontWeight::SEMIBOLD,
                ..default()
            },
            LineHeight::RelativeToFont(metrics.detail_line_height),
            TextColor(theme.danger().to_bevy()),
            TextLayout::new(Justify::Left, LineBreak::WordOrCharacter),
        ));
    }
    commands.entity(button_id).insert(ToggleControl {
        group: root_id,
        disabled: blocked,
    });
    commands.entity(root_id).insert(ToggleStoryState {
        model: model.clone(),
        state,
        button: button_id,
        indicator: indicator_id,
        indicator_text: indicator_id,
        label: label_id,
        status: status_id,
        status_text: status_id,
        detail: detail_id,
        theme,
        available_width,
        inline_size,
    });
}

#[cfg(target_arch = "wasm32")]
fn toggle_button_colors(
    model: &ToggleModel,
    state: &ToggleState,
    theme: &Theme,
    interaction: Interaction,
) -> (Color, Color, Color) {
    let blocked = model.loading || model.disabled;
    let invalid = model.error.is_some();
    let background = if blocked {
        theme.surface_2().to_bevy()
    } else if invalid {
        theme.error_soft().to_bevy_css_alpha_on(theme.surface_1())
    } else if state.is_active(TogglePart::Root) || interaction != Interaction::None {
        if state.is_pressed() {
            theme
                .selected_tint()
                .to_bevy_css_alpha_on(theme.surface_1())
        } else {
            theme.hover_tint().to_bevy_css_alpha_on(theme.surface_1())
        }
    } else if state.is_pressed() {
        theme.primary_soft().to_bevy_css_alpha_on(theme.surface_1())
    } else if model.variant == ToggleVariant::Outline {
        theme.surface_1().to_bevy()
    } else {
        theme.surface_2().to_bevy()
    };
    let border = if blocked {
        theme.border_muted().to_bevy_css_alpha_on(theme.surface_1())
    } else if invalid {
        theme.danger().to_bevy()
    } else if state.is_pressed() || state.is_active(TogglePart::Root) {
        theme.brand().to_bevy()
    } else {
        theme
            .border_strong()
            .to_bevy_css_alpha_on(theme.surface_1())
    };
    let text = if blocked {
        theme
            .text_disabled()
            .to_bevy_css_alpha_on(theme.surface_2())
    } else {
        theme.text_1().to_bevy()
    };
    (background, border, text)
}

#[cfg(target_arch = "wasm32")]
fn toggle_indicator_colors(
    model: &ToggleModel,
    state: &ToggleState,
    theme: &Theme,
) -> (Color, Color) {
    if model.loading || model.disabled {
        return (
            theme.surface_3().to_bevy(),
            theme
                .text_disabled()
                .to_bevy_css_alpha_on(theme.surface_3()),
        );
    }
    if model.error.is_some() {
        return (theme.error_soft().to_bevy(), theme.text_1().to_bevy());
    }
    if state.is_pressed() {
        return (theme.brand().to_bevy(), theme.text_on_brand().to_bevy());
    }
    (
        theme.surface_3().to_bevy(),
        theme.text_muted().to_bevy_css_alpha_on(theme.surface_3()),
    )
}

#[cfg(target_arch = "wasm32")]
fn toggle_status_colors(
    model: &ToggleModel,
    state: &ToggleState,
    theme: &Theme,
) -> (Color, Color, Color) {
    if model.loading || model.disabled {
        return (
            theme.surface_2().to_bevy(),
            theme.border_muted().to_bevy_css_alpha_on(theme.surface_1()),
            theme
                .text_disabled()
                .to_bevy_css_alpha_on(theme.surface_2()),
        );
    }
    if model.error.is_some() {
        return (
            theme.error_soft().to_bevy_css_alpha_on(theme.surface_1()),
            theme.danger().to_bevy(),
            theme.text_1().to_bevy(),
        );
    }
    if state.is_pressed() {
        return (
            theme.primary_soft().to_bevy_css_alpha_on(theme.surface_1()),
            theme.brand().to_bevy(),
            theme.text_1().to_bevy(),
        );
    }
    (
        theme.surface_2().to_bevy(),
        theme
            .border_subtle()
            .to_bevy_css_alpha_on(theme.surface_1()),
        theme.text_muted().to_bevy_css_alpha_on(theme.surface_2()),
    )
}

#[cfg(target_arch = "wasm32")]
fn toggle_detail_color(model: &ToggleModel, theme: &Theme) -> Color {
    if model.loading || model.disabled {
        theme
            .text_disabled()
            .to_bevy_css_alpha_on(theme.surface_1())
    } else if model.error.is_some() {
        theme.danger().to_bevy()
    } else {
        theme.text_2().to_bevy_css_alpha_on(theme.surface_1())
    }
}

#[cfg(target_arch = "wasm32")]
fn spawn_toggle_group_primitives(
    parent: &mut ChildSpawnerCommands,
    variant: &BevyUiStoryVariant,
    fonts: &StoryFonts,
    available_width: f32,
    inline_size: f32,
) {
    let UiStoryModel::ToggleGroup(model) = &variant.model else {
        return;
    };
    let theme = variant.theme_id.palette();
    let state = model.state();
    let border_width = theme.border.max(1.0);
    let metrics =
        toggle_group_layout_metrics(model, &state, available_width, inline_size, border_width);
    let render_nodes = toggle_group_render_nodes(model, &state);
    let root_render_node = render_nodes
        .iter()
        .find(|node| node.part == ToggleGroupPart::Root)
        .expect("invariant: toggle group render nodes include root");
    let (root_fill, root_border) = toggle_group_root_colors(model, &theme);
    let root_id = parent
        .spawn((
            Node {
                display: Display::Grid,
                width: percent(100),
                height: percent(100),
                min_width: px(0.0),
                max_width: px(metrics.width),
                padding: UiRect::all(px(metrics.root_padding)),
                border: UiRect::all(px(border_width)),
                border_radius: BorderRadius::all(px(if metrics.root_is_dense {
                    theme.radius_field
                } else {
                    theme.radius_box
                })),
                grid_template_columns: RepeatedGridTrack::fr(1, 1.0),
                grid_auto_rows: GridTrack::auto(),
                align_items: AlignItems::Stretch,
                align_self: AlignSelf::Stretch,
                row_gap: px(metrics.root_gap),
                ..default()
            },
            BackgroundColor(root_fill),
            BorderColor::all(root_border),
            if model.disabled {
                BoxShadow::default()
            } else {
                bevy_shadow_1(&theme, inline_size)
            },
        ))
        .id();
    let mut commands = parent.commands();
    let header_id = commands
        .spawn((
            ChildOf(root_id),
            Node {
                width: percent(100),
                min_width: px(0.0),
                flex_direction: FlexDirection::Row,
                flex_wrap: FlexWrap::Wrap,
                justify_content: JustifyContent::SpaceBetween,
                align_items: AlignItems::Center,
                row_gap: px(metrics.header_gap),
                column_gap: px(metrics.header_gap),
                ..default()
            },
        ))
        .id();
    let title_id = commands
        .spawn((
            ChildOf(header_id),
            Text::new(model.label.clone()),
            TextFont {
                font: fonts.inter.clone().into(),
                font_size: FontSize::Px(metrics.title_font_size),
                weight: FontWeight::BOLD,
                ..default()
            },
            LineHeight::RelativeToFont(metrics.title_line_height),
            TextColor(toggle_group_title_color(model, &theme)),
            TextLayout::new(Justify::Left, LineBreak::WordOrCharacter),
        ))
        .id();
    let (status_fill, status_border, status_text) =
        toggle_group_status_colors(model, &state, &theme);
    let status_id = commands
        .spawn((
            ChildOf(header_id),
            Node {
                width: px(metrics.status_width),
                height: px(metrics.status_height),
                min_width: px(metrics.status_width),
                min_height: px(metrics.status_height),
                max_width: px(metrics.status_width),
                max_height: px(metrics.status_height),
                padding: UiRect::axes(
                    px(metrics.status_padding_inline),
                    px(metrics.status_padding_block),
                ),
                border: UiRect::all(px(border_width)),
                border_radius: BorderRadius::MAX,
                justify_content: JustifyContent::Center,
                align_items: AlignItems::Center,
                ..default()
            },
            BackgroundColor(status_fill),
            BorderColor::all(status_border),
            Text::new(toggle_group_selected_status_label(state.selected_values()).to_uppercase()),
            TextFont {
                font: fonts.inter.clone().into(),
                font_size: FontSize::Px(metrics.status_font_size),
                weight: FontWeight::BOLD,
                ..default()
            },
            LineHeight::RelativeToFont(metrics.status_line_height),
            LetterSpacing::Rem(metrics.status_letter_spacing),
            TextColor(status_text),
            TextLayout::new(Justify::Center, LineBreak::NoWrap),
        ))
        .id();
    let list_id = commands
        .spawn((
            ChildOf(root_id),
            Node {
                display: if metrics.horizontal {
                    Display::Flex
                } else {
                    Display::Grid
                },
                width: percent(100),
                min_width: px(0.0),
                flex_direction: FlexDirection::Row,
                flex_wrap: FlexWrap::Wrap,
                grid_template_columns: RepeatedGridTrack::fr(1, 1.0),
                grid_auto_rows: GridTrack::auto(),
                align_items: AlignItems::Stretch,
                justify_items: JustifyItems::Start,
                row_gap: px(metrics.list_gap),
                column_gap: px(metrics.list_gap),
                ..default()
            },
        ))
        .id();
    let mut item_entities = Vec::with_capacity(model.items.len());
    for (index, item) in model.items.iter().enumerate() {
        let item_metrics = metrics.items[index];
        let selected = state.is_selected(&item.value);
        let focused = state.is_focused(&item.value);
        let item_disabled = model.loading || model.disabled || item.disabled;
        let (button_fill, button_border, button_text) = toggle_group_item_colors(
            model,
            selected,
            focused,
            item_disabled,
            &theme,
            Interaction::None,
        );
        let button_id = commands
            .spawn((
                ChildOf(list_id),
                Button,
                Node {
                    width: px(item_metrics.width),
                    min_width: px(item_metrics.width),
                    min_height: px(item_metrics.height),
                    max_width: px(item_metrics.width),
                    padding: UiRect::axes(
                        px(item_metrics.padding_inline),
                        px(item_metrics.padding_block),
                    ),
                    border: UiRect::all(px(border_width)),
                    border_radius: BorderRadius::all(px(theme.radius_field)),
                    flex_direction: FlexDirection::Row,
                    justify_content: JustifyContent::Center,
                    align_items: AlignItems::Center,
                    justify_self: JustifySelf::Start,
                    column_gap: px(item_metrics.gap),
                    ..default()
                },
                BackgroundColor(button_fill),
                BorderColor::all(button_border),
                toggle_group_item_shadow(selected, focused, item_disabled, &theme, inline_size),
            ))
            .id();
        let (indicator_fill, indicator_text) =
            toggle_group_indicator_colors(model, selected, item_disabled, &theme);
        let indicator_id = commands
            .spawn((
                ChildOf(button_id),
                Node {
                    width: px(item_metrics.indicator_width),
                    height: px(item_metrics.indicator_height),
                    min_width: px(item_metrics.indicator_width),
                    min_height: px(item_metrics.indicator_height),
                    max_width: px(item_metrics.indicator_width),
                    max_height: px(item_metrics.indicator_height),
                    padding: UiRect::horizontal(px(item_metrics.indicator_padding_inline)),
                    border_radius: BorderRadius::MAX,
                    justify_content: JustifyContent::Center,
                    align_items: AlignItems::Center,
                    ..default()
                },
                BackgroundColor(indicator_fill),
                Text::new(if selected { "ON" } else { "OFF" }),
                TextFont {
                    font: fonts.inter.clone().into(),
                    font_size: FontSize::Px(item_metrics.indicator_font_size),
                    weight: FontWeight::BOLD,
                    ..default()
                },
                LineHeight::RelativeToFont(item_metrics.indicator_line_height),
                LetterSpacing::Rem(item_metrics.indicator_letter_spacing),
                TextColor(indicator_text),
                TextLayout::new(Justify::Center, LineBreak::NoWrap),
            ))
            .id();
        let label_id = commands
            .spawn((
                ChildOf(button_id),
                Node {
                    min_width: px(0.0),
                    ..default()
                },
                Text::new(item.label.clone()),
                TextFont {
                    font: fonts.inter.clone().into(),
                    font_size: FontSize::Px(item_metrics.font_size),
                    weight: if selected {
                        FontWeight::BOLD
                    } else {
                        FontWeight::SEMIBOLD
                    },
                    ..default()
                },
                LineHeight::RelativeToFont(item_metrics.line_height),
                TextColor(button_text),
                TextLayout::new(Justify::Left, LineBreak::NoWrap),
            ))
            .id();
        commands.entity(button_id).insert(ToggleGroupControl {
            group: root_id,
            value: item.value.clone(),
            disabled: item_disabled,
        });
        item_entities.push(ToggleGroupItemEntities {
            value: item.value.clone(),
            button: button_id,
            indicator: indicator_id,
            label: label_id,
            disabled: item_disabled,
        });
    }
    let detail_id = commands
        .spawn((
            ChildOf(root_id),
            Node {
                width: percent(100),
                min_width: px(0.0),
                ..default()
            },
            Text::new(root_render_node.detail.clone()),
            TextFont {
                font: fonts.inter.clone().into(),
                font_size: FontSize::Px(metrics.detail_font_size),
                weight: FontWeight::NORMAL,
                ..default()
            },
            LineHeight::RelativeToFont(metrics.detail_line_height),
            TextColor(toggle_group_detail_color(model, &theme)),
            TextLayout::new(Justify::Left, LineBreak::WordOrCharacter),
        ))
        .id();
    if let Some(error) = &model.error {
        commands.spawn((
            ChildOf(root_id),
            Node {
                width: percent(100),
                min_width: px(0.0),
                padding: UiRect::all(px(metrics.error_padding)),
                border: UiRect::all(px(border_width)),
                border_radius: BorderRadius::all(px(theme.radius_field)),
                ..default()
            },
            BackgroundColor(theme.error_soft().to_bevy_css_alpha_on(theme.surface_1())),
            BorderColor::all(theme.danger().to_bevy()),
            Text::new(error.clone()),
            TextFont {
                font: fonts.inter.clone().into(),
                font_size: FontSize::Px(metrics.detail_font_size),
                weight: FontWeight::NORMAL,
                ..default()
            },
            LineHeight::RelativeToFont(metrics.detail_line_height),
            TextColor(theme.text_1().to_bevy()),
            TextLayout::new(Justify::Left, LineBreak::WordOrCharacter),
        ));
    }
    commands.entity(root_id).insert(ToggleGroupStoryState {
        model: model.clone(),
        state,
        root: root_id,
        title: title_id,
        status: status_id,
        detail: detail_id,
        items: item_entities,
        theme,
        available_width,
        inline_size,
    });
}

#[cfg(target_arch = "wasm32")]
fn toggle_group_root_colors(model: &ToggleGroupModel, theme: &Theme) -> (Color, Color) {
    if model.disabled {
        return (
            theme
                .surface_2()
                .with_opacity(scale::opacity::DISABLED)
                .to_bevy_on(theme.surface_1()),
            theme
                .border_muted()
                .with_opacity(scale::opacity::DISABLED)
                .to_bevy_on(theme.surface_1()),
        );
    }
    if model.error.is_some() {
        return (
            theme.error_soft().to_bevy_css_alpha_on(theme.surface_1()),
            theme.danger().to_bevy(),
        );
    }
    (
        theme.surface_1().to_bevy(),
        theme
            .border_subtle()
            .to_bevy_css_alpha_on(theme.surface_1()),
    )
}

#[cfg(target_arch = "wasm32")]
fn toggle_group_title_color(model: &ToggleGroupModel, theme: &Theme) -> Color {
    if model.disabled {
        theme
            .text_disabled()
            .with_opacity(scale::opacity::DISABLED)
            .to_bevy_on(theme.surface_1())
    } else {
        theme.text_1().to_bevy()
    }
}

#[cfg(target_arch = "wasm32")]
fn toggle_group_item_colors(
    model: &ToggleGroupModel,
    selected: bool,
    focused: bool,
    disabled: bool,
    theme: &Theme,
    interaction: Interaction,
) -> (Color, Color, Color) {
    let invalid = model.error.is_some();
    let background = if disabled {
        theme.surface_2().to_bevy()
    } else if invalid {
        theme.error_soft().to_bevy_css_alpha_on(theme.surface_1())
    } else if focused || interaction != Interaction::None {
        if selected {
            theme
                .selected_tint()
                .to_bevy_css_alpha_on(theme.surface_1())
        } else {
            theme.hover_tint().to_bevy_css_alpha_on(theme.surface_1())
        }
    } else if selected {
        theme.primary_soft().to_bevy_css_alpha_on(theme.surface_1())
    } else if model.variant == ToggleVariant::Outline {
        theme.surface_1().to_bevy()
    } else {
        theme.surface_2().to_bevy()
    };
    let border = if disabled {
        theme.border_muted().to_bevy_css_alpha_on(theme.surface_1())
    } else if invalid {
        theme.danger().to_bevy()
    } else if selected || focused {
        theme.brand().to_bevy()
    } else {
        theme
            .border_strong()
            .to_bevy_css_alpha_on(theme.surface_1())
    };
    let text = if disabled {
        theme
            .text_disabled()
            .to_bevy_css_alpha_on(theme.surface_2())
    } else {
        theme.text_1().to_bevy()
    };
    (background, border, text)
}

#[cfg(target_arch = "wasm32")]
fn toggle_group_indicator_colors(
    model: &ToggleGroupModel,
    selected: bool,
    disabled: bool,
    theme: &Theme,
) -> (Color, Color) {
    if disabled {
        return (
            theme.surface_3().to_bevy(),
            theme
                .text_disabled()
                .to_bevy_css_alpha_on(theme.surface_3()),
        );
    }
    if model.error.is_some() {
        return (theme.error_soft().to_bevy(), theme.text_1().to_bevy());
    }
    if selected {
        return (theme.brand().to_bevy(), theme.text_on_brand().to_bevy());
    }
    (
        theme.surface_3().to_bevy(),
        theme.text_muted().to_bevy_css_alpha_on(theme.surface_3()),
    )
}

#[cfg(target_arch = "wasm32")]
fn toggle_group_status_colors(
    model: &ToggleGroupModel,
    state: &ToggleGroupState,
    theme: &Theme,
) -> (Color, Color, Color) {
    if model.loading || model.disabled {
        return (
            theme.surface_2().to_bevy(),
            theme.border_muted().to_bevy_css_alpha_on(theme.surface_1()),
            theme
                .text_disabled()
                .to_bevy_css_alpha_on(theme.surface_2()),
        );
    }
    if model.error.is_some() {
        return (
            theme.error_soft().to_bevy_css_alpha_on(theme.surface_1()),
            theme.danger().to_bevy(),
            theme.text_1().to_bevy(),
        );
    }
    if !state.selected_values().is_empty() {
        return (
            theme.primary_soft().to_bevy_css_alpha_on(theme.surface_1()),
            theme.brand().to_bevy(),
            theme.text_1().to_bevy(),
        );
    }
    (
        theme.surface_2().to_bevy(),
        theme
            .border_subtle()
            .to_bevy_css_alpha_on(theme.surface_1()),
        theme.text_muted().to_bevy_css_alpha_on(theme.surface_2()),
    )
}

#[cfg(target_arch = "wasm32")]
fn toggle_group_detail_color(model: &ToggleGroupModel, theme: &Theme) -> Color {
    if model.loading || model.disabled {
        theme
            .text_disabled()
            .to_bevy_css_alpha_on(theme.surface_1())
    } else if model.error.is_some() {
        theme.danger().to_bevy()
    } else {
        theme.text_2().to_bevy_css_alpha_on(theme.surface_1())
    }
}

#[cfg(target_arch = "wasm32")]
fn toggle_group_item_shadow(
    selected: bool,
    focused: bool,
    disabled: bool,
    theme: &Theme,
    inline_size: f32,
) -> BoxShadow {
    if disabled {
        BoxShadow::default()
    } else if selected || focused {
        bevy_shadow_2(theme, inline_size)
    } else {
        bevy_shadow_1(theme, inline_size)
    }
}

#[cfg(target_arch = "wasm32")]
fn bevy_shadow_1(theme: &Theme, inline_size: f32) -> BoxShadow {
    BoxShadow::new(
        theme.shadow_1().to_bevy_css_alpha_on(theme.surface_1()),
        px(0.0),
        px(scale::space::xs3(inline_size)),
        px(0.0),
        px(scale::space::xs2(inline_size) * BEVY_CSS_SHADOW_BLUR_SCALE),
    )
}

#[cfg(target_arch = "wasm32")]
fn bevy_shadow_2(theme: &Theme, inline_size: f32) -> BoxShadow {
    BoxShadow::new(
        theme.shadow_2().to_bevy_css_alpha_on(theme.surface_1()),
        px(0.0),
        px(scale::space::xs2(inline_size)),
        px(-scale::space::xs3(inline_size)),
        px(scale::space::s(inline_size) * BEVY_CSS_SHADOW_BLUR_SCALE),
    )
}

#[cfg(target_arch = "wasm32")]
fn bevy_shadow_3(theme: &Theme, inline_size: f32) -> BoxShadow {
    BoxShadow::new(
        theme.shadow_3().to_bevy_css_alpha_on(theme.surface_1()),
        px(0.0),
        px(scale::space::xs(inline_size)),
        px(-scale::space::xs2(inline_size)),
        px(scale::space::m(inline_size) * BEVY_CSS_SHADOW_BLUR_SCALE),
    )
}

#[cfg(target_arch = "wasm32")]
fn spawn_tooltip_primitives(
    parent: &mut ChildSpawnerCommands,
    variant: &BevyUiStoryVariant,
    fonts: &StoryFonts,
    available_width: f32,
    inline_size: f32,
) {
    let UiStoryModel::Tooltip(model) = &variant.model else {
        return;
    };
    let theme = variant.theme_id.palette();
    let state = model.state();
    let border_width = theme.border.max(1.0);
    let metrics = tooltip_layout_metrics(model, &state, available_width, inline_size, border_width);
    let (stage_justify, stage_align) = tooltip_stage_alignment(model, &metrics);
    let (content_left, content_right, content_top, content_bottom) =
        tooltip_content_offsets(&metrics);
    let (trigger_fill, trigger_border, trigger_text) =
        tooltip_trigger_colors(model, &state, &theme, Interaction::None);
    let (content_fill, content_border, content_text) = tooltip_content_colors(model, &theme);
    let stage_id = parent
        .spawn(Node {
            position_type: PositionType::Relative,
            width: percent(100),
            height: px(metrics.stage_height),
            min_width: px(0.0),
            min_height: px(metrics.stage_height),
            max_height: px(metrics.stage_height),
            padding: UiRect::all(px(metrics.stage_padding)),
            flex_direction: FlexDirection::Row,
            justify_content: stage_justify,
            align_items: stage_align,
            ..default()
        })
        .id();
    let mut commands = parent.commands();
    let root_id = commands
        .spawn((
            ChildOf(stage_id),
            Node {
                position_type: PositionType::Relative,
                width: px(metrics.trigger_width),
                height: px(metrics.trigger_height),
                min_width: px(metrics.trigger_width),
                min_height: px(metrics.trigger_height),
                max_width: px(metrics.trigger_width),
                max_height: px(metrics.trigger_height),
                ..default()
            },
        ))
        .id();
    let blocked = model.loading || model.disabled;
    let trigger_id = commands
        .spawn((
            ChildOf(root_id),
            Button,
            Node {
                position_type: PositionType::Absolute,
                left: px(0.0),
                right: px(0.0),
                top: px(0.0),
                bottom: px(0.0),
                width: percent(100),
                height: percent(100),
                padding: UiRect::axes(
                    px(metrics.trigger_padding_inline),
                    px(metrics.trigger_padding_block),
                ),
                border: UiRect::all(px(border_width)),
                border_radius: BorderRadius::all(px(theme.radius_field)),
                justify_content: JustifyContent::Center,
                align_items: AlignItems::Center,
                ..default()
            },
            BackgroundColor(trigger_fill),
            BorderColor::all(trigger_border),
            if blocked {
                BoxShadow::default()
            } else if state.is_open() {
                bevy_shadow_2(&theme, inline_size)
            } else {
                bevy_shadow_1(&theme, inline_size)
            },
            Text::new(tooltip_trigger_copy(model)),
            TextFont {
                font: fonts.inter.clone().into(),
                font_size: FontSize::Px(metrics.trigger_font_size),
                weight: if state.is_open() || model.error.is_some() {
                    FontWeight::BOLD
                } else {
                    FontWeight::SEMIBOLD
                },
                ..default()
            },
            LineHeight::RelativeToFont(metrics.trigger_line_height),
            TextColor(trigger_text),
            TextLayout::new(Justify::Center, LineBreak::NoWrap),
        ))
        .id();
    let dense_content =
        model.density == rs_dean_ui::TooltipDensity::Dense && !blocked && model.error.is_none();
    let content_id = commands
        .spawn((
            ChildOf(root_id),
            Node {
                display: if metrics.content_visible {
                    Display::Flex
                } else {
                    Display::None
                },
                position_type: PositionType::Absolute,
                left: content_left,
                right: content_right,
                top: content_top,
                bottom: content_bottom,
                width: px(metrics.content_width),
                min_width: px(metrics.content_width),
                max_width: px(metrics.content_width),
                min_height: px(metrics.content_height),
                padding: UiRect::all(px(metrics.content_padding)),
                border: UiRect::all(px(border_width)),
                border_radius: BorderRadius::all(px(theme.radius_field)),
                flex_direction: FlexDirection::Column,
                align_items: AlignItems::Stretch,
                row_gap: px(metrics.content_gap),
                ..default()
            },
            BackgroundColor(content_fill),
            BorderColor::all(content_border),
            if dense_content || model.loading || model.error.is_some() {
                bevy_shadow_2(&theme, inline_size)
            } else {
                bevy_shadow_3(&theme, inline_size)
            },
            GlobalZIndex(10),
        ))
        .id();
    let arrow_id = commands
        .spawn((
            ChildOf(content_id),
            Node {
                display: if metrics.arrow_visible {
                    Display::Flex
                } else {
                    Display::None
                },
                width: px(metrics.arrow_edge),
                height: px(metrics.arrow_edge),
                min_width: px(metrics.arrow_edge),
                min_height: px(metrics.arrow_edge),
                max_width: px(metrics.arrow_edge),
                max_height: px(metrics.arrow_edge),
                border_radius: BorderRadius::all(px(theme.radius_field)),
                ..default()
            },
            BackgroundColor(theme.surface_elevated().to_bevy()),
        ))
        .id();
    commands.spawn((
        ChildOf(content_id),
        Node {
            width: percent(100),
            min_width: px(0.0),
            ..default()
        },
        Text::new(tooltip_content_copy(model)),
        TextFont {
            font: fonts.inter.clone().into(),
            font_size: FontSize::Px(metrics.content_font_size),
            weight: FontWeight::NORMAL,
            ..default()
        },
        LineHeight::RelativeToFont(metrics.content_line_height),
        TextColor(content_text),
        TextLayout::new(Justify::Left, LineBreak::WordOrCharacter),
    ));
    commands.entity(trigger_id).insert(TooltipControl {
        group: root_id,
        disabled: blocked,
    });
    commands.entity(root_id).insert(TooltipStoryState {
        model: model.clone(),
        state,
        stage: stage_id,
        trigger: trigger_id,
        content: content_id,
        arrow: arrow_id,
        theme,
        hovered: false,
        available_width,
        inline_size,
    });
}

#[cfg(target_arch = "wasm32")]
fn tooltip_stage_alignment(
    model: &TooltipModel,
    metrics: &rs_dean_ui::TooltipLayoutMetrics,
) -> (JustifyContent, AlignItems) {
    if !metrics.content_visible || model.disabled {
        return (JustifyContent::Center, AlignItems::Center);
    }
    match metrics.placement {
        TooltipPlacement::Top => (JustifyContent::Center, AlignItems::FlexEnd),
        TooltipPlacement::Right => (JustifyContent::FlexStart, AlignItems::Center),
        TooltipPlacement::Bottom => (JustifyContent::Center, AlignItems::FlexStart),
        TooltipPlacement::Left => (JustifyContent::FlexEnd, AlignItems::Center),
    }
}

#[cfg(target_arch = "wasm32")]
fn tooltip_content_offsets(metrics: &rs_dean_ui::TooltipLayoutMetrics) -> (Val, Val, Val, Val) {
    match metrics.placement {
        TooltipPlacement::Top => (
            px((metrics.trigger_width - metrics.content_width) / 2.0),
            auto(),
            auto(),
            px(metrics.trigger_height + metrics.placement_gap),
        ),
        TooltipPlacement::Right => (
            px(metrics.trigger_width + metrics.placement_gap),
            auto(),
            px((metrics.trigger_height - metrics.content_height) / 2.0),
            auto(),
        ),
        TooltipPlacement::Bottom => (
            px((metrics.trigger_width - metrics.content_width) / 2.0),
            auto(),
            px(metrics.trigger_height + metrics.placement_gap),
            auto(),
        ),
        TooltipPlacement::Left => (
            auto(),
            px(metrics.trigger_width + metrics.placement_gap),
            px((metrics.trigger_height - metrics.content_height) / 2.0),
            auto(),
        ),
    }
}

#[cfg(target_arch = "wasm32")]
fn tooltip_trigger_colors(
    model: &TooltipModel,
    state: &TooltipState,
    theme: &Theme,
    interaction: Interaction,
) -> (Color, Color, Color) {
    if model.loading || model.disabled {
        return (
            theme.surface_2().to_bevy(),
            theme.border_muted().to_bevy_css_alpha_on(theme.surface_1()),
            theme
                .text_disabled()
                .to_bevy_css_alpha_on(theme.surface_2()),
        );
    }
    if model.error.is_some() {
        return (
            theme.error_soft().to_bevy_css_alpha_on(theme.surface_1()),
            theme.danger().to_bevy(),
            theme.text_1().to_bevy(),
        );
    }
    if state.is_open() {
        return (
            if interaction == Interaction::None {
                theme.primary_soft()
            } else {
                theme.selected_tint()
            }
            .to_bevy_css_alpha_on(theme.surface_1()),
            theme.brand().to_bevy(),
            theme.text_1().to_bevy(),
        );
    }
    (
        if interaction == Interaction::None {
            theme.surface_2().to_bevy()
        } else {
            theme.hover_tint().to_bevy_css_alpha_on(theme.surface_1())
        },
        theme
            .border_strong()
            .to_bevy_css_alpha_on(theme.surface_1()),
        theme.text_1().to_bevy(),
    )
}

#[cfg(target_arch = "wasm32")]
fn tooltip_content_colors(model: &TooltipModel, theme: &Theme) -> (Color, Color, Color) {
    if model.disabled {
        return (
            theme.surface_2().to_bevy(),
            theme.border_muted().to_bevy_css_alpha_on(theme.surface_1()),
            theme
                .text_disabled()
                .to_bevy_css_alpha_on(theme.surface_2()),
        );
    }
    if model.loading {
        return (
            theme.info_soft().to_bevy_css_alpha_on(theme.surface_1()),
            theme.info.to_bevy(),
            theme.text_1().to_bevy(),
        );
    }
    if model.error.is_some() {
        return (
            theme.error_soft().to_bevy_css_alpha_on(theme.surface_1()),
            theme.danger().to_bevy(),
            theme.danger().to_bevy(),
        );
    }
    (
        theme.surface_elevated().to_bevy(),
        theme
            .border_subtle()
            .to_bevy_css_alpha_on(theme.surface_1()),
        theme.text_1().to_bevy(),
    )
}

#[cfg(target_arch = "wasm32")]
fn spawn_progress_primitives(
    parent: &mut ChildSpawnerCommands,
    variant: &BevyUiStoryVariant,
    fonts: &StoryFonts,
    available_width: f32,
    inline_size: f32,
) {
    let UiStoryModel::Progress(model) = &variant.model else {
        return;
    };
    let theme = variant.theme_id.palette();
    let state = model.state();
    let nodes = progress_render_nodes(model, &state);
    let track = nodes
        .iter()
        .find(|node| node.part == ProgressPart::Track)
        .expect("invariant: progress has a track");
    let indicator = nodes
        .iter()
        .find(|node| node.part == ProgressPart::Indicator)
        .expect("invariant: progress has an indicator");
    let label = nodes
        .iter()
        .find(|node| node.part == ProgressPart::Label)
        .expect("invariant: progress has a label");
    let metrics = progress_layout_metrics(model, inline_size);
    let invalid = model.error.is_some();
    let dense_root = model.density == ProgressDensity::Dense && !invalid && !model.disabled;
    let border_width = theme.border.max(1.0);
    let mut standard_model = model.clone();
    standard_model.density = ProgressDensity::Standard;
    let standard_metrics = progress_layout_metrics(&standard_model, inline_size);
    let dense_row_stretch = if model.density == ProgressDensity::Dense {
        ((standard_metrics.intrinsic_outer_height(border_width)
            - metrics.intrinsic_outer_height(border_width))
            / 3.0)
            .max(0.0)
    } else {
        0.0
    };
    let grid_template_rows = if model.density == ProgressDensity::Dense {
        vec![
            RepeatedGridTrack::px(1, metrics.track_height + dense_row_stretch),
            RepeatedGridTrack::px(
                1,
                metrics.label_font_size * metrics.line_height + dense_row_stretch,
            ),
            RepeatedGridTrack::px(
                1,
                metrics.detail_font_size * metrics.line_height + dense_row_stretch,
            ),
        ]
    } else {
        Vec::new()
    };
    let (root_fill, root_border) = progress_root_colors(&theme, invalid, model.disabled);
    let root_id = parent
        .spawn((
            Button,
            Node {
                display: Display::Grid,
                width: percent(100),
                max_width: px(metrics.max_width),
                min_width: px(0.0),
                min_height: if model.density == ProgressDensity::Dense {
                    px(standard_metrics.intrinsic_outer_height(border_width))
                } else {
                    auto()
                },
                padding: UiRect::all(px(metrics.root_padding)),
                border: UiRect::all(px(border_width)),
                border_radius: BorderRadius::all(px(if dense_root {
                    theme.radius_field
                } else {
                    theme.radius_box
                })),
                align_items: AlignItems::Stretch,
                align_content: AlignContent::Stretch,
                row_gap: px(metrics.root_gap),
                grid_auto_rows: GridTrack::auto(),
                grid_template_rows,
                ..default()
            },
            BackgroundColor(root_fill),
            BorderColor::all(root_border),
            if model.disabled {
                BoxShadow::default()
            } else {
                bevy_shadow_1(&theme, inline_size)
            },
        ))
        .id();
    let mut commands = parent.commands();
    let track_id = commands
        .spawn((
            ChildOf(root_id),
            Node {
                display: if track.visible {
                    Display::Flex
                } else {
                    Display::None
                },
                width: percent(100),
                height: px(metrics.track_height),
                min_height: px(metrics.track_height),
                border_radius: BorderRadius::MAX,
                overflow: Overflow::clip(),
                ..default()
            },
            BackgroundColor(progress_track_color(
                &theme,
                model.loading,
                invalid,
                model.disabled,
            )),
        ))
        .id();
    let indicator_id = commands
        .spawn((
            ChildOf(track_id),
            Node {
                width: percent(f32::from(indicator.percent)),
                height: percent(100),
                min_height: px(metrics.track_height),
                border_radius: BorderRadius::MAX,
                ..default()
            },
            BackgroundColor(progress_indicator_color(
                &theme,
                model.loading,
                invalid,
                model.disabled,
                state.is_highlighted(),
            )),
            BoxShadow::default(),
        ))
        .id();
    let label_row_id = commands
        .spawn((
            ChildOf(root_id),
            Node {
                width: percent(100),
                min_width: px(0.0),
                flex_direction: FlexDirection::Row,
                flex_wrap: FlexWrap::Wrap,
                justify_content: JustifyContent::SpaceBetween,
                align_items: AlignItems::FlexStart,
                row_gap: px(metrics.label_row_gap),
                column_gap: px(metrics.label_row_gap),
                ..default()
            },
        ))
        .id();
    let label_color = progress_resolve_tone(&theme, theme.text_1(), model.disabled);
    let value_color = progress_resolve_tone(&theme, theme.brand(), model.disabled);
    commands.spawn((
        ChildOf(label_row_id),
        Text::new(if model.loading {
            "Loading".to_owned()
        } else {
            label.label.clone()
        }),
        TextFont {
            font: fonts.inter.clone().into(),
            font_size: FontSize::Px(metrics.label_font_size),
            weight: FontWeight::BOLD,
            ..default()
        },
        LineHeight::RelativeToFont(metrics.line_height),
        TextColor(label_color),
        TextLayout::new(Justify::Left, LineBreak::NoWrap),
    ));
    commands.spawn((
        ChildOf(label_row_id),
        Text::new(indicator.value.clone()),
        TextFont {
            font: fonts.inter.clone().into(),
            font_size: FontSize::Px(metrics.value_font_size),
            weight: FontWeight::SEMIBOLD,
            ..default()
        },
        LineHeight::RelativeToFont(metrics.line_height),
        TextColor(value_color),
        TextLayout::new(Justify::Right, LineBreak::NoWrap),
    ));
    let detail_tone = if invalid {
        theme.danger()
    } else if model.disabled {
        theme.text_disabled()
    } else {
        theme.text_2()
    };
    let detail_color = progress_resolve_tone(&theme, detail_tone, model.disabled);
    let detail_line_break = if metrics.detail_fits_inline(
        &label.detail,
        available_width.min(metrics.max_width),
        border_width,
    ) {
        LineBreak::NoWrap
    } else {
        LineBreak::WordOrCharacter
    };
    commands.spawn((
        ChildOf(root_id),
        Text::new(label.detail.clone()),
        TextFont {
            font: fonts.inter.clone().into(),
            font_size: FontSize::Px(metrics.detail_font_size),
            weight: if invalid {
                FontWeight::SEMIBOLD
            } else {
                FontWeight::NORMAL
            },
            ..default()
        },
        LineHeight::RelativeToFont(metrics.line_height),
        TextColor(detail_color),
        TextLayout::new(Justify::Left, detail_line_break),
    ));
    commands.entity(root_id).insert(ProgressGroup {
        state,
        indicator: indicator_id,
        theme,
        inline_size,
        loading: model.loading,
        invalid,
        disabled: model.disabled,
    });
}

#[cfg(target_arch = "wasm32")]
fn progress_root_colors(theme: &Theme, invalid: bool, disabled: bool) -> (Color, Color) {
    if disabled {
        return (
            theme.surface_2().to_bevy(),
            theme.border_muted().to_bevy_on(theme.surface_2()),
        );
    }
    if invalid {
        return (
            theme.error_soft().to_bevy_on(theme.surface_1()),
            theme.danger().to_bevy(),
        );
    }
    (
        theme.surface_1().to_bevy(),
        theme.border_subtle().to_bevy_on(theme.surface_1()),
    )
}

#[cfg(target_arch = "wasm32")]
fn progress_track_color(theme: &Theme, loading: bool, invalid: bool, disabled: bool) -> Color {
    if disabled {
        theme
            .border_muted()
            .with_opacity(scale::opacity::DISABLED)
            .to_bevy_on(theme.surface_1())
    } else if invalid {
        theme.error_soft().to_bevy_on(theme.surface_1())
    } else if loading {
        theme.info_soft().to_bevy_on(theme.surface_1())
    } else {
        theme.surface_3().to_bevy()
    }
}

#[cfg(target_arch = "wasm32")]
fn progress_indicator_color(
    theme: &Theme,
    loading: bool,
    invalid: bool,
    disabled: bool,
    highlighted: bool,
) -> Color {
    if disabled {
        theme
            .surface_3()
            .with_opacity(scale::opacity::DISABLED)
            .to_bevy_on(theme.surface_1())
    } else if invalid {
        theme.danger().to_bevy()
    } else if loading {
        theme.info.to_bevy()
    } else if highlighted {
        theme.selected_tint().to_bevy_on(theme.surface_3())
    } else {
        theme.brand().to_bevy()
    }
}

#[cfg(target_arch = "wasm32")]
fn progress_resolve_tone(theme: &Theme, tone: Tone, disabled: bool) -> Color {
    if disabled {
        tone.with_opacity(scale::opacity::DISABLED)
            .to_bevy_on(theme.surface_1())
    } else {
        tone.to_bevy()
    }
}

#[cfg(target_arch = "wasm32")]
fn spawn_slider_primitives(
    parent: &mut ChildSpawnerCommands,
    variant: &BevyUiStoryVariant,
    fonts: &StoryFonts,
    available_width: f32,
    inline_size: f32,
) {
    let theme = variant.theme_id.palette();
    let UiStoryModel::Slider(model) = &variant.model else {
        return;
    };
    let state = model.state();
    let metrics = slider_layout_metrics(model, available_width, inline_size);
    let invalid = model.error.is_some();
    let blocked = model.loading || model.disabled;
    let vertical = model.orientation == SliderOrientation::Vertical && !invalid && !blocked;
    let border_width = theme.border.max(1.0);
    let root_tone = if model.disabled {
        theme.surface_2()
    } else if invalid {
        theme.error_soft()
    } else {
        theme.surface_1()
    };
    let root_fill = if model.disabled {
        root_tone
            .with_opacity(scale::opacity::DISABLED)
            .to_bevy_on(theme.surface_1())
    } else {
        root_tone.to_bevy_on(theme.surface_1())
    };
    let root_border = if model.disabled {
        theme
            .border_muted()
            .with_opacity(scale::opacity::DISABLED)
            .to_bevy_on(theme.surface_1())
    } else if invalid {
        theme.danger().to_bevy()
    } else {
        theme.border_subtle().to_bevy_on(theme.surface_1())
    };
    let root_id = parent
        .spawn((
            Node {
                display: Display::Grid,
                width: px(metrics.width),
                max_width: px(scale::container::CONTROL),
                min_width: px(0.0),
                padding: UiRect::all(px(metrics.root_padding)),
                border: UiRect::all(px(border_width)),
                border_radius: BorderRadius::all(px(
                    if slider_uses_dense_root_metrics(
                        model.density == rs_dean_ui::SliderDensity::Dense,
                        model.orientation == SliderOrientation::Vertical,
                        invalid,
                        model.disabled,
                    ) {
                        theme.radius_field
                    } else {
                        theme.radius_box
                    },
                )),
                row_gap: px(metrics.root_gap),
                ..default()
            },
            BackgroundColor(root_fill),
            BorderColor::all(root_border),
            if model.disabled {
                BoxShadow::default()
            } else {
                bevy_shadow_1(&theme, inline_size)
            },
        ))
        .id();
    let mut track_id = Entity::PLACEHOLDER;
    let mut range_id = Entity::PLACEHOLDER;
    let mut thumb_id = Entity::PLACEHOLDER;
    let mut value_id = Entity::PLACEHOLDER;
    parent.commands().entity(root_id).with_children(|slider| {
        slider
            .spawn(Node {
                width: percent(100),
                min_width: px(0.0),
                flex_direction: FlexDirection::Row,
                justify_content: JustifyContent::SpaceBetween,
                align_items: AlignItems::Center,
                column_gap: px(metrics.header_gap),
                ..default()
            })
            .with_children(|header| {
                header.spawn((
                    Node {
                        min_width: px(0.0),
                        flex_shrink: 0.0,
                        ..default()
                    },
                    Text::new(model.label.clone()),
                    TextFont {
                        font: fonts.inter.clone().into(),
                        font_size: FontSize::Px(metrics.label_font_size),
                        weight: FontWeight::BOLD,
                        ..default()
                    },
                    LineHeight::Px(metrics.label_font_size * metrics.label_line_height),
                    TextColor(if model.disabled {
                        theme
                            .text_1()
                            .with_opacity(scale::opacity::DISABLED)
                            .to_bevy_on(theme.surface_1())
                    } else {
                        theme.text_1().to_bevy_css_alpha_on(root_tone)
                    }),
                    TextLayout::new(Justify::Left, LineBreak::NoWrap),
                ));
                value_id = header
                    .spawn((
                        Node {
                            padding: UiRect::axes(
                                px(metrics.value_padding_inline),
                                px(metrics.value_padding_block),
                            ),
                            border: UiRect::all(px(border_width)),
                            border_radius: BorderRadius::MAX,
                            ..default()
                        },
                        BackgroundColor(if model.disabled {
                            root_fill
                        } else {
                            theme.surface_2().to_bevy()
                        }),
                        BorderColor::all(if model.disabled {
                            theme
                                .border_subtle()
                                .with_opacity(scale::opacity::DISABLED)
                                .to_bevy_on(theme.surface_1())
                        } else {
                            theme.border_subtle().to_bevy_on(theme.surface_2())
                        }),
                        Text::new(slider_value_label(state.value(), &model.unit)),
                        TextFont {
                            font: fonts.inter.clone().into(),
                            font_size: FontSize::Px(metrics.value_font_size),
                            weight: FontWeight::BOLD,
                            ..default()
                        },
                        LineHeight::Px(metrics.value_font_size * metrics.value_line_height),
                        TextColor(if model.disabled {
                            theme
                                .text_muted()
                                .with_opacity(scale::opacity::DISABLED)
                                .to_bevy_on(theme.surface_1())
                        } else {
                            theme.text_muted().to_bevy_css_alpha_on(theme.surface_2())
                        }),
                        TextLayout::new(Justify::Center, LineBreak::NoWrap),
                    ))
                    .id();
            });
        slider
            .spawn((
                Node {
                    position_type: PositionType::Relative,
                    display: Display::Grid,
                    width: if vertical {
                        px(metrics.track_wrap_width)
                    } else {
                        percent(100)
                    },
                    min_width: px(0.0),
                    min_height: px(metrics.track_wrap_min_height),
                    align_items: AlignItems::Center,
                    justify_items: if vertical {
                        JustifyItems::Center
                    } else {
                        JustifyItems::Stretch
                    },
                    ..default()
                },
                Button,
                SliderTrackControl {
                    group: root_id,
                    orientation: model.orientation,
                    disabled: blocked,
                },
            ))
            .with_children(|track_wrap| {
                track_id = track_wrap
                    .spawn((
                        Node {
                            width: if vertical {
                                px(metrics.track_width)
                            } else {
                                percent(100)
                            },
                            height: px(metrics.track_content_height(border_width, invalid)),
                            border: if invalid {
                                UiRect::all(px(border_width))
                            } else {
                                UiRect::ZERO
                            },
                            border_radius: BorderRadius::MAX,
                            overflow: Overflow::clip(),
                            flex_direction: FlexDirection::Column,
                            justify_content: if vertical {
                                JustifyContent::FlexEnd
                            } else {
                                JustifyContent::FlexStart
                            },
                            ..default()
                        },
                        BackgroundColor(slider_track_fill(model, &theme)),
                        BorderColor::all(if invalid {
                            theme.danger().to_bevy()
                        } else {
                            Color::NONE
                        }),
                    ))
                    .with_children(|track| {
                        range_id = track
                            .spawn((
                                Node {
                                    width: if vertical {
                                        percent(100)
                                    } else {
                                        percent(f32::from(state.percent()))
                                    },
                                    height: if vertical {
                                        percent(f32::from(state.percent()))
                                    } else {
                                        percent(100)
                                    },
                                    border_radius: BorderRadius::MAX,
                                    ..default()
                                },
                                BackgroundColor(slider_range_fill(model, &state, &theme)),
                            ))
                            .id();
                    })
                    .id();
                let thumb_size = metrics.thumb_size(state.is_focused(), blocked);
                let thumb_content_size =
                    metrics.thumb_content_size(state.is_focused(), blocked, border_width);
                thumb_id = track_wrap
                    .spawn((
                        Node {
                            position_type: PositionType::Absolute,
                            left: if vertical {
                                percent(50)
                            } else {
                                percent(f32::from(state.percent()))
                            },
                            top: if vertical {
                                percent(f32::from(100u8.saturating_sub(state.percent())))
                            } else {
                                percent(50)
                            },
                            width: px(thumb_content_size),
                            height: px(thumb_content_size),
                            margin: UiRect::new(
                                px(-thumb_size / 2.0),
                                px(0.0),
                                px(-thumb_size / 2.0),
                                px(0.0),
                            ),
                            border: UiRect::all(px(border_width)),
                            border_radius: BorderRadius::MAX,
                            ..default()
                        },
                        BackgroundColor(slider_thumb_fill(model, &state, &theme)),
                        BorderColor::all(slider_thumb_border(model, &theme)),
                        slider_thumb_shadow(model, &state, &theme, inline_size),
                    ))
                    .id();
            });
        slider.spawn((
            Node {
                width: percent(100),
                min_width: px(0.0),
                ..default()
            },
            Text::new(model.detail.clone()),
            TextFont {
                font: fonts.inter.clone().into(),
                font_size: FontSize::Px(metrics.detail_font_size),
                ..default()
            },
            LineHeight::Px(metrics.detail_font_size * metrics.detail_line_height),
            TextColor(if model.disabled {
                theme
                    .text_2()
                    .with_opacity(scale::opacity::DISABLED)
                    .to_bevy_on(theme.surface_1())
            } else {
                theme.text_2().to_bevy_css_alpha_on(root_tone)
            }),
            TextLayout::new(Justify::Left, LineBreak::WordOrCharacter),
        ));
        if let Some(error) = &model.error {
            slider.spawn((
                Node {
                    padding: UiRect::all(px(metrics.error_padding)),
                    border: UiRect::all(px(border_width)),
                    border_radius: BorderRadius::all(px(theme.radius_field)),
                    ..default()
                },
                BackgroundColor(theme.error_soft().to_bevy_on(root_tone)),
                BorderColor::all(theme.danger().to_bevy()),
                Text::new(error.clone()),
                TextFont {
                    font: fonts.inter.clone().into(),
                    font_size: FontSize::Px(metrics.error_font_size),
                    ..default()
                },
                LineHeight::Px(metrics.error_font_size * metrics.error_line_height),
                TextColor(theme.text_1().to_bevy_css_alpha_on(theme.error_soft())),
                TextLayout::new(Justify::Left, LineBreak::WordOrCharacter),
            ));
        }
    });
    parent.commands().entity(root_id).insert(SliderGroupState {
        model: model.clone(),
        state,
        track: track_id,
        range: range_id,
        thumb: thumb_id,
        value: value_id,
        theme,
        metrics,
        inline_size,
        invalid,
        blocked,
    });
}

#[cfg(target_arch = "wasm32")]
fn slider_track_fill(model: &SliderModel, theme: &Theme) -> Color {
    if model.disabled || model.loading {
        theme
            .surface_2()
            .with_opacity(scale::opacity::DISABLED)
            .to_bevy_on(theme.surface_1())
    } else if model.error.is_some() {
        theme.error_soft().to_bevy_on(theme.surface_1())
    } else {
        theme.surface_3().to_bevy()
    }
}

#[cfg(target_arch = "wasm32")]
fn slider_range_fill(model: &SliderModel, state: &SliderState, theme: &Theme) -> Color {
    if model.disabled {
        theme
            .border_muted()
            .with_opacity(scale::opacity::DISABLED * scale::opacity::DISABLED)
            .to_bevy_on(theme.surface_1())
    } else if model.loading {
        theme
            .border_muted()
            .with_opacity(scale::opacity::DISABLED)
            .to_bevy_on(theme.surface_1())
    } else if model.error.is_some() {
        theme.danger().to_bevy()
    } else if state.is_dragging() {
        theme.accent.to_bevy()
    } else {
        theme.brand().to_bevy()
    }
}

#[cfg(target_arch = "wasm32")]
fn slider_thumb_fill(model: &SliderModel, state: &SliderState, theme: &Theme) -> Color {
    if model.disabled {
        theme
            .surface_2()
            .with_opacity(scale::opacity::DISABLED * scale::opacity::DISABLED)
            .to_bevy_on(theme.surface_1())
    } else if model.loading {
        theme
            .surface_2()
            .with_opacity(scale::opacity::DISABLED)
            .to_bevy_on(theme.surface_1())
    } else if state.is_focused() {
        theme.primary_soft().to_bevy_on(theme.surface_1())
    } else {
        theme.surface_1().to_bevy()
    }
}

#[cfg(target_arch = "wasm32")]
fn slider_thumb_border(model: &SliderModel, theme: &Theme) -> Color {
    if model.disabled {
        theme
            .border_muted()
            .with_opacity(scale::opacity::DISABLED * scale::opacity::DISABLED)
            .to_bevy_on(theme.surface_1())
    } else if model.loading {
        theme
            .border_muted()
            .with_opacity(scale::opacity::DISABLED)
            .to_bevy_on(theme.surface_1())
    } else {
        theme.brand().to_bevy()
    }
}

#[cfg(target_arch = "wasm32")]
fn slider_thumb_shadow(
    model: &SliderModel,
    state: &SliderState,
    theme: &Theme,
    inline_size: f32,
) -> BoxShadow {
    if model.disabled || model.loading {
        BoxShadow::default()
    } else if state.is_focused() || model.density == rs_dean_ui::SliderDensity::Standard {
        bevy_shadow_2(theme, inline_size)
    } else {
        bevy_shadow_1(theme, inline_size)
    }
}

#[cfg(target_arch = "wasm32")]
fn spawn_resizable_primitives(
    parent: &mut ChildSpawnerCommands,
    variant: &BevyUiStoryVariant,
    fonts: &StoryFonts,
    inline_size: f32,
) {
    let theme = variant.theme_id.palette();
    let UiStoryModel::Resizable(model) = &variant.model else {
        return;
    };
    let state = model.state();
    let dense = model.density == ResizableDensity::Dense;
    let horizontal = model.orientation == ResizableOrientation::Horizontal;
    let metrics = resizable_layout_metrics(model, inline_size);
    let blocked = model.loading || model.disabled;
    let stretch_tracks = dense || blocked;
    let invalid = model.error.is_some();
    let (root_fill, root_border) = if model.disabled {
        (
            theme.surface_2().to_bevy(),
            theme.border_muted().to_bevy_on(theme.surface_2()),
        )
    } else if invalid {
        (
            theme.error_soft().to_bevy_on(theme.surface_1()),
            theme.danger().to_bevy(),
        )
    } else {
        (
            theme.surface_1().to_bevy(),
            theme.border_subtle().to_bevy_on(theme.surface_1()),
        )
    };
    let status_prefix = model.error.clone().unwrap_or_else(|| {
        format!(
            "{} panels, {}",
            model.panels.len(),
            model.orientation.label()
        )
    });
    let root_id = parent
        .spawn((
            Node {
                display: Display::Grid,
                width: percent(100),
                max_width: px(metrics.max_width),
                min_width: px(0.0),
                padding: UiRect::all(px(metrics.root_padding)),
                border: UiRect::all(px(theme.border.max(1.0))),
                border_radius: BorderRadius::all(px(if dense {
                    theme.radius_field
                } else {
                    theme.radius_box
                })),
                align_items: AlignItems::Stretch,
                row_gap: px(metrics.root_gap),
                grid_auto_rows: GridTrack::auto(),
                ..default()
            },
            BackgroundColor(root_fill),
            BorderColor::all(root_border),
            bevy_shadow_1(&theme, inline_size),
        ))
        .id();
    let mut commands = parent.commands();
    let header_id = commands
        .spawn((
            ChildOf(root_id),
            Node {
                width: percent(100),
                min_width: px(0.0),
                flex_grow: if stretch_tracks { 1.0 } else { 0.0 },
                flex_direction: FlexDirection::Row,
                flex_wrap: FlexWrap::Wrap,
                justify_content: JustifyContent::SpaceBetween,
                align_items: AlignItems::Center,
                row_gap: px(metrics.header_gap),
                column_gap: px(metrics.header_gap),
                ..default()
            },
        ))
        .id();
    commands.spawn((
        ChildOf(header_id),
        Text::new(model.label.clone()),
        TextFont {
            font: fonts.inter.clone().into(),
            font_size: FontSize::Px(metrics.title_font_size),
            weight: FontWeight::BOLD,
            ..default()
        },
        LineHeight::RelativeToFont(metrics.line_height),
        TextColor(if model.disabled {
            theme.text_disabled().to_bevy()
        } else {
            theme.text_1().to_bevy()
        }),
        TextLayout::new(Justify::Left, LineBreak::NoWrap),
    ));
    let status_copy = if invalid {
        status_prefix.clone()
    } else {
        format!(
            "{} ({})",
            status_prefix,
            resizable_sizes_label(state.panel_sizes())
        )
    };
    let status_id = commands
        .spawn((
            ChildOf(header_id),
            Text::new(status_copy),
            TextFont {
                font: fonts.inter.clone().into(),
                font_size: FontSize::Px(metrics.status_font_size),
                weight: FontWeight::SEMIBOLD,
                ..default()
            },
            LineHeight::RelativeToFont(metrics.line_height),
            TextColor(if model.disabled {
                theme.text_disabled().to_bevy()
            } else if invalid {
                theme.danger().to_bevy()
            } else {
                theme.text_muted().to_bevy()
            }),
            TextLayout::new(Justify::Right, LineBreak::WordOrCharacter),
        ))
        .id();
    let group_id = commands
        .spawn((
            ChildOf(root_id),
            Node {
                width: percent(100),
                min_width: px(0.0),
                min_height: px(metrics.group_min_height),
                flex_grow: if stretch_tracks { 1.0 } else { 0.0 },
                border: UiRect::all(px(theme.border.max(1.0))),
                border_radius: BorderRadius::all(px(theme.radius_field)),
                overflow: Overflow::clip(),
                flex_direction: if horizontal {
                    FlexDirection::Row
                } else {
                    FlexDirection::Column
                },
                ..default()
            },
            BackgroundColor(theme.surface_2().to_bevy()),
            BorderColor::all(theme.border_subtle().to_bevy_on(theme.surface_2())),
        ))
        .id();
    let mut panels = Vec::with_capacity(model.panels.len());
    let mut handles = Vec::with_capacity(model.panels.len().saturating_sub(1));
    for (index, panel) in model.panels.iter().enumerate() {
        let panel_disabled = blocked || panel.disabled;
        let active = state.is_active_panel(&panel.value);
        let emphasized_panel =
            resizable_panel_uses_emphasized_metrics(active, panel_disabled, invalid);
        let panel_padding = if emphasized_panel {
            metrics.emphasized_panel_padding
        } else {
            metrics.panel_padding
        };
        let panel_gap = if emphasized_panel {
            metrics.emphasized_panel_gap
        } else {
            metrics.panel_gap
        };
        let (panel_fill, panel_border) =
            resizable_panel_colors(&theme, active, invalid, panel_disabled);
        let panel_id = commands
            .spawn((
                ChildOf(group_id),
                Button,
                ResizablePanelTrigger {
                    group: root_id,
                    value: panel.value.clone(),
                    disabled: panel_disabled,
                },
                Node {
                    width: if horizontal { auto() } else { percent(100) },
                    min_width: px(0.0),
                    flex_basis: percent(f32::from(
                        state.panel_size(index).unwrap_or(panel.size_percent),
                    )),
                    flex_grow: 0.0,
                    flex_shrink: 1.0,
                    padding: UiRect::all(px(panel_padding)),
                    border: if active || invalid {
                        UiRect::all(px(theme.border.max(1.0)))
                    } else {
                        UiRect::ZERO
                    },
                    flex_direction: FlexDirection::Column,
                    align_items: AlignItems::Stretch,
                    row_gap: px(panel_gap),
                    ..default()
                },
                BackgroundColor(panel_fill),
                BorderColor::all(panel_border),
            ))
            .id();
        commands.spawn((
            ChildOf(panel_id),
            Text::new(panel.title.clone()),
            TextFont {
                font: fonts.inter.clone().into(),
                font_size: FontSize::Px(if panel_disabled {
                    metrics.disabled_panel_title_font_size
                } else {
                    metrics.panel_title_font_size
                }),
                weight: FontWeight::BOLD,
                ..default()
            },
            LineHeight::RelativeToFont(metrics.line_height),
            TextColor(if panel_disabled {
                theme.text_disabled().to_bevy()
            } else {
                theme.text_1().to_bevy()
            }),
            TextLayout::new(Justify::Left, LineBreak::WordOrCharacter),
        ));
        commands.spawn((
            ChildOf(panel_id),
            Text::new(panel.detail.clone()),
            TextFont {
                font: fonts.inter.clone().into(),
                font_size: FontSize::Px(metrics.detail_font_size),
                weight: if invalid {
                    FontWeight::SEMIBOLD
                } else {
                    FontWeight::NORMAL
                },
                ..default()
            },
            LineHeight::RelativeToFont(metrics.line_height),
            TextColor(if panel_disabled {
                theme.text_disabled().to_bevy()
            } else if invalid {
                theme.danger().to_bevy()
            } else {
                theme.text_2().to_bevy()
            }),
            TextLayout::new(Justify::Left, LineBreak::WordOrCharacter),
        ));
        let panel_percent = state.panel_size(index).unwrap_or(panel.size_percent);
        let meta_id = commands
            .spawn((
                ChildOf(panel_id),
                Text::new(format!("{panel_percent} of 100")),
                TextFont {
                    font: fonts.inter.clone().into(),
                    font_size: FontSize::Px(metrics.meta_font_size),
                    weight: FontWeight::SEMIBOLD,
                    ..default()
                },
                LineHeight::RelativeToFont(metrics.line_height),
                TextColor(if panel_disabled {
                    theme.text_disabled().to_bevy()
                } else {
                    theme.brand().to_bevy()
                }),
                TextLayout::new(Justify::Left, LineBreak::NoWrap),
            ))
            .id();
        panels.push(ResizablePanelEntities {
            value: panel.value.clone(),
            entity: panel_id,
            meta: meta_id,
            disabled: panel_disabled,
        });
        let Some(next_panel) = model.panels.get(index + 1) else {
            continue;
        };
        let handle_disabled = blocked || panel.disabled || next_panel.disabled;
        let resizing = state.is_resizing_handle(index);
        let emphasized_handle =
            resizable_handle_uses_emphasized_metrics(resizing, handle_disabled, invalid);
        let handle_margin_top = if emphasized_handle {
            metrics.emphasized_handle_margin_top
        } else {
            metrics.handle_margin_top
        };
        let handle_padding = if emphasized_handle {
            metrics.emphasized_handle_padding
        } else {
            metrics.handle_padding
        };
        let handle_gap = if emphasized_handle {
            metrics.emphasized_handle_gap
        } else {
            metrics.handle_gap
        };
        let (handle_fill, handle_border, handle_text) =
            resizable_handle_colors(&theme, resizing, invalid, handle_disabled);
        let handle_id = commands
            .spawn((
                ChildOf(panel_id),
                Button,
                ResizableHandleTrigger {
                    group: root_id,
                    index,
                    disabled: handle_disabled,
                },
                Node {
                    width: percent(100),
                    min_width: px(0.0),
                    margin: UiRect::top(px(handle_margin_top)),
                    padding: UiRect::all(px(handle_padding)),
                    border: UiRect::all(px(theme.border.max(1.0))),
                    border_radius: BorderRadius::all(px(theme.radius_field)),
                    flex_direction: FlexDirection::Column,
                    row_gap: px(handle_gap),
                    ..default()
                },
                BackgroundColor(handle_fill),
                BorderColor::all(handle_border),
            ))
            .id();
        let handle_label = format!(
            "Resize {} and {} ({}%)",
            panel.title, next_panel.title, panel_percent
        );
        let handle_label_id = commands
            .spawn((
                ChildOf(handle_id),
                Text::new(handle_label),
                TextFont {
                    font: fonts.inter.clone().into(),
                    font_size: FontSize::Px(metrics.detail_font_size),
                    weight: if resizing {
                        FontWeight::BOLD
                    } else {
                        FontWeight::SEMIBOLD
                    },
                    ..default()
                },
                LineHeight::RelativeToFont(metrics.line_height),
                TextColor(handle_text),
                TextLayout::new(Justify::Left, LineBreak::WordOrCharacter),
            ))
            .id();
        let range_id = commands
            .spawn((
                ChildOf(handle_id),
                Node {
                    width: percent(100),
                    height: px(metrics.range_control_height),
                    min_height: px(metrics.range_control_height),
                    align_items: AlignItems::Center,
                    ..default()
                },
            ))
            .id();
        let track_id = commands
            .spawn((
                ChildOf(range_id),
                Node {
                    width: percent(100),
                    height: px(metrics.range_track_height),
                    min_height: px(metrics.range_track_height),
                    border_radius: BorderRadius::MAX,
                    overflow: Overflow::clip(),
                    ..default()
                },
                BackgroundColor(theme.border_strong().to_bevy_on(theme.surface_2())),
            ))
            .id();
        let range_fill_id = commands
            .spawn((
                ChildOf(track_id),
                Node {
                    width: percent(f32::from(panel_percent)),
                    height: percent(100),
                    border_radius: BorderRadius::MAX,
                    ..default()
                },
                BackgroundColor(theme.brand().to_bevy()),
            ))
            .id();
        let range_thumb_id = commands
            .spawn((
                ChildOf(range_id),
                Node {
                    position_type: PositionType::Absolute,
                    left: percent(f32::from(panel_percent)),
                    top: percent(50.0),
                    width: px(metrics.range_thumb_size),
                    height: px(metrics.range_thumb_size),
                    margin: UiRect {
                        left: px(-metrics.range_thumb_size / 2.0),
                        top: px(-metrics.range_thumb_size / 2.0),
                        ..default()
                    },
                    border_radius: BorderRadius::MAX,
                    ..default()
                },
                BackgroundColor(theme.brand().to_bevy()),
            ))
            .id();
        handles.push(ResizableHandleEntities {
            index,
            entity: handle_id,
            label: handle_label_id,
            label_prefix: format!("Resize {} and {}", panel.title, next_panel.title),
            fill: range_fill_id,
            thumb: range_thumb_id,
            disabled: handle_disabled,
        });
    }
    commands.entity(root_id).insert(ResizableGroup {
        state,
        panels,
        handles,
        status: status_id,
        status_prefix,
        theme,
        blocked,
        invalid,
    });
}

#[cfg(target_arch = "wasm32")]
fn resizable_panel_colors(
    theme: &Theme,
    active: bool,
    invalid: bool,
    disabled: bool,
) -> (Color, Color) {
    if disabled {
        return (
            theme.surface_2().to_bevy(),
            theme.border_muted().to_bevy_on(theme.surface_2()),
        );
    }
    if invalid {
        return (
            theme.error_soft().to_bevy_on(theme.surface_1()),
            theme.danger().to_bevy(),
        );
    }
    if active {
        return (
            theme.primary_soft().to_bevy_on(theme.surface_2()),
            theme.brand().to_bevy(),
        );
    }
    (
        theme.surface_1().to_bevy(),
        theme.border_subtle().to_bevy_on(theme.surface_1()),
    )
}

#[cfg(target_arch = "wasm32")]
fn resizable_handle_colors(
    theme: &Theme,
    resizing: bool,
    invalid: bool,
    disabled: bool,
) -> (Color, Color, Color) {
    if disabled {
        return (
            theme.surface_3().to_bevy(),
            theme.border_muted().to_bevy_on(theme.surface_3()),
            theme.text_disabled().to_bevy(),
        );
    }
    if invalid {
        return (
            theme.error_soft().to_bevy_on(theme.surface_1()),
            theme.danger().to_bevy(),
            theme.danger().to_bevy(),
        );
    }
    if resizing {
        return (
            theme.primary_soft().to_bevy_on(theme.surface_1()),
            theme.brand().to_bevy(),
            theme.brand().to_bevy(),
        );
    }
    (
        theme.surface_2().to_bevy(),
        theme.border_subtle().to_bevy_on(theme.surface_2()),
        theme.text_muted().to_bevy(),
    )
}

#[cfg(target_arch = "wasm32")]
fn spawn_select_primitives(
    parent: &mut ChildSpawnerCommands,
    variant: &BevyUiStoryVariant,
    fonts: &StoryFonts,
    inline_size: f32,
) {
    let UiStoryModel::Select(model) = &variant.model else {
        return;
    };
    let theme = variant.theme_id.palette();
    let state = model.state();
    let dense = model.density == SelectDensity::Dense;
    let metrics = select_layout_metrics(model, inline_size);
    let trigger_metrics = select_trigger_layout_metrics(model, state.is_open(), inline_size);
    let border_width = theme.border.max(1.0);
    let blocked = model.loading || model.disabled;
    let invalid = model.error.is_some();
    let root_id = parent
        .spawn(Node {
            position_type: PositionType::Relative,
            width: percent(100),
            max_width: px(metrics.max_width),
            min_width: px(0.0),
            flex_direction: FlexDirection::Column,
            align_items: AlignItems::Stretch,
            row_gap: px(metrics.root_gap),
            ..default()
        })
        .id();
    let mut commands = parent.commands();
    let label_id = commands
        .spawn((
            ChildOf(root_id),
            Node {
                width: percent(100),
                min_width: px(0.0),
                flex_direction: FlexDirection::Row,
                align_items: AlignItems::Center,
                column_gap: px(scale::space::XS3),
                ..default()
            },
        ))
        .id();
    commands.spawn((
        ChildOf(label_id),
        Text::new(model.label.to_uppercase()),
        TextFont {
            font: fonts.inter.clone().into(),
            font_size: FontSize::Px(metrics.label_font_size),
            weight: FontWeight::BOLD,
            ..default()
        },
        LineHeight::RelativeToFont(metrics.line_height),
        LetterSpacing::Rem(metrics.label_tracking_em),
        TextColor(if model.disabled {
            theme.text_disabled().to_bevy()
        } else {
            theme.text_muted().to_bevy()
        }),
        TextLayout::new(Justify::Left, LineBreak::NoWrap),
    ));
    if model.required {
        commands.spawn((
            ChildOf(label_id),
            Text::new("*"),
            TextFont {
                font: fonts.inter.clone().into(),
                font_size: FontSize::Px(metrics.label_font_size),
                weight: FontWeight::BOLD,
                ..default()
            },
            LineHeight::RelativeToFont(metrics.line_height),
            TextColor(theme.danger().to_bevy()),
            TextLayout::new(Justify::Left, LineBreak::NoWrap),
        ));
    }
    let (trigger_fill, trigger_border, trigger_text) =
        select_trigger_colors(&theme, false, invalid, false, blocked);
    let trigger_id = commands
        .spawn((
            ChildOf(root_id),
            Button,
            Node {
                width: percent(100),
                min_width: px(0.0),
                min_height: px(trigger_metrics.trigger_min_height),
                padding: UiRect::axes(
                    px(trigger_metrics.trigger_padding_inline),
                    px(trigger_metrics.trigger_padding_block),
                ),
                border: UiRect::all(px(border_width)),
                border_radius: BorderRadius::all(px(theme.radius_field)),
                justify_content: JustifyContent::SpaceBetween,
                align_items: AlignItems::Center,
                column_gap: px(trigger_metrics.trigger_gap),
                ..default()
            },
            BackgroundColor(trigger_fill),
            BorderColor::all(trigger_border),
            bevy_shadow_1(&theme, inline_size),
        ))
        .id();
    let value_id = commands
        .spawn((
            ChildOf(trigger_id),
            Node {
                min_width: px(0.0),
                flex_grow: 1.0,
                ..default()
            },
            Text::new(selected_select_label(model, &state)),
            TextFont {
                font: fonts.inter.clone().into(),
                font_size: FontSize::Px(trigger_metrics.trigger_font_size),
                weight: if state.is_open() || invalid {
                    FontWeight::BOLD
                } else {
                    FontWeight::SEMIBOLD
                },
                ..default()
            },
            LineHeight::RelativeToFont(trigger_metrics.line_height),
            TextColor(trigger_text),
            TextLayout::new(Justify::Left, LineBreak::NoWrap),
        ))
        .id();
    commands.spawn((
        ChildOf(trigger_id),
        Text::new("v"),
        TextFont {
            font: fonts.inter.clone().into(),
            font_size: FontSize::Px(trigger_metrics.chevron_font_size),
            weight: FontWeight::BOLD,
            ..default()
        },
        LineHeight::RelativeToFont(trigger_metrics.line_height),
        TextColor(if blocked {
            theme.text_disabled().to_bevy()
        } else {
            theme.text_muted().to_bevy()
        }),
        TextLayout::new(Justify::Center, LineBreak::NoWrap),
    ));
    let content_top = trigger_metrics.content_offset(border_width)
        + if invalid {
            metrics.root_gap + metrics.error_font_size * metrics.line_height
        } else {
            0.0
        };
    let content_id = commands
        .spawn((
            ChildOf(root_id),
            Node {
                display: Display::None,
                position_type: PositionType::Absolute,
                top: px(content_top),
                left: px(0.0),
                right: px(0.0),
                width: percent(100),
                min_width: px(0.0),
                padding: UiRect::all(px(metrics.content_padding)),
                border: UiRect::all(px(border_width)),
                border_radius: BorderRadius::all(px(if dense {
                    theme.radius_field
                } else {
                    theme.radius_box
                })),
                flex_direction: FlexDirection::Column,
                align_items: AlignItems::Stretch,
                row_gap: px(metrics.content_gap),
                ..default()
            },
            BackgroundColor(theme.surface_elevated().to_bevy()),
            BorderColor::all(theme.border_subtle().to_bevy_on(theme.surface_elevated())),
            if dense {
                bevy_shadow_2(&theme, inline_size)
            } else {
                bevy_shadow_3(&theme, inline_size)
            },
            GlobalZIndex(50),
        ))
        .id();
    let mut options = Vec::new();
    for (group_index, group) in model.groups.iter().enumerate() {
        let group_disabled = blocked || group.disabled;
        let group_id = commands
            .spawn((
                ChildOf(content_id),
                Node {
                    width: percent(100),
                    min_width: px(0.0),
                    padding: if group_index == 0 {
                        UiRect::ZERO
                    } else {
                        UiRect::top(px(metrics.group_padding_top))
                    },
                    border: if group_index == 0 {
                        UiRect::ZERO
                    } else {
                        UiRect::top(px(border_width))
                    },
                    flex_direction: FlexDirection::Column,
                    align_items: AlignItems::Stretch,
                    row_gap: px(metrics.group_gap),
                    ..default()
                },
                BorderColor::all(theme.border_subtle().to_bevy_on(theme.surface_elevated())),
            ))
            .id();
        commands.spawn((
            ChildOf(group_id),
            Text::new(group.label.to_uppercase()),
            TextFont {
                font: fonts.inter.clone().into(),
                font_size: FontSize::Px(metrics.label_font_size),
                weight: FontWeight::BOLD,
                ..default()
            },
            LineHeight::RelativeToFont(metrics.line_height),
            LetterSpacing::Rem(metrics.label_tracking_em),
            TextColor(if group_disabled {
                theme.text_disabled().to_bevy()
            } else {
                theme.text_muted().to_bevy()
            }),
            TextLayout::new(Justify::Left, LineBreak::NoWrap),
        ));
        for option in &group.options {
            let option_disabled = group_disabled || option.disabled;
            let selected = state.is_selected(&option.value);
            let focused = state.is_focused(&option.value);
            let emphasized =
                select_item_uses_emphasized_metrics(selected, focused, option_disabled);
            let (fill, border, title, detail) =
                select_option_colors(&theme, selected, focused, false, option_disabled);
            let option_id = commands
                .spawn((
                    ChildOf(group_id),
                    Button,
                    Node {
                        width: percent(100),
                        min_width: px(0.0),
                        padding: UiRect::all(px(if emphasized {
                            metrics.emphasized_item_padding
                        } else {
                            metrics.item_padding
                        })),
                        border: UiRect::all(px(border_width)),
                        border_radius: BorderRadius::all(px(theme.radius_field)),
                        flex_direction: FlexDirection::Column,
                        align_items: AlignItems::Stretch,
                        row_gap: px(metrics.item_gap),
                        ..default()
                    },
                    BackgroundColor(fill),
                    BorderColor::all(border),
                    if selected || focused {
                        bevy_shadow_1(&theme, inline_size)
                    } else {
                        BoxShadow::default()
                    },
                ))
                .id();
            commands.spawn((
                ChildOf(option_id),
                Text::new(option.label.clone()),
                TextFont {
                    font: fonts.inter.clone().into(),
                    font_size: FontSize::Px(if option_disabled {
                        metrics.disabled_item_title_font_size
                    } else {
                        metrics.item_title_font_size
                    }),
                    weight: FontWeight::BOLD,
                    ..default()
                },
                LineHeight::RelativeToFont(metrics.line_height),
                TextColor(title),
                TextLayout::new(Justify::Left, LineBreak::NoWrap),
            ));
            commands.spawn((
                ChildOf(option_id),
                Text::new(option.detail.clone()),
                TextFont {
                    font: fonts.inter.clone().into(),
                    font_size: FontSize::Px(metrics.item_detail_font_size),
                    weight: FontWeight::NORMAL,
                    ..default()
                },
                LineHeight::RelativeToFont(metrics.line_height),
                TextColor(detail),
                TextLayout::new(Justify::Left, LineBreak::WordOrCharacter),
            ));
            commands.entity(option_id).insert(SelectOptionTrigger {
                group: root_id,
                value: option.value.clone(),
                disabled: option_disabled,
            });
            options.push(SelectOptionEntities {
                value: option.value.clone(),
                entity: option_id,
                disabled: option_disabled,
            });
        }
    }
    if let Some(error) = &model.error {
        commands.spawn((
            ChildOf(root_id),
            Node {
                width: percent(100),
                min_width: px(0.0),
                ..default()
            },
            Text::new(error.clone()),
            TextFont {
                font: fonts.inter.clone().into(),
                font_size: FontSize::Px(metrics.error_font_size),
                weight: FontWeight::SEMIBOLD,
                ..default()
            },
            LineHeight::RelativeToFont(metrics.line_height),
            TextColor(theme.danger().to_bevy()),
            TextLayout::new(Justify::Left, LineBreak::WordOrCharacter),
        ));
    }
    commands
        .entity(trigger_id)
        .insert(SelectTrigger { group: root_id });
    commands.entity(root_id).insert(SelectGroupState {
        state,
        model: model.clone(),
        trigger: trigger_id,
        value: value_id,
        content: content_id,
        options,
        metrics,
        inline_size,
        theme,
        hovered_trigger: false,
        hovered_value: None,
        blocked,
        invalid,
    });
}

#[cfg(target_arch = "wasm32")]
fn select_trigger_colors(
    theme: &Theme,
    open: bool,
    invalid: bool,
    hovered: bool,
    disabled: bool,
) -> (Color, Color, Color) {
    if disabled {
        return (
            theme.surface_2().to_bevy(),
            theme.border_muted().to_bevy_on(theme.surface_2()),
            theme.text_disabled().to_bevy(),
        );
    }
    if invalid {
        return (
            theme.error_soft().to_bevy_on(theme.surface_1()),
            theme.danger().to_bevy(),
            theme.text_1().to_bevy(),
        );
    }
    if open {
        return (
            theme.primary_soft().to_bevy_on(theme.surface_1()),
            theme.brand().to_bevy(),
            theme.text_1().to_bevy(),
        );
    }
    if hovered {
        return (
            theme.hover_tint().to_bevy_on(theme.surface_1()),
            theme.border_strong().to_bevy_on(theme.surface_1()),
            theme.text_1().to_bevy(),
        );
    }
    (
        theme.surface_1().to_bevy(),
        theme.border_strong().to_bevy_on(theme.surface_1()),
        theme.text_1().to_bevy(),
    )
}

#[cfg(target_arch = "wasm32")]
fn select_option_colors(
    theme: &Theme,
    selected: bool,
    focused: bool,
    hovered: bool,
    disabled: bool,
) -> (Color, Color, Color, Color) {
    if disabled {
        return (
            theme.surface_2().to_bevy(),
            theme.border_muted().to_bevy_on(theme.surface_2()),
            theme.text_disabled().to_bevy(),
            theme.text_disabled().to_bevy(),
        );
    }
    let fill = if selected {
        theme.primary_soft().to_bevy_on(theme.surface_1())
    } else if hovered && !focused {
        theme.hover_tint().to_bevy_on(theme.surface_1())
    } else {
        theme.surface_1().to_bevy()
    };
    let border = if selected || focused {
        theme.brand().to_bevy()
    } else {
        theme.border_subtle().to_bevy_on(theme.surface_1())
    };
    (
        fill,
        border,
        theme.text_1().to_bevy(),
        theme.text_2().to_bevy(),
    )
}

#[cfg(target_arch = "wasm32")]
fn spawn_sidebar_primitives(
    parent: &mut ChildSpawnerCommands,
    variant: &BevyUiStoryVariant,
    fonts: &StoryFonts,
    inline_size: f32,
) {
    let UiStoryModel::Sidebar(model) = &variant.model else {
        return;
    };
    let theme = variant.theme_id.palette();
    let state = model.state();
    let dense = model.density == SidebarDensity::Dense;
    let metrics = sidebar_layout_metrics(model, inline_size);
    let border_width = theme.border.max(1.0);
    let blocked = model.loading || model.disabled;
    let invalid = model.error.is_some();
    let root_fill = if model.disabled {
        theme.surface_2().to_bevy()
    } else if invalid {
        theme.error_soft().to_bevy_on(theme.surface_1())
    } else {
        theme.surface_1().to_bevy()
    };
    let root_border = if invalid {
        theme.danger().to_bevy()
    } else if model.disabled {
        theme.border_muted().to_bevy_on(theme.surface_2())
    } else {
        theme.border_subtle().to_bevy_on(theme.surface_1())
    };
    let root_id = parent
        .spawn((
            Node {
                width: if state.is_collapsed() {
                    px(metrics.rail_width)
                } else {
                    percent(100)
                },
                max_width: px(metrics.max_width),
                min_width: px(0.0),
                justify_self: JustifySelf::Start,
                align_self: AlignSelf::Stretch,
                border: UiRect::all(px(border_width)),
                border_radius: BorderRadius::all(px(if dense {
                    theme.radius_field
                } else {
                    theme.radius_box
                })),
                flex_direction: FlexDirection::Row,
                align_items: AlignItems::Stretch,
                overflow: Overflow::clip(),
                ..default()
            },
            BackgroundColor(root_fill),
            BorderColor::all(root_border),
            bevy_shadow_1(&theme, inline_size),
        ))
        .id();
    let mut commands = parent.commands();

    let (rail_fill, rail_border, rail_text) =
        sidebar_rail_colors(&theme, state.is_collapsed(), blocked);
    let rail_interaction = sidebar_interactive_colors(rail_fill, state.is_collapsed(), &theme);
    let rail_content_width = (metrics.rail_width - border_width).max(0.0);
    let rail_id = commands
        .spawn((
            ChildOf(root_id),
            Button,
            Node {
                width: px(rail_content_width),
                min_width: px(rail_content_width),
                min_height: px(metrics.rail_min_height),
                border: UiRect::right(px(border_width)),
                justify_content: JustifyContent::Center,
                align_items: AlignItems::Center,
                ..default()
            },
            BackgroundColor(rail_fill),
            BorderColor::all(rail_border),
            Text::new("||"),
            TextFont {
                font: fonts.inter.clone().into(),
                font_size: FontSize::Px(metrics.rail_font_size),
                weight: FontWeight::BOLD,
                ..default()
            },
            LineHeight::RelativeToFont(scale::line_height::LH0),
            TextColor(rail_text),
            TextLayout::new(Justify::Center, LineBreak::NoWrap),
            rail_interaction,
        ))
        .id();

    let panel_id = commands
        .spawn((
            ChildOf(root_id),
            Node {
                display: if state.is_collapsed() {
                    Display::None
                } else {
                    Display::Flex
                },
                min_width: px(0.0),
                flex_grow: 1.0,
                padding: UiRect::all(px(metrics.panel_padding)),
                flex_direction: FlexDirection::Column,
                row_gap: px(metrics.panel_gap),
                justify_content: JustifyContent::SpaceBetween,
                ..default()
            },
        ))
        .id();

    let header_id = commands
        .spawn((
            ChildOf(panel_id),
            Node {
                width: percent(100),
                min_width: px(0.0),
                padding: UiRect::bottom(px(metrics.header_padding_bottom)),
                border: UiRect::bottom(px(border_width)),
                flex_direction: FlexDirection::Column,
                row_gap: px(metrics.header_gap),
                ..default()
            },
            BorderColor::all(theme.border_subtle().to_bevy_on(theme.surface_1())),
        ))
        .id();
    commands.spawn((
        ChildOf(header_id),
        Text::new(model.header_label.clone()),
        TextFont {
            font: fonts.inter.clone().into(),
            font_size: FontSize::Px(metrics.title_font_size),
            weight: FontWeight::BOLD,
            ..default()
        },
        LineHeight::RelativeToFont(metrics.title_line_height),
        TextColor(if blocked {
            theme.text_disabled().to_bevy()
        } else {
            theme.text_1().to_bevy()
        }),
        TextLayout::new(Justify::Left, LineBreak::NoWrap),
    ));
    commands.spawn((
        ChildOf(header_id),
        Text::new(model.header_detail.clone()),
        TextFont {
            font: fonts.inter.clone().into(),
            font_size: FontSize::Px(metrics.detail_font_size),
            weight: FontWeight::NORMAL,
            ..default()
        },
        LineHeight::RelativeToFont(metrics.detail_line_height),
        TextColor(if blocked {
            theme.text_disabled().to_bevy()
        } else {
            theme.text_muted().to_bevy()
        }),
        TextLayout::new(Justify::Left, LineBreak::WordOrCharacter),
    ));

    let content_id = commands
        .spawn((
            ChildOf(panel_id),
            Node {
                width: percent(100),
                min_width: px(0.0),
                flex_direction: FlexDirection::Column,
                row_gap: px(metrics.content_gap),
                ..default()
            },
        ))
        .id();
    let mut menus = Vec::new();
    for group in &model.groups {
        let group_disabled = blocked || group.disabled;
        let group_id = commands
            .spawn((
                ChildOf(content_id),
                Node {
                    width: percent(100),
                    min_width: px(0.0),
                    flex_direction: FlexDirection::Column,
                    row_gap: px(metrics.group_gap),
                    ..default()
                },
            ))
            .id();
        commands.spawn((
            ChildOf(group_id),
            Text::new(group.label.to_uppercase()),
            TextFont {
                font: fonts.inter.clone().into(),
                font_size: FontSize::Px(metrics.group_label_font_size),
                weight: FontWeight::BOLD,
                ..default()
            },
            LineHeight::RelativeToFont(metrics.group_label_line_height),
            LetterSpacing::Rem(metrics.group_label_tracking_em),
            TextColor(if group_disabled {
                theme.text_disabled().to_bevy()
            } else {
                theme.text_muted().to_bevy()
            }),
            TextLayout::new(Justify::Left, LineBreak::NoWrap),
        ));
        let items_id = commands
            .spawn((
                ChildOf(group_id),
                Node {
                    width: percent(100),
                    min_width: px(0.0),
                    flex_direction: FlexDirection::Column,
                    row_gap: px(metrics.menu_gap),
                    ..default()
                },
            ))
            .id();
        for item in &group.items {
            let disabled = group_disabled || item.disabled;
            let active = state.is_active(&item.value);
            let focused = state.is_focused(&item.value);
            let control_metrics = metrics.menu_control(active, focused, disabled);
            let (fill, border, text) = sidebar_menu_colors(&theme, active, focused, disabled);
            let interaction = sidebar_interactive_colors(fill, active, &theme);
            let control_id = commands
                .spawn((
                    ChildOf(items_id),
                    Button,
                    Node {
                        width: percent(100),
                        min_width: px(0.0),
                        min_height: px(control_metrics.content_min_height(border_width)),
                        padding: UiRect::axes(
                            px(control_metrics.padding_inline),
                            px(control_metrics.padding_block),
                        ),
                        border: UiRect::all(px(border_width)),
                        border_radius: BorderRadius::all(px(theme.radius_field)),
                        justify_content: JustifyContent::SpaceBetween,
                        align_items: AlignItems::Center,
                        column_gap: px(metrics.menu_content_gap),
                        ..default()
                    },
                    BackgroundColor(fill),
                    BorderColor::all(border),
                    interaction,
                ))
                .id();
            let label_id = commands
                .spawn((
                    ChildOf(control_id),
                    Node {
                        min_width: px(0.0),
                        flex_grow: 1.0,
                        ..default()
                    },
                    Text::new(item.label.clone()),
                    TextFont {
                        font: fonts.inter.clone().into(),
                        font_size: FontSize::Px(control_metrics.font_size),
                        weight: if active {
                            FontWeight::BOLD
                        } else if focused {
                            FontWeight::SEMIBOLD
                        } else {
                            FontWeight::NORMAL
                        },
                        ..default()
                    },
                    LineHeight::RelativeToFont(control_metrics.line_height),
                    TextColor(text),
                    TextLayout::new(Justify::Left, LineBreak::NoWrap),
                ))
                .id();
            if let Some(badge) = &item.badge {
                commands.spawn((
                    ChildOf(control_id),
                    Node {
                        padding: UiRect::axes(
                            px(metrics.badge_padding_inline),
                            px(metrics.badge_padding_block),
                        ),
                        border: UiRect::all(px(border_width)),
                        border_radius: BorderRadius::MAX,
                        justify_content: JustifyContent::Center,
                        align_items: AlignItems::Center,
                        ..default()
                    },
                    BackgroundColor(theme.surface_2().to_bevy()),
                    BorderColor::all(theme.border_subtle().to_bevy_on(theme.surface_2())),
                    Text::new(badge.clone()),
                    TextFont {
                        font: fonts.inter.clone().into(),
                        font_size: FontSize::Px(metrics.badge_font_size),
                        weight: FontWeight::BOLD,
                        ..default()
                    },
                    LineHeight::RelativeToFont(metrics.badge_line_height),
                    TextColor(if disabled {
                        theme.text_disabled().to_bevy()
                    } else {
                        theme.text_muted().to_bevy()
                    }),
                    TextLayout::new(Justify::Center, LineBreak::NoWrap),
                ));
            }
            commands.entity(control_id).insert(SidebarMenuTrigger {
                group: root_id,
                value: item.value.clone(),
                disabled,
            });
            menus.push(SidebarMenuEntities {
                value: item.value.clone(),
                control: control_id,
                label: label_id,
                disabled,
            });
        }
    }

    let footer_id = commands
        .spawn((
            ChildOf(panel_id),
            Node {
                width: percent(100),
                min_width: px(0.0),
                padding: UiRect::top(px(metrics.footer_padding_top)),
                border: UiRect::top(px(border_width)),
                flex_direction: FlexDirection::Column,
                row_gap: px(metrics.footer_gap),
                ..default()
            },
            BorderColor::all(theme.border_subtle().to_bevy_on(theme.surface_1())),
        ))
        .id();
    commands.spawn((
        ChildOf(footer_id),
        Text::new(model.footer_label.to_uppercase()),
        TextFont {
            font: fonts.inter.clone().into(),
            font_size: FontSize::Px(metrics.footer_label_font_size),
            weight: FontWeight::BOLD,
            ..default()
        },
        LineHeight::RelativeToFont(metrics.footer_line_height),
        LetterSpacing::Rem(metrics.group_label_tracking_em),
        TextColor(if blocked {
            theme.text_disabled().to_bevy()
        } else {
            theme.text_muted().to_bevy()
        }),
        TextLayout::new(Justify::Left, LineBreak::NoWrap),
    ));
    commands.spawn((
        ChildOf(footer_id),
        Text::new(model.footer_detail.clone()),
        TextFont {
            font: fonts.inter.clone().into(),
            font_size: FontSize::Px(metrics.footer_detail_font_size),
            weight: FontWeight::NORMAL,
            ..default()
        },
        LineHeight::RelativeToFont(metrics.footer_line_height),
        TextColor(if blocked {
            theme.text_disabled().to_bevy()
        } else {
            theme.text_2().to_bevy()
        }),
        TextLayout::new(Justify::Left, LineBreak::WordOrCharacter),
    ));
    if let Some(error) = &model.error {
        commands.spawn((
            ChildOf(panel_id),
            Node {
                width: percent(100),
                min_width: px(0.0),
                padding: UiRect::all(px(metrics.error_padding)),
                border: UiRect::all(px(border_width)),
                border_radius: BorderRadius::all(px(theme.radius_field)),
                ..default()
            },
            BackgroundColor(theme.error_soft().to_bevy_on(theme.surface_1())),
            BorderColor::all(theme.danger().to_bevy()),
            Text::new(error.clone()),
            TextFont {
                font: fonts.inter.clone().into(),
                font_size: FontSize::Px(metrics.error_font_size),
                weight: FontWeight::NORMAL,
                ..default()
            },
            LineHeight::RelativeToFont(metrics.error_line_height),
            TextColor(theme.text_1().to_bevy()),
            TextLayout::new(Justify::Left, LineBreak::WordOrCharacter),
        ));
    }

    commands
        .entity(rail_id)
        .insert(SidebarRailTrigger { group: root_id });
    commands.entity(root_id).insert(SidebarGroupState {
        state,
        panel: panel_id,
        rail: rail_id,
        menus,
        theme,
        metrics,
        blocked,
    });
}

#[cfg(target_arch = "wasm32")]
fn sidebar_rail_colors(theme: &Theme, collapsed: bool, disabled: bool) -> (Color, Color, Color) {
    if disabled {
        return (
            theme.surface_2().to_bevy(),
            theme.border_muted().to_bevy_on(theme.surface_2()),
            theme.text_disabled().to_bevy(),
        );
    }
    if collapsed {
        return (
            theme.primary_soft().to_bevy_on(theme.surface_1()),
            theme.brand().to_bevy(),
            theme.brand().to_bevy(),
        );
    }
    (
        theme.surface_2().to_bevy(),
        theme.border_subtle().to_bevy_on(theme.surface_2()),
        theme.text_muted().to_bevy(),
    )
}

#[cfg(target_arch = "wasm32")]
fn sidebar_menu_colors(
    theme: &Theme,
    active: bool,
    focused: bool,
    disabled: bool,
) -> (Color, Color, Color) {
    if disabled {
        return (
            theme.surface_2().to_bevy(),
            Color::NONE,
            theme.text_disabled().to_bevy(),
        );
    }
    if active {
        return (
            theme.primary_soft().to_bevy_on(theme.surface_1()),
            theme.brand().to_bevy(),
            theme.text_1().to_bevy(),
        );
    }
    if focused {
        return (
            theme.surface_1().to_bevy(),
            theme.brand().to_bevy(),
            theme.text_1().to_bevy(),
        );
    }
    (
        theme.surface_1().to_bevy(),
        Color::NONE,
        theme.text_1().to_bevy(),
    )
}

#[cfg(target_arch = "wasm32")]
fn sidebar_interactive_colors(rest: Color, latched: bool, theme: &Theme) -> InteractivePrimitive {
    let mut colors = InteractivePrimitive::stateful(
        rest,
        theme.primary_soft().to_bevy_on(theme.surface_1()),
        latched,
        theme,
    );
    if latched {
        colors.hover = rest;
        colors.pressed = rest;
    }
    colors
}

#[cfg(target_arch = "wasm32")]
fn spawn_scroll_area_primitives(
    parent: &mut ChildSpawnerCommands,
    variant: &BevyUiStoryVariant,
    fonts: &StoryFonts,
    inline_size: f32,
) {
    let theme = variant.theme_id.palette();
    let UiStoryModel::ScrollArea(model) = &variant.model else {
        return;
    };
    let state = model.state();
    let nodes = scroll_area_render_nodes(model, &state);
    let root = nodes
        .iter()
        .find(|node| node.part == ScrollAreaPart::Root)
        .expect("invariant: scroll area render nodes include a root");
    let metrics = scroll_area_layout_metrics(model, inline_size);
    let invalid = model.error.is_some();
    let blocked = model.loading || model.disabled;
    let dense_root = model.density == ScrollAreaDensity::Dense && !invalid && !model.disabled;
    let root_opacity = if model.disabled {
        scale::opacity::DISABLED
    } else {
        1.0
    };
    let viewport_opacity = root_opacity
        * if blocked {
            scale::opacity::DISABLED
        } else {
            1.0
        };
    let backdrop = story_backdrop_tone();
    let root_fill_tone = if model.disabled {
        theme.surface_2()
    } else if invalid {
        theme.error_soft()
    } else {
        theme.surface_1()
    };
    let root_border_tone = if model.disabled {
        theme.border_muted()
    } else if invalid {
        theme.danger()
    } else {
        theme.border_subtle()
    };
    let root_id = parent
        .spawn((
            Node {
                display: Display::Grid,
                width: percent(100),
                max_width: px(metrics.max_width),
                min_width: px(0.0),
                padding: UiRect::all(px(metrics.root_padding)),
                border: UiRect::all(px(theme.border.max(1.0))),
                border_radius: BorderRadius::all(px(if dense_root {
                    theme.radius_field
                } else {
                    theme.radius_box
                })),
                align_items: AlignItems::Stretch,
                row_gap: px(metrics.root_gap),
                grid_auto_rows: GridTrack::auto(),
                ..default()
            },
            BackgroundColor(scroll_area_resolve_tone(
                root_fill_tone,
                root_opacity,
                theme.surface_1(),
                backdrop,
            )),
            BorderColor::all(scroll_area_resolve_tone(
                root_border_tone,
                root_opacity,
                theme.surface_1(),
                backdrop,
            )),
            if model.disabled {
                BoxShadow::default()
            } else {
                bevy_shadow_1(&theme, inline_size)
            },
        ))
        .id();
    let mut commands = parent.commands();
    let header_id = commands
        .spawn((
            ChildOf(root_id),
            Node {
                width: percent(100),
                min_width: px(0.0),
                flex_direction: FlexDirection::Row,
                flex_wrap: FlexWrap::Wrap,
                justify_content: JustifyContent::SpaceBetween,
                align_items: AlignItems::Center,
                row_gap: px(metrics.header_gap),
                column_gap: px(metrics.header_gap),
                ..default()
            },
        ))
        .id();
    commands.spawn((
        ChildOf(header_id),
        Text::new(root.label.clone()),
        TextFont {
            font: fonts.inter.clone().into(),
            font_size: FontSize::Px(metrics.title_font_size),
            weight: FontWeight::BOLD,
            ..default()
        },
        LineHeight::RelativeToFont(metrics.line_height),
        TextColor(scroll_area_resolve_tone(
            if model.disabled {
                theme.text_disabled()
            } else {
                theme.text_1()
            },
            root_opacity,
            theme.surface_1(),
            backdrop,
        )),
        TextLayout::new(Justify::Left, LineBreak::NoWrap),
    ));
    commands.spawn((
        ChildOf(header_id),
        Text::new(root.detail.clone()),
        TextFont {
            font: fonts.inter.clone().into(),
            font_size: FontSize::Px(metrics.status_font_size),
            weight: FontWeight::SEMIBOLD,
            ..default()
        },
        LineHeight::RelativeToFont(metrics.line_height),
        TextColor(scroll_area_resolve_tone(
            if model.disabled {
                theme.text_disabled()
            } else if invalid {
                theme.danger()
            } else {
                theme.text_muted()
            },
            root_opacity,
            theme.surface_1(),
            backdrop,
        )),
        TextLayout::new(Justify::Right, LineBreak::NoWrap),
    ));
    let frame_id = commands
        .spawn((
            ChildOf(root_id),
            Node {
                display: Display::Grid,
                width: percent(100),
                min_width: px(0.0),
                padding: UiRect::all(px(metrics.frame_padding)),
                border: UiRect::all(px(theme.border.max(1.0))),
                border_radius: BorderRadius::all(px(theme.radius_field)),
                align_items: AlignItems::Stretch,
                row_gap: px(metrics.frame_gap),
                grid_auto_rows: GridTrack::auto(),
                ..default()
            },
            BackgroundColor(scroll_area_resolve_tone(
                theme.surface_2(),
                root_opacity,
                theme.surface_1(),
                backdrop,
            )),
            BorderColor::all(scroll_area_resolve_tone(
                theme.border_subtle(),
                root_opacity,
                theme.surface_2(),
                backdrop,
            )),
        ))
        .id();
    let viewport_fill_tone = if blocked {
        theme.surface_2()
    } else if invalid {
        theme.error_soft()
    } else {
        theme.surface_1()
    };
    let viewport_border_tone = if blocked {
        theme.border_muted()
    } else if invalid {
        theme.danger()
    } else {
        theme.border_subtle()
    };
    let viewport_id = commands
        .spawn((
            ChildOf(frame_id),
            Button,
            ScrollAreaViewportControl {
                group: root_id,
                overflow: model.overflow,
                disabled: blocked,
            },
            Node {
                width: percent(100),
                min_width: px(0.0),
                height: px(metrics.viewport_max_height),
                max_height: px(metrics.viewport_max_height),
                padding: UiRect::all(px(metrics.viewport_padding)),
                border: if invalid || blocked {
                    UiRect::all(px(theme.border.max(1.0)))
                } else {
                    UiRect::ZERO
                },
                border_radius: BorderRadius::all(px(theme.radius_field)),
                overflow: Overflow::scroll(),
                flex_direction: FlexDirection::Column,
                align_items: AlignItems::Stretch,
                ..default()
            },
            BackgroundColor(scroll_area_resolve_tone(
                viewport_fill_tone,
                viewport_opacity,
                theme.surface_2(),
                backdrop,
            )),
            BorderColor::all(scroll_area_resolve_tone(
                viewport_border_tone,
                viewport_opacity,
                viewport_fill_tone,
                backdrop,
            )),
            BoxShadow::default(),
            ScrollPosition::default(),
        ))
        .id();
    let content_id = commands
        .spawn((
            ChildOf(viewport_id),
            Node {
                width: percent(100),
                min_width: px(0.0),
                flex_direction: FlexDirection::Column,
                align_items: AlignItems::Stretch,
                row_gap: px(metrics.content_gap),
                ..default()
            },
        ))
        .id();
    let mut items = Vec::with_capacity(model.items.len());
    for item in nodes
        .iter()
        .filter(|node| node.part == ScrollAreaPart::Content)
    {
        let emphasized =
            scroll_area_item_uses_emphasized_metrics(item.active, item.disabled, invalid);
        let item_opacity = viewport_opacity
            * if item.disabled {
                scale::opacity::DISABLED
            } else {
                1.0
            };
        let (item_fill, item_border) = scroll_area_item_colors(
            &theme,
            item.active,
            item.disabled,
            invalid,
            item_opacity,
            Interaction::None,
            theme.surface_1(),
            backdrop,
        );
        let item_id = commands
            .spawn((
                ChildOf(content_id),
                Button,
                ScrollAreaItemVisual,
                ScrollAreaItemControl {
                    group: root_id,
                    value: item.value.clone(),
                    disabled: item.disabled,
                },
                Node {
                    width: percent(100),
                    min_width: px(0.0),
                    padding: UiRect::all(px(if emphasized {
                        metrics.emphasized_item_padding
                    } else {
                        metrics.item_padding
                    })),
                    border: UiRect::all(px(theme.border.max(1.0))),
                    border_radius: BorderRadius::all(px(theme.radius_field)),
                    flex_direction: FlexDirection::Column,
                    align_items: AlignItems::Stretch,
                    row_gap: px(if emphasized {
                        metrics.emphasized_item_gap
                    } else {
                        metrics.item_gap
                    }),
                    ..default()
                },
                BackgroundColor(item_fill),
                BorderColor::all(item_border),
                if !item.disabled && item.active {
                    bevy_shadow_1(&theme, inline_size)
                } else {
                    BoxShadow::default()
                },
            ))
            .id();
        commands.spawn((
            ChildOf(item_id),
            Text::new(item.label.clone()),
            TextFont {
                font: fonts.inter.clone().into(),
                font_size: FontSize::Px(if item.disabled {
                    metrics.disabled_item_title_font_size
                } else {
                    metrics.item_title_font_size
                }),
                weight: FontWeight::BOLD,
                ..default()
            },
            LineHeight::RelativeToFont(metrics.line_height),
            TextColor(scroll_area_resolve_tone(
                if item.disabled {
                    theme.text_disabled()
                } else {
                    theme.text_1()
                },
                item_opacity,
                theme.surface_1(),
                backdrop,
            )),
            TextLayout::new(Justify::Left, LineBreak::NoWrap),
        ));
        commands.spawn((
            ChildOf(item_id),
            Text::new(item.detail.clone()),
            TextFont {
                font: fonts.inter.clone().into(),
                font_size: FontSize::Px(metrics.item_detail_font_size),
                weight: if invalid {
                    FontWeight::SEMIBOLD
                } else {
                    FontWeight::NORMAL
                },
                ..default()
            },
            LineHeight::RelativeToFont(metrics.line_height),
            TextColor(scroll_area_resolve_tone(
                if item.disabled {
                    theme.text_disabled()
                } else if invalid {
                    theme.danger()
                } else {
                    theme.text_2()
                },
                item_opacity,
                theme.surface_1(),
                backdrop,
            )),
            TextLayout::new(Justify::Left, LineBreak::WordOrCharacter),
        ));
        items.push(ScrollAreaItemEntities {
            value: item.value.clone(),
            entity: item_id,
            disabled: item.disabled,
        });
    }
    let bar_row_id = commands
        .spawn((
            ChildOf(frame_id),
            Node {
                width: percent(100),
                min_width: px(0.0),
                flex_direction: FlexDirection::Row,
                flex_wrap: FlexWrap::Wrap,
                align_items: AlignItems::Center,
                row_gap: px(metrics.bar_row_gap),
                column_gap: px(metrics.bar_row_gap),
                ..default()
            },
        ))
        .id();
    let mut bars = Vec::with_capacity(2);
    for bar in nodes.iter().filter(|node| node.part == ScrollAreaPart::Bar) {
        let axis = bar.axis.expect("invariant: scroll area bar has an axis");
        let bar_color = scroll_area_bar_color(
            &theme,
            bar.active,
            bar.disabled,
            invalid,
            root_opacity,
            backdrop,
        );
        let (width, height) = match axis {
            ScrollAreaAxis::Vertical => (metrics.vertical_bar_width, metrics.vertical_bar_height),
            ScrollAreaAxis::Horizontal => {
                (metrics.horizontal_bar_width, metrics.horizontal_bar_height)
            }
        };
        let bar_id = commands
            .spawn((
                ChildOf(bar_row_id),
                Button,
                ScrollAreaBarControl {
                    group: root_id,
                    axis,
                    disabled: bar.disabled,
                },
                Node {
                    width: px(width),
                    height: px(height),
                    min_width: px(width),
                    min_height: px(height),
                    border_radius: BorderRadius::MAX,
                    ..default()
                },
                BackgroundColor(bar_color),
                if bar.active && !bar.disabled {
                    bevy_shadow_1(&theme, inline_size)
                } else {
                    BoxShadow::default()
                },
            ))
            .id();
        bars.push(ScrollAreaBarEntities {
            axis,
            entity: bar_id,
            disabled: bar.disabled,
        });
    }
    let corner_visible = model.overflow == ScrollAreaOverflow::Both;
    let corner_id = commands
        .spawn((
            ChildOf(bar_row_id),
            Node {
                display: if corner_visible {
                    Display::Flex
                } else {
                    Display::None
                },
                width: px(metrics.corner_size),
                height: px(metrics.corner_size),
                min_width: px(metrics.corner_size),
                min_height: px(metrics.corner_size),
                border_radius: BorderRadius::all(px(theme.radius_field)),
                ..default()
            },
            BackgroundColor(scroll_area_resolve_tone(
                theme.border_subtle(),
                root_opacity,
                theme.surface_2(),
                backdrop,
            )),
        ))
        .id();
    commands.entity(root_id).insert(ScrollAreaGroup {
        state,
        hovered_item: None,
        viewport: viewport_id,
        items,
        bars,
        corner: corner_id,
        theme,
        backdrop,
        invalid,
        blocked,
        root_opacity,
        metrics,
        inline_size,
    });
}

#[cfg(target_arch = "wasm32")]
fn scroll_area_resolve_tone(tone: Tone, opacity: f32, surface: Tone, backdrop: Tone) -> Color {
    if opacity < 1.0 {
        tone.with_opacity(opacity).to_bevy_on(backdrop)
    } else {
        tone.to_bevy_on(surface)
    }
}

#[cfg(target_arch = "wasm32")]
#[allow(clippy::too_many_arguments)]
fn scroll_area_item_colors(
    theme: &Theme,
    active: bool,
    disabled: bool,
    invalid: bool,
    opacity: f32,
    interaction: Interaction,
    surface: Tone,
    backdrop: Tone,
) -> (Color, Color) {
    let (fill, border) = if disabled {
        (theme.surface_2(), theme.border_muted())
    } else if invalid {
        (theme.error_soft(), theme.danger())
    } else if active {
        (theme.primary_soft(), theme.brand())
    } else if interaction != Interaction::None {
        (theme.hover_tint(), theme.border_subtle())
    } else {
        (theme.surface_1(), theme.border_subtle())
    };
    (
        scroll_area_resolve_tone(fill, opacity, surface, backdrop),
        scroll_area_resolve_tone(border, opacity, surface, backdrop),
    )
}

#[cfg(target_arch = "wasm32")]
fn scroll_area_bar_color(
    theme: &Theme,
    active: bool,
    disabled: bool,
    invalid: bool,
    opacity: f32,
    backdrop: Tone,
) -> Color {
    let tone = if disabled {
        theme.border_muted()
    } else if invalid {
        theme.danger()
    } else if active {
        theme.brand()
    } else {
        theme.border_subtle()
    };
    let opacity = opacity
        * if disabled {
            scale::opacity::DISABLED
        } else {
            1.0
        };
    scroll_area_resolve_tone(tone, opacity, theme.surface_2(), backdrop)
}

#[cfg(target_arch = "wasm32")]
fn spawn_separator_primitives(
    parent: &mut ChildSpawnerCommands,
    variant: &BevyUiStoryVariant,
    fonts: &StoryFonts,
    available_width: f32,
    inline_size: f32,
) {
    let UiStoryModel::Separator(model) = &variant.model else {
        return;
    };
    let theme = variant.theme_id.palette();
    let blocked = model.loading || model.disabled;
    let invalid = model.error.is_some();
    let dense = model.density == SeparatorDensity::Dense && !model.disabled;
    let vertical = model.orientation == SeparatorOrientation::Vertical && !model.disabled;
    let border_width = theme.border.max(1.0);
    let metrics = separator_layout_metrics(model, available_width, inline_size, border_width);
    let root_fill = if model.disabled {
        theme.surface_2().to_bevy()
    } else if invalid {
        theme.error_soft().to_bevy_on(theme.surface_1())
    } else {
        theme.surface_1().to_bevy()
    };
    let root_border = if model.disabled {
        theme.border_muted().to_bevy()
    } else if invalid {
        theme.danger().to_bevy()
    } else {
        theme.border_subtle().to_bevy()
    };
    let line_fill = if blocked {
        theme.border_muted().to_bevy()
    } else if invalid {
        theme.danger().to_bevy()
    } else {
        theme.border_subtle().to_bevy()
    };
    let root_id = parent
        .spawn((
            Button,
            Node {
                width: if vertical {
                    px(metrics.width)
                } else {
                    percent(100)
                },
                max_width: px(metrics.width),
                min_width: px(0.0),
                min_height: px(metrics.height),
                padding: UiRect::all(px(metrics.padding)),
                border: UiRect::all(px(border_width)),
                border_radius: BorderRadius::all(px(theme.radius_field)),
                flex_direction: if vertical {
                    FlexDirection::Row
                } else {
                    FlexDirection::Column
                },
                align_items: if vertical {
                    AlignItems::Center
                } else {
                    AlignItems::Stretch
                },
                align_self: if vertical {
                    AlignSelf::FlexStart
                } else {
                    AlignSelf::Stretch
                },
                row_gap: px(metrics.gap),
                column_gap: px(metrics.gap),
                ..default()
            },
            BackgroundColor(root_fill),
            BorderColor::all(root_border),
            BoxShadow::new(
                theme.text_1().to_bevy().with_alpha(0.035),
                px(0.0),
                px(scale::space::XS3),
                px(0.0),
                px(scale::space::XS2),
            ),
        ))
        .id();
    let mut commands = parent.commands();
    let line_id = commands
        .spawn((
            ChildOf(root_id),
            Node {
                width: px(metrics.line_width),
                height: px(metrics.line_height),
                min_width: px(metrics.line_width),
                min_height: px(metrics.line_height),
                max_width: px(metrics.line_width),
                max_height: px(metrics.line_height),
                border_radius: BorderRadius::MAX,
                ..default()
            },
            BackgroundColor(line_fill),
        ))
        .id();
    if let Some(label) = &model.label {
        commands.spawn((
            ChildOf(root_id),
            Node {
                width: if vertical { auto() } else { percent(100) },
                min_width: px(0.0),
                ..default()
            },
            Text::new(label.to_uppercase()),
            TextFont {
                font: fonts.inter.clone().into(),
                font_size: FontSize::Px(metrics.label_font_size),
                weight: if dense {
                    FontWeight::SEMIBOLD
                } else {
                    FontWeight::BOLD
                },
                ..default()
            },
            LineHeight::RelativeToFont(scale::line_height::LH0),
            LetterSpacing::Rem(0.08),
            TextColor(if blocked {
                theme.text_disabled().to_bevy()
            } else if invalid {
                theme.danger().to_bevy()
            } else {
                theme.text_muted().to_bevy()
            }),
            TextLayout::new(Justify::Left, LineBreak::NoWrap),
        ));
    }
    if let Some(error) = &model.error {
        commands.spawn((
            ChildOf(root_id),
            Node {
                width: percent(100),
                min_width: px(0.0),
                ..default()
            },
            Text::new(error.clone()),
            TextFont {
                font: fonts.inter.clone().into(),
                font_size: FontSize::Px(metrics.label_font_size),
                weight: FontWeight::SEMIBOLD,
                ..default()
            },
            LineHeight::RelativeToFont(scale::line_height::LH0),
            TextColor(theme.danger().to_bevy()),
            TextLayout::new(Justify::Left, LineBreak::WordOrCharacter),
        ));
    }
    commands.entity(root_id).insert(SeparatorGroupState {
        model: model.clone(),
        state: model.state(),
        root: root_id,
        line: line_id,
        theme,
        available_width,
        inline_size,
    });
}

#[cfg(target_arch = "wasm32")]
fn spawn_sheet_primitives(
    parent: &mut ChildSpawnerCommands,
    variant: &BevyUiStoryVariant,
    fonts: &StoryFonts,
    inline_size: f32,
) {
    let UiStoryModel::Sheet(model) = &variant.model else {
        return;
    };
    let theme = variant.theme_id.palette();
    let state = model.state();
    let blocked = model.loading || model.disabled;
    let metrics = sheet_layout_metrics(model, inline_size);
    let border_width = theme.border.max(1.0);
    let render_nodes = sheet_render_nodes(model, &state);
    let trigger_node = render_nodes
        .iter()
        .find(|node| node.part == SheetPart::Trigger)
        .expect("invariant: sheet render nodes include trigger");
    let content_node = render_nodes
        .iter()
        .find(|node| node.part == SheetPart::Content)
        .expect("invariant: sheet render nodes include content");
    let header_node = render_nodes
        .iter()
        .find(|node| node.part == SheetPart::Header)
        .expect("invariant: sheet render nodes include header");
    let close_node = render_nodes
        .iter()
        .find(|node| node.part == SheetPart::Close)
        .expect("invariant: sheet render nodes include close");
    let action_nodes = render_nodes
        .iter()
        .filter(|node| node.part == SheetPart::Footer)
        .collect::<Vec<_>>();
    let trigger_metrics = metrics.trigger_control(state.is_open(), blocked);
    let (trigger_fill, trigger_border, trigger_text) =
        sheet_trigger_colors(&theme, state.is_open(), blocked);

    let root_id = parent
        .spawn(Node {
            display: Display::Grid,
            width: percent(100),
            min_width: px(0.0),
            align_content: AlignContent::Stretch,
            grid_auto_rows: GridTrack::auto(),
            row_gap: px(metrics.root_gap),
            ..default()
        })
        .id();
    let mut commands = parent.commands();
    let trigger_id = commands
        .spawn((
            ChildOf(root_id),
            Button,
            SheetTriggerControl {
                group: root_id,
                disabled: blocked,
            },
            Node {
                width: auto(),
                min_width: px(0.0),
                min_height: px(trigger_metrics.min_height),
                padding: UiRect::axes(
                    px(trigger_metrics.padding_inline),
                    px(trigger_metrics.padding_block),
                ),
                border: UiRect::all(px(border_width)),
                border_radius: BorderRadius::all(px(theme.radius_field)),
                justify_self: JustifySelf::Start,
                justify_content: JustifyContent::Center,
                align_items: AlignItems::Center,
                column_gap: px(trigger_metrics.gap),
                ..default()
            },
            BackgroundColor(trigger_fill),
            BorderColor::all(trigger_border),
            bevy_shadow_1(&theme, inline_size),
            Text::new(trigger_node.label.clone()),
            TextFont {
                font: fonts.inter.clone().into(),
                font_size: FontSize::Px(trigger_metrics.font_size),
                weight: if state.is_open() {
                    FontWeight::BOLD
                } else {
                    FontWeight::SEMIBOLD
                },
                ..default()
            },
            LineHeight::RelativeToFont(trigger_metrics.line_height),
            TextColor(trigger_text),
            TextLayout::new(Justify::Center, LineBreak::NoWrap),
            sheet_interactive_primitive(
                &theme,
                theme.surface_1(),
                trigger_fill,
                state.is_open(),
                blocked,
                true,
            ),
        ))
        .id();

    let panel_fill = theme.surface_elevated().to_bevy_on(theme.surface_1());
    let content_id = commands
        .spawn((
            ChildOf(root_id),
            Node {
                display: if state.is_open() {
                    Display::Grid
                } else {
                    Display::None
                },
                width: percent(100),
                max_width: px(metrics.max_width),
                min_width: px(0.0),
                padding: UiRect::all(px(metrics.content_padding)),
                border: UiRect::all(px(border_width)),
                border_radius: BorderRadius::all(px(
                    if model.density == rs_dean_ui::SheetDensity::Dense {
                        theme.radius_field
                    } else {
                        theme.radius_box
                    },
                )),
                justify_self: sheet_content_justify(model.side),
                align_items: AlignItems::Stretch,
                align_content: AlignContent::Stretch,
                grid_auto_rows: GridTrack::auto(),
                row_gap: px(metrics.content_gap),
                ..default()
            },
            BackgroundColor(panel_fill),
            sheet_content_border(&theme, model.side),
            match metrics.content_shadow_level {
                2 => bevy_shadow_2(&theme, inline_size),
                _ => bevy_shadow_3(&theme, inline_size),
            },
        ))
        .id();
    let header_id = commands
        .spawn((
            ChildOf(content_id),
            Node {
                display: Display::Grid,
                width: percent(100),
                min_width: px(0.0),
                align_items: AlignItems::Stretch,
                align_content: AlignContent::Stretch,
                grid_auto_rows: GridTrack::auto(),
                row_gap: px(metrics.header_gap),
                ..default()
            },
        ))
        .id();
    commands.spawn((
        ChildOf(header_id),
        Node {
            width: percent(100),
            min_width: px(0.0),
            ..default()
        },
        Text::new(header_node.label.clone()),
        TextFont {
            font: fonts.inter.clone().into(),
            font_size: FontSize::Px(metrics.title_font_size),
            weight: FontWeight::BOLD,
            ..default()
        },
        LineHeight::RelativeToFont(metrics.title_line_height),
        TextColor(theme.text_1().to_bevy()),
        TextLayout::new(Justify::Left, LineBreak::WordOrCharacter),
    ));
    commands.spawn((
        ChildOf(header_id),
        Node {
            width: percent(100),
            min_width: px(0.0),
            ..default()
        },
        Text::new(header_node.detail.clone()),
        TextFont {
            font: fonts.inter.clone().into(),
            font_size: FontSize::Px(metrics.description_font_size),
            weight: FontWeight::NORMAL,
            ..default()
        },
        LineHeight::RelativeToFont(metrics.description_line_height),
        TextColor(theme.text_2().to_bevy()),
        TextLayout::new(Justify::Left, LineBreak::WordOrCharacter),
    ));
    commands.spawn((
        ChildOf(content_id),
        Node {
            width: percent(100),
            min_width: px(0.0),
            ..default()
        },
        Text::new(content_node.detail.clone()),
        TextFont {
            font: fonts.inter.clone().into(),
            font_size: FontSize::Px(metrics.body_font_size),
            weight: FontWeight::NORMAL,
            ..default()
        },
        LineHeight::RelativeToFont(metrics.body_line_height),
        TextColor(theme.text_2().to_bevy()),
        TextLayout::new(Justify::Left, LineBreak::WordOrCharacter),
    ));

    let footer_id = commands
        .spawn((
            ChildOf(content_id),
            Node {
                width: percent(100),
                min_width: px(0.0),
                flex_direction: FlexDirection::Row,
                flex_wrap: FlexWrap::Wrap,
                justify_content: JustifyContent::FlexEnd,
                align_items: AlignItems::Center,
                row_gap: px(metrics.footer_gap),
                column_gap: px(metrics.footer_gap),
                ..default()
            },
        ))
        .id();
    let mut actions = Vec::with_capacity(action_nodes.len());
    for action in action_nodes {
        let action_disabled = blocked;
        let control_metrics =
            metrics.action_control(action.index, action.selected, action_disabled);
        let (fill, border, text) =
            sheet_action_colors(&theme, action.index, action.selected, action_disabled);
        let entity = commands
            .spawn((
                ChildOf(footer_id),
                Button,
                SheetActionControl {
                    group: root_id,
                    value: action.value.clone(),
                    activate: true,
                    close_sheet: action.close_sheet,
                    disabled: action_disabled,
                },
                Node {
                    width: auto(),
                    min_width: px(0.0),
                    min_height: px(control_metrics.min_height),
                    padding: UiRect::axes(
                        px(control_metrics.padding_inline),
                        px(control_metrics.padding_block),
                    ),
                    border: UiRect::all(px(border_width)),
                    border_radius: BorderRadius::all(px(theme.radius_field)),
                    justify_content: JustifyContent::Center,
                    align_items: AlignItems::Center,
                    column_gap: px(control_metrics.gap),
                    ..default()
                },
                BackgroundColor(fill),
                BorderColor::all(border),
                Text::new(action.label.clone()),
                TextFont {
                    font: fonts.inter.clone().into(),
                    font_size: FontSize::Px(control_metrics.font_size),
                    weight: if action.index == 0 || action.selected {
                        FontWeight::BOLD
                    } else {
                        FontWeight::SEMIBOLD
                    },
                    ..default()
                },
                LineHeight::RelativeToFont(control_metrics.line_height),
                TextColor(text),
                TextLayout::new(Justify::Center, LineBreak::NoWrap),
                sheet_interactive_primitive(
                    &theme,
                    theme.surface_elevated(),
                    fill,
                    action.selected,
                    action_disabled,
                    action.index == 0 || action.selected,
                ),
            ))
            .id();
        actions.push(SheetActionEntities {
            value: action.value.clone(),
            entity,
            index: action.index,
            disabled: action_disabled,
        });
    }

    let close_metrics = metrics.close_control();
    let close_disabled = blocked;
    let (close_fill, close_border, close_text) =
        sheet_action_colors(&theme, usize::MAX, false, close_disabled);
    let close_id = commands
        .spawn((
            ChildOf(footer_id),
            Button,
            SheetActionControl {
                group: root_id,
                value: close_node.value.clone(),
                activate: false,
                close_sheet: true,
                disabled: close_disabled,
            },
            Node {
                width: auto(),
                min_width: px(0.0),
                min_height: px(close_metrics.min_height),
                padding: UiRect::axes(
                    px(close_metrics.padding_inline),
                    px(close_metrics.padding_block),
                ),
                border: UiRect::all(px(border_width)),
                border_radius: BorderRadius::all(px(theme.radius_field)),
                justify_content: JustifyContent::Center,
                align_items: AlignItems::Center,
                column_gap: px(close_metrics.gap),
                ..default()
            },
            BackgroundColor(close_fill),
            BorderColor::all(close_border),
            Text::new(close_node.label.clone()),
            TextFont {
                font: fonts.inter.clone().into(),
                font_size: FontSize::Px(close_metrics.font_size),
                weight: FontWeight::SEMIBOLD,
                ..default()
            },
            LineHeight::RelativeToFont(close_metrics.line_height),
            TextColor(close_text),
            TextLayout::new(Justify::Center, LineBreak::NoWrap),
            sheet_interactive_primitive(
                &theme,
                theme.surface_elevated(),
                close_fill,
                false,
                close_disabled,
                false,
            ),
        ))
        .id();

    commands.entity(root_id).insert(SheetGroupState {
        state,
        trigger: trigger_id,
        content: content_id,
        actions,
        close: close_id,
        metrics,
        theme,
        blocked,
    });
}

#[cfg(target_arch = "wasm32")]
const fn sheet_content_justify(side: SheetSide) -> JustifySelf {
    match side {
        SheetSide::Right => JustifySelf::End,
        SheetSide::Left => JustifySelf::Start,
        SheetSide::Top | SheetSide::Bottom => JustifySelf::Stretch,
    }
}

#[cfg(target_arch = "wasm32")]
fn sheet_content_border(theme: &Theme, side: SheetSide) -> BorderColor {
    let subtle = theme.border_subtle().to_bevy_on(theme.surface_elevated());
    let brand = theme.brand().to_bevy();
    match side {
        SheetSide::Top => BorderColor {
            bottom: brand,
            ..BorderColor::all(subtle)
        },
        SheetSide::Right => BorderColor {
            left: brand,
            ..BorderColor::all(subtle)
        },
        SheetSide::Bottom => BorderColor {
            top: brand,
            ..BorderColor::all(subtle)
        },
        SheetSide::Left => BorderColor {
            right: brand,
            ..BorderColor::all(subtle)
        },
    }
}

#[cfg(target_arch = "wasm32")]
fn sheet_trigger_colors(theme: &Theme, open: bool, blocked: bool) -> (Color, Color, Color) {
    if blocked {
        return (
            theme.surface_2().to_bevy_on(theme.surface_1()),
            theme.border_muted().to_bevy_on(theme.surface_1()),
            theme.text_disabled().to_bevy(),
        );
    }
    if open {
        return (
            theme.primary_soft().to_bevy_on(theme.surface_1()),
            theme.brand().to_bevy(),
            theme.text_1().to_bevy(),
        );
    }
    (
        theme.surface_2().to_bevy_on(theme.surface_1()),
        theme.border_strong().to_bevy_on(theme.surface_1()),
        theme.text_1().to_bevy(),
    )
}

#[cfg(target_arch = "wasm32")]
fn sheet_action_colors(
    theme: &Theme,
    index: usize,
    selected: bool,
    disabled: bool,
) -> (Color, Color, Color) {
    if disabled {
        return (
            theme.surface_2().to_bevy_on(theme.surface_elevated()),
            theme.border_muted().to_bevy_on(theme.surface_elevated()),
            theme.text_disabled().to_bevy(),
        );
    }
    if selected {
        return (
            theme.selected_tint().to_bevy_on(theme.surface_elevated()),
            theme.brand().to_bevy(),
            theme.text_1().to_bevy(),
        );
    }
    if index == 0 {
        return (
            theme.primary_soft().to_bevy_on(theme.surface_elevated()),
            theme.brand().to_bevy(),
            theme.text_1().to_bevy(),
        );
    }
    (
        theme.surface_2().to_bevy_on(theme.surface_elevated()),
        theme.border_strong().to_bevy_on(theme.surface_elevated()),
        theme.text_1().to_bevy(),
    )
}

#[cfg(target_arch = "wasm32")]
fn sheet_interactive_primitive(
    theme: &Theme,
    surface: Tone,
    rest: Color,
    selected: bool,
    disabled: bool,
    primary: bool,
) -> InteractivePrimitive {
    let selected_fill = theme.selected_tint().to_bevy_on(surface);
    let hover = if disabled {
        rest
    } else if primary || selected {
        selected_fill
    } else {
        theme.hover_tint().to_bevy_on(surface)
    };
    InteractivePrimitive {
        rest,
        selected: selected_fill,
        hover,
        pressed: hover,
        latched: selected,
        stateful: true,
    }
}

#[cfg(target_arch = "wasm32")]
fn spawn_skeleton_primitives(
    parent: &mut ChildSpawnerCommands,
    variant: &BevyUiStoryVariant,
    fonts: &StoryFonts,
    inline_size: f32,
) {
    let UiStoryModel::Skeleton(model) = &variant.model else {
        return;
    };
    let theme = variant.theme_id.palette();
    let metrics = skeleton_layout_metrics(model, inline_size);
    let invalid = model.error.is_some();
    let border_width = theme.border.max(1.0);
    let root_fill = if model.disabled || !model.loading {
        theme.surface_2().to_bevy()
    } else if invalid {
        theme.error_soft().to_bevy_on(theme.surface_1())
    } else {
        theme.surface_1().to_bevy()
    };
    let border = if invalid {
        theme.danger().to_bevy()
    } else if model.disabled {
        theme.border_muted().to_bevy_on(theme.surface_2())
    } else if !model.loading {
        theme.border_subtle().to_bevy_on(theme.surface_2())
    } else {
        theme.border_subtle().to_bevy_on(theme.surface_1())
    };
    let root_id = parent
        .spawn((
            Node {
                display: Display::Grid,
                width: percent(100),
                max_width: px(metrics.max_width),
                min_width: px(0.0),
                justify_self: JustifySelf::Start,
                padding: UiRect::all(px(metrics.root_padding)),
                border: UiRect::all(px(border_width)),
                border_radius: BorderRadius::all(px(if metrics.dense_root {
                    theme.radius_field
                } else {
                    theme.radius_box
                })),
                align_items: AlignItems::Stretch,
                row_gap: px(metrics.root_gap),
                grid_auto_rows: GridTrack::auto(),
                ..default()
            },
            BackgroundColor(root_fill),
            BorderColor::all(border),
            if metrics.shadow_level == 1 {
                bevy_shadow_1(&theme, inline_size)
            } else {
                BoxShadow::default()
            },
            Button,
            SkeletonRootTrigger,
        ))
        .id();
    let mut commands = parent.commands();
    commands.spawn((
        ChildOf(root_id),
        Node {
            width: percent(100),
            min_width: px(0.0),
            ..default()
        },
        Text::new(
            model
                .error
                .as_deref()
                .unwrap_or(&model.detail)
                .to_uppercase(),
        ),
        TextFont {
            font: fonts.inter.clone().into(),
            font_size: FontSize::Px(metrics.status_font_size),
            weight: FontWeight::BOLD,
            ..default()
        },
        LineHeight::RelativeToFont(metrics.status_line_height),
        LetterSpacing::Rem(metrics.status_tracking_em),
        TextColor(if model.disabled {
            theme.text_muted().to_bevy().with_alpha(0.45)
        } else {
            theme.text_muted().to_bevy()
        }),
        TextLayout::new(Justify::Left, LineBreak::WordOrCharacter),
    ));

    let mut placeholders = Vec::new();
    if model.loading {
        let content_id = commands
            .spawn((
                ChildOf(root_id),
                Node {
                    display: Display::Grid,
                    width: percent(100),
                    min_width: px(0.0),
                    align_items: AlignItems::Stretch,
                    row_gap: px(metrics.content_gap),
                    grid_auto_rows: GridTrack::auto(),
                    ..default()
                },
            ))
            .id();
        placeholders.push(spawn_skeleton_placeholder(
            &mut commands,
            SkeletonPlaceholderSpec {
                parent: content_id,
                group: root_id,
                part: SkeletonPart::Block,
                outer_height: metrics.block_height,
                pill: false,
                interactive: true,
                invalid,
                disabled: model.disabled,
            },
            &theme,
        ));
        let mut lines = commands.spawn((
            ChildOf(content_id),
            Node {
                display: Display::Grid,
                width: percent(100),
                min_width: px(0.0),
                align_items: AlignItems::Stretch,
                row_gap: px(metrics.text_gap),
                grid_auto_rows: GridTrack::auto(),
                ..default()
            },
        ));
        if !model.disabled {
            lines.insert((
                Button,
                SkeletonPlaceholderTrigger {
                    group: root_id,
                    part: SkeletonPart::Text,
                    disabled: false,
                },
            ));
        }
        let lines_id = lines.id();
        for _ in 0..model.text_lines {
            placeholders.push(spawn_skeleton_placeholder(
                &mut commands,
                SkeletonPlaceholderSpec {
                    parent: lines_id,
                    group: root_id,
                    part: SkeletonPart::Text,
                    outer_height: metrics.line_height,
                    pill: true,
                    interactive: false,
                    invalid,
                    disabled: model.disabled,
                },
                &theme,
            ));
        }
        placeholders.push(spawn_skeleton_placeholder(
            &mut commands,
            SkeletonPlaceholderSpec {
                parent: content_id,
                group: root_id,
                part: SkeletonPart::Media,
                outer_height: metrics.media_min_height,
                pill: false,
                interactive: true,
                invalid,
                disabled: model.disabled,
            },
            &theme,
        ));
    }

    if let Some(error) = &model.error {
        commands.spawn((
            ChildOf(root_id),
            Node {
                width: percent(100),
                min_width: px(0.0),
                padding: UiRect::all(px(metrics.error_padding)),
                border: UiRect::all(px(border_width)),
                border_radius: BorderRadius::all(px(theme.radius_field)),
                ..default()
            },
            BackgroundColor(theme.error_soft().to_bevy_on(theme.surface_1())),
            BorderColor::all(theme.danger().to_bevy()),
            Text::new(error.clone()),
            TextFont {
                font: fonts.inter.clone().into(),
                font_size: FontSize::Px(metrics.error_font_size),
                weight: FontWeight::NORMAL,
                ..default()
            },
            LineHeight::RelativeToFont(metrics.error_line_height),
            TextColor(theme.text_1().to_bevy()),
            TextLayout::new(Justify::Left, LineBreak::WordOrCharacter),
        ));
    }

    commands.entity(root_id).insert(SkeletonGroupState {
        model: model.clone(),
        state: model.state(),
        placeholders,
        theme,
        inline_size,
        phase_seconds: 0.0,
    });
}

#[cfg(target_arch = "wasm32")]
fn spawn_skeleton_placeholder(
    commands: &mut Commands<'_, '_>,
    spec: SkeletonPlaceholderSpec,
    theme: &Theme,
) -> SkeletonPlaceholderEntities {
    let active = false;
    let uses_border = skeleton_placeholder_uses_border(active, spec.invalid, spec.disabled);
    let border_width = if uses_border {
        theme.border.max(1.0)
    } else {
        0.0
    };
    let content_height = (spec.outer_height - border_width * 2.0).max(0.0);
    let (fill, border) = skeleton_placeholder_colors(theme, active, spec.invalid, spec.disabled);
    let mut entity = commands.spawn((
        ChildOf(spec.parent),
        Node {
            width: percent(100),
            height: px(content_height),
            min_height: px(content_height),
            border: if uses_border {
                UiRect::all(px(border_width))
            } else {
                UiRect::ZERO
            },
            border_radius: if spec.pill {
                BorderRadius::MAX
            } else {
                BorderRadius::all(px(theme.radius_field))
            },
            ..default()
        },
        BackgroundColor(fill),
        BorderColor::all(border),
        BoxShadow::default(),
    ));
    if spec.interactive && !spec.disabled {
        entity.insert((
            Button,
            SkeletonPlaceholderTrigger {
                group: spec.group,
                part: spec.part,
                disabled: spec.disabled,
            },
        ));
    }
    SkeletonPlaceholderEntities {
        entity: entity.id(),
        part: spec.part,
        outer_height: spec.outer_height,
        disabled: spec.disabled,
    }
}

#[cfg(target_arch = "wasm32")]
fn skeleton_placeholder_colors(
    theme: &Theme,
    active: bool,
    invalid: bool,
    disabled: bool,
) -> (Color, Color) {
    if disabled {
        return (theme.surface_2().to_bevy().with_alpha(0.42), Color::NONE);
    }
    if invalid {
        return (
            theme.error_soft().to_bevy_on(theme.surface_1()),
            theme.danger().to_bevy(),
        );
    }
    if active {
        return (
            theme.selected_tint().to_bevy_on(theme.surface_1()),
            theme.brand().to_bevy(),
        );
    }
    (theme.surface_3().to_bevy(), Color::NONE)
}

#[cfg(target_arch = "wasm32")]
fn spawn_sonner_primitives(
    parent: &mut ChildSpawnerCommands,
    variant: &BevyUiStoryVariant,
    fonts: &StoryFonts,
    available_width: f32,
    inline_size: f32,
) {
    let UiStoryModel::Sonner(model) = &variant.model else {
        return;
    };
    let theme = variant.theme_id.palette();
    let blocked = model.loading || model.disabled;
    let invalid = model.error.is_some();
    let metrics = sonner_layout_metrics(model, available_width, inline_size);
    let border_width = theme.border.max(1.0);
    let root_id = parent
        .spawn((
            Node {
                display: Display::Grid,
                width: px(metrics.max_width),
                max_width: px(scale::container::CONTROL),
                min_width: px(0.0),
                justify_self: JustifySelf::Start,
                padding: UiRect::all(px(metrics.provider_padding)),
                border: if invalid {
                    UiRect::all(px(border_width))
                } else {
                    UiRect::ZERO
                },
                border_radius: BorderRadius::all(px(theme.radius_box)),
                row_gap: px(metrics.provider_gap),
                ..default()
            },
            BackgroundColor(if invalid {
                theme.error_soft().to_bevy_on(theme.surface_1())
            } else {
                Color::NONE
            }),
            BorderColor::all(if invalid {
                theme.danger().to_bevy()
            } else {
                Color::NONE
            }),
        ))
        .id();
    let mut commands = parent.commands();
    commands.spawn((
        ChildOf(root_id),
        Text::new(
            model
                .error
                .clone()
                .unwrap_or_else(|| format!("{} toast notifications", model.toasts.len()))
                .to_uppercase(),
        ),
        TextFont {
            font: fonts.inter.clone().into(),
            font_size: FontSize::Px(metrics.meta_font_size),
            weight: FontWeight::NORMAL,
            ..default()
        },
        LineHeight::Px(metrics.meta_font_size * metrics.meta_line_height),
        LetterSpacing::Rem(metrics.meta_letter_spacing),
        TextColor(if model.disabled {
            theme.text_disabled().to_bevy()
        } else {
            theme.text_muted().to_bevy()
        }),
        TextLayout::new(Justify::Left, LineBreak::NoWrap),
    ));
    let viewport_id = commands
        .spawn((
            ChildOf(root_id),
            Node {
                display: Display::Grid,
                width: percent(100),
                min_width: px(0.0),
                justify_items: if model.position == SonnerPosition::BottomCenter {
                    JustifyItems::Center
                } else {
                    JustifyItems::End
                },
                row_gap: px(metrics.viewport_gap),
                ..default()
            },
        ))
        .id();
    let mut toast_entities = Vec::with_capacity(model.toasts.len());
    for toast in &model.toasts {
        let toast_disabled = blocked || toast.disabled;
        let toast_metrics = metrics.toast(false, invalid, toast_disabled);
        let (toast_fill, toast_border) =
            sonner_toast_colors(&theme, toast.tone, false, invalid, toast_disabled);
        let toast_id = commands
            .spawn((
                ChildOf(viewport_id),
                Node {
                    display: Display::Grid,
                    width: auto(),
                    max_width: percent(100),
                    min_width: px(0.0),
                    padding: UiRect::all(px(toast_metrics.padding)),
                    border: UiRect::all(px(border_width)),
                    border_radius: BorderRadius::all(px(if toast_metrics.dense {
                        theme.radius_field
                    } else {
                        theme.radius_box
                    })),
                    row_gap: px(toast_metrics.gap),
                    ..default()
                },
                BackgroundColor(toast_fill),
                BorderColor::all(toast_border),
                sonner_toast_shadow(toast_metrics.shadow_level, &theme, inline_size),
                SonnerToastTrigger {
                    group: root_id,
                    toast_value: toast.value.clone(),
                    disabled: toast_disabled,
                },
            ))
            .id();
        let header_id = commands
            .spawn((
                ChildOf(toast_id),
                Node {
                    width: percent(100),
                    min_width: px(0.0),
                    flex_direction: FlexDirection::Row,
                    justify_content: JustifyContent::SpaceBetween,
                    align_items: AlignItems::Start,
                    column_gap: px(metrics.header_gap),
                    ..default()
                },
            ))
            .id();
        let copy_id = commands
            .spawn((
                ChildOf(header_id),
                Node {
                    display: Display::Grid,
                    min_width: px(0.0),
                    flex_grow: 1.0,
                    row_gap: px(metrics.copy_gap),
                    ..default()
                },
            ))
            .id();
        let title_id = commands
            .spawn((
                ChildOf(copy_id),
                Text::new(toast.title.clone()),
                TextFont {
                    font: fonts.inter.clone().into(),
                    font_size: FontSize::Px(metrics.title_font_size),
                    weight: FontWeight::BOLD,
                    ..default()
                },
                LineHeight::Px(metrics.title_font_size * metrics.title_line_height),
                TextColor(sonner_text_color(&theme, true, toast_disabled)),
                TextLayout::new(Justify::Left, LineBreak::WordOrCharacter),
            ))
            .id();
        let description_id = commands
            .spawn((
                ChildOf(copy_id),
                Text::new(toast.description.clone()),
                TextFont {
                    font: fonts.inter.clone().into(),
                    font_size: FontSize::Px(metrics.description_font_size),
                    weight: FontWeight::NORMAL,
                    ..default()
                },
                LineHeight::Px(metrics.description_font_size * metrics.description_line_height),
                TextColor(sonner_text_color(&theme, false, toast_disabled)),
                TextLayout::new(Justify::Left, LineBreak::WordOrCharacter),
            ))
            .id();
        let dismiss_disabled = toast_disabled;
        let (dismiss_fill, dismiss_border, dismiss_text) =
            feedback_control_colors(&theme, false, dismiss_disabled);
        let dismiss_content_size = metrics.dismiss_content_size(border_width);
        let dismiss_id = commands
            .spawn((
                ChildOf(header_id),
                Button,
                Node {
                    width: px(dismiss_content_size),
                    height: px(dismiss_content_size),
                    min_width: px(dismiss_content_size),
                    min_height: px(dismiss_content_size),
                    flex_shrink: 0.0,
                    border: UiRect::all(px(border_width)),
                    border_radius: BorderRadius::all(px(theme.radius_field)),
                    justify_content: JustifyContent::Center,
                    align_items: AlignItems::Center,
                    ..default()
                },
                BackgroundColor(dismiss_fill),
                BorderColor::all(dismiss_border),
                BoxShadow::default(),
                InteractivePrimitive::stateful(
                    dismiss_fill,
                    theme.primary_soft().to_bevy_on(theme.surface_1()),
                    false,
                    &theme,
                ),
            ))
            .id();
        let dismiss_label_id = commands
            .spawn((
                ChildOf(dismiss_id),
                Text::new("x"),
                TextFont {
                    font: fonts.inter.clone().into(),
                    font_size: FontSize::Px(metrics.action_font_size),
                    weight: FontWeight::BOLD,
                    ..default()
                },
                TextColor(dismiss_text),
                TextLayout::new(Justify::Center, LineBreak::NoWrap),
            ))
            .id();
        commands.entity(dismiss_id).insert(SonnerDismissTrigger {
            group: root_id,
            toast_value: toast.value.clone(),
            disabled: dismiss_disabled,
        });

        let mut action_id = None;
        let mut action_disabled = true;
        if let Some(action) = &toast.action {
            action_disabled = toast_disabled || action.disabled;
            let (action_fill, action_border, action_text) =
                feedback_control_colors(&theme, false, action_disabled);
            let action_row_id = commands
                .spawn((
                    ChildOf(toast_id),
                    Node {
                        flex_direction: FlexDirection::Row,
                        flex_wrap: FlexWrap::Wrap,
                        align_items: AlignItems::Center,
                        column_gap: px(metrics.action_row_gap),
                        row_gap: px(metrics.action_row_gap),
                        ..default()
                    },
                ))
                .id();
            let entity = commands
                .spawn((
                    ChildOf(action_row_id),
                    Button,
                    Node {
                        min_height: px(metrics.action_content_min_height(border_width)),
                        padding: UiRect::axes(
                            px(metrics.action_padding_inline),
                            px(metrics.action_padding_block),
                        ),
                        border: UiRect::all(px(border_width)),
                        border_radius: BorderRadius::all(px(theme.radius_field)),
                        align_self: AlignSelf::Start,
                        justify_content: JustifyContent::Center,
                        align_items: AlignItems::Center,
                        ..default()
                    },
                    BackgroundColor(action_fill),
                    BorderColor::all(action_border),
                    Text::new(action.label.clone()),
                    TextFont {
                        font: fonts.inter.clone().into(),
                        font_size: FontSize::Px(metrics.action_font_size),
                        weight: FontWeight::SEMIBOLD,
                        ..default()
                    },
                    TextColor(action_text),
                    TextLayout::new(Justify::Center, LineBreak::NoWrap),
                    BoxShadow::default(),
                    InteractivePrimitive::stateful(
                        action_fill,
                        theme.primary_soft().to_bevy_on(theme.surface_1()),
                        false,
                        &theme,
                    ),
                ))
                .id();
            commands.entity(entity).insert(SonnerActionTrigger {
                group: root_id,
                toast_value: toast.value.clone(),
                disabled: action_disabled,
            });
            action_id = Some(entity);
        }
        toast_entities.push(SonnerToastEntities {
            value: toast.value.clone(),
            toast: toast_id,
            title: title_id,
            description: description_id,
            action: action_id,
            dismiss: dismiss_id,
            dismiss_label: dismiss_label_id,
            tone: toast.tone,
            disabled: toast_disabled,
            action_disabled,
        });
    }
    if let Some(error) = &model.error {
        commands.spawn((
            ChildOf(root_id),
            Node {
                padding: UiRect::all(px(metrics.error_padding)),
                border: UiRect::all(px(border_width)),
                border_radius: BorderRadius::all(px(theme.radius_field)),
                ..default()
            },
            BackgroundColor(theme.error_soft().to_bevy_on(theme.surface_1())),
            BorderColor::all(theme.danger().to_bevy()),
            Text::new(error.clone()),
            TextFont {
                font: fonts.inter.clone().into(),
                font_size: FontSize::Px(metrics.error_font_size),
                ..default()
            },
            LineHeight::Px(metrics.error_font_size * metrics.error_line_height),
            TextColor(theme.text_1().to_bevy_css_alpha_on(theme.error_soft())),
            TextLayout::new(Justify::Left, LineBreak::WordOrCharacter),
        ));
    }
    commands.entity(root_id).insert(SonnerGroupState {
        state: model.state(),
        toasts: toast_entities,
        theme,
        metrics,
        inline_size,
        invalid,
        disabled: model.disabled,
    });
}

#[cfg(target_arch = "wasm32")]
fn sonner_toast_shadow(level: u8, theme: &Theme, inline_size: f32) -> BoxShadow {
    match level {
        1 => bevy_shadow_1(theme, inline_size),
        2 => bevy_shadow_2(theme, inline_size),
        _ => BoxShadow::default(),
    }
}

#[cfg(target_arch = "wasm32")]
fn sonner_text_color(theme: &Theme, title: bool, disabled: bool) -> Color {
    let tone = if title {
        theme.text_1()
    } else {
        theme.text_2()
    };
    if disabled {
        tone.with_opacity(scale::opacity::DISABLED)
            .to_bevy_on(theme.surface_1())
    } else {
        tone.to_bevy()
    }
}

#[cfg(target_arch = "wasm32")]
#[derive(Debug, Clone, Copy)]
enum FeedbackTone {
    Default,
    Info,
    Success,
    Warning,
    Destructive,
}

#[cfg(target_arch = "wasm32")]
fn sonner_toast_colors(
    theme: &Theme,
    tone: SonnerTone,
    active: bool,
    invalid: bool,
    disabled: bool,
) -> (Color, Color) {
    feedback_surface_colors(
        theme,
        match tone {
            SonnerTone::Default => FeedbackTone::Default,
            SonnerTone::Info => FeedbackTone::Info,
            SonnerTone::Success => FeedbackTone::Success,
            SonnerTone::Warning => FeedbackTone::Warning,
            SonnerTone::Destructive => FeedbackTone::Destructive,
        },
        active,
        invalid,
        disabled,
    )
}

#[cfg(target_arch = "wasm32")]
fn toast_card_colors(
    theme: &Theme,
    tone: ToastTone,
    active: bool,
    invalid: bool,
    disabled: bool,
) -> (Color, Color) {
    feedback_surface_colors(
        theme,
        match tone {
            ToastTone::Default => FeedbackTone::Default,
            ToastTone::Info => FeedbackTone::Info,
            ToastTone::Success => FeedbackTone::Success,
            ToastTone::Warning => FeedbackTone::Warning,
            ToastTone::Destructive => FeedbackTone::Destructive,
        },
        active,
        invalid,
        disabled,
    )
}

#[cfg(target_arch = "wasm32")]
fn feedback_surface_colors(
    theme: &Theme,
    tone: FeedbackTone,
    active: bool,
    invalid: bool,
    disabled: bool,
) -> (Color, Color) {
    if disabled {
        return (
            theme
                .surface_2()
                .with_opacity(scale::opacity::DISABLED)
                .to_bevy_on(theme.surface_1()),
            theme
                .border_muted()
                .with_opacity(scale::opacity::DISABLED)
                .to_bevy_on(theme.surface_1()),
        );
    }
    if invalid {
        return (
            theme.error_soft().to_bevy_on(theme.surface_1()),
            theme.danger().to_bevy(),
        );
    }
    if active {
        return (
            theme.primary_soft().to_bevy_on(theme.surface_1()),
            theme.brand().to_bevy(),
        );
    }
    match tone {
        FeedbackTone::Default => (
            theme.surface_elevated().to_bevy(),
            theme.border_subtle().to_bevy_on(theme.surface_elevated()),
        ),
        FeedbackTone::Info => (
            theme.info_soft().to_bevy_on(theme.surface_1()),
            theme.info.to_bevy(),
        ),
        FeedbackTone::Success => (
            theme.success_soft().to_bevy_on(theme.surface_1()),
            theme.success.to_bevy(),
        ),
        FeedbackTone::Warning => (
            theme.warning_soft().to_bevy_on(theme.surface_1()),
            theme.warning.to_bevy(),
        ),
        FeedbackTone::Destructive => (
            theme.error_soft().to_bevy_on(theme.surface_1()),
            theme.danger().to_bevy(),
        ),
    }
}

#[cfg(target_arch = "wasm32")]
fn feedback_control_colors(theme: &Theme, active: bool, disabled: bool) -> (Color, Color, Color) {
    if disabled {
        return (
            theme.surface_2().to_bevy(),
            theme.border_muted().to_bevy_on(theme.surface_2()),
            theme.text_disabled().to_bevy(),
        );
    }
    if active {
        return (
            theme.primary_soft().to_bevy_on(theme.surface_1()),
            theme.brand().to_bevy(),
            theme.text_1().to_bevy(),
        );
    }
    (
        theme.surface_2().to_bevy(),
        theme.border_strong().to_bevy_on(theme.surface_2()),
        theme.text_1().to_bevy(),
    )
}

#[cfg(target_arch = "wasm32")]
fn spawn_toast_primitives(
    parent: &mut ChildSpawnerCommands,
    variant: &BevyUiStoryVariant,
    fonts: &StoryFonts,
    available_width: f32,
    inline_size: f32,
) {
    let UiStoryModel::Toast(model) = &variant.model else {
        return;
    };
    let theme = variant.theme_id.palette();
    let state = model.state();
    let blocked = model.loading || model.disabled;
    let invalid = model.error.is_some();
    let border_width = theme.border.max(1.0);
    let metrics = toast_layout_metrics(model, &state, available_width, inline_size, border_width);
    let root_id = parent
        .spawn((
            Node {
                width: percent(100),
                max_width: px(metrics.max_width),
                min_width: px(0.0),
                justify_self: JustifySelf::Start,
                align_self: AlignSelf::Start,
                padding: UiRect::all(px(metrics.provider_padding)),
                border: if invalid {
                    UiRect::all(px(border_width))
                } else {
                    UiRect::ZERO
                },
                border_radius: BorderRadius::all(px(theme.radius_box)),
                display: Display::Grid,
                grid_template_columns: RepeatedGridTrack::fr(1, 1.0),
                grid_auto_rows: GridTrack::auto(),
                row_gap: px(metrics.provider_gap),
                align_content: AlignContent::Start,
                ..default()
            },
            BackgroundColor(if invalid {
                theme.error_soft().to_bevy_on(theme.surface_1())
            } else {
                Color::NONE
            }),
            BorderColor::all(if invalid {
                theme.danger().to_bevy()
            } else {
                Color::NONE
            }),
        ))
        .id();
    let mut commands = parent.commands();
    commands.spawn((
        ChildOf(root_id),
        Text::new(
            model
                .error
                .as_deref()
                .unwrap_or("Provider for one transient notification.")
                .to_uppercase(),
        ),
        TextFont {
            font: fonts.inter.clone().into(),
            font_size: FontSize::Px(metrics.meta_font_size),
            weight: FontWeight::NORMAL,
            ..default()
        },
        LineHeight::Px(metrics.meta_font_size * metrics.meta_line_height),
        LetterSpacing::Rem(metrics.meta_letter_spacing),
        TextColor(if model.disabled {
            theme.text_disabled().to_bevy()
        } else {
            theme.text_muted().to_bevy()
        }),
        TextLayout::new(Justify::Left, LineBreak::NoWrap),
    ));
    let viewport_id = commands
        .spawn((
            ChildOf(root_id),
            Node {
                width: percent(100),
                min_width: px(0.0),
                display: Display::Grid,
                grid_template_columns: RepeatedGridTrack::fr(1, 1.0),
                grid_auto_rows: GridTrack::auto(),
                justify_items: if model.position == ToastPosition::BottomCenter {
                    JustifyItems::Center
                } else {
                    JustifyItems::End
                },
                row_gap: px(metrics.viewport_gap),
                align_content: AlignContent::Start,
                align_self: AlignSelf::Start,
                ..default()
            },
        ))
        .id();
    let (card_fill, card_border) = toast_card_colors(&theme, model.tone, false, invalid, blocked);
    let card_id = commands
        .spawn((
            ChildOf(viewport_id),
            Node {
                display: if state.is_open() {
                    Display::Grid
                } else {
                    Display::None
                },
                width: px(metrics.card_width),
                max_width: percent(100),
                min_width: px(0.0),
                align_self: AlignSelf::Start,
                padding: UiRect::all(px(metrics.card_padding)),
                border: UiRect::all(px(border_width)),
                border_radius: BorderRadius::all(px(if metrics.card_is_dense {
                    theme.radius_field
                } else {
                    theme.radius_box
                })),
                grid_template_columns: RepeatedGridTrack::fr(1, 1.0),
                grid_auto_rows: GridTrack::auto(),
                row_gap: px(metrics.card_gap),
                align_content: AlignContent::Start,
                ..default()
            },
            BackgroundColor(card_fill),
            BorderColor::all(card_border),
            toast_card_shadow(metrics, &theme, inline_size),
            ToastCardTrigger {
                group: root_id,
                disabled: blocked,
            },
        ))
        .id();
    let header_id = commands
        .spawn((
            ChildOf(card_id),
            Node {
                width: percent(100),
                min_width: px(0.0),
                flex_direction: FlexDirection::Row,
                justify_content: JustifyContent::SpaceBetween,
                align_items: AlignItems::Start,
                column_gap: px(metrics.header_gap),
                ..default()
            },
        ))
        .id();
    let copy_id = commands
        .spawn((
            ChildOf(header_id),
            Node {
                display: Display::Grid,
                min_width: px(0.0),
                flex_grow: 1.0,
                grid_template_columns: RepeatedGridTrack::fr(1, 1.0),
                grid_auto_rows: GridTrack::auto(),
                row_gap: px(metrics.copy_gap),
                ..default()
            },
        ))
        .id();
    let title_id = commands
        .spawn((
            ChildOf(copy_id),
            Text::new(model.title.clone()),
            TextFont {
                font: fonts.inter.clone().into(),
                font_size: FontSize::Px(metrics.title_font_size),
                weight: FontWeight::BOLD,
                ..default()
            },
            LineHeight::Px(metrics.title_font_size * metrics.title_line_height),
            TextColor(toast_text_color(&theme, true, blocked)),
            TextLayout::new(Justify::Left, LineBreak::WordOrCharacter),
        ))
        .id();
    let description_id = commands
        .spawn((
            ChildOf(copy_id),
            Text::new(model.description.clone()),
            TextFont {
                font: fonts.inter.clone().into(),
                font_size: FontSize::Px(metrics.description_font_size),
                weight: FontWeight::NORMAL,
                ..default()
            },
            LineHeight::Px(metrics.description_font_size * metrics.description_line_height),
            TextColor(toast_text_color(&theme, false, blocked)),
            TextLayout::new(Justify::Left, LineBreak::WordOrCharacter),
        ))
        .id();
    let mut action_id = None;
    let mut action_disabled = true;
    if let Some(action) = &model.action {
        action_disabled = blocked || action.disabled;
        let (action_fill, action_border, action_text) =
            feedback_control_colors(&theme, false, action_disabled);
        let action_row_id = commands
            .spawn((
                ChildOf(card_id),
                Node {
                    flex_direction: FlexDirection::Row,
                    flex_wrap: FlexWrap::Wrap,
                    align_items: AlignItems::Center,
                    column_gap: px(metrics.action_row_gap),
                    row_gap: px(metrics.action_row_gap),
                    ..default()
                },
            ))
            .id();
        let entity = commands
            .spawn((
                ChildOf(action_row_id),
                Button,
                Node {
                    min_height: px(metrics.action_content_min_height(border_width)),
                    padding: UiRect::axes(
                        px(metrics.action_padding_inline),
                        px(metrics.action_padding_block),
                    ),
                    border: UiRect::all(px(border_width)),
                    border_radius: BorderRadius::all(px(theme.radius_field)),
                    align_self: AlignSelf::Start,
                    justify_content: JustifyContent::Center,
                    align_items: AlignItems::Center,
                    ..default()
                },
                BackgroundColor(action_fill),
                BorderColor::all(action_border),
                Text::new(action.label.clone()),
                TextFont {
                    font: fonts.inter.clone().into(),
                    font_size: FontSize::Px(metrics.action_font_size),
                    weight: FontWeight::SEMIBOLD,
                    ..default()
                },
                LineHeight::Px(metrics.action_font_size * metrics.action_line_height),
                TextColor(action_text),
                TextLayout::new(Justify::Center, LineBreak::NoWrap),
                BoxShadow::default(),
                InteractivePrimitive::stateful(
                    action_fill,
                    theme.primary_soft().to_bevy_on(theme.surface_1()),
                    false,
                    &theme,
                ),
            ))
            .id();
        commands.entity(entity).insert(ToastActionTrigger {
            group: root_id,
            value: action.value.clone(),
            disabled: action_disabled,
        });
        action_id = Some(entity);
    }
    if let Some(error) = &model.error {
        commands.spawn((
            ChildOf(root_id),
            Node {
                padding: UiRect::all(px(metrics.error_padding)),
                border: UiRect::all(px(border_width)),
                border_radius: BorderRadius::all(px(theme.radius_field)),
                ..default()
            },
            BackgroundColor(theme.error_soft().to_bevy_on(theme.surface_1())),
            BorderColor::all(theme.danger().to_bevy()),
            Text::new(error.clone()),
            TextFont {
                font: fonts.inter.clone().into(),
                font_size: FontSize::Px(metrics.error_font_size),
                ..default()
            },
            LineHeight::Px(metrics.error_font_size * metrics.error_line_height),
            TextColor(theme.text_1().to_bevy_css_alpha_on(theme.error_soft())),
            TextLayout::new(Justify::Left, LineBreak::WordOrCharacter),
        ));
    }
    commands.entity(root_id).insert(ToastGroupState {
        model: model.clone(),
        state,
        card: card_id,
        title: title_id,
        description: description_id,
        action: action_id,
        theme,
        available_width,
        inline_size,
        border_width,
        action_disabled,
    });
}

#[cfg(target_arch = "wasm32")]
fn toast_card_shadow(metrics: ToastLayoutMetrics, theme: &Theme, inline_size: f32) -> BoxShadow {
    match metrics.card_shadow_level {
        1 => bevy_shadow_1(theme, inline_size),
        2 => bevy_shadow_2(theme, inline_size),
        _ => BoxShadow::default(),
    }
}

#[cfg(target_arch = "wasm32")]
fn toast_text_color(theme: &Theme, primary: bool, disabled: bool) -> Color {
    let tone = if primary {
        theme.text_1()
    } else {
        theme.text_2()
    };
    if disabled {
        tone.with_opacity(scale::opacity::DISABLED)
            .to_bevy_on(theme.surface_1())
    } else {
        tone.to_bevy()
    }
}

#[cfg(target_arch = "wasm32")]
fn spawn_tabs_primitives(
    parent: &mut ChildSpawnerCommands,
    variant: &BevyUiStoryVariant,
    fonts: &StoryFonts,
    available_width: f32,
    inline_size: f32,
) {
    let UiStoryModel::Tabs(model) = &variant.model else {
        return;
    };
    let theme = variant.theme_id.palette();
    let state = model.state();
    let render_nodes = tabs_render_nodes(model, &state);
    let invalid = model.error.is_some();
    let border_width = theme.border.max(1.0);
    let metrics = tabs_layout_metrics(model, available_width, inline_size, border_width);
    let dense_root = model.density == TabsDensity::Dense && !model.disabled && !invalid;
    let flex_root = metrics.desktop_vertical;
    let root_opacity = tabs_root_opacity(model);
    let root_fill_tone = if model.disabled {
        theme.surface_2()
    } else if invalid {
        theme.error_soft()
    } else {
        theme.surface_1()
    };
    let root_border_tone = if model.disabled {
        theme.border_muted()
    } else if invalid {
        theme.danger()
    } else {
        theme.border_subtle()
    };
    let root_id = parent
        .spawn((
            Node {
                width: percent(100),
                max_width: px(metrics.width),
                min_width: px(0.0),
                padding: UiRect::all(px(metrics.root_padding)),
                border: UiRect::all(px(border_width)),
                border_radius: BorderRadius::all(px(if dense_root {
                    theme.radius_field
                } else {
                    theme.radius_box
                })),
                display: if flex_root {
                    Display::Flex
                } else {
                    Display::Grid
                },
                flex_direction: if metrics.desktop_vertical {
                    FlexDirection::Row
                } else {
                    FlexDirection::Column
                },
                grid_template_columns: RepeatedGridTrack::fr(1, 1.0),
                grid_auto_rows: GridTrack::auto(),
                row_gap: px(metrics.root_gap),
                column_gap: px(metrics.root_gap),
                align_items: AlignItems::Stretch,
                justify_self: JustifySelf::Start,
                ..default()
            },
            BackgroundColor(tabs_resolve_tone(
                root_fill_tone,
                root_opacity,
                theme.surface_1(),
            )),
            BorderColor::all(tabs_resolve_tone(
                root_border_tone,
                root_opacity,
                theme.surface_1(),
            )),
            if model.disabled {
                BoxShadow::default()
            } else {
                bevy_shadow_1(&theme, inline_size)
            },
        ))
        .id();
    let mut commands = parent.commands();
    let root_detail = render_nodes
        .iter()
        .find(|node| node.part == TabsPart::Root)
        .map_or_else(
            || "Selected tab: none".to_owned(),
            |node| node.detail.clone(),
        );
    let status_id = commands
        .spawn((
            ChildOf(root_id),
            Node {
                width: if metrics.desktop_vertical {
                    px(metrics.vertical_status_width)
                } else {
                    percent(100)
                },
                min_width: px(0.0),
                min_height: px(metrics.status_font_size * metrics.status_line_height),
                flex_shrink: if metrics.desktop_vertical { 0.0 } else { 1.0 },
                align_self: AlignSelf::Stretch,
                ..default()
            },
            Text::new(root_detail.to_uppercase()),
            TextFont {
                font: fonts.inter.clone().into(),
                font_size: FontSize::Px(metrics.status_font_size),
                weight: FontWeight::SEMIBOLD,
                ..default()
            },
            LineHeight::RelativeToFont(metrics.status_line_height),
            LetterSpacing::Rem(metrics.status_letter_spacing),
            TextColor(tabs_resolve_tone(
                if model.disabled {
                    theme.text_disabled()
                } else {
                    theme.text_muted()
                },
                root_opacity,
                root_fill_tone,
            )),
            TextLayout::new(Justify::Left, LineBreak::WordOrCharacter),
        ))
        .id();
    let list_id = commands
        .spawn((
            ChildOf(root_id),
            Node {
                width: if metrics.desktop_vertical {
                    px(metrics.vertical_list_width)
                } else {
                    percent(100)
                },
                min_width: px(0.0),
                flex_shrink: 0.0,
                padding: UiRect::all(px(metrics.list_padding)),
                border_radius: BorderRadius::all(px(theme.radius_field)),
                flex_direction: if model.orientation == TabsOrientation::Vertical {
                    FlexDirection::Column
                } else {
                    FlexDirection::Row
                },
                flex_wrap: if model.orientation == TabsOrientation::Horizontal {
                    FlexWrap::Wrap
                } else {
                    FlexWrap::NoWrap
                },
                align_items: if model.orientation == TabsOrientation::Vertical {
                    AlignItems::Stretch
                } else {
                    AlignItems::Center
                },
                row_gap: px(metrics.list_gap),
                column_gap: px(metrics.list_gap),
                ..default()
            },
            BackgroundColor(tabs_resolve_tone(
                theme.surface_2(),
                root_opacity,
                root_fill_tone,
            )),
        ))
        .id();
    let mut trigger_entities = Vec::with_capacity(model.items.len());
    for item in &model.items {
        let Some(node) = render_nodes
            .iter()
            .find(|node| node.part == TabsPart::Trigger && node.value == item.value)
        else {
            continue;
        };
        let control = tabs_trigger_layout_metrics(
            model.density,
            node.focused,
            node.disabled,
            invalid,
            inline_size,
        );
        let (fill, border, text) = tabs_trigger_colors(
            model,
            &state,
            &item.value,
            node.disabled,
            Interaction::None,
            &theme,
        );
        let trigger_id = commands
            .spawn((
                ChildOf(list_id),
                Button,
                Node {
                    width: if model.orientation == TabsOrientation::Vertical {
                        percent(100)
                    } else {
                        auto()
                    },
                    min_width: px(0.0),
                    min_height: px(control.min_height),
                    padding: UiRect::axes(px(control.padding_inline), px(control.padding_block)),
                    border: UiRect::all(px(border_width)),
                    border_radius: BorderRadius::all(px(theme.radius_field)),
                    justify_content: JustifyContent::Center,
                    align_items: AlignItems::Center,
                    ..default()
                },
                BackgroundColor(fill),
                BorderColor::all(border),
                Outline::new(px(border_width * 2.0), px(border_width * 2.0), Color::NONE),
                tabs_trigger_shadow(
                    model,
                    &state,
                    &item.value,
                    node.disabled,
                    &theme,
                    inline_size,
                ),
                Text::new(item.label.clone()),
                TextFont {
                    font: fonts.inter.clone().into(),
                    font_size: FontSize::Px(control.font_size),
                    weight: tabs_trigger_weight(model, &state, &item.value, node.disabled),
                    ..default()
                },
                LineHeight::RelativeToFont(control.line_height),
                TextColor(text),
                TextLayout::new(Justify::Center, LineBreak::NoWrap),
            ))
            .id();
        commands.entity(trigger_id).insert(TabsControl {
            group: root_id,
            value: item.value.clone(),
            disabled: node.disabled,
        });
        trigger_entities.push(TabsTriggerEntities {
            value: item.value.clone(),
            entity: trigger_id,
            disabled: node.disabled,
        });
    }
    let content_node = render_nodes
        .iter()
        .find(|node| node.part == TabsPart::Content && node.visible)
        .expect("invariant: valid tabs render nodes include selected content");
    let content_metrics =
        tabs_content_layout_metrics(model.density, content_node.disabled, invalid, inline_size);
    let content_min_height =
        tabs_content_min_height(model, &state, available_width, inline_size, border_width);
    let (content_fill, content_border, content_text) =
        tabs_content_colors(model, content_node.disabled, &theme);
    let content_host_id = commands
        .spawn((
            ChildOf(root_id),
            Node {
                width: percent(100),
                min_width: px(0.0),
                flex_grow: if metrics.desktop_vertical { 1.0 } else { 0.0 },
                align_self: AlignSelf::Stretch,
                ..default()
            },
        ))
        .id();
    let content_id = commands
        .spawn((
            ChildOf(content_host_id),
            Node {
                width: percent(100),
                min_width: px(0.0),
                min_height: px(content_min_height.max(content_metrics.min_height)),
                flex_grow: 0.0,
                align_self: AlignSelf::Start,
                padding: UiRect::axes(
                    px(content_metrics.padding_inline),
                    px(content_metrics.padding_block),
                ),
                border: UiRect::all(px(border_width)),
                border_radius: BorderRadius::all(px(theme.radius_field)),
                row_gap: px(metrics.content_gap),
                ..default()
            },
            BackgroundColor(content_fill),
            BorderColor::all(content_border),
            Text::new(content_node.detail.clone()),
            TextFont {
                font: fonts.inter.clone().into(),
                font_size: FontSize::Px(content_metrics.font_size),
                weight: FontWeight::NORMAL,
                ..default()
            },
            LineHeight::RelativeToFont(content_metrics.line_height),
            TextColor(content_text),
            TextLayout::new(Justify::Left, LineBreak::WordOrCharacter),
        ))
        .id();
    if let Some(error) = &model.error {
        commands.spawn((
            ChildOf(root_id),
            Node {
                width: percent(100),
                min_width: px(0.0),
                padding: UiRect::all(px(metrics.error_padding)),
                border: UiRect::all(px(border_width)),
                border_radius: BorderRadius::all(px(theme.radius_field)),
                ..default()
            },
            BackgroundColor(tabs_resolve_tone(
                theme.error_soft(),
                root_opacity,
                root_fill_tone,
            )),
            BorderColor::all(tabs_resolve_tone(
                theme.danger(),
                root_opacity,
                root_fill_tone,
            )),
            Text::new(error.clone()),
            TextFont {
                font: fonts.inter.clone().into(),
                font_size: FontSize::Px(scale::font_size::f0(inline_size)),
                weight: FontWeight::NORMAL,
                ..default()
            },
            LineHeight::RelativeToFont(scale::line_height::LH0),
            TextColor(tabs_resolve_tone(
                theme.text_1(),
                root_opacity,
                theme.error_soft(),
            )),
            TextLayout::new(Justify::Left, LineBreak::WordOrCharacter),
        ));
    }
    commands.entity(root_id).insert(TabsStoryState {
        model: model.clone(),
        state,
        focus_visible: false,
        status: status_id,
        triggers: trigger_entities,
        content: content_id,
        theme,
        metrics,
        available_width,
        inline_size,
    });
}

#[cfg(target_arch = "wasm32")]
fn tabs_resolve_tone(tone: Tone, opacity: f32, backdrop: Tone) -> Color {
    tone.with_opacity(opacity).to_bevy_css_alpha_on(backdrop)
}

#[cfg(target_arch = "wasm32")]
fn tabs_root_opacity(model: &TabsModel) -> f32 {
    if model.disabled {
        scale::opacity::DISABLED
    } else {
        1.0
    }
}

#[cfg(target_arch = "wasm32")]
fn tabs_control_opacity(model: &TabsModel, disabled: bool) -> f32 {
    if disabled {
        tabs_root_opacity(model) * scale::opacity::DISABLED
    } else {
        tabs_root_opacity(model)
    }
}

#[cfg(target_arch = "wasm32")]
fn tabs_trigger_colors(
    model: &TabsModel,
    state: &TabsState,
    value: &str,
    disabled: bool,
    interaction: Interaction,
    theme: &Theme,
) -> (Color, Color, Color) {
    let invalid = model.error.is_some();
    let selected = state.is_selected(value);
    let focused = state.is_focused(value);
    let opacity = tabs_control_opacity(model, disabled);
    let (fill, border, text) = if disabled {
        (
            Some(theme.surface_2()),
            Some(theme.border_muted()),
            theme.text_disabled(),
        )
    } else if invalid {
        (
            Some(theme.error_soft()),
            Some(theme.danger()),
            theme.text_1(),
        )
    } else if focused {
        (
            Some(theme.selected_tint()),
            Some(theme.focus_ring()),
            theme.text_1(),
        )
    } else if matches!(interaction, Interaction::Hovered | Interaction::Pressed) {
        (
            Some(if selected {
                theme.selected_tint()
            } else {
                theme.hover_tint()
            }),
            selected.then(|| theme.brand()),
            if selected {
                theme.text_1()
            } else {
                theme.text_2()
            },
        )
    } else if selected {
        (
            Some(theme.primary_soft()),
            Some(theme.brand()),
            theme.text_1(),
        )
    } else {
        (None, None, theme.text_2())
    };
    (
        fill.map_or(Color::NONE, |tone| {
            tabs_resolve_tone(tone, opacity, theme.surface_2())
        }),
        border.map_or(Color::NONE, |tone| {
            tabs_resolve_tone(tone, opacity, theme.surface_2())
        }),
        tabs_resolve_tone(text, opacity, theme.surface_2()),
    )
}

#[cfg(target_arch = "wasm32")]
fn tabs_trigger_weight(
    model: &TabsModel,
    state: &TabsState,
    value: &str,
    disabled: bool,
) -> FontWeight {
    if !disabled && (model.error.is_some() || state.is_focused(value) || state.is_selected(value)) {
        FontWeight::BOLD
    } else {
        FontWeight::SEMIBOLD
    }
}

#[cfg(target_arch = "wasm32")]
fn tabs_trigger_shadow(
    model: &TabsModel,
    state: &TabsState,
    value: &str,
    disabled: bool,
    theme: &Theme,
    inline_size: f32,
) -> BoxShadow {
    if !disabled && (model.error.is_some() || state.is_focused(value) || state.is_selected(value)) {
        bevy_shadow_1(theme, inline_size)
    } else {
        BoxShadow::default()
    }
}

#[cfg(target_arch = "wasm32")]
fn tabs_content_colors(model: &TabsModel, disabled: bool, theme: &Theme) -> (Color, Color, Color) {
    let opacity = tabs_control_opacity(model, disabled);
    let (fill, border, text) = if disabled {
        (
            theme.surface_2(),
            theme.border_muted(),
            theme.text_disabled(),
        )
    } else if model.error.is_some() {
        (theme.error_soft(), theme.danger(), theme.text_1())
    } else {
        (
            theme.surface_elevated(),
            theme.border_subtle(),
            theme.text_2(),
        )
    };
    (
        tabs_resolve_tone(fill, opacity, theme.surface_1()),
        tabs_resolve_tone(border, opacity, fill),
        tabs_resolve_tone(text, opacity, fill),
    )
}

#[cfg(target_arch = "wasm32")]
fn spawn_textarea_primitives(
    parent: &mut ChildSpawnerCommands,
    variant: &BevyUiStoryVariant,
    fonts: &StoryFonts,
    available_width: f32,
    inline_size: f32,
) {
    let UiStoryModel::Textarea(model) = &variant.model else {
        return;
    };
    let theme = variant.theme_id.palette();
    let state = model.state();
    let render_nodes = textarea_render_nodes(model, &state);
    let invalid = model.error.is_some();
    let border_width = theme.border.max(1.0);
    let metrics = textarea_layout_metrics(model, available_width, inline_size, border_width);
    let dense_root =
        textarea_uses_dense_root_metrics(model.density, model.loading, model.disabled, invalid);
    let root_opacity = textarea_root_opacity(model);
    let root_fill_tone = if model.disabled || model.loading {
        theme.surface_2()
    } else if invalid {
        theme.error_soft()
    } else {
        theme.surface_1()
    };
    let root_border_tone = if model.disabled {
        theme.border_muted()
    } else if invalid {
        theme.danger()
    } else {
        theme.border_subtle()
    };
    let root_id = parent
        .spawn((
            Node {
                display: Display::Grid,
                width: percent(100),
                max_width: px(metrics.width),
                min_width: px(0.0),
                padding: UiRect::all(px(metrics.root_padding)),
                border: UiRect::all(px(border_width)),
                border_radius: BorderRadius::all(px(if dense_root {
                    theme.radius_field
                } else {
                    theme.radius_box
                })),
                grid_template_columns: RepeatedGridTrack::fr(1, 1.0),
                grid_auto_rows: GridTrack::auto(),
                row_gap: px(metrics.root_gap),
                align_items: AlignItems::Stretch,
                justify_self: JustifySelf::Start,
                ..default()
            },
            BackgroundColor(textarea_resolve_tone(
                root_fill_tone,
                root_opacity,
                theme.surface_1(),
            )),
            BorderColor::all(textarea_resolve_tone(
                root_border_tone,
                root_opacity,
                theme.surface_1(),
            )),
            if model.disabled {
                BoxShadow::default()
            } else {
                bevy_shadow_1(&theme, inline_size)
            },
        ))
        .id();
    let mut commands = parent.commands();
    let root_node = render_nodes
        .iter()
        .find(|node| node.part == TextareaPart::Root)
        .expect("invariant: textarea render nodes include root");
    let label_id = commands
        .spawn((
            ChildOf(root_id),
            Node {
                width: percent(100),
                min_width: px(0.0),
                min_height: px(metrics.label_font_size * metrics.label_line_height),
                align_items: AlignItems::Center,
                column_gap: px(metrics.root_gap),
                ..default()
            },
        ))
        .id();
    commands.spawn((
        ChildOf(label_id),
        Text::new(root_node.label.clone()),
        TextFont {
            font: fonts.inter.clone().into(),
            font_size: FontSize::Px(metrics.label_font_size),
            weight: FontWeight::BOLD,
            ..default()
        },
        LineHeight::RelativeToFont(metrics.label_line_height),
        TextColor(textarea_resolve_tone(
            if model.disabled {
                theme.text_disabled()
            } else {
                theme.text_1()
            },
            root_opacity,
            root_fill_tone,
        )),
        TextLayout::new(Justify::Left, LineBreak::WordOrCharacter),
    ));
    if model.required {
        commands.spawn((
            ChildOf(label_id),
            Text::new("*"),
            TextFont {
                font: fonts.inter.clone().into(),
                font_size: FontSize::Px(metrics.label_font_size),
                weight: FontWeight::BOLD,
                ..default()
            },
            LineHeight::RelativeToFont(metrics.label_line_height),
            TextColor(textarea_resolve_tone(
                theme.danger(),
                root_opacity,
                root_fill_tone,
            )),
            TextLayout::new(Justify::Left, LineBreak::NoWrap),
        ));
    }

    let control_node = render_nodes
        .iter()
        .find(|node| node.part == TextareaPart::Control)
        .expect("invariant: textarea render nodes include control");
    let (control_fill, control_border, control_text) =
        textarea_control_colors(model, &state, state.value().is_empty(), &theme);
    let control_id = commands
        .spawn((
            ChildOf(root_id),
            Button,
            TextareaControl {
                group: root_id,
                disabled: control_node.disabled,
            },
            Node {
                position_type: PositionType::Relative,
                width: percent(100),
                min_width: px(0.0),
                min_height: px(metrics.control_height),
                padding: UiRect::axes(
                    px(metrics.control_padding_inline),
                    px(metrics.control_padding_block),
                ),
                border: UiRect::all(px(border_width)),
                border_radius: BorderRadius::all(px(theme.radius_field)),
                align_items: AlignItems::FlexStart,
                justify_content: JustifyContent::FlexStart,
                overflow: Overflow::clip(),
                ..default()
            },
            BackgroundColor(control_fill),
            BorderColor::all(control_border),
            Outline::new(px(border_width * 2.0), px(border_width * 2.0), Color::NONE),
            BoxShadow::default(),
        ))
        .id();
    let value_text_id = commands
        .spawn((
            ChildOf(control_id),
            Node {
                width: percent(100),
                min_width: px(0.0),
                ..default()
            },
            Text::new(textarea_control_copy(model, &state)),
            TextFont {
                font: fonts.inter.clone().into(),
                font_size: FontSize::Px(metrics.control_font_size),
                weight: FontWeight::NORMAL,
                ..default()
            },
            LineHeight::RelativeToFont(metrics.control_line_height),
            TextColor(control_text),
            TextLayout::new(Justify::Left, LineBreak::WordOrCharacter),
        ))
        .id();

    let resize_handle_size = scale::space::xs2(inline_size);
    let resize_handle_id = commands
        .spawn((
            ChildOf(control_id),
            Button,
            TextareaResizeHandle {
                group: root_id,
                disabled: control_node.disabled,
            },
            Node {
                position_type: PositionType::Absolute,
                right: px(0.0),
                bottom: px(0.0),
                width: px(resize_handle_size),
                height: px(resize_handle_size),
                min_width: px(resize_handle_size),
                min_height: px(resize_handle_size),
                justify_content: JustifyContent::FlexEnd,
                align_items: AlignItems::FlexEnd,
                ..default()
            },
            BackgroundColor(Color::NONE),
            Text::new("//"),
            TextFont {
                font: fonts.inter.clone().into(),
                font_size: FontSize::Px(scale::font_size::F000),
                weight: FontWeight::SEMIBOLD,
                ..default()
            },
            TextColor(textarea_resolve_tone(
                if control_node.disabled {
                    theme.text_disabled()
                } else {
                    theme.text_muted()
                },
                textarea_control_opacity(model),
                if model.loading || model.disabled {
                    theme.surface_2()
                } else if invalid {
                    theme.error_soft()
                } else {
                    theme.surface_1()
                },
            )),
            TextLayout::new(Justify::Right, LineBreak::NoWrap),
        ))
        .id();

    let meta_id = commands
        .spawn((
            ChildOf(root_id),
            Node {
                width: percent(100),
                min_width: px(0.0),
                flex_direction: FlexDirection::Row,
                flex_wrap: FlexWrap::Wrap,
                align_items: AlignItems::FlexStart,
                justify_content: JustifyContent::SpaceBetween,
                row_gap: px(metrics.meta_gap),
                column_gap: px(metrics.meta_gap),
                ..default()
            },
        ))
        .id();
    let hint_node = render_nodes
        .iter()
        .find(|node| node.part == TextareaPart::Hint)
        .expect("invariant: textarea render nodes include hint");
    let hint_id = commands
        .spawn((
            ChildOf(meta_id),
            Node {
                min_width: px(0.0),
                flex_grow: 1.0,
                flex_basis: px(180.0),
                ..default()
            },
            Text::new(hint_node.detail.clone()),
            TextFont {
                font: fonts.inter.clone().into(),
                font_size: FontSize::Px(metrics.hint_font_size),
                weight: FontWeight::NORMAL,
                ..default()
            },
            LineHeight::RelativeToFont(metrics.hint_line_height),
            TextColor(textarea_hint_color(model, &theme)),
            TextLayout::new(Justify::Left, LineBreak::WordOrCharacter),
        ))
        .id();
    let counter_node = render_nodes
        .iter()
        .find(|node| node.part == TextareaPart::Counter)
        .expect("invariant: textarea render nodes include counter");
    let counter_width = textarea_counter_width(&counter_node.label, &metrics);
    let (counter_fill, counter_text, counter_weight) =
        textarea_counter_colors(model, &state, &theme);
    let counter_id = commands
        .spawn((
            ChildOf(meta_id),
            Node {
                width: px(counter_width),
                min_width: px(counter_width),
                max_width: px(counter_width),
                flex_shrink: 0.0,
                padding: UiRect::axes(
                    px(metrics.counter_padding_inline),
                    px(metrics.counter_padding_block),
                ),
                border_radius: BorderRadius::all(px(scale::radius::PILL)),
                justify_content: JustifyContent::Center,
                align_items: AlignItems::Center,
                ..default()
            },
            BackgroundColor(counter_fill),
            Text::new(counter_node.label.clone()),
            TextFont {
                font: fonts.inter.clone().into(),
                font_size: FontSize::Px(metrics.counter_font_size),
                weight: counter_weight,
                ..default()
            },
            LineHeight::RelativeToFont(metrics.counter_line_height),
            TextColor(counter_text),
            TextLayout::new(Justify::Center, LineBreak::NoWrap),
        ))
        .id();
    commands.entity(root_id).insert(TextareaStoryState {
        model: model.clone(),
        state,
        focus_visible: false,
        control: control_id,
        value_text: value_text_id,
        resize_handle: resize_handle_id,
        hint: hint_id,
        counter: counter_id,
        theme,
        metrics,
        control_height: metrics.control_height,
        resizing: false,
        inline_size,
    });
}

#[cfg(target_arch = "wasm32")]
fn textarea_resolve_tone(tone: Tone, opacity: f32, backdrop: Tone) -> Color {
    tone.with_opacity(opacity).to_bevy_css_alpha_on(backdrop)
}

#[cfg(target_arch = "wasm32")]
fn textarea_root_opacity(model: &TextareaModel) -> f32 {
    if model.disabled {
        scale::opacity::DISABLED
    } else {
        1.0
    }
}

#[cfg(target_arch = "wasm32")]
fn textarea_control_opacity(model: &TextareaModel) -> f32 {
    let local = if model.loading || model.disabled {
        scale::opacity::DISABLED
    } else {
        1.0
    };
    textarea_root_opacity(model) * local
}

#[cfg(target_arch = "wasm32")]
fn textarea_control_copy(model: &TextareaModel, state: &TextareaState) -> String {
    if state.value().is_empty() {
        if model.loading {
            "Loading draft".to_owned()
        } else {
            model.placeholder.clone()
        }
    } else {
        state.value().to_owned()
    }
}

#[cfg(target_arch = "wasm32")]
fn textarea_control_colors(
    model: &TextareaModel,
    state: &TextareaState,
    placeholder: bool,
    theme: &Theme,
) -> (Color, Color, Color) {
    let blocked = model.loading || model.disabled;
    let invalid = model.error.is_some();
    let opacity = textarea_control_opacity(model);
    let root_fill = if model.disabled || model.loading {
        theme.surface_2()
    } else if invalid {
        theme.error_soft()
    } else {
        theme.surface_1()
    };
    let (fill, border, text) = if blocked {
        (
            theme.surface_2(),
            theme.border_muted(),
            theme.text_disabled(),
        )
    } else if invalid {
        (theme.error_soft(), theme.danger(), theme.text_1())
    } else if state.is_focused() {
        (theme.surface_1(), theme.brand(), theme.text_1())
    } else {
        (
            theme.surface_1(),
            theme.border_strong(),
            if placeholder {
                theme.text_muted()
            } else {
                theme.text_1()
            },
        )
    };
    (
        textarea_resolve_tone(fill, opacity, root_fill),
        textarea_resolve_tone(border, opacity, fill),
        textarea_resolve_tone(text, opacity, fill),
    )
}

#[cfg(target_arch = "wasm32")]
fn textarea_hint_color(model: &TextareaModel, theme: &Theme) -> Color {
    let root_fill = if model.disabled || model.loading {
        theme.surface_2()
    } else if model.error.is_some() {
        theme.error_soft()
    } else {
        theme.surface_1()
    };
    textarea_resolve_tone(
        if model.disabled {
            theme.text_disabled()
        } else if model.error.is_some() {
            theme.danger()
        } else {
            theme.text_2()
        },
        textarea_root_opacity(model),
        root_fill,
    )
}

#[cfg(target_arch = "wasm32")]
fn textarea_counter_colors(
    model: &TextareaModel,
    state: &TextareaState,
    theme: &Theme,
) -> (Color, Color, FontWeight) {
    let limit = model.error.is_some()
        || model
            .max_length
            .is_some_and(|max_length| state.current_length() >= usize::from(max_length));
    let root_fill = if model.disabled || model.loading {
        theme.surface_2()
    } else if model.error.is_some() {
        theme.error_soft()
    } else {
        theme.surface_1()
    };
    let (fill, text, weight) = if model.disabled {
        (
            theme.surface_2(),
            theme.text_disabled(),
            FontWeight::SEMIBOLD,
        )
    } else if limit {
        (theme.warning_soft(), theme.text_1(), FontWeight::BOLD)
    } else {
        (theme.surface_2(), theme.text_muted(), FontWeight::SEMIBOLD)
    };
    (
        textarea_resolve_tone(fill, textarea_root_opacity(model), root_fill),
        textarea_resolve_tone(text, textarea_root_opacity(model), fill),
        weight,
    )
}

#[cfg(target_arch = "wasm32")]
fn spawn_typography_primitives(
    parent: &mut ChildSpawnerCommands,
    variant: &BevyUiStoryVariant,
    fonts: &StoryFonts,
    available_width: f32,
    inline_size: f32,
) {
    let UiStoryModel::Typography(model) = &variant.model else {
        return;
    };
    let theme = variant.theme_id.palette();
    let state = model.state();
    let render_nodes = typography_render_nodes(model, &state);
    let metrics = typography_layout_metrics(model, &state, available_width, inline_size);
    let border_width = theme.border.max(1.0);
    let blocked = model.loading || model.disabled;
    let h1 = render_nodes
        .iter()
        .find(|node| node.part == TypographyPart::H1)
        .expect("invariant: typography render nodes include h1");
    let h2 = render_nodes
        .iter()
        .find(|node| node.part == TypographyPart::H2)
        .expect("invariant: typography render nodes include h2");
    let paragraph = render_nodes
        .iter()
        .find(|node| node.part == TypographyPart::P)
        .expect("invariant: typography render nodes include paragraph");
    let list_items = render_nodes
        .iter()
        .filter(|node| node.part == TypographyPart::List && node.index.is_some())
        .collect::<Vec<_>>();
    let blockquote = render_nodes
        .iter()
        .find(|node| node.part == TypographyPart::Blockquote)
        .expect("invariant: typography render nodes include blockquote");
    let (root_fill, root_border) = typography_root_colors(model, &state, &theme);
    let root_id = parent
        .spawn((
            Button,
            Node {
                display: Display::Grid,
                width: percent(100),
                max_width: px(metrics.width),
                min_width: px(0.0),
                padding: UiRect::all(px(metrics.root_padding)),
                border: if metrics.root_framed {
                    UiRect::all(px(border_width))
                } else {
                    UiRect::ZERO
                },
                border_radius: BorderRadius::all(px(theme.radius_box)),
                grid_template_columns: RepeatedGridTrack::fr(1, 1.0),
                grid_auto_rows: GridTrack::auto(),
                align_items: AlignItems::Stretch,
                align_content: AlignContent::Stretch,
                row_gap: px(metrics.root_gap),
                ..default()
            },
            BackgroundColor(root_fill),
            BorderColor::all(root_border),
        ))
        .id();
    let mut commands = parent.commands();
    let h1_id = commands
        .spawn((
            ChildOf(root_id),
            Button,
            typography_text_node(),
            Text::new(h1.label.clone()),
            TextFont {
                font: fonts.inter.clone().into(),
                font_size: FontSize::Px(metrics.h1_font_size),
                weight: FontWeight::EXTRA_BOLD,
                ..default()
            },
            LineHeight::RelativeToFont(metrics.h1_line_height),
            TextColor(typography_h1_color(model, &state, &theme)),
            TextLayout::new(Justify::Left, LineBreak::WordOrCharacter),
        ))
        .id();
    let h2_id = commands
        .spawn((
            ChildOf(root_id),
            Button,
            typography_text_node(),
            Text::new(h2.label.clone()),
            TextFont {
                font: fonts.inter.clone().into(),
                font_size: FontSize::Px(metrics.h2_font_size),
                weight: FontWeight::BOLD,
                ..default()
            },
            LineHeight::RelativeToFont(metrics.h2_line_height),
            TextColor(typography_h2_color(model, &state, &theme)),
            TextLayout::new(Justify::Left, LineBreak::WordOrCharacter),
        ))
        .id();
    let paragraph_id = commands
        .spawn((
            ChildOf(root_id),
            Button,
            typography_text_node(),
            Text::new(paragraph.detail.clone()),
            TextFont {
                font: fonts.inter.clone().into(),
                font_size: FontSize::Px(metrics.paragraph_font_size),
                weight: FontWeight::NORMAL,
                ..default()
            },
            LineHeight::RelativeToFont(metrics.paragraph_line_height),
            TextColor(typography_paragraph_color(model, &state, &theme)),
            TextLayout::new(Justify::Left, LineBreak::WordOrCharacter),
        ))
        .id();
    let list_id = commands
        .spawn((
            ChildOf(root_id),
            Node {
                display: Display::Grid,
                width: percent(100),
                min_width: px(0.0),
                padding: UiRect::left(px(metrics.list_padding_start)),
                grid_template_columns: RepeatedGridTrack::fr(1, 1.0),
                grid_auto_rows: GridTrack::auto(),
                align_items: AlignItems::Stretch,
                row_gap: px(metrics.list_gap),
                ..default()
            },
        ))
        .id();
    let mut list_item_entities = Vec::with_capacity(list_items.len());
    for (index, item) in list_items.into_iter().enumerate() {
        let disabled = blocked || item.disabled;
        let color = typography_list_item_color(model, &state, index, item.disabled, &theme);
        let weight = typography_list_item_weight(model, &state, index, item.disabled);
        let row_id = commands
            .spawn((
                ChildOf(list_id),
                Button,
                Node {
                    position_type: PositionType::Relative,
                    width: percent(100),
                    min_width: px(0.0),
                    padding: UiRect::left(px(metrics.list_item_padding_start)),
                    ..default()
                },
            ))
            .id();
        let bullet_id = commands
            .spawn((
                ChildOf(row_id),
                Node {
                    position_type: PositionType::Absolute,
                    left: px(-metrics.list_padding_start),
                    width: px(metrics.list_item_padding_start),
                    min_width: px(metrics.list_item_padding_start),
                    max_width: px(metrics.list_item_padding_start),
                    ..default()
                },
                Text::new("•"),
                TextFont {
                    font: fonts.inter.clone().into(),
                    font_size: FontSize::Px(metrics.list_font_size),
                    weight,
                    ..default()
                },
                LineHeight::RelativeToFont(metrics.list_line_height),
                TextColor(color),
                TextLayout::new(Justify::Center, LineBreak::NoWrap),
            ))
            .id();
        let label_id = commands
            .spawn((
                ChildOf(row_id),
                typography_text_node(),
                Text::new(item.label.clone()),
                TextFont {
                    font: fonts.inter.clone().into(),
                    font_size: FontSize::Px(metrics.list_font_size),
                    weight,
                    ..default()
                },
                LineHeight::RelativeToFont(metrics.list_line_height),
                TextColor(color),
                TextLayout::new(Justify::Left, LineBreak::WordOrCharacter),
            ))
            .id();
        commands.entity(row_id).insert(TypographyControl {
            group: root_id,
            target: TypographyTarget::ListItem(index),
            disabled,
        });
        list_item_entities.push(TypographyListItemEntities {
            row: row_id,
            bullet: bullet_id,
            label: label_id,
            disabled,
        });
    }
    let (blockquote_fill, blockquote_border, blockquote_text) =
        typography_blockquote_colors(model, &state, &theme);
    let blockquote_id = commands
        .spawn((
            ChildOf(root_id),
            Button,
            Node {
                width: percent(100),
                min_width: px(0.0),
                padding: UiRect::left(px(metrics.blockquote_padding_start)),
                border: UiRect::left(px(border_width)),
                ..default()
            },
            BackgroundColor(blockquote_fill),
            BorderColor::all(blockquote_border),
            Text::new(blockquote.detail.clone()),
            TextFont {
                font: fonts.inter.clone().into(),
                font_size: FontSize::Px(metrics.blockquote_font_size),
                weight: typography_blockquote_weight(model, &state),
                ..default()
            },
            LineHeight::RelativeToFont(metrics.blockquote_line_height),
            TextColor(blockquote_text),
            TextLayout::new(Justify::Left, LineBreak::WordOrCharacter),
        ))
        .id();

    for (entity, part) in [
        (root_id, TypographyPart::Root),
        (h1_id, TypographyPart::H1),
        (h2_id, TypographyPart::H2),
        (paragraph_id, TypographyPart::P),
        (blockquote_id, TypographyPart::Blockquote),
    ] {
        commands.entity(entity).insert(TypographyControl {
            group: root_id,
            target: TypographyTarget::Part(part),
            disabled: blocked,
        });
    }
    commands.entity(root_id).insert(TypographyStoryState {
        model: model.clone(),
        state,
        root: root_id,
        h1: h1_id,
        h2: h2_id,
        paragraph: paragraph_id,
        list: list_id,
        list_items: list_item_entities,
        blockquote: blockquote_id,
        theme,
        hovered: None,
        available_width,
        inline_size,
    });
}

#[cfg(target_arch = "wasm32")]
fn typography_text_node() -> Node {
    Node {
        width: percent(100),
        min_width: px(0.0),
        ..default()
    }
}

#[cfg(target_arch = "wasm32")]
fn typography_root_backdrop(
    model: &TypographyModel,
    state: &TypographyState,
    theme: &Theme,
) -> Tone {
    if model.loading {
        theme.info_soft()
    } else if model.error.is_some() {
        theme.error_soft()
    } else if state.is_active(TypographyPart::Root) && !model.disabled {
        theme.selected_tint()
    } else {
        theme.surface_1()
    }
}

#[cfg(target_arch = "wasm32")]
fn typography_root_opacity(model: &TypographyModel) -> f32 {
    if model.disabled {
        scale::opacity::DISABLED
    } else {
        1.0
    }
}

#[cfg(target_arch = "wasm32")]
fn typography_resolve_tone(tone: Tone, model: &TypographyModel, backdrop: Tone) -> Color {
    tone.with_opacity(typography_root_opacity(model))
        .to_bevy_css_alpha_on(backdrop)
}

#[cfg(target_arch = "wasm32")]
fn typography_root_colors(
    model: &TypographyModel,
    state: &TypographyState,
    theme: &Theme,
) -> (Color, Color) {
    if model.disabled {
        return (Color::NONE, Color::NONE);
    }
    if model.loading {
        return (
            theme.info_soft().to_bevy_css_alpha_on(theme.surface_1()),
            theme.info.to_bevy(),
        );
    }
    if model.error.is_some() {
        return (
            theme.error_soft().to_bevy_css_alpha_on(theme.surface_1()),
            theme.danger().to_bevy(),
        );
    }
    if state.is_active(TypographyPart::Root) {
        return (
            theme
                .selected_tint()
                .to_bevy_css_alpha_on(theme.surface_1()),
            Color::NONE,
        );
    }
    (Color::NONE, Color::NONE)
}

#[cfg(target_arch = "wasm32")]
fn typography_h1_color(model: &TypographyModel, state: &TypographyState, theme: &Theme) -> Color {
    let tone = if model.disabled {
        theme.text_disabled()
    } else if state.is_active(TypographyPart::H1) {
        theme.brand()
    } else {
        theme.text_1()
    };
    typography_resolve_tone(tone, model, typography_root_backdrop(model, state, theme))
}

#[cfg(target_arch = "wasm32")]
fn typography_h2_color(model: &TypographyModel, state: &TypographyState, theme: &Theme) -> Color {
    let tone = if model.disabled {
        theme.text_disabled()
    } else if state.is_active(TypographyPart::H2) {
        theme.brand()
    } else {
        theme.text_1()
    };
    typography_resolve_tone(tone, model, typography_root_backdrop(model, state, theme))
}

#[cfg(target_arch = "wasm32")]
fn typography_paragraph_color(
    model: &TypographyModel,
    state: &TypographyState,
    theme: &Theme,
) -> Color {
    let tone = if model.disabled {
        theme.text_disabled()
    } else if model.error.is_some() {
        theme.danger()
    } else if state.is_active(TypographyPart::P) {
        theme.text_1()
    } else {
        theme.text_2()
    };
    typography_resolve_tone(tone, model, typography_root_backdrop(model, state, theme))
}

#[cfg(target_arch = "wasm32")]
fn typography_list_item_color(
    model: &TypographyModel,
    state: &TypographyState,
    index: usize,
    item_disabled: bool,
    theme: &Theme,
) -> Color {
    let disabled = model.loading || model.disabled || item_disabled;
    let tone = if disabled {
        theme.text_disabled()
    } else if model.error.is_some() {
        theme.danger()
    } else if state.is_list_item_active(index) {
        theme.brand()
    } else {
        theme.text_2()
    };
    typography_resolve_tone(tone, model, typography_root_backdrop(model, state, theme))
}

#[cfg(target_arch = "wasm32")]
fn typography_list_item_weight(
    model: &TypographyModel,
    state: &TypographyState,
    index: usize,
    item_disabled: bool,
) -> FontWeight {
    let disabled = model.loading || model.disabled || item_disabled;
    if disabled {
        FontWeight::NORMAL
    } else if model.error.is_some() || state.is_list_item_active(index) {
        FontWeight::BOLD
    } else {
        FontWeight::NORMAL
    }
}

#[cfg(target_arch = "wasm32")]
fn typography_blockquote_colors(
    model: &TypographyModel,
    state: &TypographyState,
    theme: &Theme,
) -> (Color, Color, Color) {
    let root_backdrop = typography_root_backdrop(model, state, theme);
    let active =
        state.is_active(TypographyPart::Blockquote) && !model.disabled && model.error.is_none();
    let fill_tone = if active {
        Some(theme.primary_soft())
    } else {
        None
    };
    let border_tone = if model.disabled {
        theme.border_muted()
    } else if model.error.is_some() {
        theme.danger()
    } else {
        theme.brand()
    };
    let text_tone = if model.disabled {
        theme.text_disabled()
    } else if model.error.is_some() {
        theme.danger()
    } else {
        theme.text_1()
    };
    let text_backdrop = fill_tone.unwrap_or(root_backdrop);
    (
        fill_tone.map_or(Color::NONE, |tone| {
            typography_resolve_tone(tone, model, root_backdrop)
        }),
        typography_resolve_tone(border_tone, model, root_backdrop),
        typography_resolve_tone(text_tone, model, text_backdrop),
    )
}

#[cfg(target_arch = "wasm32")]
fn typography_blockquote_weight(model: &TypographyModel, state: &TypographyState) -> FontWeight {
    if !model.disabled && (model.error.is_some() || state.is_active(TypographyPart::Blockquote)) {
        FontWeight::BOLD
    } else {
        FontWeight::SEMIBOLD
    }
}

#[cfg(target_arch = "wasm32")]
const fn component_is_control_row(id: UiComponentId) -> bool {
    matches!(bevy_ui_flow(id), BevyUiFlow::ControlRow)
}

#[cfg(target_arch = "wasm32")]
fn spawn_control_row_primitives(
    parent: &mut ChildSpawnerCommands,
    id: UiComponentId,
    variant: &BevyUiStoryVariant,
    fonts: &StoryFonts,
) {
    let theme = variant.theme_id.palette();
    let Some(root) = story_root(variant) else {
        return;
    };
    if matches!(
        id,
        UiComponentId::Badge
            | UiComponentId::Button
            | UiComponentId::Label
            | UiComponentId::Marker
            | UiComponentId::Toggle
    ) {
        let primary = variant
            .primitives
            .iter()
            .rev()
            .find(|primitive| {
                !matches!(
                    primitive.kind,
                    UiWidgetSlotKind::Section | UiWidgetSlotKind::Marker
                )
            })
            .unwrap_or(root);
        let interactive = primary.intent != UiWidgetIntent::None && !primary.disabled;
        let background = root.fill;
        let mut entity = parent.spawn((
            Node {
                width: percent(100),
                min_width: px(0.0),
                min_height: px(root.size.y.max(scale::space::M)),
                padding: UiRect::axes(px(scale::space::XS), px(scale::space::XS2)),
                border: UiRect::all(px(theme.border.max(1.0))),
                border_radius: if id == UiComponentId::Badge {
                    BorderRadius::MAX
                } else {
                    BorderRadius::all(px(theme.radius_field))
                },
                justify_content: JustifyContent::Center,
                align_items: AlignItems::Center,
                ..default()
            },
            BackgroundColor(background),
            BorderColor::all(if primary.selected {
                theme.brand().to_bevy()
            } else {
                theme.border_subtle().to_bevy()
            }),
            Text::new(primary.label.clone()),
            TextFont {
                font: fonts.inter.clone().into(),
                font_size: FontSize::Px(if id == UiComponentId::Badge {
                    scale::font_size::F00
                } else {
                    scale::font_size::F0
                }),
                weight: FontWeight::BOLD,
                ..default()
            },
            TextColor(if primary.disabled {
                theme.text_disabled().to_bevy()
            } else {
                primary.text
            }),
            TextLayout::new(Justify::Center, LineBreak::WordOrCharacter),
        ));
        if interactive {
            entity.insert((
                Button,
                InteractivePrimitive::stateful(
                    background,
                    theme.selected_tint().to_bevy(),
                    primary.selected,
                    &theme,
                ),
            ));
        }
        return;
    }

    parent
        .spawn((
            Node {
                width: percent(100),
                min_width: px(0.0),
                min_height: px(scale::space::L),
                padding: UiRect::all(px(scale::space::XS2)),
                border: UiRect::all(px(theme.border.max(1.0))),
                border_radius: BorderRadius::all(px(theme.radius_field)),
                flex_direction: FlexDirection::Row,
                flex_wrap: FlexWrap::Wrap,
                align_items: AlignItems::Center,
                row_gap: px(scale::space::XS3),
                column_gap: px(scale::space::XS3),
                ..default()
            },
            BackgroundColor(root.fill),
            BorderColor::all(theme.border_subtle().to_bevy()),
        ))
        .with_children(|row| {
            for primitive in variant.primitives.iter().skip(1).filter(|primitive| {
                !matches!(
                    primitive.kind,
                    UiWidgetSlotKind::Section | UiWidgetSlotKind::List | UiWidgetSlotKind::ListItem
                ) && primitive.role != UiBlockRole::Layout
            }) {
                spawn_row_primitive(row, primitive, &theme, fonts);
            }
        });
}

#[cfg(target_arch = "wasm32")]
fn spawn_row_primitive(
    parent: &mut ChildSpawnerCommands,
    primitive: &BevyUiPrimitive,
    theme: &Theme,
    fonts: &StoryFonts,
) {
    let grow = matches!(
        primitive.kind,
        UiWidgetSlotKind::Input | UiWidgetSlotKind::Select | UiWidgetSlotKind::Text
    );
    let background = primitive_background(primitive);
    let interactive = primitive.intent != UiWidgetIntent::None && !primitive.disabled;
    let mut entity = parent.spawn((
        Node {
            min_width: px(if grow { 120.0 } else { scale::space::S }),
            flex_grow: if grow { 1.0 } else { 0.0 },
            min_height: px(primitive_min_height(primitive)),
            padding: primitive_padding(primitive.kind),
            border: if primitive_has_border(primitive.kind) {
                UiRect::all(px(theme.border.max(1.0)))
            } else {
                UiRect::ZERO
            },
            border_radius: primitive_radius(primitive.kind, theme),
            justify_content: primitive_justify(primitive.kind),
            align_items: AlignItems::Center,
            ..default()
        },
        BackgroundColor(background),
        BorderColor::all(if primitive.selected {
            theme.brand().to_bevy()
        } else {
            theme.border_subtle().to_bevy()
        }),
        Text::new(primitive_copy(primitive)),
        TextFont {
            font: fonts.inter.clone().into(),
            font_size: FontSize::Px(primitive_font_size(UiComponentId::Button, primitive)),
            weight: primitive_font_weight(primitive),
            ..default()
        },
        TextColor(if primitive.disabled {
            theme.text_disabled().to_bevy()
        } else {
            primitive.text
        }),
        TextLayout::new(Justify::Left, LineBreak::WordOrCharacter),
    ));
    if interactive {
        entity.insert((
            Button,
            InteractivePrimitive::stateful(
                background,
                theme.selected_tint().to_bevy(),
                primitive.selected,
                theme,
            ),
        ));
    }
}

#[cfg(target_arch = "wasm32")]
fn spawn_stack_primitives(
    parent: &mut ChildSpawnerCommands,
    id: UiComponentId,
    variant: &BevyUiStoryVariant,
    fonts: &StoryFonts,
) {
    let theme = variant.theme_id.palette();
    let Some(root) = story_root(variant) else {
        return;
    };
    parent
        .spawn((
            Node {
                width: percent(100),
                min_width: px(0.0),
                min_height: px(scale::space::L),
                padding: UiRect::all(px(scale::space::XS)),
                border: UiRect::all(px(theme.border.max(1.0))),
                border_radius: BorderRadius::all(px(theme.radius_box)),
                flex_direction: FlexDirection::Column,
                align_items: AlignItems::Start,
                row_gap: px(scale::space::XS2),
                ..default()
            },
            BackgroundColor(if component_is_overlay(id) {
                theme.surface_1().to_bevy()
            } else {
                root.fill
            }),
            BorderColor::all(theme.border_subtle().to_bevy()),
        ))
        .with_children(|stack| {
            for primitive in variant.primitives.iter().skip(1) {
                if matches!(
                    primitive.kind,
                    UiWidgetSlotKind::List
                        | UiWidgetSlotKind::ListItem
                        | UiWidgetSlotKind::Overlay
                        | UiWidgetSlotKind::Row
                        | UiWidgetSlotKind::Section
                        | UiWidgetSlotKind::Table
                ) || primitive.role == UiBlockRole::Layout
                {
                    continue;
                }
                if matches!(
                    primitive.kind,
                    UiWidgetSlotKind::Header | UiWidgetSlotKind::Panel
                ) {
                    let copy = if !primitive.value.is_empty() && primitive.value != primitive.label
                    {
                        primitive.value.clone()
                    } else {
                        primitive.label.clone()
                    };
                    stack.spawn((
                        Node {
                            width: percent(100),
                            min_width: px(0.0),
                            padding: if primitive.kind == UiWidgetSlotKind::Panel {
                                UiRect::all(px(scale::space::XS2))
                            } else {
                                UiRect::ZERO
                            },
                            border: if primitive.kind == UiWidgetSlotKind::Panel {
                                UiRect::all(px(theme.border.max(1.0)))
                            } else {
                                UiRect::ZERO
                            },
                            border_radius: BorderRadius::all(px(theme.radius_field)),
                            ..default()
                        },
                        BackgroundColor(if primitive.kind == UiWidgetSlotKind::Panel {
                            primitive.fill
                        } else {
                            Color::NONE
                        }),
                        BorderColor::all(theme.border_subtle().to_bevy()),
                        Text::new(copy),
                        TextFont {
                            font: fonts.inter.clone().into(),
                            font_size: FontSize::Px(
                                if primitive.kind == UiWidgetSlotKind::Header {
                                    scale::font_size::F1
                                } else {
                                    scale::font_size::F0
                                },
                            ),
                            weight: if primitive.kind == UiWidgetSlotKind::Header {
                                FontWeight::BOLD
                            } else {
                                FontWeight::NORMAL
                            },
                            ..default()
                        },
                        TextColor(if primitive.disabled {
                            theme.text_disabled().to_bevy()
                        } else {
                            primitive.text
                        }),
                        TextLayout::new(Justify::Left, LineBreak::WordOrCharacter),
                    ));
                    continue;
                }
                spawn_primitive(stack, id, primitive, &theme, fonts);
            }
        });
}

#[cfg(target_arch = "wasm32")]
fn story_root(variant: &BevyUiStoryVariant) -> Option<&BevyUiPrimitive> {
    variant
        .primitives
        .iter()
        .find(|primitive| primitive.role == UiBlockRole::Root)
        .or_else(|| variant.primitives.first())
}

#[cfg(target_arch = "wasm32")]
const fn component_is_overlay(id: UiComponentId) -> bool {
    matches!(
        id,
        UiComponentId::AlertDialog
            | UiComponentId::ContextMenu
            | UiComponentId::Dialog
            | UiComponentId::Drawer
            | UiComponentId::DropdownMenu
            | UiComponentId::HoverCard
            | UiComponentId::Popover
            | UiComponentId::Select
            | UiComponentId::Sheet
            | UiComponentId::Tooltip
    )
}

#[cfg(target_arch = "wasm32")]
fn spawn_primitive(
    parent: &mut ChildSpawnerCommands,
    id: UiComponentId,
    primitive: &BevyUiPrimitive,
    theme: &Theme,
    fonts: &StoryFonts,
) {
    if primitive.kind == UiWidgetSlotKind::Separator {
        if id == UiComponentId::Breadcrumb {
            spawn_text(
                parent,
                primitive.label.clone(),
                fonts.inter.clone(),
                scale::font_size::F0,
                FontWeight::NORMAL,
                theme.text_muted().to_bevy(),
            );
            return;
        }
        parent.spawn((
            Node {
                width: if primitive.size.x >= primitive.size.y {
                    percent(100)
                } else {
                    px(theme.border.max(1.0))
                },
                height: if primitive.size.x >= primitive.size.y {
                    px(theme.border.max(1.0))
                } else {
                    px(scale::space::L)
                },
                ..default()
            },
            BackgroundColor(primitive.fill),
        ));
        return;
    }

    let full_width = primitive_uses_full_width(id, primitive.kind);
    let compact = primitive_is_compact(primitive.kind);
    let interactive = primitive.intent != UiWidgetIntent::None && !primitive.disabled;
    let copy = primitive_copy(primitive);
    let background = primitive_background(primitive);
    let text_color = if primitive.disabled {
        primitive.text.with_alpha(0.38)
    } else {
        primitive.text
    };
    let font_size = primitive_font_size(id, primitive);
    let weight = primitive_font_weight(primitive);
    let font = fonts.inter.clone();
    let min_height = primitive_min_height(primitive);
    let mut entity = parent.spawn((
        Node {
            width: if full_width { percent(100) } else { auto() },
            max_width: percent(100),
            min_width: if full_width {
                px(0.0)
            } else if compact {
                px(primitive.size.x.max(scale::space::S))
            } else {
                px(primitive.size.x.max(40.0))
            },
            min_height: px(min_height),
            padding: primitive_padding(primitive.kind),
            border: if primitive_has_border(primitive.kind) {
                UiRect::all(px(theme.border.max(1.0)))
            } else {
                UiRect::ZERO
            },
            border_radius: primitive_radius(primitive.kind, theme),
            justify_content: primitive_justify(primitive.kind),
            align_items: AlignItems::Center,
            ..default()
        },
        Text::new(copy),
        TextFont {
            font: font.into(),
            font_size: FontSize::Px(font_size),
            weight,
            ..default()
        },
        TextColor(text_color),
        TextLayout::new(Justify::Left, LineBreak::WordOrCharacter),
        BackgroundColor(background),
        BorderColor::all(if primitive.selected {
            theme.brand().to_bevy()
        } else {
            theme.border_subtle().to_bevy()
        }),
    ));

    if interactive {
        let rest = background;
        entity.insert((
            Button,
            InteractivePrimitive::stateful(
                rest,
                theme.selected_tint().to_bevy(),
                primitive.selected,
                theme,
            ),
        ));
    }
}

#[cfg(target_arch = "wasm32")]
fn centered_text_padding(box_size: f32, font_size: f32, value: &str) -> UiRect {
    let glyph_width = font_size * 0.62;
    let text_width = value.chars().count() as f32 * glyph_width;
    let horizontal = ((box_size - text_width) / 2.0).max(0.0);
    let vertical = ((box_size - font_size * 1.2) / 2.0).max(0.0);
    UiRect::new(px(horizontal), px(horizontal), px(vertical), px(vertical))
}

#[cfg(target_arch = "wasm32")]
fn spawn_text(
    parent: &mut ChildSpawnerCommands,
    value: impl Into<String>,
    font: Handle<Font>,
    font_size: f32,
    weight: FontWeight,
    color: Color,
) {
    spawn_text_with_line_height(
        parent,
        value,
        font,
        font_size,
        weight,
        color,
        scale::line_height::LH0,
    );
}

#[cfg(target_arch = "wasm32")]
fn spawn_text_with_line_height(
    parent: &mut ChildSpawnerCommands,
    value: impl Into<String>,
    font: Handle<Font>,
    font_size: f32,
    weight: FontWeight,
    color: Color,
    line_height: f32,
) {
    parent.spawn((
        Node {
            min_width: px(0.0),
            ..default()
        },
        Text::new(value),
        TextFont {
            font: font.into(),
            font_size: FontSize::Px(font_size),
            weight,
            ..default()
        },
        LineHeight::Px(font_size * line_height),
        TextColor(color),
        TextLayout::new(Justify::Left, LineBreak::WordOrCharacter),
    ));
}

#[cfg(target_arch = "wasm32")]
fn scroll_message_scroller_viewport(
    mut wheel: MessageReader<MouseWheel>,
    hover_map: Res<HoverMap>,
    parents: Query<&ChildOf>,
    viewport_controls: Query<&MessageScrollerViewportControl>,
    mut viewports: Query<(&mut ScrollPosition, &ComputedNode), Without<StoryViewport>>,
    mut groups: Query<&mut MessageScrollerGroup>,
) {
    let delta = wheel
        .read()
        .map(|event| match event.unit {
            MouseScrollUnit::Line => event.y * SCROLL_LINE_HEIGHT,
            MouseScrollUnit::Pixel => event.y,
        })
        .sum::<f32>();
    if delta.abs() <= f32::EPSILON {
        return;
    }
    let Some((viewport, group_entity)) =
        hovered_message_scroller_viewport(&hover_map, &parents, &viewport_controls)
    else {
        return;
    };
    let Ok((mut scroll_position, computed)) = viewports.get_mut(viewport) else {
        return;
    };
    let max_y =
        (computed.content_size().y - computed.size().y).max(0.0) * computed.inverse_scale_factor();
    scroll_position.y = (scroll_position.y - delta).clamp(0.0, max_y);
    if let Ok(mut group) = groups.get_mut(group_entity) {
        group.state.apply(MessageScrollerIntent::SetAtLatest(false));
    }
}

#[cfg(target_arch = "wasm32")]
fn scroll_scroll_area_viewport(
    mut wheel: MessageReader<MouseWheel>,
    hover_map: Res<HoverMap>,
    parents: Query<&ChildOf>,
    viewport_controls: Query<&ScrollAreaViewportControl>,
    mut viewports: Query<(&mut ScrollPosition, &ComputedNode), Without<StoryViewport>>,
) {
    let delta = wheel.read().fold(Vec2::ZERO, |delta, event| {
        let factor = match event.unit {
            MouseScrollUnit::Line => SCROLL_LINE_HEIGHT,
            MouseScrollUnit::Pixel => 1.0,
        };
        delta + Vec2::new(event.x * factor, event.y * factor) * SCROLL_AREA_WHEEL_SCALE
    });
    if delta.length_squared() <= f32::EPSILON {
        return;
    }
    let Some((viewport, control)) =
        hovered_scroll_area_viewport(&hover_map, &parents, &viewport_controls)
    else {
        return;
    };
    if control.disabled {
        return;
    }
    let Ok((mut scroll_position, computed)) = viewports.get_mut(viewport) else {
        return;
    };
    let scale = computed.inverse_scale_factor();
    let max_x = (computed.content_size().x - computed.size().x).max(0.0) * scale;
    let max_y = (computed.content_size().y - computed.size().y).max(0.0) * scale;

    if control.overflow.has_vertical() {
        scroll_position.y = (scroll_position.y - delta.y).clamp(0.0, max_y);
    }
    if control.overflow.has_horizontal() {
        let horizontal_delta = if delta.x.abs() > f32::EPSILON {
            delta.x
        } else if !control.overflow.has_vertical() {
            delta.y
        } else {
            0.0
        };
        scroll_position.x = (scroll_position.x - horizontal_delta).clamp(0.0, max_x);
    }
}

#[cfg(target_arch = "wasm32")]
fn scroll_story_viewport(
    mut wheel: MessageReader<MouseWheel>,
    mut viewport: Query<(&mut ScrollPosition, &ComputedNode), With<StoryViewport>>,
    hover_map: Res<HoverMap>,
    parents: Query<&ChildOf>,
    message_scroller_viewports: Query<&MessageScrollerViewportControl>,
    scroll_area_viewports: Query<&ScrollAreaViewportControl>,
) {
    if hovered_message_scroller_viewport(&hover_map, &parents, &message_scroller_viewports)
        .is_some()
        || hovered_scroll_area_viewport(&hover_map, &parents, &scroll_area_viewports).is_some()
    {
        return;
    }
    let Ok((mut scroll_position, computed)) = viewport.single_mut() else {
        return;
    };
    let max_y =
        (computed.content_size().y - computed.size().y).max(0.0) * computed.inverse_scale_factor();

    for event in wheel.read() {
        let delta = match event.unit {
            MouseScrollUnit::Line => event.y * SCROLL_LINE_HEIGHT,
            MouseScrollUnit::Pixel => event.y,
        };
        scroll_position.y = (scroll_position.y - delta).clamp(0.0, max_y);
    }
}

#[cfg(target_arch = "wasm32")]
fn hovered_scroll_area_viewport(
    hover_map: &HoverMap,
    parents: &Query<&ChildOf>,
    viewports: &Query<&ScrollAreaViewportControl>,
) -> Option<(Entity, ScrollAreaViewportControl)> {
    for hovered in hover_map.0.values() {
        for entity in hovered.keys() {
            let mut current = Some(*entity);
            while let Some(candidate) = current {
                if let Ok(control) = viewports.get(candidate) {
                    return Some((candidate, *control));
                }
                current = parents.get(candidate).ok().map(ChildOf::parent);
            }
        }
    }
    None
}

#[cfg(target_arch = "wasm32")]
fn hovered_message_scroller_viewport(
    hover_map: &HoverMap,
    parents: &Query<&ChildOf>,
    viewports: &Query<&MessageScrollerViewportControl>,
) -> Option<(Entity, Entity)> {
    for hovered in hover_map.0.values() {
        for entity in hovered.keys() {
            let mut current = Some(*entity);
            while let Some(candidate) = current {
                if let Ok(control) = viewports.get(candidate) {
                    return Some((candidate, control.group));
                }
                current = parents.get(candidate).ok().map(ChildOf::parent);
            }
        }
    }
    None
}

#[cfg(target_arch = "wasm32")]
fn update_story_grid_columns(windows: Query<&Window>, mut grids: Query<(&StoryGrid, &mut Node)>) {
    let Ok(window) = windows.single() else {
        return;
    };
    for (grid, mut node) in &mut grids {
        let columns = story_grid_column_count(window.width(), grid.single_column);
        let expected = RepeatedGridTrack::fr(columns, 1.0);
        if node.grid_template_columns != expected {
            node.grid_template_columns = expected;
        }
    }
}

#[cfg(target_arch = "wasm32")]
fn stretch_story_variant_roots(
    cells: Query<&Children, (With<StoryVariantCell>, Changed<Children>)>,
    mut roots: Query<&mut Node, Without<StoryVariantCell>>,
) {
    for children in &cells {
        for child in children.iter() {
            if let Ok(mut root) = roots.get_mut(child) {
                root.flex_grow = 1.0;
            }
        }
    }
}

#[cfg(target_arch = "wasm32")]
fn handle_alert_dialog_presses(
    mut presses: MessageReader<Pointer<Press>>,
    parents: Query<&ChildOf>,
    controls: Query<&AlertDialogControl>,
    mut groups: Query<&mut AlertDialogGroupState>,
) {
    for press in presses.read() {
        let mut current = Some(press.entity);
        while let Some(entity) = current {
            if let Ok(control) = controls.get(entity) {
                if !control.disabled
                    && let Ok(mut group) = groups.get_mut(control.group)
                {
                    match control.part {
                        AlertDialogPart::Trigger => {
                            group.state.apply(AlertDialogIntent::Open);
                        }
                        AlertDialogPart::Action => {
                            let value = group.model.action.value.clone();
                            group.state.apply(AlertDialogIntent::Confirm(value));
                        }
                        AlertDialogPart::Cancel => {
                            group.state.apply(AlertDialogIntent::Cancel);
                        }
                        AlertDialogPart::Root
                        | AlertDialogPart::Content
                        | AlertDialogPart::Header
                        | AlertDialogPart::Footer => {}
                    }
                }
                break;
            }
            current = parents.get(entity).ok().map(ChildOf::parent);
        }
    }
}

