#[cfg(target_arch = "wasm32")]
fn handle_breadcrumb_hover(
    links: Query<(&Interaction, &BreadcrumbLinkControl), Changed<Interaction>>,
    mut groups: Query<&mut BreadcrumbGroupState>,
) {
    for (interaction, link) in &links {
        let Ok(mut group) = groups.get_mut(link.group) else {
            continue;
        };
        match interaction {
            Interaction::Hovered | Interaction::Pressed => {
                group
                    .state
                    .apply(BreadcrumbIntent::Focus(link.value.clone()));
            }
            Interaction::None if group.state.is_active(&link.value) => {
                group.state.apply(BreadcrumbIntent::Clear);
            }
            Interaction::None => {}
        }
    }
}

