#[cfg(target_arch = "wasm32")]
fn handle_tabs_keyboard(
    mut keyboard: MessageReader<KeyboardInput>,
    mut groups: Query<&mut TabsStoryState>,
) {
    for input in keyboard.read() {
        if input.state != ButtonState::Pressed {
            continue;
        }
        for mut group in &mut groups {
            if group.model.loading || group.model.disabled {
                continue;
            }
            let Some(focused_value) = group.state.focused_value().map(str::to_owned) else {
                continue;
            };
            if input.text.as_deref() == Some(" ") {
                group.focus_visible = true;
                group.state.apply(TabsIntent::Select(focused_value));
                continue;
            }
            match &input.logical_key {
                Key::Enter => {
                    group.focus_visible = true;
                    group.state.apply(TabsIntent::Select(focused_value));
                }
                Key::Character(value) if value.as_str() == " " => {
                    group.focus_visible = true;
                    group.state.apply(TabsIntent::Select(focused_value));
                }
                Key::Escape | Key::Tab => {
                    group.focus_visible = false;
                    group.state.apply(TabsIntent::Blur);
                }
                _ => {}
            }
        }
    }
}

