#[cfg(target_arch = "wasm32")]
fn handle_textarea_drags(
    mut drag_starts: MessageReader<Pointer<DragStart>>,
    mut drags: MessageReader<Pointer<Drag>>,
    mut drag_ends: MessageReader<Pointer<DragEnd>>,
    parents: Query<&ChildOf>,
    handles: Query<(&TextareaResizeHandle, &ComputedUiRenderTargetInfo)>,
    mut groups: Query<&mut TextareaStoryState>,
) {
    for drag_start in drag_starts.read() {
        if let Some((handle, _)) = textarea_resize_handle(drag_start.entity, &parents, &handles)
            && !handle.disabled
            && let Ok(mut group) = groups.get_mut(handle.group)
        {
            group.state.apply(TextareaIntent::Focus);
            group.resizing = true;
        }
    }
    for drag in drags.read() {
        let Some((handle, target_info)) = textarea_resize_handle(drag.entity, &parents, &handles)
        else {
            continue;
        };
        if handle.disabled {
            continue;
        }
        if let Ok(mut group) = groups.get_mut(handle.group) {
            let maximum = group.metrics.control_height + scale::space::xl4(group.inline_size);
            group.control_height = (group.control_height
                + drag.delta.y / target_info.scale_factor().max(1.0))
            .clamp(group.metrics.control_min_height, maximum);
            group.resizing = true;
        }
    }
    for drag_end in drag_ends.read() {
        if let Some((handle, _)) = textarea_resize_handle(drag_end.entity, &parents, &handles)
            && let Ok(mut group) = groups.get_mut(handle.group)
        {
            group.resizing = false;
        }
    }
}

#[cfg(target_arch = "wasm32")]
fn textarea_resize_handle<'a>(
    entity: Entity,
    parents: &Query<&ChildOf>,
    handles: &'a Query<(&TextareaResizeHandle, &ComputedUiRenderTargetInfo)>,
) -> Option<(&'a TextareaResizeHandle, &'a ComputedUiRenderTargetInfo)> {
    let mut current = Some(entity);
    while let Some(candidate) = current {
        if let Ok(handle) = handles.get(candidate) {
            return Some(handle);
        }
        current = parents.get(candidate).ok().map(ChildOf::parent);
    }
    None
}

#[cfg(target_arch = "wasm32")]
fn handle_textarea_keyboard(
    mut keyboard: MessageReader<KeyboardInput>,
    mut groups: Query<&mut TextareaStoryState>,
) {
    for input in keyboard.read() {
        if input.state != ButtonState::Pressed {
            continue;
        }
        for mut group in &mut groups {
            if group.model.loading || group.model.disabled || !group.state.is_focused() {
                continue;
            }
            match &input.logical_key {
                Key::Backspace => {
                    let mut value = group.state.value().to_owned();
                    value.pop();
                    let max_length = group.model.max_length;
                    group
                        .state
                        .apply_bounded(TextareaIntent::Input(value), max_length);
                    group.focus_visible = true;
                }
                Key::Enter => {
                    let mut value = group.state.value().to_owned();
                    value.push('\n');
                    let max_length = group.model.max_length;
                    group
                        .state
                        .apply_bounded(TextareaIntent::Input(value), max_length);
                    group.focus_visible = true;
                }
                Key::Escape | Key::Tab => {
                    group.state.apply(TextareaIntent::Blur);
                    group.focus_visible = false;
                }
                _ => {
                    if let Some(text) = input.text.as_ref()
                        && text.chars().all(|character| !character.is_control())
                    {
                        let mut value = group.state.value().to_owned();
                        value.push_str(text);
                        let max_length = group.model.max_length;
                        group
                            .state
                            .apply_bounded(TextareaIntent::Input(value), max_length);
                        group.focus_visible = true;
                    }
                }
            }
        }
    }
}

