#[cfg(target_arch = "wasm32")]
fn handle_command_presses(
    mut presses: MessageReader<Pointer<Press>>,
    parents: Query<&ChildOf>,
    inputs: Query<&CommandInputTrigger>,
    items: Query<&CommandItemTrigger>,
    mut groups: Query<&mut CommandGroupState>,
) {
    for press in presses.read() {
        let mut current = Some(press.entity);
        let mut input_target = None;
        let mut item_target = None;
        while let Some(entity) = current {
            if let Ok(input) = inputs.get(entity) {
                input_target = Some(*input);
                break;
            }
            if let Ok(item) = items.get(entity) {
                item_target = Some(item.clone());
                break;
            }
            current = parents.get(entity).ok().map(ChildOf::parent);
        }

        if let Some(target) = input_target {
            for mut group in &mut groups {
                group.focused = false;
            }
            if !target.disabled
                && let Ok(mut group) = groups.get_mut(target.group)
            {
                group.focused = true;
                group.state.apply(CommandIntent::Open);
            }
        } else if let Some(target) = item_target
            && !target.disabled
            && let Ok(mut group) = groups.get_mut(target.group)
        {
            group.state.apply(CommandIntent::Select(target.value));
            group.focused = false;
        }
    }
}

#[cfg(target_arch = "wasm32")]
fn handle_command_keyboard(
    mut keyboard: MessageReader<KeyboardInput>,
    mut groups: Query<&mut CommandGroupState>,
) {
    for input in keyboard.read() {
        if input.state != ButtonState::Pressed {
            continue;
        }
        for mut group in &mut groups {
            if group.blocked || !group.focused {
                continue;
            }
            match &input.logical_key {
                Key::Backspace => {
                    let mut query = group.state.query().to_owned();
                    query.pop();
                    group.state.apply(CommandIntent::Input(query));
                }
                Key::Escape | Key::Tab => {
                    group.state.apply(CommandIntent::Close);
                    group.focused = false;
                }
                Key::Enter => {
                    if let Some(value) = group.state.highlighted_value().map(str::to_owned) {
                        group.state.apply(CommandIntent::Select(value));
                        group.focused = false;
                    }
                }
                Key::ArrowDown | Key::ArrowUp => {
                    let values = command_render_nodes(&group.model, &group.state)
                        .into_iter()
                        .filter(|node| node.part == CommandPart::Item && !node.disabled)
                        .map(|node| node.value)
                        .collect::<Vec<_>>();
                    if !values.is_empty() {
                        let current = group.state.highlighted_value().and_then(|value| {
                            values.iter().position(|candidate| candidate == value)
                        });
                        let index = if matches!(input.logical_key, Key::ArrowUp) {
                            current.map_or(values.len() - 1, |index| {
                                index.checked_sub(1).unwrap_or(values.len() - 1)
                            })
                        } else {
                            current.map_or(0, |index| (index + 1) % values.len())
                        };
                        group
                            .state
                            .apply(CommandIntent::Highlight(values[index].clone()));
                    }
                }
                _ => {
                    if let Some(text) = input.text.as_ref()
                        && text.chars().all(|character| !character.is_control())
                    {
                        let mut query = group.state.query().to_owned();
                        query.push_str(text);
                        group.state.apply(CommandIntent::Input(query));
                    }
                }
            }
        }
    }
}

#[cfg(target_arch = "wasm32")]
fn handle_context_menu_presses(
    mut presses: MessageReader<Pointer<Press>>,
    parents: Query<&ChildOf>,
    triggers: Query<&ContextMenuTriggerControl>,
    entries: Query<&ContextMenuEntryControl>,
    mut groups: Query<&mut ContextMenuGroupState>,
) {
    for press in presses.read() {
        let mut current = Some(press.entity);
        while let Some(entity) = current {
            if let Ok(entry) = entries.get(entity) {
                if !entry.disabled
                    && let Ok(mut group) = groups.get_mut(entry.group)
                {
                    group
                        .state
                        .apply(ContextMenuIntent::Focus(entry.value.clone()));
                    match entry.part {
                        ContextMenuPart::Item => {
                            group
                                .state
                                .apply(ContextMenuIntent::Select(entry.value.clone()));
                        }
                        ContextMenuPart::Submenu => {
                            group
                                .state
                                .apply(ContextMenuIntent::OpenSubmenu(entry.value.clone()));
                        }
                        ContextMenuPart::Root
                        | ContextMenuPart::Trigger
                        | ContextMenuPart::Content
                        | ContextMenuPart::Separator => {}
                    }
                }
                break;
            }
            if let Ok(trigger) = triggers.get(entity) {
                if !trigger.disabled
                    && let Ok(mut group) = groups.get_mut(trigger.group)
                {
                    group.state.apply(ContextMenuIntent::Toggle);
                }
                break;
            }
            current = parents.get(entity).ok().map(ChildOf::parent);
        }
    }
}

#[cfg(target_arch = "wasm32")]
fn handle_data_table_presses(
    mut presses: MessageReader<Pointer<Press>>,
    parents: Query<&ChildOf>,
    filters: Query<&DataTableFilterControl>,
    headers: Query<&DataTableHeaderControl>,
    rows: Query<&DataTableRowControl>,
    pages: Query<&DataTablePageControl>,
    mut groups: Query<&mut DataTableGroupState>,
) {
    for press in presses.read() {
        let mut current = Some(press.entity);
        while let Some(entity) = current {
            if let Ok(filter) = filters.get(entity) {
                let target = *filter;
                for mut group in &mut groups {
                    group.focused = false;
                }
                if !target.disabled
                    && let Ok(mut group) = groups.get_mut(target.group)
                {
                    group.focused = true;
                }
                break;
            }
            if let Ok(header) = headers.get(entity) {
                let target = header.clone();
                if let Ok(mut group) = groups.get_mut(target.group) {
                    group.focused = false;
                    if !target.disabled {
                        group.state.apply(DataTableIntent::Sort(target.column), 0);
                    }
                }
                break;
            }
            if let Ok(row) = rows.get(entity) {
                let target = row.clone();
                if let Ok(mut group) = groups.get_mut(target.group) {
                    group.focused = false;
                    if !target.disabled {
                        group
                            .state
                            .apply(DataTableIntent::SelectRow(target.value), 0);
                    }
                }
                break;
            }
            if let Ok(page) = pages.get(entity) {
                let target = *page;
                if let Ok(mut group) = groups.get_mut(target.group) {
                    group.focused = false;
                    if !target.disabled {
                        let max_page = max_data_table_page_index(&group.model, &group.state);
                        let intent = match target.action {
                            DataTablePageAction::Previous => DataTableIntent::PreviousPage,
                            DataTablePageAction::Next => DataTableIntent::NextPage,
                        };
                        group.state.apply(intent, max_page);
                    }
                }
                break;
            }
            current = parents.get(entity).ok().map(ChildOf::parent);
        }
    }
}

#[cfg(target_arch = "wasm32")]
fn handle_data_table_keyboard(
    mut keyboard: MessageReader<KeyboardInput>,
    mut groups: Query<&mut DataTableGroupState>,
) {
    for input in keyboard.read() {
        if input.state != ButtonState::Pressed {
            continue;
        }
        for mut group in &mut groups {
            if group.blocked || !group.focused {
                continue;
            }
            match &input.logical_key {
                Key::Backspace => {
                    let mut filter = group.state.filter().to_owned();
                    filter.pop();
                    group.state.apply(DataTableIntent::Filter(filter), 0);
                }
                Key::Escape => {
                    if group.state.filter().is_empty() {
                        group.focused = false;
                    } else {
                        group.state.apply(DataTableIntent::Filter(String::new()), 0);
                    }
                }
                Key::Tab => {
                    group.focused = false;
                }
                _ => {
                    if let Some(text) = input.text.as_ref()
                        && text.chars().all(|character| !character.is_control())
                    {
                        let mut filter = group.state.filter().to_owned();
                        filter.push_str(text);
                        group.state.apply(DataTableIntent::Filter(filter), 0);
                    }
                }
            }
        }
    }
}

