#[cfg(target_arch = "wasm32")]
fn handle_drawer_presses(
    mut presses: MessageReader<Pointer<Press>>,
    parents: Query<&ChildOf>,
    triggers: Query<&DrawerTriggerControl>,
    handles: Query<&DrawerHandleControl>,
    actions: Query<&DrawerActionControl>,
    mut groups: Query<&mut DrawerGroupState>,
) {
    for press in presses.read() {
        let mut current = Some(press.entity);
        while let Some(entity) = current {
            if let Ok(action) = actions.get(entity) {
                if !action.disabled
                    && let Ok(mut group) = groups.get_mut(action.group)
                {
                    group
                        .state
                        .apply(DrawerIntent::ActivateFooter(action.value.clone()));
                    if action.close_drawer {
                        group.state.apply(DrawerIntent::Close);
                    }
                }
                break;
            }
            if let Ok(handle) = handles.get(entity) {
                if !handle.disabled
                    && let Ok(mut group) = groups.get_mut(handle.group)
                {
                    if group.state.is_dragging() {
                        group.state.apply(DrawerIntent::EndDrag);
                    } else {
                        group.state.apply(DrawerIntent::StartDrag);
                    }
                }
                break;
            }
            if let Ok(trigger) = triggers.get(entity) {
                if !trigger.disabled
                    && let Ok(mut group) = groups.get_mut(trigger.group)
                {
                    group.state.apply(DrawerIntent::Toggle);
                }
                break;
            }
            current = parents.get(entity).ok().map(ChildOf::parent);
        }
    }
}

