#[cfg(target_arch = "wasm32")]
fn handle_hover_card_presses(
    mut presses: MessageReader<Pointer<Press>>,
    parents: Query<&ChildOf>,
    controls: Query<&HoverCardControl>,
    mut groups: Query<&mut HoverCardGroupState>,
) {
    for press in presses.read() {
        let mut current = Some(press.entity);
        while let Some(entity) = current {
            if let Ok(control) = controls.get(entity) {
                if !control.disabled
                    && control.part == HoverCardPart::Trigger
                    && let Ok(mut group) = groups.get_mut(control.group)
                {
                    let was_open = group.state.is_open();
                    group.state.apply(HoverCardIntent::Toggle);
                    group.suppress_hover_open = was_open && !group.state.is_open();
                }
                break;
            }
            current = parents.get(entity).ok().map(ChildOf::parent);
        }
    }
}

#[cfg(target_arch = "wasm32")]
fn handle_hover_card_interactions(
    controls: Query<(&Interaction, &HoverCardControl), Changed<Interaction>>,
    mut groups: Query<&mut HoverCardGroupState>,
) {
    for (interaction, control) in &controls {
        if control.disabled {
            continue;
        }
        let Ok(mut group) = groups.get_mut(control.group) else {
            continue;
        };
        match interaction {
            Interaction::Hovered => {
                if !group.hovered {
                    group.hovered = true;
                    if !group.suppress_hover_open {
                        group.state.apply(HoverCardIntent::Open(control.part));
                    }
                }
            }
            Interaction::Pressed => {
                group.hovered = true;
            }
            Interaction::None => {
                if group.hovered {
                    group.hovered = false;
                    group.suppress_hover_open = false;
                    group.state.apply(HoverCardIntent::Close);
                }
            }
        }
    }
}

