fn handle_input_presses(
    mut presses: MessageReader<Pointer<Press>>,
    parents: Query<&ChildOf>,
    controls: Query<&InputControlTrigger>,
    suffixes: Query<&InputSuffixControl>,
    mut groups: Query<&mut InputGroupState>,
) {
    for press in presses.read() {
        let mut current = Some(press.entity);
        let mut target = None;
        while let Some(entity) = current {
            if let Ok(suffix) = suffixes.get(entity) {
                target = Some(InputPressTarget::Suffix {
                    group: suffix.group,
                    value: suffix.value.clone(),
                    disabled: suffix.disabled,
                });
                break;
            }
            if let Ok(control) = controls.get(entity) {
                target = Some(InputPressTarget::Control {
                    group: control.group,
                    disabled: control.disabled,
                });
                break;
            }
            current = parents.get(entity).ok().map(ChildOf::parent);
        }
        let Some(target) = target else {
            continue;
        };
        let disabled = match &target {
            InputPressTarget::Control { disabled, .. }
            | InputPressTarget::Suffix { disabled, .. } => *disabled,
        };
        if disabled {
            continue;
        }
        for mut group in &mut groups {
            if group.state.is_focused() {
                group.state.apply(InputIntent::Blur);
            }
        }
        match target {
            InputPressTarget::Control { group, .. } => {
                if let Ok(mut group) = groups.get_mut(group) {
                    group.state.apply(InputIntent::Focus);
                }
            }
            InputPressTarget::Suffix { group, value, .. } => {
                if let Ok(mut group) = groups.get_mut(group) {
                    group.state.apply(InputIntent::ActivateSuffix(value));
                }
            }
        }
    }
}

