#[cfg(target_arch = "wasm32")]
#[allow(clippy::type_complexity)]
fn handle_message_interactions(
    mut sets: ParamSet<(
        Query<(&Interaction, &mut MessageGroup), (Changed<Interaction>, With<MessageRootControl>)>,
        Query<(&Interaction, &MessageActionControl), Changed<Interaction>>,
        Query<&mut MessageGroup>,
    )>,
) {
    for (interaction, mut group) in &mut sets.p0() {
        if group.model.loading || group.model.disabled {
            continue;
        }
        match interaction {
            Interaction::Hovered | Interaction::Pressed => {
                group.state.apply(MessageIntent::Hover(MessagePart::Root));
            }
            Interaction::None => {
                group.state.apply(MessageIntent::Leave);
            }
        }
    }

    let actions = sets
        .p1()
        .iter()
        .map(|(interaction, control)| (*interaction, control.clone()))
        .collect::<Vec<_>>();
    let mut groups = sets.p2();
    for (interaction, control) in actions {
        if control.disabled {
            continue;
        }
        let Ok(mut group) = groups.get_mut(control.group) else {
            continue;
        };
        match interaction {
            Interaction::Pressed => {
                group
                    .state
                    .apply(MessageIntent::Activate(control.value.clone()));
            }
            Interaction::Hovered => {
                group
                    .state
                    .apply(MessageIntent::Hover(MessagePart::Actions));
            }
            Interaction::None => {}
        }
    }
}

#[cfg(target_arch = "wasm32")]
#[allow(clippy::type_complexity)]
fn handle_message_scroller_interactions(
    mut sets: ParamSet<(
        Query<
            (&Interaction, &mut MessageScrollerGroup),
            (Changed<Interaction>, With<MessageScrollerRootControl>),
        >,
        Query<(&Interaction, &MessageScrollerJumpControl), Changed<Interaction>>,
        Query<&mut MessageScrollerGroup>,
    )>,
) {
    for (interaction, mut group) in &mut sets.p0() {
        if group.model.loading || group.model.disabled {
            continue;
        }
        match interaction {
            Interaction::Hovered | Interaction::Pressed => {
                group
                    .state
                    .apply(MessageScrollerIntent::Hover(MessageScrollerPart::Root));
            }
            Interaction::None => {
                group.state.apply(MessageScrollerIntent::Leave);
            }
        }
    }

    let jumps = sets
        .p1()
        .iter()
        .map(|(interaction, control)| (*interaction, *control))
        .collect::<Vec<_>>();
    let mut groups = sets.p2();
    for (interaction, control) in jumps {
        if control.disabled {
            continue;
        }
        let Ok(mut group) = groups.get_mut(control.group) else {
            continue;
        };
        match interaction {
            Interaction::Pressed => {
                group.state.apply(MessageScrollerIntent::JumpToLatest);
            }
            Interaction::Hovered => {
                group.state.apply(MessageScrollerIntent::Hover(
                    MessageScrollerPart::JumpButton,
                ));
            }
            Interaction::None => {}
        }
    }
}

#[cfg(target_arch = "wasm32")]
fn handle_native_select_presses(
    mut presses: MessageReader<Pointer<Press>>,
    parents: Query<&ChildOf>,
    triggers: Query<&NativeSelectTriggerControl>,
    options: Query<&NativeSelectOptionControl>,
    mut groups: Query<&mut NativeSelectGroup>,
) {
    for press in presses.read() {
        let mut current = Some(press.entity);
        while let Some(entity) = current {
            if let Ok(option) = options.get(entity) {
                if !option.disabled
                    && let Ok(mut group) = groups.get_mut(option.group)
                {
                    group
                        .state
                        .apply(NativeSelectIntent::Select(option.value.clone()));
                    group.open = false;
                }
                break;
            }
            if let Ok(trigger) = triggers.get(entity) {
                if !trigger.disabled
                    && let Ok(mut group) = groups.get_mut(trigger.group)
                {
                    group.state.apply(NativeSelectIntent::Focus);
                    group.open = !group.open;
                }
                break;
            }
            current = parents.get(entity).ok().map(ChildOf::parent);
        }
    }
}

