#[cfg(target_arch = "wasm32")]
fn handle_skeleton_presses(
    mut presses: MessageReader<Pointer<Press>>,
    parents: Query<&ChildOf>,
    roots: Query<(), With<SkeletonRootTrigger>>,
    mut groups: Query<&mut SkeletonGroupState>,
) {
    for press in presses.read() {
        let mut current = Some(press.entity);
        while let Some(entity) = current {
            if roots.contains(entity) {
                if let Ok(mut group) = groups.get_mut(entity)
                    && group.model.loading
                    && group.model.animated
                    && !group.model.disabled
                {
                    group.state.apply(SkeletonIntent::ToggleAnimation);
                }
                break;
            }
            current = parents.get(entity).ok().map(ChildOf::parent);
        }
    }
}

#[cfg(target_arch = "wasm32")]
fn handle_slider_presses(
    mut presses: MessageReader<Pointer<Press>>,
    parents: Query<&ChildOf>,
    controls: Query<(
        &SliderTrackControl,
        &ComputedNode,
        &ComputedUiRenderTargetInfo,
        &UiGlobalTransform,
    )>,
    mut groups: Query<&mut SliderGroupState>,
) {
    for press in presses.read() {
        let mut current = Some(press.entity);
        let mut target = None;
        while let Some(entity) = current {
            if let Ok((control, node, target_info, transform)) = controls.get(entity) {
                let value = groups.get(control.group).ok().and_then(|group| {
                    slider_value_at_pointer(
                        &group.model,
                        control.orientation,
                        node,
                        target_info.scale_factor(),
                        transform,
                        press.pointer_location.position,
                    )
                });
                target = Some((control.group, control.disabled, value));
                break;
            }
            current = parents.get(entity).ok().map(ChildOf::parent);
        }
        let Some((target_group, disabled, value)) = target else {
            continue;
        };
        for mut group in &mut groups {
            group.state.apply(SliderIntent::Clear);
        }
        if disabled {
            continue;
        }
        if let Ok(mut group) = groups.get_mut(target_group) {
            group.state.apply(SliderIntent::Focus);
            group.state.apply(SliderIntent::StartDrag);
            if let Some(value) = value {
                group.state.apply(SliderIntent::SetValue(value));
            }
        }
    }
}

#[cfg(target_arch = "wasm32")]
fn handle_slider_drags(
    mut drag_starts: MessageReader<Pointer<DragStart>>,
    mut drags: MessageReader<Pointer<Drag>>,
    mut drag_ends: MessageReader<Pointer<DragEnd>>,
    mut releases: MessageReader<Pointer<Release>>,
    parents: Query<&ChildOf>,
    controls: Query<(
        &SliderTrackControl,
        &ComputedNode,
        &ComputedUiRenderTargetInfo,
        &UiGlobalTransform,
    )>,
    mut groups: Query<&mut SliderGroupState>,
) {
    for drag_start in drag_starts.read() {
        if let Some(control) = slider_control_for_entity(drag_start.entity, &parents, &controls)
            && !control.disabled
            && let Ok(mut group) = groups.get_mut(control.group)
        {
            group.state.apply(SliderIntent::Focus);
            group.state.apply(SliderIntent::StartDrag);
        }
    }
    for drag in drags.read() {
        let Some((control, node, target_info, transform)) =
            slider_control_details(drag.entity, &parents, &controls)
        else {
            continue;
        };
        if control.disabled {
            continue;
        }
        let value = groups.get(control.group).ok().and_then(|group| {
            slider_value_at_pointer(
                &group.model,
                control.orientation,
                node,
                target_info.scale_factor(),
                transform,
                drag.pointer_location.position,
            )
        });
        if let Ok(mut group) = groups.get_mut(control.group) {
            group.state.apply(SliderIntent::StartDrag);
            if let Some(value) = value {
                group.state.apply(SliderIntent::SetValue(value));
            }
        }
    }
    for drag_end in drag_ends.read() {
        if let Some((control, node, target_info, transform)) =
            slider_control_details(drag_end.entity, &parents, &controls)
        {
            let value = groups.get(control.group).ok().and_then(|group| {
                slider_value_at_pointer(
                    &group.model,
                    control.orientation,
                    node,
                    target_info.scale_factor(),
                    transform,
                    drag_end.pointer_location.position,
                )
            });
            if !control.disabled
                && let Ok(mut group) = groups.get_mut(control.group)
            {
                if let Some(value) = value {
                    group.state.apply(SliderIntent::SetValue(value));
                }
                group.state.apply(SliderIntent::StopDrag);
            }
        }
    }
    if releases.read().next().is_some() {
        for mut group in &mut groups {
            group.state.apply(SliderIntent::StopDrag);
        }
    }
}

#[cfg(target_arch = "wasm32")]
fn handle_slider_keyboard(
    mut keyboard: MessageReader<KeyboardInput>,
    mut groups: Query<&mut SliderGroupState>,
) {
    for input in keyboard.read() {
        if input.state != ButtonState::Pressed {
            continue;
        }
        for mut group in &mut groups {
            if group.blocked || !group.state.is_focused() {
                continue;
            }
            let intent = match &input.logical_key {
                Key::ArrowRight | Key::ArrowUp => Some(SliderIntent::Increment),
                Key::ArrowLeft | Key::ArrowDown => Some(SliderIntent::Decrement),
                Key::Home => Some(SliderIntent::SetValue(group.model.min)),
                Key::End => Some(SliderIntent::SetValue(group.model.max)),
                Key::Escape | Key::Tab => Some(SliderIntent::Clear),
                _ => None,
            };
            if let Some(intent) = intent {
                group.state.apply(intent);
            }
        }
    }
}

#[cfg(target_arch = "wasm32")]
fn handle_slider_release_interactions(
    controls: Query<(&Interaction, &SliderTrackControl), Changed<Interaction>>,
    mut groups: Query<&mut SliderGroupState>,
) {
    for (interaction, control) in &controls {
        if *interaction != Interaction::Pressed
            && let Ok(mut group) = groups.get_mut(control.group)
        {
            group.state.apply(SliderIntent::StopDrag);
        }
    }
}

#[cfg(target_arch = "wasm32")]
fn slider_control_for_entity<'a>(
    entity: Entity,
    parents: &Query<&ChildOf>,
    controls: &'a Query<(
        &SliderTrackControl,
        &ComputedNode,
        &ComputedUiRenderTargetInfo,
        &UiGlobalTransform,
    )>,
) -> Option<&'a SliderTrackControl> {
    slider_control_details(entity, parents, controls).map(|(control, _, _, _)| control)
}

#[cfg(target_arch = "wasm32")]
fn slider_control_details<'a>(
    entity: Entity,
    parents: &Query<&ChildOf>,
    controls: &'a Query<(
        &SliderTrackControl,
        &ComputedNode,
        &ComputedUiRenderTargetInfo,
        &UiGlobalTransform,
    )>,
) -> Option<(
    &'a SliderTrackControl,
    &'a ComputedNode,
    &'a ComputedUiRenderTargetInfo,
    &'a UiGlobalTransform,
)> {
    let mut current = Some(entity);
    while let Some(candidate) = current {
        if let Ok(control) = controls.get(candidate) {
            return Some(control);
        }
        current = parents.get(candidate).ok().map(ChildOf::parent);
    }
    None
}

#[cfg(target_arch = "wasm32")]
fn slider_value_at_pointer(
    model: &SliderModel,
    orientation: SliderOrientation,
    node: &ComputedNode,
    scale_factor: f32,
    transform: &UiGlobalTransform,
    position: Vec2,
) -> Option<i32> {
    let normalized = node.normalize_point(*transform, position * scale_factor)?;
    let ratio = match orientation {
        SliderOrientation::Horizontal => normalized.x + 0.5,
        SliderOrientation::Vertical => 0.5 - normalized.y,
    }
    .clamp(0.0, 1.0);
    let span = model.max.saturating_sub(model.min) as f32;
    Some(model.min.saturating_add((span * ratio).round() as i32))
}

#[cfg(target_arch = "wasm32")]
fn handle_sonner_hover(
    hover_map: Res<HoverMap>,
    parents: Query<&ChildOf>,
    toasts: Query<&SonnerToastTrigger>,
    mut groups: Query<(Entity, &mut SonnerGroupState)>,
) {
    for (group_entity, mut group) in &mut groups {
        let mut provider_hovered = false;
        let mut hovered_toast = None;
        for hovered in hover_map.0.values() {
            for entity in hovered.keys() {
                let mut current = Some(*entity);
                while let Some(candidate) = current {
                    if let Ok(toast) = toasts.get(candidate)
                        && toast.group == group_entity
                        && !toast.disabled
                    {
                        hovered_toast = Some(toast.toast_value.clone());
                    }
                    if candidate == group_entity {
                        provider_hovered = true;
                        break;
                    }
                    current = parents.get(candidate).ok().map(ChildOf::parent);
                }
            }
        }

        if !group.disabled && provider_hovered && !group.state.is_paused() {
            group.state.apply(SonnerIntent::Pause);
        } else if (!provider_hovered || group.disabled) && group.state.is_paused() {
            group.state.apply(SonnerIntent::Resume);
        }
        let active_value = group.state.active_value().map(str::to_owned);
        match (active_value.as_deref(), hovered_toast) {
            (Some(active), Some(value)) if active == value => {}
            (_, Some(value)) => {
                group.state.apply(SonnerIntent::Focus(value));
            }
            (Some(_), None) => {
                group.state.apply(SonnerIntent::Blur);
            }
            (None, None) => {}
        }
    }
}

#[cfg(target_arch = "wasm32")]
fn handle_sonner_presses(
    mut presses: MessageReader<Pointer<Press>>,
    parents: Query<&ChildOf>,
    actions: Query<&SonnerActionTrigger>,
    dismisses: Query<&SonnerDismissTrigger>,
    mut groups: Query<&mut SonnerGroupState>,
) {
    for press in presses.read() {
        let mut current = Some(press.entity);
        while let Some(entity) = current {
            if let Ok(action) = actions.get(entity) {
                if !action.disabled
                    && let Ok(mut group) = groups.get_mut(action.group)
                {
                    group
                        .state
                        .apply(SonnerIntent::Activate(action.toast_value.clone()));
                }
                break;
            }
            if let Ok(dismiss) = dismisses.get(entity) {
                if !dismiss.disabled
                    && let Ok(mut group) = groups.get_mut(dismiss.group)
                {
                    group
                        .state
                        .apply(SonnerIntent::Dismiss(dismiss.toast_value.clone()));
                }
                break;
            }
            current = parents.get(entity).ok().map(ChildOf::parent);
        }
    }
}

#[cfg(target_arch = "wasm32")]
fn handle_toast_hover(
    hover_map: Res<HoverMap>,
    parents: Query<&ChildOf>,
    cards: Query<&ToastCardTrigger>,
    mut groups: Query<(Entity, &mut ToastGroupState)>,
) {
    for (group_entity, mut group) in &mut groups {
        let mut provider_hovered = false;
        let mut card_hovered = false;
        for hovered in hover_map.0.values() {
            for entity in hovered.keys() {
                let mut current = Some(*entity);
                while let Some(candidate) = current {
                    if let Ok(card) = cards.get(candidate)
                        && card.group == group_entity
                        && !card.disabled
                    {
                        card_hovered = true;
                    }
                    if candidate == group_entity {
                        provider_hovered = true;
                        break;
                    }
                    current = parents.get(candidate).ok().map(ChildOf::parent);
                }
            }
        }

        if !group.model.disabled && provider_hovered && !group.state.is_paused() {
            group.state.apply(ToastIntent::Pause);
        } else if (!provider_hovered || group.model.disabled) && group.state.is_paused() {
            group.state.apply(ToastIntent::Resume);
        }

        let blocked = group.model.loading || group.model.disabled;
        if !blocked && card_hovered && !group.state.is_focused() {
            group.state.apply(ToastIntent::Focus);
        } else if (blocked || !card_hovered) && group.state.is_focused() {
            group.state.apply(ToastIntent::Blur);
        }
    }
}

#[cfg(target_arch = "wasm32")]
fn handle_toast_presses(
    mut presses: MessageReader<Pointer<Press>>,
    parents: Query<&ChildOf>,
    actions: Query<&ToastActionTrigger>,
    mut groups: Query<&mut ToastGroupState>,
) {
    for press in presses.read() {
        let mut current = Some(press.entity);
        while let Some(entity) = current {
            if let Ok(action) = actions.get(entity) {
                if !action.disabled
                    && let Ok(mut group) = groups.get_mut(action.group)
                {
                    group
                        .state
                        .apply(ToastIntent::Activate(action.value.clone()));
                }
                break;
            }
            current = parents.get(entity).ok().map(ChildOf::parent);
        }
    }
}

#[cfg(target_arch = "wasm32")]
fn handle_tooltip_hover(
    hover_map: Res<HoverMap>,
    parents: Query<&ChildOf>,
    mut groups: Query<&mut TooltipStoryState>,
) {
    for mut group in &mut groups {
        if group.model.loading || group.model.disabled {
            group.hovered = false;
            continue;
        }
        let mut hovered_part = None;
        'pointers: for hovered in hover_map.0.values() {
            for entity in hovered.keys() {
                let mut current = Some(*entity);
                while let Some(candidate) = current {
                    if candidate == group.content {
                        hovered_part = Some(TooltipPart::Content);
                        break 'pointers;
                    }
                    if candidate == group.trigger {
                        hovered_part = Some(TooltipPart::Trigger);
                        break 'pointers;
                    }
                    current = parents.get(candidate).ok().map(ChildOf::parent);
                }
            }
        }

        match hovered_part {
            Some(part) if !group.hovered || !group.state.is_active(part) => {
                group.hovered = true;
                group.state.apply(TooltipIntent::Hover(part));
            }
            Some(_) => {}
            None if group.hovered => {
                group.hovered = false;
                group.state.apply(TooltipIntent::Leave);
            }
            None => {}
        }
    }
}

#[cfg(target_arch = "wasm32")]
fn handle_tooltip_presses(
    mut presses: MessageReader<Pointer<Press>>,
    parents: Query<&ChildOf>,
    controls: Query<&TooltipControl>,
    mut groups: Query<&mut TooltipStoryState>,
) {
    for press in presses.read() {
        let mut current = Some(press.entity);
        let mut target = None;
        while let Some(entity) = current {
            if let Ok(control) = controls.get(entity) {
                target = Some(*control);
                break;
            }
            current = parents.get(entity).ok().map(ChildOf::parent);
        }

        if !target.is_some_and(|control| control.disabled) {
            for mut group in &mut groups {
                group.state.apply(TooltipIntent::Blur);
            }
            if let Some(control) = target
                && let Ok(mut group) = groups.get_mut(control.group)
            {
                group
                    .state
                    .apply(TooltipIntent::Focus(TooltipPart::Trigger));
            }
        }
    }
}

#[cfg(target_arch = "wasm32")]
fn handle_toggle_presses(
    mut presses: MessageReader<Pointer<Press>>,
    parents: Query<&ChildOf>,
    controls: Query<&ToggleControl>,
    mut groups: Query<&mut ToggleStoryState>,
) {
    for press in presses.read() {
        let mut current = Some(press.entity);
        let mut target = None;
        while let Some(entity) = current {
            if let Ok(control) = controls.get(entity) {
                target = Some(*control);
                break;
            }
            current = parents.get(entity).ok().map(ChildOf::parent);
        }

        if !target.is_some_and(|control| control.disabled) {
            for mut group in &mut groups {
                group.state.apply(ToggleIntent::Blur);
            }
            if let Some(control) = target
                && let Ok(mut group) = groups.get_mut(control.group)
            {
                group.state.apply(ToggleIntent::Focus(TogglePart::Root));
                group.state.apply(ToggleIntent::Toggle);
            }
        }
    }
}

#[cfg(target_arch = "wasm32")]
fn handle_toggle_keyboard(
    mut keyboard: MessageReader<KeyboardInput>,
    mut groups: Query<&mut ToggleStoryState>,
) {
    for input in keyboard.read() {
        if input.state != ButtonState::Pressed {
            continue;
        }
        for mut group in &mut groups {
            if group.model.loading
                || group.model.disabled
                || !group.state.is_active(TogglePart::Root)
            {
                continue;
            }
            if input.text.as_deref() == Some(" ") {
                group.state.apply(ToggleIntent::Toggle);
                continue;
            }
            match &input.logical_key {
                Key::Enter => {
                    group.state.apply(ToggleIntent::Toggle);
                }
                Key::Character(value) if value.as_str() == " " => {
                    group.state.apply(ToggleIntent::Toggle);
                }
                Key::Escape | Key::Tab => {
                    group.state.apply(ToggleIntent::Blur);
                }
                _ => {}
            }
        }
    }
}

#[cfg(target_arch = "wasm32")]
fn handle_toggle_group_presses(
    mut presses: MessageReader<Pointer<Press>>,
    parents: Query<&ChildOf>,
    controls: Query<&ToggleGroupControl>,
    mut groups: Query<&mut ToggleGroupStoryState>,
) {
    for press in presses.read() {
        let mut current = Some(press.entity);
        let mut target = None;
        while let Some(entity) = current {
            if let Ok(control) = controls.get(entity) {
                target = Some(control.clone());
                break;
            }
            current = parents.get(entity).ok().map(ChildOf::parent);
        }

        if !target.as_ref().is_some_and(|control| control.disabled) {
            for mut group in &mut groups {
                let selection_mode = group.model.selection_mode;
                group.state.apply(selection_mode, ToggleGroupIntent::Blur);
            }
            if let Some(control) = target
                && let Ok(mut group) = groups.get_mut(control.group)
            {
                let selection_mode = group.model.selection_mode;
                group.state.apply(
                    selection_mode,
                    ToggleGroupIntent::Focus(control.value.clone()),
                );
                group
                    .state
                    .apply(selection_mode, ToggleGroupIntent::Toggle(control.value));
            }
        }
    }
}

#[cfg(target_arch = "wasm32")]
fn handle_toggle_group_keyboard(
    mut keyboard: MessageReader<KeyboardInput>,
    mut groups: Query<&mut ToggleGroupStoryState>,
) {
    for input in keyboard.read() {
        if input.state != ButtonState::Pressed {
            continue;
        }
        for mut group in &mut groups {
            if group.model.loading || group.model.disabled {
                continue;
            }
            let Some(value) = group.state.focused_value().map(str::to_owned) else {
                continue;
            };
            let selection_mode = group.model.selection_mode;
            if input.text.as_deref() == Some(" ") {
                group
                    .state
                    .apply(selection_mode, ToggleGroupIntent::Toggle(value));
                continue;
            }
            match &input.logical_key {
                Key::Enter => {
                    group
                        .state
                        .apply(selection_mode, ToggleGroupIntent::Toggle(value));
                }
                Key::Character(character) if character.as_str() == " " => {
                    group
                        .state
                        .apply(selection_mode, ToggleGroupIntent::Toggle(value));
                }
                Key::Escape | Key::Tab => {
                    group.state.apply(selection_mode, ToggleGroupIntent::Blur);
                }
                _ => {}
            }
        }
    }
}

#[cfg(target_arch = "wasm32")]
fn handle_typography_hover(
    hover_map: Res<HoverMap>,
    parents: Query<&ChildOf>,
    controls: Query<&TypographyControl>,
    mut groups: Query<&mut TypographyStoryState>,
) {
    for mut group in &mut groups {
        if group.model.loading || group.model.disabled {
            if group.hovered.take().is_some() {
                group.state.apply(TypographyIntent::Leave);
            }
            continue;
        }
        let target = typography_hover_target(&hover_map, &parents, &controls, group.root);
        match target {
            Some(TypographyTarget::Part(TypographyPart::Root)) if group.hovered.is_none() => {
                group.hovered = target;
                group
                    .state
                    .apply(TypographyIntent::Hover(TypographyPart::Root));
            }
            Some(TypographyTarget::Part(TypographyPart::Root)) => {}
            Some(target) if group.hovered != Some(target) => {
                group.hovered = Some(target);
                match target {
                    TypographyTarget::Part(part) => {
                        group.state.apply(TypographyIntent::Hover(part));
                    }
                    TypographyTarget::ListItem(index) => {
                        group.state.apply(TypographyIntent::HoverListItem(index));
                    }
                }
            }
            Some(_) => {}
            None if group.hovered.take().is_some() => {
                group.state.apply(TypographyIntent::Leave);
            }
            None => {}
        }
    }
}

#[cfg(target_arch = "wasm32")]
fn typography_hover_target(
    hover_map: &HoverMap,
    parents: &Query<&ChildOf>,
    controls: &Query<&TypographyControl>,
    group: Entity,
) -> Option<TypographyTarget> {
    let mut root_hovered = false;
    for hovered in hover_map.0.values() {
        for entity in hovered.keys() {
            let mut current = Some(*entity);
            while let Some(candidate) = current {
                if let Ok(control) = controls.get(candidate)
                    && control.group == group
                    && !control.disabled
                {
                    if control.target == TypographyTarget::Part(TypographyPart::Root) {
                        root_hovered = true;
                    } else {
                        return Some(control.target);
                    }
                }
                current = parents.get(candidate).ok().map(ChildOf::parent);
            }
        }
    }
    root_hovered.then_some(TypographyTarget::Part(TypographyPart::Root))
}

#[cfg(target_arch = "wasm32")]
fn handle_typography_presses(
    mut presses: MessageReader<Pointer<Press>>,
    parents: Query<&ChildOf>,
    controls: Query<&TypographyControl>,
    mut groups: Query<&mut TypographyStoryState>,
) {
    for press in presses.read() {
        let mut current = Some(press.entity);
        let mut target = None;
        let mut blocked_target = false;
        while let Some(entity) = current {
            if let Ok(control) = controls.get(entity) {
                if control.disabled {
                    blocked_target = true;
                } else {
                    target = Some(*control);
                    break;
                }
            }
            current = parents.get(entity).ok().map(ChildOf::parent);
        }
        if target.is_none() && blocked_target {
            continue;
        }

        for mut group in &mut groups {
            group.state.apply(TypographyIntent::Blur);
        }
        if let Some(control) = target
            && let Ok(mut group) = groups.get_mut(control.group)
        {
            group
                .state
                .apply(TypographyIntent::Focus(TypographyPart::Root));
        }
    }
}

#[cfg(target_arch = "wasm32")]
fn handle_typography_keyboard(
    mut keyboard: MessageReader<KeyboardInput>,
    mut groups: Query<&mut TypographyStoryState>,
) {
    for input in keyboard.read() {
        if input.state != ButtonState::Pressed {
            continue;
        }
        if matches!(input.logical_key, Key::Escape | Key::Tab) {
            for mut group in &mut groups {
                group.state.apply(TypographyIntent::Blur);
            }
        }
    }
}

#[cfg(target_arch = "wasm32")]
fn handle_story_presses(
    mut presses: MessageReader<Pointer<Press>>,
    parents: Query<&ChildOf>,
    triggers: Query<&AccordionTrigger>,
    mut groups: Query<&mut AccordionGroup>,
    mut primitives: ClickablePrimitiveQuery,
) {
    for press in presses.read() {
        let mut current = Some(press.entity);
        while let Some(entity) = current {
            if let Ok(trigger) = triggers.get(entity) {
                if !trigger.disabled
                    && let Ok(mut group) = groups.get_mut(trigger.group)
                {
                    group
                        .state
                        .apply(AccordionIntent::Toggle(trigger.value.clone()));
                }
                break;
            }
            if let Ok((mut colors, mut background, interaction)) = primitives.get_mut(entity) {
                if colors.stateful {
                    colors.latched = !colors.latched;
                    if *interaction == Interaction::None {
                        background.0 = if colors.latched {
                            colors.selected
                        } else {
                            colors.rest
                        };
                    }
                }
                break;
            }
            current = parents.get(entity).ok().map(ChildOf::parent);
        }
    }
}

#[cfg(target_arch = "wasm32")]
fn sync_accordion_state(
    groups: Query<&AccordionGroup, Changed<AccordionGroup>>,
    mut items: AccordionItemVisualQuery,
    mut triggers: AccordionTriggerVisualQuery,
    mut contents: Query<&mut Node, With<AccordionContent>>,
    mut indicators: Query<&mut Text, With<AccordionIndicator>>,
) {
    for group in &groups {
        for entities in &group.items {
            let open = group.state.is_open(&entities.value);
            if let Ok((mut background, mut border)) = items.get_mut(entities.item) {
                background.0 = if open {
                    group.theme.primary_soft().to_bevy()
                } else {
                    group.theme.surface_1().to_bevy()
                };
                *border = BorderColor::all(if open {
                    group.theme.brand().to_bevy()
                } else {
                    group.theme.border_faint().to_bevy()
                });
            }
            if let Ok((interaction, mut colors, mut background)) =
                triggers.get_mut(entities.trigger)
            {
                colors.rest = if open {
                    group.theme.selected_tint().to_bevy()
                } else {
                    Color::NONE
                };
                if *interaction == Interaction::None {
                    background.0 = colors.rest;
                }
            }
            if let Ok(mut node) = contents.get_mut(entities.content) {
                node.display = if open { Display::Flex } else { Display::None };
            }
            if let Ok(mut indicator) = indicators.get_mut(entities.indicator) {
                indicator.0 = if open { "-" } else { "+" }.to_owned();
            }
        }
    }
}

#[cfg(target_arch = "wasm32")]
fn sync_alert_dialog_state(
    groups: Query<&AlertDialogGroupState, Changed<AlertDialogGroupState>>,
    mut nodes: Query<&mut Node>,
) {
    for group in &groups {
        let open = group.state.is_open();
        if let Ok(mut trigger) = nodes.get_mut(group.trigger) {
            trigger.flex_grow = if open { 0.0 } else { 1.0 };
        }
        if let Ok(mut overlay) = nodes.get_mut(group.overlay) {
            overlay.display = if open { Display::Flex } else { Display::None };
        }
    }
}

#[cfg(target_arch = "wasm32")]
#[allow(clippy::type_complexity)]
fn sync_attachment_state(
    mut actions: Query<
        (
            &AttachmentActionState,
            &Interaction,
            &mut InteractivePrimitive,
            &mut BackgroundColor,
            &mut BorderColor,
            &mut TextFont,
        ),
        Changed<AttachmentActionState>,
    >,
) {
    for (action, interaction, mut colors, mut background, mut border, mut font) in &mut actions {
        let active = action.state.activated_value() == Some(action.value.as_str());
        colors.latched = active;
        colors.hover = if active {
            action
                .theme
                .selected_tint()
                .to_bevy_on(action.theme.surface_1())
        } else {
            action.theme.hover_tint().to_bevy()
        };
        background.0 = match interaction {
            Interaction::Pressed => colors.pressed,
            Interaction::Hovered => colors.hover,
            Interaction::None if active => colors.selected,
            Interaction::None => colors.rest,
        };
        *border = BorderColor::all(if active {
            action.theme.brand().to_bevy()
        } else {
            action.theme.border_strong().to_bevy()
        });
        font.weight = if active {
            FontWeight::BOLD
        } else {
            FontWeight::SEMIBOLD
        };
    }
}

#[cfg(target_arch = "wasm32")]
fn sync_badge_state(
    mut badges: Query<(&Interaction, &mut BadgeStoryState, &mut BoxShadow), Changed<Interaction>>,
) {
    for (interaction, mut badge, mut shadow) in &mut badges {
        match interaction {
            Interaction::Hovered | Interaction::Pressed => {
                badge.state.apply(BadgeIntent::Highlight);
            }
            Interaction::None => {
                badge.state.apply(BadgeIntent::ClearHighlight);
            }
        }
        *shadow = if badge.state.is_highlighted() {
            bevy_shadow_1(&badge.theme, badge.inline_size)
        } else {
            BoxShadow::default()
        };
    }
}

#[cfg(target_arch = "wasm32")]
fn sync_breadcrumb_state(
    groups: Query<&BreadcrumbGroupState, Changed<BreadcrumbGroupState>>,
    mut links: Query<(
        &Interaction,
        &mut InteractivePrimitive,
        &mut BackgroundColor,
        &mut TextColor,
    )>,
) {
    for group in &groups {
        for link in &group.links {
            let active = group.state.is_active(&link.value);
            let Ok((interaction, mut colors, mut background, mut text)) =
                links.get_mut(link.entity)
            else {
                continue;
            };
            colors.latched = active;
            colors.rest = if active { colors.selected } else { Color::NONE };
            if *interaction == Interaction::None {
                background.0 = colors.rest;
            }
            text.0 = if active {
                group.theme.text_1().to_bevy()
            } else {
                group.theme.text_2().to_bevy()
            };
        }
    }
}

#[cfg(target_arch = "wasm32")]
fn sync_bubble_state(
    groups: Query<&BubbleGroupState, Changed<BubbleGroupState>>,
    mut actions: Query<(
        &Interaction,
        &mut InteractivePrimitive,
        &mut BackgroundColor,
        &mut BorderColor,
    )>,
) {
    for group in &groups {
        for action in &group.actions {
            let active = group.state.is_active(&action.value);
            let Ok((interaction, mut colors, mut background, mut border)) =
                actions.get_mut(action.entity)
            else {
                continue;
            };
            colors.latched = active;
            *border = BorderColor::all(if active {
                group.theme.brand().to_bevy()
            } else {
                group.theme.border_strong().to_bevy()
            });
            if *interaction == Interaction::None {
                background.0 = if active { colors.selected } else { colors.rest };
            }
        }
    }
}

#[cfg(target_arch = "wasm32")]
fn sync_button_group_state(
    groups: Query<&ButtonGroupStoryState, Changed<ButtonGroupStoryState>>,
    mut items: Query<(
        &Interaction,
        &mut InteractivePrimitive,
        &mut BackgroundColor,
    )>,
    mut texts: Query<&mut TextColor>,
) {
    for group in &groups {
        for item in &group.items {
            let selected = group.state.is_selected(&item.value);
            let (fill, text, hover) =
                button_group_item_colors(group.variant, selected, false, false, &group.theme);
            let Ok((interaction, mut colors, mut background)) = items.get_mut(item.entity) else {
                continue;
            };
            colors.rest = fill;
            colors.selected = fill;
            colors.hover = hover;
            colors.pressed = hover;
            colors.latched = selected;
            if *interaction == Interaction::None {
                background.0 = fill;
            }
            for text_entity in &item.text_entities {
                if let Ok(mut text_color) = texts.get_mut(*text_entity) {
                    text_color.0 = text;
                }
            }
        }
    }
}

#[cfg(target_arch = "wasm32")]
fn sync_button_state(
    mut buttons: Query<(&Interaction, &mut ButtonStoryState, &mut BoxShadow), Changed<Interaction>>,
) {
    for (interaction, mut button, mut shadow) in &mut buttons {
        let intent = if *interaction == Interaction::Pressed {
            ButtonIntent::Press
        } else {
            ButtonIntent::Release
        };
        let _ = button.state.apply(intent);
        *shadow = if button.state.is_pressed() {
            bevy_shadow_1(&button.theme, button.inline_size)
        } else {
            BoxShadow::default()
        };
    }
}

#[cfg(target_arch = "wasm32")]
#[allow(clippy::too_many_arguments)]
fn sync_calendar_state(
    groups: Query<&CalendarGroupState, Changed<CalendarGroupState>>,
    interactions: Query<&Interaction>,
    mut controls: Query<&mut CalendarControl>,
    mut visuals: Query<&mut InteractivePrimitive>,
    mut backgrounds: Query<&mut BackgroundColor>,
    mut borders: Query<&mut BorderColor>,
    mut texts: Query<&mut Text>,
    mut text_colors: Query<&mut TextColor>,
    mut text_fonts: Query<&mut TextFont>,
) {
    for group in &groups {
        if let Ok(mut title) = texts.get_mut(group.title) {
            title.0 = format!(
                "{} {}",
                month_name(group.state.visible_month()),
                group.state.visible_year()
            );
        }
        let nodes = calendar_render_nodes(&group.model, &group.state);
        let day_nodes = nodes
            .iter()
            .filter(|node| node.part == CalendarPart::Day)
            .collect::<Vec<_>>();
        let root_fill = if group.model.disabled {
            group.theme.surface_2()
        } else {
            group.theme.surface_1()
        };
        for day in &group.days {
            let Some(node) = day_nodes.get(day.index).copied() else {
                continue;
            };
            let Some(date) = node.date else {
                continue;
            };
            let (fill, border, text, hover, weight) =
                calendar_day_colors(node, root_fill, &group.theme);
            if let Ok(mut control) = controls.get_mut(day.entity) {
                control.kind = CalendarControlKind::Day(date);
                control.disabled = node.disabled;
            }
            let interaction = interactions
                .get(day.entity)
                .copied()
                .unwrap_or(Interaction::None);
            if let Ok(mut visual) = visuals.get_mut(day.entity) {
                visual.rest = fill;
                visual.selected = fill;
                visual.hover = hover;
                visual.pressed = hover;
                visual.latched = node.selected || node.in_range;
            }
            if let Ok(mut background) = backgrounds.get_mut(day.entity) {
                background.0 = match interaction {
                    Interaction::Pressed | Interaction::Hovered if !node.disabled => hover,
                    Interaction::Pressed | Interaction::Hovered | Interaction::None => fill,
                };
            }
            if let Ok(mut border_color) = borders.get_mut(day.entity) {
                *border_color = BorderColor::all(border);
            }
            if let Ok(mut copy) = texts.get_mut(day.text) {
                copy.0 = node.label.clone();
            }
            if let Ok(mut color) = text_colors.get_mut(day.text) {
                color.0 = text;
            }
            if let Ok(mut font) = text_fonts.get_mut(day.text) {
                font.weight = weight;
            }
        }
        let range_node = nodes
            .iter()
            .find(|node| node.part == CalendarPart::Range)
            .expect("invariant: calendar render nodes include range");
        let (fill, border, text, weight) =
            calendar_range_colors(range_node.selected, root_fill, &group.theme);
        if let Ok(mut background) = backgrounds.get_mut(group.range) {
            background.0 = fill;
        }
        if let Ok(mut border_color) = borders.get_mut(group.range) {
            *border_color = BorderColor::all(border);
        }
        if let Ok(mut copy) = texts.get_mut(group.range) {
            copy.0 = range_node.detail.clone();
        }
        if let Ok(mut color) = text_colors.get_mut(group.range) {
            color.0 = text;
        }
        if let Ok(mut font) = text_fonts.get_mut(group.range) {
            font.weight = weight;
        }
    }
}

#[cfg(target_arch = "wasm32")]
#[allow(clippy::too_many_arguments)]
fn sync_date_picker_state(
    groups: Query<&DatePickerGroupState, Changed<DatePickerGroupState>>,
    interactions: Query<&Interaction>,
    mut controls: Query<&mut DatePickerControl>,
    mut layout_nodes: Query<&mut Node>,
    mut visuals: Query<&mut InteractivePrimitive>,
    mut backgrounds: Query<&mut BackgroundColor>,
    mut borders: Query<&mut BorderColor>,
    mut texts: Query<&mut Text>,
    mut text_colors: Query<&mut TextColor>,
    mut text_fonts: Query<&mut TextFont>,
) {
    for group in &groups {
        let render_nodes = date_picker_render_nodes(&group.model, &group.state);
        let metrics = date_picker_layout_metrics(
            group.model.density,
            group.state.is_open(),
            group.model.disabled,
            group.inline_size,
        );
        let trigger_node = render_nodes
            .iter()
            .find(|node| node.part == DatePickerPart::Trigger)
            .expect("invariant: date picker render nodes include trigger");
        let value_node = render_nodes
            .iter()
            .find(|node| node.part == DatePickerPart::Value)
            .expect("invariant: date picker render nodes include value");
        let trigger_palette = date_picker_trigger_palette(
            group.state.is_open(),
            group.model.disabled,
            group.blocked,
            group.root_fill,
            &group.theme,
        );
        if let Ok(mut layout) = layout_nodes.get_mut(group.trigger) {
            layout.min_height = px(metrics.trigger_min_height);
            layout.flex_grow = if group.state.is_open() { 0.0 } else { 1.0 };
            layout.padding = UiRect::axes(
                px(metrics.trigger_padding_inline),
                px(metrics.trigger_padding_block),
            );
            layout.column_gap = px(metrics.trigger_gap);
        }
        if let Ok(mut control) = controls.get_mut(group.trigger) {
            control.disabled = group.blocked;
        }
        if let Ok(mut visual) = visuals.get_mut(group.trigger) {
            visual.rest = trigger_palette.background;
            visual.selected = trigger_palette.background;
            visual.hover = trigger_palette.hover;
            visual.pressed = trigger_palette.hover;
            visual.latched = group.state.is_open();
        }
        let trigger_interaction = interactions
            .get(group.trigger)
            .copied()
            .unwrap_or(Interaction::None);
        if let Ok(mut background) = backgrounds.get_mut(group.trigger) {
            background.0 = match trigger_interaction {
                Interaction::Hovered | Interaction::Pressed if !group.blocked => {
                    trigger_palette.hover
                }
                Interaction::Hovered | Interaction::Pressed | Interaction::None => {
                    trigger_palette.background
                }
            };
        }
        if let Ok(mut border) = borders.get_mut(group.trigger) {
            *border = BorderColor::all(trigger_palette.border);
        }
        let trigger_weight = if group.state.is_open() {
            FontWeight::BOLD
        } else {
            FontWeight::SEMIBOLD
        };
        if let Ok(mut label) = texts.get_mut(group.trigger_label) {
            label.0 = trigger_node.label.clone();
        }
        if let Ok(mut color) = text_colors.get_mut(group.trigger_label) {
            color.0 = trigger_palette.text;
        }
        if let Ok(mut font) = text_fonts.get_mut(group.trigger_label) {
            font.font_size = FontSize::Px(metrics.trigger_font_size);
            font.weight = trigger_weight;
        }
        if let Ok(mut value) = texts.get_mut(group.value) {
            value.0 = value_node.label.clone();
        }
        if let Ok(mut color) = text_colors.get_mut(group.value) {
            color.0 = if value_node.selected {
                trigger_palette.text
            } else {
                date_picker_resolve_tone(group.theme.text_muted(), group.blocked, group.root_fill)
            };
        }
        if let Ok(mut font) = text_fonts.get_mut(group.value) {
            font.font_size = FontSize::Px(metrics.trigger_font_size);
            font.weight = trigger_weight;
        }
        if let Ok(mut marker) = layout_nodes.get_mut(group.marker) {
            marker.width = px(metrics.marker_size);
            marker.height = px(metrics.marker_size);
            marker.min_width = px(metrics.marker_size);
            marker.min_height = px(metrics.marker_size);
        }
        if let Ok(mut font) = text_fonts.get_mut(group.marker) {
            font.font_size = FontSize::Px(metrics.marker_font_size);
        }
        if let Ok(mut popover) = layout_nodes.get_mut(group.popover) {
            popover.display = if group.state.is_open() {
                Display::Flex
            } else {
                Display::None
            };
            popover.flex_grow = if group.state.is_open() { 1.0 } else { 0.0 };
        }
        if let Ok(mut title) = texts.get_mut(group.title) {
            title.0 = format!(
                "{} {}",
                month_name(group.state.visible_month()),
                group.state.visible_year()
            );
        }

        let popover_fill = group.theme.surface_elevated();
        for day in &group.days {
            let Some(node) = render_nodes
                .iter()
                .find(|node| node.part == DatePickerPart::Calendar && node.index == day.index)
            else {
                continue;
            };
            let Some(date) = node.date else {
                continue;
            };
            let (fill, border, text, hover, weight) = calendar_day_palette(
                node.selected,
                false,
                node.current_month,
                node.disabled,
                popover_fill,
                &group.theme,
            );
            if let Ok(mut control) = controls.get_mut(day.entity) {
                control.kind = DatePickerControlKind::Day(date);
                control.disabled = node.disabled;
            }
            if let Ok(mut visual) = visuals.get_mut(day.entity) {
                visual.rest = fill;
                visual.selected = fill;
                visual.hover = hover;
                visual.pressed = hover;
                visual.latched = node.selected;
            }
            let interaction = interactions
                .get(day.entity)
                .copied()
                .unwrap_or(Interaction::None);
            if let Ok(mut background) = backgrounds.get_mut(day.entity) {
                background.0 = match interaction {
                    Interaction::Hovered | Interaction::Pressed if !node.disabled => hover,
                    Interaction::Hovered | Interaction::Pressed | Interaction::None => fill,
                };
            }
            if let Ok(mut border_color) = borders.get_mut(day.entity) {
                *border_color = BorderColor::all(border);
            }
            if let Ok(mut copy) = texts.get_mut(day.text) {
                copy.0 = node.label.clone();
            }
            if let Ok(mut color) = text_colors.get_mut(day.text) {
                color.0 = text;
            }
            if let Ok(mut font) = text_fonts.get_mut(day.text) {
                font.weight = weight;
            }
        }

        let clear_disabled = group.blocked || group.state.selected().is_none();
        let clear_palette =
            date_picker_control_palette(clear_disabled, group.root_fill, &group.theme);
        if let Ok(mut control) = controls.get_mut(group.clear) {
            control.disabled = clear_disabled;
        }
        if let Ok(mut visual) = visuals.get_mut(group.clear) {
            visual.rest = clear_palette.background;
            visual.selected = clear_palette.background;
            visual.hover = clear_palette.hover;
            visual.pressed = clear_palette.hover;
            visual.latched = false;
        }
        let clear_interaction = interactions
            .get(group.clear)
            .copied()
            .unwrap_or(Interaction::None);
        if let Ok(mut background) = backgrounds.get_mut(group.clear) {
            background.0 = match clear_interaction {
                Interaction::Hovered | Interaction::Pressed if !clear_disabled => {
                    clear_palette.hover
                }
                Interaction::Hovered | Interaction::Pressed | Interaction::None => {
                    clear_palette.background
                }
            };
        }
        if let Ok(mut border) = borders.get_mut(group.clear) {
            *border = BorderColor::all(clear_palette.border);
        }
        if let Ok(mut color) = text_colors.get_mut(group.clear) {
            color.0 = clear_palette.text;
        }
    }
}

#[cfg(target_arch = "wasm32")]
#[allow(clippy::too_many_arguments)]
fn sync_dialog_state(
    groups: Query<&DialogGroupState, Changed<DialogGroupState>>,
    interactions: Query<&Interaction>,
    mut controls: Query<&mut DialogControl>,
    mut layout_nodes: Query<&mut Node>,
    mut visuals: Query<&mut InteractivePrimitive>,
    mut backgrounds: Query<&mut BackgroundColor>,
    mut borders: Query<&mut BorderColor>,
    mut texts: Query<&mut Text>,
    mut text_colors: Query<&mut TextColor>,
    mut text_fonts: Query<&mut TextFont>,
) {
    for group in &groups {
        let border_width = group.theme.border.max(1.0);
        let metrics = dialog_layout_metrics(
            &group.model,
            group.state.is_open(),
            group.available_width,
            group.inline_size,
            border_width,
        );
        let render_nodes = dialog_render_nodes(&group.model, &group.state);
        let trigger_node = render_nodes
            .iter()
            .find(|node| node.part == DialogPart::Trigger)
            .expect("invariant: dialog render nodes include trigger");
        let root_fill = group.theme.surface_1();
        let trigger_palette = dialog_trigger_palette(
            group.state.is_open(),
            group.blocked,
            root_fill,
            &group.theme,
        );
        if let Ok(mut layout) = layout_nodes.get_mut(group.trigger) {
            layout.min_height = px(metrics.trigger_height);
            layout.flex_grow = if group.state.is_open() { 0.0 } else { 1.0 };
        }
        if let Ok(mut control) = controls.get_mut(group.trigger) {
            control.disabled = group.blocked;
        }
        if let Ok(mut visual) = visuals.get_mut(group.trigger) {
            visual.rest = trigger_palette.background;
            visual.selected = trigger_palette.background;
            visual.hover = trigger_palette.hover;
            visual.pressed = trigger_palette.hover;
            visual.latched = group.state.is_open();
        }
        let trigger_interaction = interactions
            .get(group.trigger)
            .copied()
            .unwrap_or(Interaction::None);
        if let Ok(mut background) = backgrounds.get_mut(group.trigger) {
            background.0 = match trigger_interaction {
                Interaction::Hovered | Interaction::Pressed if !group.blocked => {
                    trigger_palette.hover
                }
                Interaction::Hovered | Interaction::Pressed | Interaction::None => {
                    trigger_palette.background
                }
            };
        }
        if let Ok(mut border) = borders.get_mut(group.trigger) {
            *border = BorderColor::all(trigger_palette.border);
        }
        if let Ok(mut text) = texts.get_mut(group.trigger_text) {
            text.0 = trigger_node.label.clone();
        }
        if let Ok(mut color) = text_colors.get_mut(group.trigger_text) {
            color.0 = trigger_palette.text;
        }
        if let Ok(mut font) = text_fonts.get_mut(group.trigger_text) {
            font.weight = if group.state.is_open() {
                FontWeight::BOLD
            } else {
                FontWeight::SEMIBOLD
            };
        }
        if let Ok(mut overlay) = layout_nodes.get_mut(group.overlay) {
            overlay.display = if group.state.is_open() {
                Display::Flex
            } else {
                Display::None
            };
            overlay.min_height = px(metrics.overlay_height);
            overlay.flex_grow = if group.state.is_open() { 1.0 } else { 0.0 };
        }

        let content_fill = group.theme.surface_elevated();
        for action in &group.actions {
            let Some(node) = render_nodes
                .iter()
                .find(|node| node.part == DialogPart::Footer && node.value == action.value)
            else {
                continue;
            };
            let disabled = group.blocked || node.disabled || !node.actionable;
            let palette = dialog_action_palette(
                node.index,
                node.selected,
                disabled,
                content_fill,
                &group.theme,
            );
            if let Ok(mut control) = controls.get_mut(action.entity) {
                control.kind = DialogControlKind::Action {
                    value: action.value.clone(),
                    close_dialog: action.close_dialog,
                };
                control.disabled = disabled;
            }
            if let Ok(mut visual) = visuals.get_mut(action.entity) {
                visual.rest = palette.background;
                visual.selected = palette.background;
                visual.hover = palette.hover;
                visual.pressed = palette.hover;
                visual.latched = node.selected;
            }
            let interaction = interactions
                .get(action.entity)
                .copied()
                .unwrap_or(Interaction::None);
            if let Ok(mut background) = backgrounds.get_mut(action.entity) {
                background.0 = match interaction {
                    Interaction::Hovered | Interaction::Pressed if !disabled => palette.hover,
                    Interaction::Hovered | Interaction::Pressed | Interaction::None => {
                        palette.background
                    }
                };
            }
            if let Ok(mut border) = borders.get_mut(action.entity) {
                *border = BorderColor::all(palette.border);
            }
            if let Ok(mut text) = texts.get_mut(action.entity) {
                text.0 = node.label.clone();
            }
            if let Ok(mut color) = text_colors.get_mut(action.entity) {
                color.0 = palette.text;
            }
            if let Ok(mut font) = text_fonts.get_mut(action.entity) {
                font.weight = if node.index == 0 || node.selected {
                    FontWeight::BOLD
                } else {
                    FontWeight::SEMIBOLD
                };
            }
        }
    }
}

#[cfg(target_arch = "wasm32")]
#[allow(clippy::too_many_arguments)]
fn sync_dropdown_menu_state(
    groups: Query<&DropdownMenuGroupState, Changed<DropdownMenuGroupState>>,
    interactions: Query<&Interaction>,
    mut trigger_controls: Query<&mut DropdownMenuTriggerControl>,
    mut item_controls: Query<&mut DropdownMenuItemControl>,
    mut layout_nodes: Query<&mut Node>,
    mut visuals: Query<&mut InteractivePrimitive>,
    mut backgrounds: Query<&mut BackgroundColor>,
    mut borders: Query<&mut BorderColor>,
    mut texts: Query<&mut Text>,
    mut text_colors: Query<&mut TextColor>,
    mut text_fonts: Query<&mut TextFont>,
) {
    for group in &groups {
        let render_nodes = dropdown_menu_render_nodes(&group.model, &group.state);
        let metrics = dropdown_menu_layout_metrics(
            group.model.density,
            group.state.is_open(),
            group.model.disabled,
            group.inline_size,
        );
        let trigger_node = render_nodes
            .iter()
            .find(|node| node.part == DropdownMenuPart::Trigger)
            .expect("invariant: dropdown menu render nodes include trigger");
        let root_fill = group.theme.surface_1();
        let trigger_palette = dropdown_menu_trigger_palette(
            group.state.is_open(),
            group.blocked,
            root_fill,
            &group.theme,
        );
        if let Ok(mut layout) = layout_nodes.get_mut(group.trigger) {
            layout.min_height = px(metrics.trigger_min_height);
            layout.padding = UiRect::axes(
                px(metrics.trigger_padding_inline),
                px(metrics.trigger_padding_block),
            );
        }
        if let Ok(mut control) = trigger_controls.get_mut(group.trigger) {
            control.disabled = group.blocked;
        }
        if let Ok(mut visual) = visuals.get_mut(group.trigger) {
            visual.rest = trigger_palette.background;
            visual.selected = trigger_palette.background;
            visual.hover = trigger_palette.hover;
            visual.pressed = trigger_palette.hover;
            visual.latched = group.state.is_open();
        }
        let trigger_interaction = interactions
            .get(group.trigger)
            .copied()
            .unwrap_or(Interaction::None);
        if let Ok(mut background) = backgrounds.get_mut(group.trigger) {
            background.0 = match trigger_interaction {
                Interaction::Hovered | Interaction::Pressed if !group.blocked => {
                    trigger_palette.hover
                }
                Interaction::Hovered | Interaction::Pressed | Interaction::None => {
                    trigger_palette.background
                }
            };
        }
        if let Ok(mut border) = borders.get_mut(group.trigger) {
            *border = BorderColor::all(trigger_palette.border);
        }
        if let Ok(mut text) = texts.get_mut(group.trigger) {
            text.0 = trigger_node.label.clone();
        }
        if let Ok(mut color) = text_colors.get_mut(group.trigger) {
            color.0 = trigger_palette.text;
        }
        if let Ok(mut font) = text_fonts.get_mut(group.trigger) {
            font.font_size = FontSize::Px(metrics.trigger_font_size);
            font.weight = if group.state.is_open() {
                FontWeight::BOLD
            } else {
                FontWeight::SEMIBOLD
            };
        }
        if let Ok(mut content) = layout_nodes.get_mut(group.content) {
            content.display = if group.state.is_open() {
                Display::Flex
            } else {
                Display::None
            };
            content.top = px(metrics.trigger_min_height + metrics.content_margin_top);
            content.padding = UiRect::all(px(metrics.content_padding));
        }

        for entry in &group.entries {
            let dynamic = render_nodes
                .iter()
                .find(|node| node.part == entry.part && node.value == entry.value);
            let visible = dynamic.is_some_and(|node| node.visible);
            if let Ok(mut layout) = layout_nodes.get_mut(entry.entity) {
                layout.display = if visible {
                    Display::Flex
                } else {
                    Display::None
                };
            }
            if entry.part == DropdownMenuPart::Label {
                if let Some(node) = dynamic
                    && let Some(label) = entry.label
                    && let Ok(mut text) = texts.get_mut(label)
                {
                    text.0 = node.label.to_uppercase();
                }
                continue;
            }
            if entry.part == DropdownMenuPart::Separator {
                continue;
            }
            let Some(node) = dynamic else {
                continue;
            };
            let disabled = node.disabled || entry.disabled;
            let destructive = node.destructive || entry.destructive;
            let item_metrics = dropdown_menu_item_metrics(&metrics, group.model.density, node);
            let palette = dropdown_menu_item_palette(
                node.selected,
                node.active,
                disabled,
                destructive,
                group.content_fill,
                &group.theme,
            );
            if let Ok(mut layout) = layout_nodes.get_mut(entry.entity) {
                layout.min_height = px(item_metrics.min_height);
                layout.padding = UiRect::axes(
                    px(item_metrics.padding_inline),
                    px(item_metrics.padding_block),
                );
                layout.border = UiRect::all(px(if node.selected {
                    group.theme.border.max(1.0)
                } else {
                    0.0
                }));
                layout.column_gap = px(item_metrics.gap);
            }
            if let Ok(mut control) = item_controls.get_mut(entry.entity) {
                control.disabled = disabled;
            }
            if let Ok(mut visual) = visuals.get_mut(entry.entity) {
                visual.rest = palette.background;
                visual.selected = palette.background;
                visual.hover = palette.hover;
                visual.pressed = palette.hover;
                visual.latched = node.selected || node.active;
            }
            let interaction = interactions
                .get(entry.entity)
                .copied()
                .unwrap_or(Interaction::None);
            if let Ok(mut background) = backgrounds.get_mut(entry.entity) {
                background.0 = match interaction {
                    Interaction::Hovered | Interaction::Pressed if !disabled => palette.hover,
                    Interaction::Hovered | Interaction::Pressed | Interaction::None => {
                        palette.background
                    }
                };
            }
            if let Ok(mut border) = borders.get_mut(entry.entity) {
                *border = BorderColor::all(palette.border);
            }
            if let Some(label) = entry.label {
                if let Ok(mut text) = texts.get_mut(label) {
                    text.0 = node.label.clone();
                }
                if let Ok(mut color) = text_colors.get_mut(label) {
                    color.0 = palette.text;
                }
                if let Ok(mut font) = text_fonts.get_mut(label) {
                    font.font_size = FontSize::Px(item_metrics.font_size);
                    font.weight = dropdown_menu_item_weight(node);
                }
            }
            if let Some(detail) = entry.detail {
                if let Ok(mut text) = texts.get_mut(detail) {
                    text.0 = node.detail.clone();
                }
                if let Ok(mut color) = text_colors.get_mut(detail) {
                    color.0 = palette.detail;
                }
            }
            if let Some(shortcut) = entry.shortcut {
                if let Ok(mut text) = texts.get_mut(shortcut) {
                    text.0 = node.shortcut.clone();
                }
                if let Ok(mut color) = text_colors.get_mut(shortcut) {
                    color.0 = palette.shortcut_text;
                }
                if let Ok(mut background) = backgrounds.get_mut(shortcut) {
                    background.0 = palette.shortcut_background;
                }
                if let Ok(mut border) = borders.get_mut(shortcut) {
                    *border = BorderColor::all(palette.shortcut_border);
                }
            }
        }
    }
}

#[cfg(target_arch = "wasm32")]
fn sync_empty_state(
    groups: Query<&EmptyGroupState, Changed<EmptyGroupState>>,
    mut actions: Query<(
        &Interaction,
        &mut InteractivePrimitive,
        &mut BackgroundColor,
        &mut BorderColor,
    )>,
) {
    for group in &groups {
        let active = group.state.is_active(EmptyPart::Action);
        let palette = empty_action_palette(active, false, group.root_fill, &group.theme);
        let Ok((interaction, mut visual, mut background, mut border)) =
            actions.get_mut(group.action)
        else {
            continue;
        };
        visual.rest = palette.background;
        visual.selected = palette.selected;
        visual.hover = palette.hover;
        visual.pressed = palette.hover;
        visual.latched = active;
        if *interaction == Interaction::None {
            background.0 = palette.background;
        }
        *border = BorderColor::all(palette.border);
    }
}

#[cfg(target_arch = "wasm32")]
fn sync_card_state(
    mut actions: Query<
        (
            &CardActionState,
            &Interaction,
            &mut InteractivePrimitive,
            &mut BackgroundColor,
            &mut BorderColor,
        ),
        Changed<CardActionState>,
    >,
) {
    for (action, interaction, mut colors, mut background, mut border) in &mut actions {
        let active = action.state.is_active(CardPart::Footer);
        let rest = if active {
            action.theme.selected_tint().to_bevy_on(action.root_fill)
        } else {
            action.theme.surface_2().to_bevy_on(action.root_fill)
        };
        colors.rest = rest;
        colors.selected = action.theme.selected_tint().to_bevy_on(action.root_fill);
        colors.latched = active;
        if *interaction == Interaction::None {
            background.0 = rest;
        }
        *border = BorderColor::all(if active {
            action.theme.brand().to_bevy_on(action.root_fill)
        } else {
            action.theme.border_strong().to_bevy_on(action.root_fill)
        });
    }
}

#[cfg(target_arch = "wasm32")]
#[allow(clippy::too_many_arguments)]
fn sync_carousel_state(
    groups: Query<&CarouselGroupState, Changed<CarouselGroupState>>,
    interactions: Query<&Interaction>,
    mut controls: Query<&mut CarouselControl>,
    mut visuals: Query<&mut InteractivePrimitive>,
    mut backgrounds: Query<&mut BackgroundColor>,
    mut borders: Query<&mut BorderColor>,
    mut shadows: Query<&mut BoxShadow>,
    mut texts: Query<&mut Text>,
    mut text_colors: Query<&mut TextColor>,
) {
    for group in &groups {
        let nodes = carousel_render_nodes(&group.model, &group.state);
        for slide in &group.slides {
            let Some(node) = nodes
                .iter()
                .find(|node| node.part == CarouselPart::Item && node.index == slide.index)
            else {
                continue;
            };
            let (fill, border) = carousel_item_tones(node.selected, node.disabled, &group.theme);
            if let Ok(mut background) = backgrounds.get_mut(slide.panel) {
                background.0 = fill.to_bevy_on(group.root_fill);
            }
            if let Ok(mut border_color) = borders.get_mut(slide.panel) {
                *border_color = BorderColor::all(border.to_bevy_on(group.root_fill));
            }
            if let Ok(mut shadow) = shadows.get_mut(slide.panel) {
                *shadow = if node.selected && !node.disabled {
                    bevy_shadow_1(&group.theme, group.inline_size)
                } else {
                    BoxShadow::default()
                };
            }
            if let Ok(mut title) = texts.get_mut(slide.title) {
                title.0 = node.label.clone();
            }
            if let Ok(mut detail) = texts.get_mut(slide.detail) {
                detail.0 = node.detail.clone();
            }
            if let Ok(mut color) = text_colors.get_mut(slide.title) {
                color.0 = group.theme.text_1().to_bevy_on(fill);
            }
            if let Ok(mut color) = text_colors.get_mut(slide.detail) {
                color.0 = group.theme.text_2().to_bevy_on(fill);
            }
        }

        for (part, nav) in [
            (CarouselPart::Previous, group.previous),
            (CarouselPart::Next, group.next),
        ] {
            let Some(node) = nodes.iter().find(|node| node.part == part) else {
                continue;
            };
            let (background, border, text, hover) =
                carousel_nav_colors(node.disabled, group.root_fill, &group.theme);
            if let Ok(mut control) = controls.get_mut(nav.control) {
                control.disabled = node.disabled;
            }
            if let Ok(mut visual) = visuals.get_mut(nav.control) {
                visual.rest = background;
                visual.selected = background;
                visual.hover = hover;
                visual.pressed = hover;
                visual.latched = false;
            }
            let interaction = interactions
                .get(nav.control)
                .copied()
                .unwrap_or(Interaction::None);
            if let Ok(mut fill) = backgrounds.get_mut(nav.control) {
                fill.0 = match interaction {
                    Interaction::Hovered | Interaction::Pressed if !node.disabled => hover,
                    Interaction::Hovered | Interaction::Pressed | Interaction::None => background,
                };
            }
            if let Ok(mut border_color) = borders.get_mut(nav.control) {
                *border_color = BorderColor::all(border);
            }
            if let Ok(mut color) = text_colors.get_mut(nav.text) {
                color.0 = text;
            }
        }

        if let Some(node) = nodes
            .iter()
            .find(|node| node.part == CarouselPart::Indicator)
            && let Ok(mut indicator) = texts.get_mut(group.indicator)
        {
            indicator.0 = node.label.clone();
        }
    }
}

#[cfg(target_arch = "wasm32")]
#[allow(clippy::too_many_arguments)]
fn sync_chart_state(
    groups: Query<&ChartGroupState, Changed<ChartGroupState>>,
    interactions: Query<&Interaction>,
    mut controls: Query<&mut ChartControl>,
    mut visuals: Query<&mut InteractivePrimitive>,
    mut layout_nodes: Query<&mut Node>,
    mut backgrounds: Query<&mut BackgroundColor>,
    mut borders: Query<&mut BorderColor>,
    mut shadows: Query<&mut BoxShadow>,
    mut texts: Query<&mut Text>,
    mut text_colors: Query<&mut TextColor>,
    mut text_fonts: Query<&mut TextFont>,
) {
    for group in &groups {
        let nodes = chart_render_nodes(&group.model, &group.state);
        for series in &group.series {
            let Some(node) = nodes
                .iter()
                .find(|node| node.part == ChartPart::Series && node.value == series.value)
            else {
                continue;
            };
            let palette = chart_series_palette(
                node.selected,
                node.disabled,
                node.tone,
                group.root_fill,
                &group.theme,
            );
            if let Ok(mut control) = controls.get_mut(series.button) {
                control.disabled = node.disabled;
            }
            if let Ok(mut visual) = visuals.get_mut(series.button) {
                visual.rest = palette.background;
                visual.selected = palette.background;
                visual.hover = palette.hover;
                visual.pressed = palette.hover;
                visual.latched = node.selected;
            }
            let interaction = interactions
                .get(series.button)
                .copied()
                .unwrap_or(Interaction::None);
            if let Ok(mut background) = backgrounds.get_mut(series.button) {
                background.0 = match interaction {
                    Interaction::Hovered | Interaction::Pressed if !node.disabled => palette.hover,
                    Interaction::Hovered | Interaction::Pressed | Interaction::None => {
                        palette.background
                    }
                };
            }
            if let Ok(mut border) = borders.get_mut(series.button) {
                *border = BorderColor::all(palette.border);
            }
            if let Ok(mut shadow) = shadows.get_mut(series.button) {
                *shadow = if node.selected {
                    bevy_shadow_1(&group.theme, group.inline_size)
                } else {
                    BoxShadow::default()
                };
            }
            if let Ok(mut label) = texts.get_mut(series.label) {
                label.0 = node.label.to_uppercase();
            }
            if let Ok(mut amount) = texts.get_mut(series.amount) {
                amount.0 = format!("{}{}", node.amount, group.model.unit);
            }
            for text_entity in [series.label, series.amount] {
                if let Ok(mut color) = text_colors.get_mut(text_entity) {
                    color.0 = palette.label;
                }
            }
            if let Ok(mut track) = backgrounds.get_mut(series.track) {
                track.0 = palette.track;
            }
            if let Ok(mut bar) = backgrounds.get_mut(series.bar) {
                bar.0 = palette.bar;
            }
            if let Ok(mut bar) = layout_nodes.get_mut(series.bar) {
                bar.width = percent(f32::from(node.amount));
            }
        }

        for legend in &group.legends {
            let Some(node) = nodes
                .iter()
                .find(|node| node.part == ChartPart::Legend && node.value == legend.value)
            else {
                continue;
            };
            let (fill, border, text) =
                chart_legend_colors(node.selected, group.root_fill, &group.theme);
            if let Ok(mut background) = backgrounds.get_mut(legend.pill) {
                background.0 = fill;
            }
            if let Ok(mut border_color) = borders.get_mut(legend.pill) {
                *border_color = BorderColor::all(border);
            }
            if let Ok(mut copy) = texts.get_mut(legend.text) {
                copy.0 = node.label.clone();
            }
            if let Ok(mut color) = text_colors.get_mut(legend.text) {
                color.0 = text;
            }
            if let Ok(mut font) = text_fonts.get_mut(legend.text) {
                font.weight = if node.selected {
                    FontWeight::BOLD
                } else {
                    FontWeight::SEMIBOLD
                };
            }
        }

        if let Some(node) = nodes.iter().find(|node| node.part == ChartPart::Tooltip)
            && let Ok(mut tooltip) = texts.get_mut(group.tooltip)
        {
            tooltip.0 = format!("{}: {}", node.label, node.detail);
        }
    }
}

#[cfg(target_arch = "wasm32")]
#[allow(clippy::too_many_arguments)]
fn sync_collapsible_state(
    groups: Query<&CollapsibleGroupState, Changed<CollapsibleGroupState>>,
    interactions: Query<&Interaction>,
    mut controls: Query<&mut CollapsibleControl>,
    mut visuals: Query<&mut InteractivePrimitive>,
    mut layout_nodes: Query<&mut Node>,
    mut backgrounds: Query<&mut BackgroundColor>,
    mut texts: Query<&mut Text>,
    mut text_colors: Query<&mut TextColor>,
    mut text_fonts: Query<&mut TextFont>,
) {
    for group in &groups {
        let open = group.state.is_open();
        let blocked = group.model.loading || group.model.disabled;
        let metrics = collapsible_layout_metrics(
            group.model.density,
            group.model.disabled,
            open,
            group.inline_size,
        );
        let nodes = collapsible_render_nodes(&group.model, &group.state);
        let trigger_node = nodes
            .iter()
            .find(|node| node.part == CollapsiblePart::Trigger)
            .expect("invariant: collapsible has a trigger");
        let content_node = nodes
            .iter()
            .find(|node| node.part == CollapsiblePart::Content)
            .expect("invariant: collapsible has content");
        let palette = collapsible_trigger_palette(
            open,
            blocked,
            group.model.disabled,
            group.root_fill,
            &group.theme,
        );

        if let Ok(mut control) = controls.get_mut(group.trigger) {
            control.disabled = blocked;
        }
        if let Ok(mut trigger) = layout_nodes.get_mut(group.trigger) {
            let root_radius =
                if group.model.density == CollapsibleDensity::Dense && !group.model.disabled {
                    group.theme.radius_field
                } else {
                    group.theme.radius_box
                };
            trigger.min_height = px(metrics.trigger_min_height);
            trigger.flex_grow = if open { 0.0 } else { 1.0 };
            trigger.padding = UiRect::axes(
                px(metrics.trigger_padding_inline),
                px(metrics.trigger_padding_block),
            );
            trigger.column_gap = px(metrics.trigger_gap);
            trigger.border_radius = collapsible_trigger_radius(root_radius, open);
        }
        if let Ok(mut visual) = visuals.get_mut(group.trigger) {
            visual.rest = palette.background;
            visual.selected = palette.background;
            visual.hover = palette.hover;
            visual.pressed = palette.hover;
            visual.latched = open;
        }
        let interaction = interactions
            .get(group.trigger)
            .copied()
            .unwrap_or(Interaction::None);
        if let Ok(mut background) = backgrounds.get_mut(group.trigger) {
            background.0 = match interaction {
                Interaction::Hovered | Interaction::Pressed if !blocked => palette.hover,
                Interaction::Hovered | Interaction::Pressed | Interaction::None => {
                    palette.background
                }
            };
        }
        if let Ok(mut label) = texts.get_mut(group.trigger_label) {
            label.0 = trigger_node.label.clone();
        }
        if let Ok(mut color) = text_colors.get_mut(group.trigger_label) {
            color.0 = palette.label;
        }
        if let Ok(mut font) = text_fonts.get_mut(group.trigger_label) {
            font.font_size = FontSize::Px(metrics.trigger_font_size);
        }
        if let Ok(mut indicator) = texts.get_mut(group.indicator) {
            indicator.0 = if open { "-" } else { "+" }.to_owned();
        }
        if let Ok(mut content) = layout_nodes.get_mut(group.content) {
            content.display = if open { Display::Flex } else { Display::None };
            content.flex_grow = if open { 1.0 } else { 0.0 };
            content.padding = UiRect::all(px(metrics.content_padding));
        }
        if let Ok(mut content) = texts.get_mut(group.content) {
            content.0 = content_node.detail.clone();
        }
        if let Ok(mut font) = text_fonts.get_mut(group.content) {
            font.font_size = FontSize::Px(metrics.content_font_size);
        }
    }
}

#[cfg(target_arch = "wasm32")]
#[allow(clippy::too_many_arguments)]
fn sync_combobox_state(
    groups: Query<&ComboboxGroup, Changed<ComboboxGroup>>,
    interactions: Query<&Interaction>,
    mut layout_nodes: Query<&mut Node>,
    mut controls: Query<&mut ComboboxOptionTrigger>,
    mut backgrounds: Query<&mut BackgroundColor>,
    mut borders: Query<&mut BorderColor>,
    mut visuals: Query<&mut InteractivePrimitive>,
    mut texts: Query<&mut Text>,
    mut text_colors: Query<&mut TextColor>,
    mut text_fonts: Query<&mut TextFont>,
) {
    for group in &groups {
        let metrics =
            combobox_layout_metrics(group.model.density, group.model.disabled, group.inline_size);
        let render_nodes = combobox_render_nodes(&group.model, &group.state);
        if let Ok(mut list) = layout_nodes.get_mut(group.list) {
            list.display = if group.state.is_open() {
                Display::Flex
            } else {
                Display::None
            };
        }
        if let Ok(mut input) = layout_nodes.get_mut(group.input) {
            input.flex_grow = if group.state.is_open() { 0.0 } else { 1.0 };
        }
        let query_empty = group.state.query().is_empty();
        let (input_background, input_border, input_text) = combobox_input_colors(
            group.state.is_open(),
            query_empty,
            group.blocked,
            group.root_fill,
            &group.theme,
        );
        if let Ok(mut input) = texts.get_mut(group.input) {
            input.0 = if query_empty {
                group.model.placeholder.clone()
            } else {
                group.state.query().to_owned()
            };
        }
        if let Ok(mut color) = text_colors.get_mut(group.input) {
            color.0 = input_text;
        }
        if let Ok(mut background) = backgrounds.get_mut(group.input) {
            background.0 = input_background;
        }
        if let Ok(mut border) = borders.get_mut(group.input) {
            *border = BorderColor::all(input_border);
        }
        if let Ok(mut visual) = visuals.get_mut(group.input) {
            visual.rest = input_background;
            visual.selected = input_background;
            visual.hover = input_background;
            visual.pressed = input_background;
        }
        for option in &group.options {
            let node = render_nodes
                .iter()
                .find(|node| node.part == ComboboxPart::Option && node.value == option.value);
            let visible = group.state.is_open() && node.is_some_and(|node| node.visible);
            if let Ok(mut layout) = layout_nodes.get_mut(option.entity) {
                layout.display = if visible {
                    Display::Flex
                } else {
                    Display::None
                };
            }
            let selected = node.is_some_and(|node| node.selected);
            let disabled = node.map_or(group.blocked || option.disabled, |node| node.disabled);
            let palette =
                combobox_option_palette(selected, disabled, group.root_fill, &group.theme);
            if let Ok(mut control) = controls.get_mut(option.entity) {
                control.disabled = disabled;
            }
            if let Ok(mut visual) = visuals.get_mut(option.entity) {
                visual.rest = palette.background;
                visual.selected = palette.background;
                visual.hover = palette.hover;
                visual.pressed = palette.hover;
                visual.latched = selected;
            }
            let interaction = interactions
                .get(option.entity)
                .copied()
                .unwrap_or(Interaction::None);
            if let Ok(mut background) = backgrounds.get_mut(option.entity) {
                background.0 = match interaction {
                    Interaction::Hovered | Interaction::Pressed if !disabled => palette.hover,
                    Interaction::Hovered | Interaction::Pressed | Interaction::None => {
                        palette.background
                    }
                };
            }
            if let Ok(mut border) = borders.get_mut(option.entity) {
                *border = BorderColor::all(palette.border);
            }
            if let Ok(mut label) = texts.get_mut(option.label) {
                label.0 = node.map_or_else(
                    || {
                        group
                            .model
                            .options
                            .iter()
                            .find(|candidate| candidate.value == option.value)
                            .map_or_else(String::new, |candidate| candidate.label.clone())
                    },
                    |node| node.label.clone(),
                );
            }
            if let Ok(mut color) = text_colors.get_mut(option.label) {
                color.0 = palette.text;
            }
            if let Ok(mut font) = text_fonts.get_mut(option.label) {
                font.weight = if selected {
                    FontWeight::BOLD
                } else {
                    FontWeight::NORMAL
                };
                font.font_size = FontSize::Px(metrics.option_font_size);
            }
            if let Ok(mut meta) = texts.get_mut(option.meta) {
                meta.0 = if selected { "SELECTED" } else { "" }.to_owned();
            }
            if let Ok(mut color) = text_colors.get_mut(option.meta) {
                color.0 = palette.meta;
            }
        }
        let empty = render_nodes
            .iter()
            .find(|node| node.part == ComboboxPart::Empty)
            .expect("invariant: combobox has an empty node");
        if let Ok(mut layout) = layout_nodes.get_mut(group.empty) {
            layout.display = if empty.visible {
                Display::Flex
            } else {
                Display::None
            };
        }
        if let Ok(mut copy) = texts.get_mut(group.empty) {
            copy.0 = empty.label.clone();
        }
    }
}

#[cfg(target_arch = "wasm32")]
#[allow(clippy::type_complexity)]
fn sync_checkbox_state(
    groups: Query<&CheckboxGroupState, Changed<CheckboxGroupState>>,
    mut indicators: Query<
        (
            &Interaction,
            &mut InteractivePrimitive,
            &mut BackgroundColor,
            &mut BorderColor,
            &mut Text,
            &mut TextColor,
        ),
        With<CheckboxTrigger>,
    >,
) {
    for group in &groups {
        let checked = group.state.checked();
        let (fill, border, text_color) =
            checkbox_indicator_colors(&group.theme, checked, group.invalid, group.blocked);
        if let Ok((
            interaction,
            mut colors,
            mut background,
            mut border_color,
            mut text,
            mut color,
        )) = indicators.get_mut(group.indicator)
        {
            *colors =
                checkbox_interaction(&group.theme, checked, group.invalid, group.blocked, fill);
            if *interaction == Interaction::None {
                background.0 = fill;
            }
            *border_color = BorderColor::all(border);
            text.0 = checkbox_indicator_label(checked).to_owned();
            color.0 = text_color;
        }
    }
}

#[cfg(target_arch = "wasm32")]
#[allow(clippy::type_complexity)]
fn sync_radio_group_interactions(
    controls: Query<(&RadioGroupControl, &Interaction), Changed<Interaction>>,
    groups: Query<&RadioGroupGroup>,
    mut items: Query<
        (&mut BackgroundColor, &mut BorderColor, &mut BoxShadow),
        (
            With<RadioGroupItemVisual>,
            Without<RadioGroupControl>,
            Without<RadioGroupDotVisual>,
        ),
    >,
) {
    for (control, interaction) in &controls {
        let Ok(group) = groups.get(control.group) else {
            continue;
        };
        let Some(entry) = group
            .items
            .iter()
            .find(|entry| entry.value == control.value)
        else {
            continue;
        };
        let selected = group.state.is_selected(&entry.value);
        let focused = group.state.is_focused(&entry.value);
        let root_opacity = if group.root_disabled {
            scale::opacity::DISABLED
        } else {
            1.0
        };
        let item_opacity = root_opacity
            * if entry.disabled {
                scale::opacity::DISABLED
            } else {
                1.0
            };
        let (fill, border) = radio_group_item_colors(
            &group.theme,
            selected,
            focused,
            entry.disabled,
            item_opacity,
            *interaction,
        );
        if let Ok((mut background, mut border_color, mut shadow)) = items.get_mut(entry.item) {
            background.0 = fill;
            *border_color = BorderColor::all(border);
            *shadow = if !entry.disabled && (selected || focused) {
                bevy_shadow_1(&group.theme, group.inline_size)
            } else {
                BoxShadow::default()
            };
        }
    }
}

#[cfg(target_arch = "wasm32")]
#[allow(clippy::type_complexity)]
fn sync_radio_group_state(
    groups: Query<&RadioGroupGroup, Changed<RadioGroupGroup>>,
    mut items: Query<
        (
            &mut Node,
            &mut BackgroundColor,
            &mut BorderColor,
            &mut BoxShadow,
        ),
        (
            With<RadioGroupItemVisual>,
            Without<RadioGroupControl>,
            Without<RadioGroupDotVisual>,
        ),
    >,
    mut controls: Query<
        (
            &Interaction,
            &mut BackgroundColor,
            &mut BorderColor,
            &mut BoxShadow,
        ),
        (
            With<RadioGroupControl>,
            Without<RadioGroupItemVisual>,
            Without<RadioGroupDotVisual>,
        ),
    >,
    mut dots: Query<
        (&mut Node, &mut BackgroundColor),
        (
            With<RadioGroupDotVisual>,
            Without<RadioGroupItemVisual>,
            Without<RadioGroupControl>,
        ),
    >,
) {
    for group in &groups {
        let root_opacity = if group.root_disabled {
            scale::opacity::DISABLED
        } else {
            1.0
        };
        for entry in &group.items {
            let selected = group.state.is_selected(&entry.value);
            let focused = group.state.is_focused(&entry.value);
            let emphasized =
                radio_group_item_uses_emphasized_metrics(selected, focused, entry.disabled);
            let item_opacity = root_opacity
                * if entry.disabled {
                    scale::opacity::DISABLED
                } else {
                    1.0
                };
            let control_opacity = item_opacity
                * if entry.disabled {
                    scale::opacity::DISABLED
                } else {
                    1.0
                };
            let interaction = controls
                .get(entry.control)
                .map_or(Interaction::None, |(interaction, _, _, _)| *interaction);
            let (item_fill, item_border) = radio_group_item_colors(
                &group.theme,
                selected,
                focused,
                entry.disabled,
                item_opacity,
                interaction,
            );
            if let Ok((mut node, mut fill, mut border, mut shadow)) = items.get_mut(entry.item) {
                node.padding = UiRect::all(px(if emphasized {
                    group.metrics.emphasized_item_padding
                } else {
                    group.metrics.item_padding
                }));
                node.column_gap = px(if emphasized {
                    group.metrics.emphasized_item_gap
                } else {
                    group.metrics.item_gap
                });
                fill.0 = item_fill;
                *border = BorderColor::all(item_border);
                *shadow = if !entry.disabled && (selected || focused) {
                    bevy_shadow_1(&group.theme, group.inline_size)
                } else {
                    BoxShadow::default()
                };
            }
            let (control_fill, control_border, dot_color) = radio_group_control_colors(
                &group.theme,
                selected,
                entry.disabled,
                group.invalid,
                control_opacity,
            );
            if let Ok((_, mut fill, mut border, mut shadow)) = controls.get_mut(entry.control) {
                fill.0 = control_fill;
                *border = BorderColor::all(control_border);
                *shadow = if !entry.disabled && (group.invalid || selected) {
                    bevy_shadow_1(&group.theme, group.inline_size)
                } else {
                    BoxShadow::default()
                };
            }
            if let Ok((mut node, mut fill)) = dots.get_mut(entry.dot) {
                node.display = if selected {
                    Display::Flex
                } else {
                    Display::None
                };
                fill.0 = dot_color;
            }
        }
    }
}

#[cfg(target_arch = "wasm32")]
fn sync_command_state(
    groups: Query<&CommandGroupState, Changed<CommandGroupState>>,
    mut nodes: Query<&mut Node>,
    mut borders: Query<&mut BorderColor>,
    mut visuals: Query<(
        &Interaction,
        &mut InteractivePrimitive,
        &mut BackgroundColor,
    )>,
    mut texts: Query<(&mut Text, &mut TextColor)>,
) {
    for group in &groups {
        let render_nodes = command_render_nodes(&group.model, &group.state);
        let visible_items = render_nodes
            .iter()
            .filter(|node| node.part == CommandPart::Item && node.visible)
            .collect::<Vec<_>>();
        let metrics = command_layout_metrics(
            &group.model,
            &group.state,
            group.available_width,
            group.inline_size,
            group.theme.border.max(1.0),
        );

        if let Ok(mut list) = nodes.get_mut(group.list) {
            list.display = if group.state.is_open() {
                Display::Flex
            } else {
                Display::None
            };
            list.height = px(metrics.list_height);
            list.max_height = px(metrics.list_max_height);
        }
        if let Ok(mut empty) = nodes.get_mut(group.empty) {
            empty.display = if group.state.is_open() && visible_items.is_empty() {
                Display::Flex
            } else {
                Display::None
            };
        }
        for entry in &group.groups {
            let visible = render_nodes.iter().any(|node| {
                node.part == CommandPart::Group && node.visible && node.value == entry.value
            });
            if let Ok(mut node) = nodes.get_mut(entry.entity) {
                node.display = if visible {
                    Display::Flex
                } else {
                    Display::None
                };
            }
        }
        for entry in &group.items {
            let visible = visible_items.iter().any(|node| node.value == entry.value);
            let selected = group.state.is_selected(&entry.value);
            let highlighted = group.state.is_highlighted(&entry.value);
            if let Ok(mut node) = nodes.get_mut(entry.entity) {
                node.display = if visible {
                    Display::Flex
                } else {
                    Display::None
                };
            }
            if let Ok(mut border) = borders.get_mut(entry.entity) {
                *border = BorderColor::all(command_item_border(
                    &group.theme,
                    selected,
                    highlighted,
                    entry.disabled,
                ));
            }
            let fill = command_item_fill(&group.theme, selected, highlighted, entry.disabled);
            if let Ok((interaction, mut colors, mut background)) = visuals.get_mut(entry.entity) {
                colors.rest = fill;
                colors.selected = group
                    .theme
                    .selected_tint()
                    .to_bevy_on(group.theme.surface_1());
                colors.latched = selected || highlighted;
                if *interaction == Interaction::None {
                    background.0 = fill;
                }
            }
        }

        if let Ok(mut border) = borders.get_mut(group.input) {
            *border = BorderColor::all(if group.focused && group.state.is_open() {
                group.theme.brand().to_bevy()
            } else {
                group.theme.border_strong().to_bevy()
            });
        }
        if let Ok((mut text, mut color)) = texts.get_mut(group.input_text) {
            let placeholder = group.state.query().is_empty();
            text.0 = if placeholder {
                group.model.placeholder.clone()
            } else {
                group.state.query().to_owned()
            };
            color.0 = if group.blocked {
                group.theme.text_disabled().to_bevy()
            } else if placeholder {
                group.theme.text_muted().to_bevy()
            } else {
                group.theme.text_1().to_bevy()
            };
        }
    }
}

#[cfg(target_arch = "wasm32")]
#[allow(clippy::too_many_arguments)]
fn sync_context_menu_state(
    groups: Query<&ContextMenuGroupState, Changed<ContextMenuGroupState>>,
    interactions: Query<&Interaction>,
    mut controls: Query<&mut ContextMenuEntryControl>,
    mut visuals: Query<&mut InteractivePrimitive>,
    mut layout_nodes: Query<&mut Node>,
    mut backgrounds: Query<&mut BackgroundColor>,
    mut borders: Query<&mut BorderColor>,
    mut texts: Query<&mut Text>,
    mut text_colors: Query<&mut TextColor>,
) {
    for group in &groups {
        let open = group.state.is_open();
        let metrics = context_menu_layout_metrics(
            group.model.density,
            group.model.disabled,
            group.inline_size,
        );
        let render_nodes = context_menu_render_nodes(&group.model, &group.state);
        if let Ok(mut trigger) = layout_nodes.get_mut(group.trigger) {
            trigger.flex_grow = 1.0;
        }
        if let Ok(mut content) = layout_nodes.get_mut(group.content) {
            content.display = if open { Display::Flex } else { Display::None };
            content.flex_grow = if open { 1.0 } else { 0.0 };
        }

        for entry in &group.entries {
            let dynamic = render_nodes.iter().find(|node| {
                node.part == entry.part
                    && node.value == entry.value
                    && node.parent_value == entry.parent_value
            });
            let visible = dynamic.is_some_and(|node| node.visible);
            if let Ok(mut layout) = layout_nodes.get_mut(entry.entity) {
                layout.display = if visible {
                    Display::Flex
                } else {
                    Display::None
                };
                if entry.part != ContextMenuPart::Separator {
                    layout.flex_grow = if visible { 1.0 } else { 0.0 };
                    layout.min_height = px(metrics.item_min_height);
                }
            }
            if entry.part == ContextMenuPart::Separator {
                continue;
            }

            let selected = dynamic.is_some_and(|node| node.selected);
            let active = dynamic.is_some_and(|node| node.active);
            let submenu_open = dynamic.is_some_and(|node| node.submenu_open);
            let disabled = dynamic.map_or(group.blocked || entry.disabled, |node| node.disabled);
            let destructive = dynamic.map_or(entry.destructive, |node| node.destructive);
            let palette = context_menu_row_palette(
                entry.part,
                selected,
                active,
                submenu_open,
                disabled,
                destructive,
                &group.theme,
            );
            if let Ok(mut control) = controls.get_mut(entry.entity) {
                control.disabled = disabled;
            }
            if let Ok(mut visual) = visuals.get_mut(entry.entity) {
                visual.rest = palette.background;
                visual.selected = palette.background;
                visual.hover = palette.hover;
                visual.pressed = palette.hover;
                visual.latched = selected || active || submenu_open;
            }
            let interaction = interactions
                .get(entry.entity)
                .copied()
                .unwrap_or(Interaction::None);
            if let Ok(mut background) = backgrounds.get_mut(entry.entity) {
                background.0 = match interaction {
                    Interaction::Hovered | Interaction::Pressed if !disabled => palette.hover,
                    Interaction::Hovered | Interaction::Pressed | Interaction::None => {
                        palette.background
                    }
                };
            }
            if let Ok(mut border) = borders.get_mut(entry.entity) {
                *border = BorderColor::all(palette.border);
            }
            if let Some(label_entity) = entry.label {
                if let Some(node) = dynamic
                    && let Ok(mut label) = texts.get_mut(label_entity)
                {
                    label.0 = node.label.clone();
                }
                if let Ok(mut color) = text_colors.get_mut(label_entity) {
                    color.0 = palette.label;
                }
            }
            if let Some(detail_entity) = entry.detail {
                if let Some(node) = dynamic
                    && let Ok(mut detail) = texts.get_mut(detail_entity)
                {
                    detail.0 = node.detail.clone();
                }
                if let Ok(mut color) = text_colors.get_mut(detail_entity) {
                    color.0 = palette.detail;
                }
            }
            if let Some(marker_entity) = entry.marker {
                if let Ok(mut marker) = texts.get_mut(marker_entity) {
                    marker.0 = if entry.part == ContextMenuPart::Submenu {
                        if submenu_open { "open" } else { ">" }.to_owned()
                    } else {
                        dynamic.map_or_else(String::new, |node| node.shortcut.clone())
                    };
                }
                if let Ok(mut color) = text_colors.get_mut(marker_entity) {
                    color.0 = palette.marker;
                }
            }
        }
    }
}

#[cfg(target_arch = "wasm32")]
#[allow(clippy::too_many_arguments)]
fn sync_data_table_state(
    groups: Query<&DataTableGroupState, Changed<DataTableGroupState>>,
    interactions: Query<&Interaction>,
    mut layout_nodes: Query<&mut Node>,
    mut header_controls: Query<&mut DataTableHeaderControl>,
    mut row_controls: Query<&mut DataTableRowControl>,
    mut page_controls: Query<&mut DataTablePageControl>,
    mut backgrounds: Query<&mut BackgroundColor>,
    mut borders: Query<&mut BorderColor>,
    mut visuals: Query<&mut InteractivePrimitive>,
    mut texts: Query<&mut Text>,
    mut text_colors: Query<&mut TextColor>,
) {
    for group in &groups {
        let render_nodes = data_table_render_nodes(&group.model, &group.state);
        let column_weights = data_table_column_weights(&group.model, &render_nodes);
        let placeholder = group.state.filter().is_empty();
        let (filter_background, filter_border, filter_text) = data_table_filter_colors(
            placeholder,
            group.focused,
            group.blocked,
            group.root_fill,
            &group.theme,
        );
        if let Ok(mut text) = texts.get_mut(group.filter) {
            text.0 = if placeholder {
                group.model.filter_placeholder.clone()
            } else {
                group.state.filter().to_owned()
            };
        }
        if let Ok(mut color) = text_colors.get_mut(group.filter) {
            color.0 = filter_text;
        }
        if let Ok(mut background) = backgrounds.get_mut(group.filter) {
            background.0 = filter_background;
        }
        if let Ok(mut border) = borders.get_mut(group.filter) {
            *border = BorderColor::all(filter_border);
        }
        if let Ok(mut visual) = visuals.get_mut(group.filter) {
            visual.rest = filter_background;
            visual.selected = filter_background;
            visual.hover = filter_background;
            visual.pressed = filter_background;
        }

        for (column_index, entry) in group.headers.iter().enumerate() {
            let node = render_nodes
                .iter()
                .find(|node| {
                    node.part == DataTablePart::Header && node.column_value == entry.column
                })
                .expect("invariant: data table render nodes include every header");
            let disabled = node.disabled || entry.disabled;
            let palette =
                data_table_header_palette(node.selected, disabled, group.root_fill, &group.theme);
            if let Ok(mut layout) = layout_nodes.get_mut(entry.entity) {
                layout.flex_grow = column_weights[column_index];
            }
            if let Ok(mut control) = header_controls.get_mut(entry.entity) {
                control.disabled = disabled;
            }
            if let Ok(mut visual) = visuals.get_mut(entry.entity) {
                visual.rest = palette.background;
                visual.selected = palette.background;
                visual.hover = palette.background;
                visual.pressed = palette.background;
                visual.latched = node.selected && !disabled;
            }
            if let Ok(mut background) = backgrounds.get_mut(entry.entity) {
                background.0 = palette.background;
            }
            if let Ok(mut border) = borders.get_mut(entry.entity) {
                *border = BorderColor::all(palette.border);
            }
            if let Ok(mut label) = texts.get_mut(entry.label) {
                label.0 = node.label.to_uppercase();
            }
            if let Ok(mut color) = text_colors.get_mut(entry.label) {
                color.0 = palette.text;
            }
            if let Ok(mut marker) = texts.get_mut(entry.marker) {
                marker.0 = data_table_sort_marker(node.sort_direction).to_owned();
            }
            if let Ok(mut color) = text_colors.get_mut(entry.marker) {
                color.0 = palette.marker;
            }
        }

        for entry in &group.rows {
            let node = render_nodes
                .iter()
                .find(|node| node.part == DataTablePart::Row && node.row_value == entry.value);
            let visible = node.is_some();
            let selected = node.is_some_and(|node| node.selected);
            let disabled = node.map_or(group.blocked || entry.disabled, |node| node.disabled);
            let palette = data_table_row_palette(selected, disabled, group.root_fill, &group.theme);
            if let Ok(mut layout) = layout_nodes.get_mut(entry.entity) {
                layout.display = if visible {
                    Display::Flex
                } else {
                    Display::None
                };
            }
            if let Ok(mut control) = row_controls.get_mut(entry.entity) {
                control.disabled = disabled;
            }
            if let Ok(mut visual) = visuals.get_mut(entry.entity) {
                visual.rest = palette.background;
                visual.selected = palette.background;
                visual.hover = palette.hover;
                visual.pressed = palette.hover;
                visual.latched = selected;
            }
            let interaction = interactions
                .get(entry.entity)
                .copied()
                .unwrap_or(Interaction::None);
            if let Ok(mut background) = backgrounds.get_mut(entry.entity) {
                background.0 = match interaction {
                    Interaction::Hovered | Interaction::Pressed if visible && !disabled => {
                        palette.hover
                    }
                    Interaction::Hovered | Interaction::Pressed | Interaction::None => {
                        palette.background
                    }
                };
            }
            if let Ok(mut border) = borders.get_mut(entry.entity) {
                *border = BorderColor::all(palette.border);
            }
            for (column_index, cell) in entry.cells.iter().enumerate() {
                if let Ok(mut layout) = layout_nodes.get_mut(*cell) {
                    layout.flex_grow = column_weights[column_index];
                }
                if let Ok(mut color) = text_colors.get_mut(*cell) {
                    color.0 = palette.text;
                }
            }
        }

        let empty = render_nodes
            .iter()
            .find(|node| node.part == DataTablePart::Row && node.value == "empty");
        if let Ok(mut layout) = layout_nodes.get_mut(group.empty) {
            layout.display = if empty.is_some() {
                Display::Flex
            } else {
                Display::None
            };
        }
        if let Some(empty) = empty
            && let Ok(mut text) = texts.get_mut(group.empty)
        {
            text.0 = empty.label.clone();
        }

        let pagination = render_nodes
            .iter()
            .find(|node| node.part == DataTablePart::Pagination)
            .expect("invariant: data table render nodes include pagination");
        if let Ok(mut text) = texts.get_mut(group.page_label) {
            text.0 = pagination.label.to_uppercase();
        }
        let previous_disabled = group.blocked || group.state.page_index() == 0;
        let next_disabled = group.blocked
            || group.state.page_index() >= max_data_table_page_index(&group.model, &group.state);
        for (entity, disabled) in [
            (group.previous, previous_disabled),
            (group.next, next_disabled),
        ] {
            let palette = data_table_page_palette(disabled, group.root_fill, &group.theme);
            if let Ok(mut control) = page_controls.get_mut(entity) {
                control.disabled = disabled;
            }
            if let Ok(mut visual) = visuals.get_mut(entity) {
                visual.rest = palette.background;
                visual.selected = palette.background;
                visual.hover = palette.hover;
                visual.pressed = palette.hover;
                visual.latched = false;
            }
            let interaction = interactions
                .get(entity)
                .copied()
                .unwrap_or(Interaction::None);
            if let Ok(mut background) = backgrounds.get_mut(entity) {
                background.0 = match interaction {
                    Interaction::Hovered | Interaction::Pressed if !disabled => palette.hover,
                    Interaction::Hovered | Interaction::Pressed | Interaction::None => {
                        palette.background
                    }
                };
            }
            if let Ok(mut border) = borders.get_mut(entity) {
                *border = BorderColor::all(palette.border);
            }
            if let Ok(mut color) = text_colors.get_mut(entity) {
                color.0 = palette.text;
            }
        }
    }
}

#[cfg(target_arch = "wasm32")]
fn sync_direction_state(
    groups: Query<&DirectionGroupState, Changed<DirectionGroupState>>,
    mut nodes: Query<&mut Node>,
    mut borders: Query<&mut BorderColor>,
    mut surfaces: Query<&mut BackgroundColor, Without<InteractivePrimitive>>,
    mut visuals: Query<
        (
            &Interaction,
            &mut InteractivePrimitive,
            &mut BackgroundColor,
        ),
        With<InteractivePrimitive>,
    >,
    mut texts: Query<(&mut Text, &mut TextFont, &mut TextColor, &mut TextLayout)>,
) {
    for group in &groups {
        let provider_direction = group.state.direction();
        let scope_direction = group.model.scope_direction;
        let effective_direction = group.state.effective_direction(&group.model);
        for entity in [group.root, group.header, group.actions] {
            if let Ok(mut node) = nodes.get_mut(entity) {
                node.direction = direction_inline(provider_direction);
            }
        }
        if let Ok(mut content) = nodes.get_mut(group.content_panel) {
            content.direction = direction_inline(effective_direction);
        }
        if let Ok(mut badge) = nodes.get_mut(group.content_badge) {
            badge.direction = direction_inline(effective_direction);
        }

        let provider_justify = direction_text_justify(provider_direction);
        for entity in [group.eyebrow, group.title, group.provider_detail] {
            if let Ok((_, _, _, mut layout)) = texts.get_mut(entity) {
                layout.justify = provider_justify;
            }
        }
        if let Ok((mut text, _, _, _)) = texts.get_mut(group.title) {
            text.0 = provider_direction.name().to_owned();
        }
        if let Ok((mut text, _, _, _)) = texts.get_mut(group.provider_detail) {
            text.0 = direction_provider_detail(provider_direction, scope_direction);
        }

        let provider_active = provider_direction.is_rtl();
        let (provider_fill, provider_border, provider_text) =
            direction_action_colors(&group.theme, provider_active, group.blocked);
        if let Ok((interaction, mut colors, mut background)) =
            visuals.get_mut(group.provider_action)
        {
            colors.rest = provider_fill;
            colors.selected = group
                .theme
                .selected_tint()
                .to_bevy_on(group.theme.surface_2());
            colors.latched = provider_active;
            if group.blocked {
                colors.hover = provider_fill;
                colors.pressed = provider_fill;
            }
            if *interaction == Interaction::None {
                background.0 = provider_fill;
            }
        }
        if let Ok(mut border) = borders.get_mut(group.provider_action) {
            *border = BorderColor::all(provider_border);
        }
        if let Ok((mut text, mut font, mut color, _)) = texts.get_mut(group.provider_action) {
            text.0 = direction_provider_action_label(provider_direction);
            font.weight = if provider_active {
                FontWeight::BOLD
            } else {
                FontWeight::SEMIBOLD
            };
            color.0 = provider_text;
        }

        let scope_active = group.state.scope_active();
        let (scope_action_fill, scope_action_border, scope_action_text) =
            direction_action_colors(&group.theme, scope_active, group.blocked);
        if let Ok((interaction, mut colors, mut background)) = visuals.get_mut(group.scope_action) {
            colors.rest = scope_action_fill;
            colors.selected = group
                .theme
                .selected_tint()
                .to_bevy_on(group.theme.surface_2());
            colors.latched = scope_active;
            if group.blocked {
                colors.hover = scope_action_fill;
                colors.pressed = scope_action_fill;
            }
            if *interaction == Interaction::None {
                background.0 = scope_action_fill;
            }
        }
        if let Ok(mut border) = borders.get_mut(group.scope_action) {
            *border = BorderColor::all(scope_action_border);
        }
        if let Ok((mut text, mut font, mut color, _)) = texts.get_mut(group.scope_action) {
            text.0 = direction_scope_action_label(scope_active, scope_direction);
            font.weight = if scope_active {
                FontWeight::BOLD
            } else {
                FontWeight::SEMIBOLD
            };
            color.0 = scope_action_text;
        }

        let (scope_fill, scope_border) =
            direction_scope_colors(&group.theme, scope_active, group.disabled);
        if let Ok(mut background) = surfaces.get_mut(group.scope_panel) {
            background.0 = scope_fill;
        }
        if let Ok(mut border) = borders.get_mut(group.scope_panel) {
            *border = BorderColor::all(scope_border);
        }
        if let Ok((mut text, _, _, _)) = texts.get_mut(group.scope_badge) {
            text.0 = direction_scope_badge_label(scope_active, scope_direction);
        }
        if let Ok((mut text, _, mut color, mut layout)) = texts.get_mut(group.scope_detail) {
            text.0 = direction_render_nodes(&group.model, &group.state)
                .into_iter()
                .find(|node| node.part == DirectionPart::Scope)
                .map_or_else(String::new, |node| node.detail);
            color.0 = if group.disabled {
                group.theme.text_disabled().to_bevy()
            } else {
                group.theme.text_2().to_bevy()
            };
            layout.justify = direction_text_justify(scope_direction);
        }

        let (content_fill, content_border) =
            direction_content_colors(&group.theme, effective_direction, group.disabled);
        if let Ok(mut background) = surfaces.get_mut(group.content_panel) {
            background.0 = content_fill;
        }
        if let Ok(mut border) = borders.get_mut(group.content_panel) {
            *border = BorderColor::all(content_border);
        }
        if let Ok((mut text, _, _, _)) = texts.get_mut(group.content_badge) {
            text.0 = direction_content_badge_label(effective_direction);
        }
        if let Ok((_, _, mut color, mut layout)) = texts.get_mut(group.content_detail) {
            color.0 = if group.disabled {
                group.theme.text_disabled().to_bevy()
            } else {
                group.theme.text_2().to_bevy()
            };
            layout.justify = direction_text_justify(effective_direction);
        }
    }
}

#[cfg(target_arch = "wasm32")]
fn sync_drawer_state(
    groups: Query<&DrawerGroupState, Changed<DrawerGroupState>>,
    mut nodes: Query<&mut Node>,
    mut borders: Query<&mut BorderColor>,
    mut visuals: Query<(
        &Interaction,
        &mut InteractivePrimitive,
        &mut BackgroundColor,
    )>,
    mut texts: Query<(&mut TextFont, &mut TextColor)>,
) {
    for group in &groups {
        let open = group.state.is_open();
        if let Ok(mut overlay) = nodes.get_mut(group.overlay) {
            overlay.display = if open { Display::Grid } else { Display::None };
        }

        let (trigger_fill, trigger_border, trigger_text) =
            drawer_trigger_colors(&group.theme, open, group.blocked);
        if let Ok((interaction, mut colors, mut background)) = visuals.get_mut(group.trigger) {
            colors.rest = trigger_fill;
            colors.selected = group
                .theme
                .selected_tint()
                .to_bevy_on(group.theme.surface_2());
            colors.latched = open;
            if group.blocked {
                colors.hover = trigger_fill;
                colors.pressed = trigger_fill;
            }
            if *interaction == Interaction::None {
                background.0 = trigger_fill;
            }
        }
        if let Ok(mut border) = borders.get_mut(group.trigger) {
            *border = BorderColor::all(trigger_border);
        }
        if let Ok((mut font, mut color)) = texts.get_mut(group.trigger) {
            font.weight = if open {
                FontWeight::BOLD
            } else {
                FontWeight::SEMIBOLD
            };
            color.0 = trigger_text;
        }

        let dragging = group.state.is_dragging();
        let handle_fill = if dragging {
            group.theme.brand().to_bevy()
        } else if group.blocked {
            group.theme.surface_2().to_bevy()
        } else {
            group.theme.surface_3().to_bevy()
        };
        if let Ok(mut handle) = nodes.get_mut(group.handle) {
            let width = if dragging {
                group.active_handle_width
            } else {
                group.handle_width
            };
            handle.width = px(width);
            handle.min_width = px(width);
            handle.max_width = px(width);
        }
        if let Ok(mut border) = borders.get_mut(group.handle) {
            *border = BorderColor::all(if dragging {
                group.theme.brand().to_bevy()
            } else if group.blocked {
                group.theme.border_muted().to_bevy()
            } else {
                group.theme.border_subtle().to_bevy()
            });
        }
        if let Ok((interaction, mut colors, mut background)) = visuals.get_mut(group.handle) {
            colors.rest = handle_fill;
            colors.selected = group.theme.brand().to_bevy();
            colors.latched = dragging;
            if group.blocked {
                colors.hover = handle_fill;
                colors.pressed = handle_fill;
            }
            if *interaction == Interaction::None {
                background.0 = handle_fill;
            }
        }

        for (index, action) in group.actions.iter().enumerate() {
            let selected = group.state.active_action() == Some(action.value.as_str());
            let (fill, border, text) =
                drawer_action_colors(&group.theme, index, selected, action.disabled);
            if let Ok(mut border_color) = borders.get_mut(action.entity) {
                *border_color = BorderColor::all(border);
            }
            if let Ok((interaction, mut colors, mut background)) = visuals.get_mut(action.entity) {
                colors.rest = fill;
                colors.selected = group
                    .theme
                    .selected_tint()
                    .to_bevy_on(group.theme.surface_2());
                colors.latched = selected;
                if action.disabled {
                    colors.hover = fill;
                    colors.pressed = fill;
                }
                if *interaction == Interaction::None {
                    background.0 = fill;
                }
            }
            if let Ok((mut font, mut color)) = texts.get_mut(action.entity) {
                font.weight = if index == 0 || selected {
                    FontWeight::BOLD
                } else {
                    FontWeight::SEMIBOLD
                };
                color.0 = text;
            }
        }
    }
}

#[cfg(target_arch = "wasm32")]
fn sync_field_state(
    groups: Query<&FieldGroup, Changed<FieldGroup>>,
    mut controls: Query<
        (
            &Interaction,
            &mut InteractivePrimitive,
            &mut BackgroundColor,
            &mut BorderColor,
        ),
        With<FieldControlTrigger>,
    >,
    mut texts: Query<(&mut Text, &mut TextColor)>,
) {
    for group in &groups {
        let focused = group.state.is_focused();
        let placeholder = group.state.value().is_empty();
        let (fill, border, text_color) = field_control_colors(
            &group.theme,
            focused,
            group.invalid,
            group.blocked,
            placeholder,
        );
        if let Ok((interaction, mut colors, mut background, mut border_color)) =
            controls.get_mut(group.control)
        {
            colors.rest = fill;
            colors.selected = fill;
            colors.hover = fill;
            colors.pressed = fill;
            colors.latched = focused;
            if *interaction == Interaction::None {
                background.0 = fill;
            }
            *border_color = BorderColor::all(border);
        }
        if let Ok((mut text, mut color)) = texts.get_mut(group.value_text) {
            text.0 = if placeholder {
                group.placeholder.clone()
            } else {
                group.state.value().to_owned()
            };
            color.0 = text_color;
        }
    }
}

#[cfg(target_arch = "wasm32")]
#[allow(clippy::too_many_arguments)]
fn sync_hover_card_state(
    groups: Query<&HoverCardGroupState, Changed<HoverCardGroupState>>,
    interactions: Query<&Interaction>,
    mut nodes: Query<&mut Node>,
    mut visuals: Query<&mut InteractivePrimitive>,
    mut backgrounds: Query<&mut BackgroundColor>,
    mut borders: Query<&mut BorderColor>,
    mut texts: Query<(&mut Text, &mut TextFont, &mut TextColor)>,
    mut shadows: Query<&mut BoxShadow>,
) {
    for group in &groups {
        let open = group.state.is_open();
        let palette =
            hover_card_trigger_palette(open, group.blocked, group.root_fill, &group.theme);
        if let Ok(mut content) = nodes.get_mut(group.content) {
            content.display = if open { Display::Flex } else { Display::None };
        }
        if let Ok(mut visual) = visuals.get_mut(group.trigger) {
            visual.rest = palette.background;
            visual.selected = palette.background;
            visual.hover = palette.hover;
            visual.pressed = palette.hover;
            visual.latched = open;
        }
        let interaction = interactions
            .get(group.trigger)
            .copied()
            .unwrap_or(Interaction::None);
        if let Ok(mut background) = backgrounds.get_mut(group.trigger) {
            background.0 = match interaction {
                Interaction::Hovered | Interaction::Pressed if !group.blocked => palette.hover,
                Interaction::Hovered | Interaction::Pressed | Interaction::None => {
                    palette.background
                }
            };
        }
        if let Ok(mut border) = borders.get_mut(group.trigger) {
            *border = BorderColor::all(palette.border);
        }
        if let Ok((mut text, mut font, mut color)) = texts.get_mut(group.trigger_text) {
            text.0 = if group.model.loading {
                "Loading preview".to_owned()
            } else {
                group.model.trigger_label.clone()
            };
            font.weight = if open {
                FontWeight::BOLD
            } else {
                FontWeight::SEMIBOLD
            };
            color.0 = palette.text;
        }
        if let Ok(mut shadow) = shadows.get_mut(group.trigger) {
            *shadow = if group.blocked {
                BoxShadow::default()
            } else if open {
                bevy_shadow_2(&group.theme, group.inline_size)
            } else {
                bevy_shadow_1(&group.theme, group.inline_size)
            };
        }
    }
}

#[cfg(target_arch = "wasm32")]
#[allow(clippy::too_many_arguments)]
fn sync_input_state(
    groups: Query<&InputGroupState, Changed<InputGroupState>>,
    interactions: Query<&Interaction>,
    mut nodes: Query<&mut Node>,
    mut visuals: Query<&mut InteractivePrimitive>,
    mut backgrounds: Query<&mut BackgroundColor>,
    mut borders: Query<&mut BorderColor>,
    mut suffix_controls: Query<&mut InputSuffixControl>,
    mut texts: Query<(&mut Text, &mut TextFont, &mut TextColor)>,
    mut shadows: Query<&mut BoxShadow>,
) {
    for group in &groups {
        let metrics = input_layout_metrics(&group.model, &group.state, group.inline_size);
        let render_nodes = input_render_nodes(&group.model, &group.state);
        let prefix_node = render_nodes
            .iter()
            .find(|node| node.part == InputPart::Prefix)
            .expect("invariant: input render nodes include prefix");
        let suffix_node = render_nodes
            .iter()
            .find(|node| node.part == InputPart::Suffix)
            .expect("invariant: input render nodes include suffix");
        let row_palette = input_row_palette(
            group.model.loading,
            group.model.disabled,
            group.model.error.is_some(),
            group.state.is_focused(),
            group.root_fill,
            &group.theme,
        );
        let prefix_palette =
            input_prefix_palette(group.model.disabled, group.root_fill, &group.theme);
        let placeholder = group.state.value().is_empty();
        let control_text = input_control_text_color(
            group.model.loading,
            group.model.disabled,
            placeholder,
            group.root_fill,
            &group.theme,
        );
        let suffix_active = group.state.is_active(InputPart::Suffix);
        let suffix_palette = input_suffix_palette(
            suffix_active,
            suffix_node.disabled,
            group.model.disabled,
            row_palette.fill_tone,
            &group.theme,
        );

        if let Ok(mut row) = nodes.get_mut(group.row) {
            row.min_height = px(metrics.row_min_height);
        }
        if let Ok(mut background) = backgrounds.get_mut(group.row) {
            background.0 = row_palette.background;
        }
        if let Ok(mut border) = borders.get_mut(group.row) {
            *border = BorderColor::all(row_palette.border);
        }
        if let Ok(mut shadow) = shadows.get_mut(group.row) {
            *shadow = input_row_shadow(
                group.model.disabled,
                group.state.is_focused(),
                &group.theme,
                group.inline_size,
            );
        }

        if let Ok(mut prefix) = nodes.get_mut(group.prefix) {
            prefix.display = if prefix_node.visible {
                Display::Flex
            } else {
                Display::None
            };
            prefix.padding = UiRect::horizontal(px(metrics.prefix_padding_inline));
        }
        if let Ok(mut background) = backgrounds.get_mut(group.prefix) {
            background.0 = prefix_palette.background;
        }
        if let Ok(mut border) = borders.get_mut(group.prefix) {
            *border = BorderColor::all(prefix_palette.border);
        }
        if let Ok((mut text, mut font, mut color)) = texts.get_mut(group.prefix) {
            text.0 = prefix_node.label.clone();
            font.font_size = FontSize::Px(metrics.prefix_font_size);
            color.0 = prefix_palette.text;
        }

        if let Ok(mut control) = nodes.get_mut(group.control) {
            control.padding = UiRect::axes(
                px(metrics.control_padding_inline),
                px(metrics.control_padding_block),
            );
        }
        if let Ok((mut text, mut font, mut color)) = texts.get_mut(group.control_text) {
            text.0 = input_display_value(
                group.model.input_kind,
                group.state.value(),
                &group.model.placeholder,
            );
            font.font_size = FontSize::Px(metrics.control_font_size);
            color.0 = control_text;
        }

        if let Ok(mut suffix) = nodes.get_mut(group.suffix) {
            suffix.display = if suffix_node.visible {
                Display::Flex
            } else {
                Display::None
            };
            suffix.padding = UiRect::horizontal(px(metrics.suffix_padding_inline));
        }
        if let Ok(mut control) = suffix_controls.get_mut(group.suffix) {
            control.disabled = suffix_node.disabled;
        }
        if let Ok(mut visual) = visuals.get_mut(group.suffix) {
            visual.rest = suffix_palette.background;
            visual.selected = suffix_palette.selected;
            visual.hover = suffix_palette.hover;
            visual.pressed = suffix_palette.hover;
            visual.latched = suffix_active;
        }
        let suffix_interaction = interactions
            .get(group.suffix)
            .copied()
            .unwrap_or(Interaction::None);
        if let Ok(mut background) = backgrounds.get_mut(group.suffix) {
            background.0 = match suffix_interaction {
                Interaction::Hovered | Interaction::Pressed if !suffix_node.disabled => {
                    suffix_palette.hover
                }
                Interaction::Hovered | Interaction::Pressed | Interaction::None => {
                    suffix_palette.background
                }
            };
        }
        if let Ok(mut border) = borders.get_mut(group.suffix) {
            *border = BorderColor::all(suffix_palette.border);
        }
        if let Ok((mut text, mut font, mut color)) = texts.get_mut(group.suffix_text) {
            text.0 = suffix_node.label.clone();
            font.font_size = FontSize::Px(metrics.suffix_font_size);
            font.weight = if suffix_active {
                FontWeight::BOLD
            } else {
                FontWeight::SEMIBOLD
            };
            color.0 = suffix_palette.text;
        }
    }
}

#[cfg(target_arch = "wasm32")]
